} from 'lucide-react';
import { MOCK_PROPERTIES, MOCK_SERVICES } from '../constants';
import { Property, RealEstateService, PropertyCategory } from '../types';

const CatalogView: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'imoveis' | 'servicos'>('imoveis');
  const [properties, setProperties] = useState<Property[]>(MOCK_PROPERTIES);
  const [services, setServices] = useState<RealEstateService[]>(MOCK_SERVICES);
  const [showModal, setShowModal] = useState(false);
  const [editingItem, setEditingItem] = useState<any>(null);

  const [newProp, setNewProp] = useState<Partial<Property>>({
    title: '', type: 'Casa', dealType: 'Venda', price: 0, location: '', beds: 1, baths: 1, area: 0, description: ''
  });

  const handleDeleteProp = (id: string) => {
    if(confirm('Eliminar este imóvel do catálogo público?')) {
      setProperties(properties.filter(p => p.id !== id));
    }
  };

  const handleDeleteService = (id: string) => {
    if(confirm('Eliminar este serviço das ofertas?')) {
      setServices(services.filter(s => s.id !== id));
    }
  };

  const handleSaveProperty = (e: React.FormEvent) => {
    e.preventDefault();
    const item: Property = {
      id: editingItem?.id || Math.random().toString(36).substr(2, 9),
      title: newProp.title || '',
      type: newProp.type as PropertyCategory,
      dealType: newProp.dealType as 'Venda' | 'Aluguel',
      price: Number(newProp.price),
      location: newProp.location || '',
      beds: Number(newProp.beds),
      baths: Number(newProp.baths),
      area: Number(newProp.area),
      description: newProp.description || '',
      image: editingItem?.image || 'https://images.unsplash.com/photo-1564013799919-ab600027ffc6?auto=format&fit=crop&q=80&w=800',
      gallery: editingItem?.gallery || [],
      featured: true
    };

    if(editingItem) {
      setProperties(properties.map(p => p.id === item.id ? item : p));
    } else {
      setProperties([item, ...properties]);
    }
    setShowModal(false);
    setEditingItem(null);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">Gestão de Catálogo</h1>
          <p className="text-slate-500 font-medium">Controlo centralizado de imóveis e serviços públicos.</p>
        </div>
        <div className="flex bg-white p-1 rounded-2xl border border-slate-200 shadow-sm">
          <button onClick={() => setActiveTab('imoveis')} className={`px-6 py-2.5 rounded-xl text-xs font-black transition-all ${activeTab === 'imoveis' ? 'bg-blue-600 text-white' : 'text-slate-500 hover:text-slate-800'}`}>Imóveis</button>
          <button onClick={() => setActiveTab('servicos')} className={`px-6 py-2.5 rounded-xl text-xs font-black transition-all ${activeTab === 'servicos' ? 'bg-blue-600 text-white' : 'text-slate-500 hover:text-slate-800'}`}>Serviços</button>
        </div>
      </div>

      <div className="flex items-center justify-between gap-4">
        <div className="relative flex-1 max-w-md">
          <Search size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" />
          <input className="w-full pl-12 pr-4 py-4 bg-white border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 font-bold text-sm" placeholder="Pesquisar no catálogo..." />
        </div>
        <button onClick={() => { setEditingItem(null); setShowModal(true); }} className="flex items-center gap-2 bg-blue-600 text-white px-8 py-4 rounded-2xl font-black text-sm hover:bg-blue-700 transition-all shadow-xl shadow-blue-500/20">
          <Plus size={20} /> {activeTab === 'imoveis' ? 'Novo Imóvel' : 'Novo Serviço'}
        </button>
      </div>

      {activeTab === 'imoveis' ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {properties.map(prop => (
            <div key={prop.id} className="group bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden hover:shadow-2xl transition-all relative">
              <div className="h-48 relative overflow-hidden">
                <img src={prop.image} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" />
                <div className="absolute top-4 left-4 bg-white/90 backdrop-blur-md px-3 py-1 rounded-xl text-[10px] font-black uppercase text-blue-600 shadow-sm">{prop.dealType}</div>
              </div>
              <div className="p-8">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{prop.type}</p>
                <h3 className="text-lg font-black text-slate-900 mb-4 truncate">{prop.title}</h3>
                <div className="flex items-center justify-between pt-6 border-t border-slate-50">
                   <p className="text-blue-600 font-black">{prop.price.toLocaleString()} MT</p>
                   <div className="flex gap-2">
                     <button onClick={() => { setEditingItem(prop); setNewProp(prop); setShowModal(true); }} className="p-2.5 bg-slate-50 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl transition-all"><Edit3 size={16} /></button>
                     <button onClick={() => handleDeleteProp(prop.id)} className="p-2.5 bg-slate-50 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all"><Trash2 size={16} /></button>
                   </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50/50 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                <th className="px-8 py-6">Serviço</th>
                <th className="px-8 py-6">Descrição</th>
                <th className="px-8 py-6 text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {services.map(service => (
                <tr key={service.id} className="hover:bg-slate-50/50 transition-all group">
                  <td className="px-8 py-6">
                    <div className="flex items-center gap-3">
                      <div className="p-2 bg-blue-50 text-blue-600 rounded-xl"><Paintbrush size={18} /></div>
                      <p className="text-sm font-black text-slate-900">{service.title}</p>
                    </div>
                  </td>
                  <td className="px-8 py-6 text-xs text-slate-500 font-medium max-w-xs truncate">{service.description}</td>
                  <td className="px-8 py-6 text-right">
                    <div className="flex justify-end gap-2">
                      <button className="p-2 text-slate-400 hover:text-blue-600"><Edit3 size={16} /></button>
                      <button onClick={() => handleDeleteService(service.id)} className="p-2 text-slate-400 hover:text-red-600"><Trash2 size={16} /></button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white rounded-[3rem] p-10 max-w-2xl w-full shadow-2xl relative overflow-y-auto max-h-[90vh]">
            <button onClick={() => setShowModal(false)} className="absolute top-8 right-8 p-2 text-slate-400 hover:text-slate-900 bg-slate-50 rounded-xl"><X size={24} /></button>
            <h2 className="text-2xl font-black text-slate-900 mb-8">{editingItem ? 'Editar Item' : 'Novo Registo de Catálogo'}</h2>
            <form onSubmit={handleSaveProperty} className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Título do Imóvel</label>
                  <input required value={newProp.title} onChange={e => setNewProp({...newProp, title: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 border-none focus:ring-2 focus:ring-blue-500 font-bold" />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Categoria</label>
                  <select value={newProp.type} onChange={e => setNewProp({...newProp, type: e.target.value as PropertyCategory})} className="w-full bg-slate-50 rounded-2xl p-4 border-none font-bold">
                    <option>Casa</option><option>Apartamento</option><option>Hotel</option><option>Terreno</option>
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Preço (MT)</label>
                  <input type="number" value={newProp.price} onChange={e => setNewProp({...newProp, price: Number(e.target.value)})} className="w-full bg-slate-50 rounded-2xl p-4 border-none font-bold" />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Localização</label>
                  <input value={newProp.location} onChange={e => setNewProp({...newProp, location: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 border-none font-bold" placeholder="Bairro..." />
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Descrição Pública</label>
                <textarea rows={3} value={newProp.description} onChange={e => setNewProp({...newProp, description: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 border-none font-bold" />
              </div>
              <div className="p-8 border-4 border-dashed border-slate-100 rounded-[2rem] flex flex-col items-center justify-center gap-3 bg-slate-50 hover:bg-slate-100 transition-all cursor-pointer">
                <Camera size={32} className="text-slate-300" />
                <p className="text-[10px] font-black text-slate-400 uppercase">Fazer Upload de Fotos Reais</p>
              </div>
              <button type="submit" className="w-full py-5 bg-blue-600 text-white font-black rounded-3xl shadow-xl hover:bg-blue-700 transition-all">
                Publicar no Catálogo <Check size={20} className="inline ml-2" />
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default CatalogView;

