import React, { useState, useEffect } from 'react';
import { 
  Plus, Search, Edit3, Trash2, X, Check, Camera, 
  Loader2
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { Property, RealEstateService, PropertyCategory } from '../types';

const CatalogView: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'imoveis' | 'servicos'>('imoveis');
  const [properties, setProperties] = useState<Property[]>([]);
  const [services, setServices] = useState<RealEstateService[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editingItem, setEditingItem] = useState<any>(null);

  const [newProp, setNewProp] = useState<Partial<Property>>({
    title: '', type: 'Casa', dealType: 'Venda', price: 0, location: '', beds: 1, baths: 1, area: 0, description: ''
  });

  useEffect(() => {
    fetchData();
  }, [activeTab]);

  async function fetchData() {
    setLoading(true);
    if (activeTab === 'imoveis') {
      const { data, error } = await supabase.from('properties').select('*').order('created_at', { ascending: false });
      if (!error) setProperties(data || []);
    } else {
      const { data, error } = await supabase.from('services').select('*').order('created_at', { ascending: false });
      if (!error) setServices(data || []);
    }
    setLoading(false);
  }

  const handleDeleteProp = async (id: string) => {
    if(confirm('Eliminar este imóvel do catálogo público?')) {
      const { error } = await supabase.from('properties').delete().eq('id', id);
      if (!error) fetchData();
    }
  };

  const handleSaveProperty = async (e: React.FormEvent) => {
    e.preventDefault();
    const payload = {
      title: newProp.title,
      type: newProp.type,
      deal_type: newProp.dealType,
      price: newProp.price,
      location: newProp.location,
      beds: newProp.beds,
      baths: newProp.baths,
      area: newProp.area,
      description: newProp.description,
      image: 'https://images.unsplash.com/photo-1564013799919-ab600027ffc6?auto=format&fit=crop&q=80&w=800'
    };

    let result;
    if (editingItem) {
      result = await supabase.from('properties').update(payload).eq('id', editingItem.id);
    } else {
      result = await supabase.from('properties').insert([payload]);
    }

    if (!result.error) {
      setShowModal(false);
      setEditingItem(null);
      fetchData();
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">Gestão de Catálogo</h1>
          <p className="text-slate-500 font-medium">Controlo centralizado via Supabase Cloud.</p>
        </div>
        <div className="flex bg-white p-1 rounded-2xl border border-slate-200 shadow-sm">
          <button onClick={() => setActiveTab('imoveis')} className={`px-6 py-2.5 rounded-xl text-xs font-black transition-all ${activeTab === 'imoveis' ? 'bg-blue-600 text-white' : 'text-slate-500 hover:text-slate-800'}`}>Imóveis</button>
          <button onClick={() => setActiveTab('servicos')} className={`px-6 py-2.5 rounded-xl text-xs font-black transition-all ${activeTab === 'servicos' ? 'bg-blue-600 text-white' : 'text-slate-500 hover:text-slate-800'}`}>Serviços</button>
        </div>
      </div>

      <div className="flex items-center justify-between gap-4">
        <div className="relative flex-1 max-w-md">
          <Search size={18} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" />
          <input className="w-full pl-12 pr-4 py-4 bg-white border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-blue-500 font-bold text-sm" placeholder="Pesquisar..." />
        </div>
        <button onClick={() => { setEditingItem(null); setShowModal(true); }} className="flex items-center gap-2 bg-blue-600 text-white px-8 py-4 rounded-2xl font-black text-sm hover:bg-blue-700 transition-all shadow-xl shadow-blue-500/20">
          <Plus size={20} /> Novo Registro
        </button>
      </div>

      {loading ? (
        <div className="flex flex-col items-center justify-center py-20 gap-4">
          <Loader2 className="animate-spin text-blue-600" size={40} />
          <p className="text-slate-400 font-black text-xs uppercase tracking-widest">Sincronizando com Supabase...</p>
        </div>
      ) : activeTab === 'imoveis' ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
