import React, { useState, useEffect } from 'react';
import { ArrowUpCircle, ArrowDownCircle, Plus, DollarSign, X, Loader2 } from 'lucide-react';
import { supabase } from '../supabaseClient';
import { Transaction } from '../types';

const FinanceView: React.FC = () => {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [newLaunch, setNewLaunch] = useState({
    description: '',
    category: 'Vendas',
    amount: '',
    type: 'DESPESA' as 'RECEITA' | 'DESPESA',
  });

  useEffect(() => {
    fetchTransactions();
  }, []);

  async function fetchTransactions() {
    setLoading(true);
    const { data, error } = await supabase.from('transactions').select('*').order('date', { ascending: false });
    if (!error) setTransactions(data || []);
    setLoading(false);
  }

  const handleLaunch = async (e: React.FormEvent) => {
    e.preventDefault();
    const payload = {
      description: newLaunch.description,
      category: newLaunch.category,
      amount: Number(newLaunch.amount),
      type: newLaunch.type,
      date: new Date().toISOString().split('T')[0]
    };

    const { error } = await supabase.from('transactions').insert([payload]);
    if (!error) {
      setShowModal(false);
      setNewLaunch({ description: '', category: 'Vendas', amount: '', type: 'DESPESA' });
      fetchTransactions();
    }
  };

  const totals = transactions.reduce((acc, curr) => {
    if (curr.type === 'RECEITA') acc.receita += Number(curr.amount);
    else acc.despesa += Number(curr.amount);
    return acc;
  }, { receita: 0, despesa: 0 });

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">Financeiro Cloud</h1>
          <p className="text-slate-500 font-medium">Controlo absoluto via Supabase.</p>
        </div>
        <button onClick={() => setShowModal(true)} className="flex items-center gap-2 px-8 py-3 bg-blue-600 text-white rounded-2xl font-black shadow-xl">
          <Plus size={20} /> Novo Lançamento
        </button>
      </div>

      {loading ? (
        <div className="flex justify-center py-20"><Loader2 className="animate-spin text-blue-600" size={40} /></div>
      ) : (
        <>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
              <p className="text-3xl font-black text-green-600">{totals.receita.toLocaleString()} MT</p>
              <span className="text-xs font-bold text-slate-400 uppercase">Receitas</span>
            </div>
            <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
              <p className="text-3xl font-black text-red-600">{totals.despesa.toLocaleString()} MT</p>
              <span className="text-xs font-bold text-slate-400 uppercase">Despesas</span>
            </div>
            <div className="bg-slate-900 p-8 rounded-[2.5rem] shadow-2xl">
              <p className="text-3xl font-black text-white">{(totals.receita - totals.despesa).toLocaleString()} MT</p>
              <span className="text-xs font-bold text-slate-500 uppercase">Saldo Total</span>
            </div>
          </div>

          <div className="bg-white rounded-[2.5rem] border border-slate-100 overflow-hidden shadow-sm">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50/50 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                  <th className="px-8 py-5">Descrição</th>
                  <th className="px-8 py-5">Categoria</th>
                  <th className="px-8 py-5 text-right">Valor</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {transactions.map((t) => (
                  <tr key={t.id} className="hover:bg-slate-50/80 transition-all">
                    <td className="px-8 py-6 font-bold">{t.description}</td>
                    <td className="px-8 py-6">{t.category}</td>
                    <td className={`px-8 py-6 text-right font-black ${t.type === 'RECEITA' ? 'text-green-600' : 'text-red-600'}`}>
                      {t.type === 'RECEITA' ? '+' : '-'} {t.amount.toLocaleString()} MT
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </>
      )}

      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white rounded-[2.5rem] p-10 max-w-lg w-full shadow-2xl relative">
            <button onClick={() => setShowModal(false)} className="absolute top-8 right-8 text-slate-400"><X size={24} /></button>
            <h2 className="text-2xl font-black text-slate-900 mb-6">Novo Lançamento</h2>
            <form onSubmit={handleLaunch} className="space-y-6">
              <div className="flex p-1 bg-slate-100 rounded-2xl">
                <button type="button" onClick={() => setNewLaunch({...newLaunch, type: 'RECEITA'})} className={`flex-1 py-3 text-sm font-bold rounded-xl ${newLaunch.type === 'RECEITA' ? 'bg-white text-green-600 shadow-sm' : 'text-slate-500'}`}>Receita</button>
                <button type="button" onClick={() => setNewLaunch({...newLaunch, type: 'DESPESA'})} className={`flex-1 py-3 text-sm font-bold rounded-xl ${newLaunch.type === 'DESPESA' ? 'bg-white text-red-600 shadow-sm' : 'text-slate-500'}`}>Despesa</button>
              </div>
              <input required placeholder="Descrição" value={newLaunch.description} onChange={e => setNewLaunch({...newLaunch, description: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none" />
              <input required type="number" placeholder="Montante (MT)" value={newLaunch.amount} onChange={e => setNewLaunch({...newLaunch, amount: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none text-xl" />
              <button type="submit" className="w-full py-5 bg-blue-600 text-white font-black rounded-2xl shadow-xl hover:bg-blue-700 transition-all">Confirmar no Supabase</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default FinanceView;

