        <div className="flex p-1 bg-white border border-slate-200 rounded-2xl">
          <button onClick={() => setActiveTab('dashboard')} className={`px-6 py-2.5 rounded-xl text-xs font-black transition-all ${activeTab === 'dashboard' ? 'bg-blue-600 text-white' : 'text-slate-500'}`}>Geral</button>
          <button onClick={() => setActiveTab('funcionarios')} className={`px-6 py-2.5 rounded-xl text-xs font-black transition-all ${activeTab === 'funcionarios' ? 'bg-blue-600 text-white' : 'text-slate-500'}`}>Equipa</button>
          <button onClick={() => setActiveTab('assiduidade')} className={`px-6 py-2.5 rounded-xl text-xs font-black transition-all ${activeTab === 'assiduidade' ? 'bg-blue-600 text-white' : 'text-slate-500'}`}>Presenças</button>
        </div>
      </div>

      {activeTab === 'dashboard' && (
        <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
           <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
             <p className="text-3xl font-black text-blue-600">{employees.length}</p>
             <span className="text-xs font-bold text-slate-400 uppercase">Staff Total</span>
           </div>
           <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
             <p className="text-3xl font-black text-green-600">{(employees.reduce((acc, c) => acc + Number(c.salary), 0)).toLocaleString()} MT</p>
             <span className="text-xs font-bold text-slate-400 uppercase">Folha Mensal</span>
           </div>
        </div>
      )}

      {activeTab === 'funcionarios' && (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <button onClick={() => setShowAddModal(true)} className="aspect-square flex flex-col items-center justify-center gap-4 bg-white border-4 border-dashed border-slate-100 rounded-[3rem] text-slate-300 hover:text-blue-600 hover:border-blue-100 transition-all">
            <Plus size={48} />
            <span className="font-black text-xs uppercase">Novo Colaborador</span>
