          {employees.map(emp => (
            <div key={emp.id} className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm relative group">
              <button onClick={() => removeEmployee(emp.id)} className="absolute top-6 right-6 p-2 text-slate-200 hover:text-red-500 transition-colors"><Trash2 size={18} /></button>
              <img src={emp.avatar} className="w-20 h-20 rounded-3xl object-cover mb-6 ring-4 ring-slate-50" />
