import React, { useState, useEffect } from 'react';
import { 
  Plus, Users, DollarSign, UserCheck, AlertCircle, Clock, 
  FileBadge, Loader2, X, CheckCircle, Trash2, LayoutDashboard,
  Lock
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { Employee, AttendanceRecord, UserRole, AttendanceStatus } from '../types';

type HRTab = 'dashboard' | 'funcionarios' | 'assiduidade';

const HRView: React.FC = () => {
  const [activeTab, setActiveTab] = useState<HRTab>('dashboard');
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [attendance, setAttendance] = useState<AttendanceRecord[]>([]);
  const [loading, setLoading] = useState(true);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [showAddModal, setShowAddModal] = useState(false);

  const [newEmp, setNewEmp] = useState<Partial<Employee>>({
    name: '', role: UserRole.EMPLOYEE, department: 'Operações', salary: 0, email: '', phone: ''
  });

  useEffect(() => {
    fetchData();
  }, [activeTab]);

  async function fetchData() {
    setLoading(true);
    setErrorMsg(null);
    try {
      const empRes = await supabase.from('employees').select('*').order('name');
      if (empRes.error) throw empRes.error;
      setEmployees(empRes.data || []);

      const attRes = await supabase.from('attendance').select('*, employees(name, avatar)').order('date', { ascending: false });
      if (!attRes.error) setAttendance(attRes.data || []);
    } catch (err: any) {
      setErrorMsg("Erro de Permissão: Esta área requer autenticação administrativa no Supabase.");
    } finally {
      setLoading(false);
    }
  }

  const handleAddEmployee = async (e: React.FormEvent) => {
    e.preventDefault();
    const payload = {
      name: newEmp.name,
      role: newEmp.role,
      department: newEmp.department,
      salary: newEmp.salary,
      email: newEmp.email,
      phone: newEmp.phone,
      avatar: `https://picsum.photos/seed/${newEmp.name}/100`,
      status: 'Ativo'
    };

    try {
      const { error } = await supabase.from('employees').insert([payload]);
      if (error) throw error;
      setShowAddModal(false);
      fetchData();
    } catch (err: any) {
      alert("Erro de Segurança: Operação negada pelo RLS.");
    }
  };

  const removeEmployee = async (id: string) => {
    if (!id) return;
    if (confirm('Rescindir contrato e remover do sistema? Esta ação é definitiva.')) {
      try {
        const { error } = await supabase.from('employees').delete().match({ id });
        if (error) throw error;
        fetchData();
      } catch (err: any) {
        alert("Erro de Segurança: Você não tem permissão para excluir funcionários.");
      }
    }
  };

  if (loading) return <div className="flex justify-center py-20"><Loader2 className="animate-spin text-blue-600" size={40} /></div>;

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
