          <button onClick={() => setActiveTab('assiduidade')} className={`px-6 py-2.5 rounded-xl text-xs font-black transition-all ${activeTab === 'assiduidade' ? 'bg-blue-600 text-white' : 'text-slate-500'}`}>Presenças</button>
        </div>
      </div>

      {errorMsg && (
        <div className="bg-slate-900 text-white p-12 rounded-[3rem] text-center space-y-4">
           <Lock size={48} className="mx-auto text-blue-500" />
           <h2 className="text-2xl font-black">Área Restrita</h2>
           <p className="text-slate-400 max-w-md mx-auto">{errorMsg}</p>
           <div className="pt-4">
             <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest">Row Level Security Ativo</span>
           </div>
