import React, { useState, useEffect } from 'react';
import { UserRole, User } from './types';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import Navbar from './components/Navbar';
import Footer from './components/Footer';
import { supabase } from './supabaseClient';

// ERP Views
import DashboardView from './views/DashboardView';
import FinanceView from './views/FinanceView';
import HRView from './views/HRView';
import ProjectsView from './views/ProjectsView';
import PlansView from './views/PlansView';
import ReportsView from './views/ReportsView';
import AdminView from './views/AdminView';
import CatalogView from './views/CatalogView';
import LoginView from './views/LoginView';

// Public Views
import HomeView from './views/HomeView';
import PropertyListView from './views/PropertyListView';
import PropertyDetailView from './views/PropertyDetailView';
import ServicesView from './views/ServicesView';
import ContactView from './views/ContactView';
import AboutView from './views/AboutView';
import CareerView from './views/CareerView';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [currentPath, setCurrentPath] = useState('home');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [selectedPropertyId, setSelectedPropertyId] = useState<string | null>(null);
  const [isInitializing, setIsInitializing] = useState(true);

  useEffect(() => {
    // 1. Verificar sessão atual ao carregar
    checkUser();

    // 2. Escutar mudanças de autenticação (Login/Logout)
    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, session) => {
      if (session) {
        await fetchAndSetUser(session.user);
      } else {
        setCurrentUser(null);
        if (['dashboard', 'finance', 'hr', 'projects', 'plans', 'reports', 'admin', 'catalog'].includes(currentPath)) {
          setCurrentPath('home');
        }
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  async function checkUser() {
    const { data: { session } } = await supabase.auth.getSession();
    if (session?.user) {
      await fetchAndSetUser(session.user);
    }
    setIsInitializing(false);
  }

  async function fetchAndSetUser(sbUser: any) {
    // Buscar detalhes do funcionário
    const { data: emp } = await supabase
      .from('employees')
      .select('*')
      .eq('email', sbUser.email)
      .single();

    const user: User = {
      id: sbUser.id,
      name: emp?.name || sbUser.email.split('@')[0],
      email: sbUser.email,
      role: emp?.role || UserRole.EMPLOYEE,
      avatar: emp?.avatar || `https://picsum.photos/seed/${sbUser.id}/100`,
      permissions: emp?.permissions || []
    };
    setCurrentUser(user);
    if (currentPath === 'login') setCurrentPath('dashboard');
  }

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setCurrentUser(null);
    setCurrentPath('home');
  };

  const handleViewProperty = (id: string) => {
    setSelectedPropertyId(id);
    setCurrentPath('imovel-detalhes');
    window.scrollTo(0, 0);
  };

  const isERPRoute = ['dashboard', 'finance', 'hr', 'projects', 'plans', 'reports', 'admin', 'catalog'].includes(currentPath);

  const renderContent = () => {
    switch (currentPath) {
      case 'home': return <HomeView onNavigate={setCurrentPath} onViewProperty={handleViewProperty} />;
      case 'imoveis': return <PropertyListView onViewProperty={handleViewProperty} />;
      case 'imovel-detalhes': return <PropertyDetailView propertyId={selectedPropertyId} onBack={() => setCurrentPath('imoveis')} />;
      case 'servicos': return <ServicesView />;
      case 'contato': return <ContactView />;
      case 'sobre': return <AboutView />;
      case 'carreira': return <CareerView />;
      case 'login': return (
        <LoginView 
          onLoginSuccess={(user) => {
            setCurrentUser(user);
            setCurrentPath('dashboard');
          }} 
          onBack={() => setCurrentPath('home')}
        />
      );
      case 'dashboard': return <DashboardView />;
      case 'catalog': return <CatalogView />;
      case 'finance': return <FinanceView />;
      case 'hr': return <HRView />;
      case 'projects': return <ProjectsView />;
      case 'plans': return <PlansView />;
      case 'reports': return <ReportsView />;
      case 'admin': return <AdminView />;
      default: return <HomeView onNavigate={setCurrentPath} onViewProperty={handleViewProperty} />;
    }
  };

  if (isInitializing) return null; // Ou um loader global

  if (isERPRoute && currentUser) {
    return (
      <div className="flex h-screen overflow-hidden bg-slate-50">
        <Sidebar 
          currentPath={currentPath} 
          onNavigate={setCurrentPath} 
          userRole={currentUser.role}
          isOpen={isSidebarOpen}
          toggleSidebar={() => setIsSidebarOpen(!isSidebarOpen)}
        />
        <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
          <Header user={currentUser} onLogout={handleLogout} onOpenSidebar={() => setIsSidebarOpen(true)} />
          <main className="flex-1 overflow-y-auto p-4 md:p-8">
            <div className="max-w-7xl mx-auto">{renderContent()}</div>
          </main>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-white flex flex-col">
      <Navbar currentPath={currentPath} onNavigate={setCurrentPath} isLoggedIn={!!currentUser} />
      <main className="flex-1">
        {renderContent()}
      </main>
      <Footer onNavigate={setCurrentPath} />
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { 
  Shield, Key, Lock, Settings, UserCog, Save, 
  CheckCircle2, AlertCircle, Loader2, Search,
  ShieldAlert, Fingerprint
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { UserRole, Employee } from '../types';

const AdminView: React.FC = () => {
  const [users, setUsers] = useState<Employee[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [editingUser, setEditingUser] = useState<Employee | null>(null);
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState<{type: 'success' | 'error', text: string} | null>(null);

  useEffect(() => {
    fetchUsers();
  }, []);

  async function fetchUsers() {
    setLoading(true);
    const { data, error } = await supabase.from('employees').select('*').order('name');
    if (!error) setUsers(data || []);
    setLoading(false);
  }

  const handleUpdatePermissions = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingUser) return;

    setSaving(true);
    const { error } = await supabase
      .from('employees')
      .update({ 
        role: editingUser.role,
        permissions: editingUser.permissions 
      })
      .eq('id', editingUser.id);

    if (error) {
      setMsg({ type: 'error', text: 'Falha ao atualizar: ' + error.message });
    } else {
      setMsg({ type: 'success', text: 'Permissões atualizadas com sucesso!' });
      fetchUsers();
      setTimeout(() => setEditingUser(null), 1500);
    }
    setSaving(false);
    setTimeout(() => setMsg(null), 3000);
  };

  const togglePermission = (perm: string) => {
    if (!editingUser) return;
    const current = editingUser.permissions || [];
    const newPerms = current.includes(perm) 
      ? current.filter(p => p !== perm) 
      : [...current, perm];
    setEditingUser({ ...editingUser, permissions: newPerms });
  };

  const filteredUsers = users.filter(u => 
    u.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    u.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const availablePermissions = [
    'Ver_Financeiro', 'Editar_Financeiro', 'Gerir_RH', 
    'Acesso_Admin', 'Editar_Catalogo', 'Gerir_Projetos',
    'Relatorios_Avancados', 'Configuracao_TI'
  ];

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">Gestão de Acessos</h1>
          <p className="text-slate-500 font-medium">Controlo centralizado de utilizadores e privilégios RLS.</p>
        </div>
        <div className="flex items-center gap-2 px-4 py-2 bg-blue-50 text-blue-700 rounded-full text-[10px] font-black uppercase tracking-widest border border-blue-100">
          <Fingerprint size={14} /> Auditoria Ativa
        </div>
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
        {/* User List Card */}
        <div className="xl:col-span-2 bg-white rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden">
          <div className="p-8 border-b border-slate-50 flex items-center justify-between gap-4">
            <div className="relative flex-1">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                value={searchTerm}
                onChange={e => setSearchTerm(e.target.value)}
                placeholder="Pesquisar utilizador por nome ou email..." 
                className="w-full pl-12 pr-4 py-4 bg-slate-50 rounded-2xl border-none font-bold text-sm outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50/50 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                  <th className="px-8 py-5">Colaborador</th>
                  <th className="px-8 py-5">Cargo ERP</th>
                  <th className="px-8 py-5">Status</th>
                  <th className="px-8 py-5 text-right">Ação</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {loading ? (
                  <tr><td colSpan={4} className="py-20 text-center"><Loader2 className="animate-spin mx-auto text-blue-600" /></td></tr>
                ) : filteredUsers.map(user => (
                  <tr key={user.id} className="hover:bg-slate-50/50 transition-all group">
                    <td className="px-8 py-6">
                      <div className="flex items-center gap-4">
                        <img src={user.avatar} className="w-10 h-10 rounded-xl object-cover" />
                        <div>
                          <p className="text-sm font-black text-slate-900">{user.name}</p>
                          <p className="text-[10px] text-slate-400 font-bold">{user.email}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-8 py-6">
                      <span className="text-xs font-bold text-slate-600">{user.role}</span>
                    </td>
                    <td className="px-8 py-6">
                      <span className={`text-[9px] font-black uppercase px-2 py-1 rounded-lg ${user.status === 'Ativo' ? 'bg-green-50 text-green-600' : 'bg-red-50 text-red-600'}`}>
                        {user.status}
                      </span>
                    </td>
                    <td className="px-8 py-6 text-right">
                      <button 
                        onClick={() => setEditingUser(user)}
                        className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl transition-all"
                      >
                        <UserCog size={20} />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        {/* Permissions Editor Sidebar */}
        <div className="space-y-8">
          {editingUser ? (
            <div className="bg-slate-900 rounded-[3rem] p-8 text-white shadow-2xl animate-in slide-in-from-right-4">
              <div className="flex items-center justify-between mb-8">
                <h3 className="text-xl font-black flex items-center gap-2"><Shield size={20} className="text-blue-400" /> Editar Perfil</h3>
                <button onClick={() => setEditingUser(null)} className="text-slate-500 hover:text-white"><Settings size={20} /></button>
              </div>

              <form onSubmit={handleUpdatePermissions} className="space-y-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Nível de Acesso (Role)</label>
                  <select 
                    value={editingUser.role}
                    onChange={e => setEditingUser({...editingUser, role: e.target.value as UserRole})}
                    className="w-full bg-white/5 border border-white/10 rounded-2xl p-4 text-sm font-bold outline-none focus:ring-2 focus:ring-blue-500"
                  >
                    {Object.values(UserRole).map(r => <option key={r} value={r} className="text-slate-900">{r}</option>)}
                  </select>
                </div>

                <div className="space-y-4">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Permissões Granulares</label>
                  <div className="grid grid-cols-1 gap-2">
                    {availablePermissions.map(perm => (
                      <button
                        key={perm}
                        type="button"
                        onClick={() => togglePermission(perm)}
                        className={`flex items-center justify-between p-4 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${
                          editingUser.permissions?.includes(perm)
                            ? 'bg-blue-600 text-white'
                            : 'bg-white/5 text-slate-500 border border-white/5 hover:border-white/20'
                        }`}
                      >
                        {perm.replace('_', ' ')}
                        {editingUser.permissions?.includes(perm) && <CheckCircle2 size={14} />}
                      </button>
                    ))}
                  </div>
                </div>

                {msg && (
                  <div className={`p-4 rounded-2xl text-[10px] font-black uppercase text-center ${msg.type === 'success' ? 'bg-green-500/20 text-green-400' : 'bg-red-500/20 text-red-400'}`}>
                    {msg.text}
                  </div>
                )}

                <button 
                  disabled={saving}
                  type="submit" 
                  className="w-full py-5 bg-blue-600 hover:bg-blue-700 text-white rounded-3xl font-black text-xs uppercase tracking-widest shadow-xl shadow-blue-600/20 flex items-center justify-center gap-2"
                >
                  {saving ? <Loader2 className="animate-spin" size={16} /> : <><Save size={16} /> Gravar Alterações</>}
