import React, { useState, useEffect } from 'react';
import { 
  Shield, Key, Lock, Settings, UserCog, Save, 
  CheckCircle2, AlertCircle, Loader2, Search,
  ShieldAlert, Fingerprint, Zap
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { UserRole, Employee } from '../types';

const AdminView: React.FC = () => {
  const [users, setUsers] = useState<Employee[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [editingUser, setEditingUser] = useState<Employee | null>(null);
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState<{type: 'success' | 'error', text: string} | null>(null);

  const availablePermissions = [
    'Ver_Financeiro', 'Editar_Financeiro', 'Gerir_RH', 
    'Acesso_Admin', 'Editar_Catalogo', 'Gerir_Projetos',
    'Relatorios_Avancados', 'Configuracao_TI'
  ];

  useEffect(() => {
    fetchUsers();
  }, []);

  async function fetchUsers() {
    setLoading(true);
    const { data, error } = await supabase.from('employees').select('*').order('name');
    if (!error) setUsers(data || []);
    setLoading(false);
  }

  const handleUpdatePermissions = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!editingUser) return;

    setSaving(true);
    const { error } = await supabase
      .from('employees')
      .update({ 
        role: editingUser.role,
        permissions: editingUser.permissions 
      })
      .eq('id', editingUser.id);

    if (error) {
      setMsg({ type: 'error', text: 'Falha ao atualizar: ' + error.message });
    } else {
      setMsg({ type: 'success', text: 'Permissões atualizadas com sucesso!' });
      fetchUsers();
    }
    setSaving(false);
    setTimeout(() => setMsg(null), 3000);
  };

  const grantAllPermissions = () => {
    if (!editingUser) return;
    setEditingUser({ ...editingUser, permissions: availablePermissions });
  };

  const togglePermission = (perm: string) => {
    if (!editingUser) return;
    const current = editingUser.permissions || [];
    const newPerms = current.includes(perm) 
      ? current.filter(p => p !== perm) 
      : [...current, perm];
    setEditingUser({ ...editingUser, permissions: newPerms });
  };

  const filteredUsers = users.filter(u => 
    u.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    u.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">Gestão de Acessos</h1>
          <p className="text-slate-500 font-medium">Controlo centralizado de privilégios e acesso universal.</p>
        </div>
        <div className="flex items-center gap-2 px-4 py-2 bg-blue-50 text-blue-700 rounded-full text-[10px] font-black uppercase tracking-widest border border-blue-100">
          <Fingerprint size={14} /> Auditoria Ativa
        </div>
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
        {/* User List Card */}
        <div className="xl:col-span-2 bg-white rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden">
          <div className="p-8 border-b border-slate-50 flex items-center justify-between gap-4">
            <div className="relative flex-1">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                value={searchTerm}
                onChange={e => setSearchTerm(e.target.value)}
                placeholder="Pesquisar por nome ou email..." 
                className="w-full pl-12 pr-4 py-4 bg-slate-50 rounded-2xl border-none font-bold text-sm outline-none focus:ring-2 focus:ring-blue-500"
              />
            </div>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50/50 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                  <th className="px-8 py-5">Colaborador</th>
                  <th className="px-8 py-5">Cargo ERP</th>
                  <th className="px-8 py-5">Permissões</th>
                  <th className="px-8 py-5 text-right">Ação</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {loading ? (
                  <tr><td colSpan={4} className="py-20 text-center"><Loader2 className="animate-spin mx-auto text-blue-600" /></td></tr>
                ) : filteredUsers.map(user => (
                  <tr key={user.id} className="hover:bg-slate-50/50 transition-all group">
                    <td className="px-8 py-6">
                      <div className="flex items-center gap-4">
                        <img src={user.avatar} className="w-10 h-10 rounded-xl object-cover" />
                        <div>
                          <p className="text-sm font-black text-slate-900">{user.name}</p>
                          <p className="text-[10px] text-slate-400 font-bold">{user.email}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-8 py-6">
                      <span className="text-xs font-bold text-slate-600">{user.role}</span>
                    </td>
                    <td className="px-8 py-6">
                      <span className="text-[10px] font-black uppercase text-blue-600 bg-blue-50 px-2 py-1 rounded-lg">
                        {user.permissions?.length || 0} Ativas
                      </span>
                    </td>
                    <td className="px-8 py-6 text-right">
                      <button 
                        onClick={() => setEditingUser(user)}
                        className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl transition-all"
                      >
                        <UserCog size={20} />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        {/* Permissions Editor Sidebar */}
        <div className="space-y-8">
          {editingUser ? (
            <div className="bg-slate-900 rounded-[3rem] p-8 text-white shadow-2xl animate-in slide-in-from-right-4">
              <div className="flex items-center justify-between mb-8">
                <h3 className="text-xl font-black flex items-center gap-2"><Shield size={20} className="text-blue-400" /> Editar Perfil</h3>
                <button onClick={() => setEditingUser(null)} className="text-slate-500 hover:text-white"><Settings size={20} /></button>
              </div>

              <div className="mb-6">
                <button 
                  onClick={grantAllPermissions}
                  className="w-full py-4 bg-green-600 hover:bg-green-700 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest flex items-center justify-center gap-2 shadow-lg shadow-green-600/20"
                >
                  <Zap size={14} /> Conceder Acesso Total
                </button>
              </div>

              <form onSubmit={handleUpdatePermissions} className="space-y-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Cargo ERP</label>
                  <select 
                    value={editingUser.role}
                    onChange={e => setEditingUser({...editingUser, role: e.target.value as UserRole})}
                    className="w-full bg-white/5 border border-white/10 rounded-2xl p-4 text-sm font-bold outline-none focus:ring-2 focus:ring-blue-500"
                  >
                    {Object.values(UserRole).map(r => <option key={r} value={r} className="text-slate-900">{r}</option>)}
                  </select>
                </div>

                <div className="space-y-4">
                  <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Privilégios Ativos</label>
                  <div className="grid grid-cols-1 gap-2">
                    {availablePermissions.map(perm => (
                      <button
                        key={perm}
                        type="button"
                        onClick={() => togglePermission(perm)}
                        className={`flex items-center justify-between p-4 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${
                          editingUser.permissions?.includes(perm)
                            ? 'bg-blue-600 text-white'
                            : 'bg-white/5 text-slate-500 border border-white/5 hover:border-white/20'
                        }`}
                      >
                        {perm.replace('_', ' ')}
                        {editingUser.permissions?.includes(perm) && <CheckCircle2 size={14} />}
                      </button>
                    ))}
                  </div>
                </div>

                {msg && (
                  <div className={`p-4 rounded-2xl text-[10px] font-black uppercase text-center ${msg.type === 'success' ? 'bg-green-500/20 text-green-400' : 'bg-red-500/20 text-red-400'}`}>
                    {msg.text}
                  </div>
                )}

                <button 
                  disabled={saving}
                  type="submit" 
                  className="w-full py-5 bg-blue-600 hover:bg-blue-700 text-white rounded-3xl font-black text-xs uppercase tracking-widest shadow-xl shadow-blue-600/20 flex items-center justify-center gap-2"
                >
                  {saving ? <Loader2 className="animate-spin" size={16} /> : <><Save size={16} /> Salvar Alterações</>}
                </button>
              </form>
            </div>
          ) : (
            <div className="bg-white p-10 rounded-[3rem] border border-slate-100 text-center space-y-4 shadow-sm">
              <ShieldAlert size={48} className="mx-auto text-slate-100" />
              <h3 className="text-lg font-black text-slate-900">Privilégios</h3>
              <p className="text-sm text-slate-400 font-medium">Selecione um colaborador para ver o resumo de acesso ou conceder permissões totais.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

