import React, { useState } from 'react';
import { supabase } from '../supabaseClient';
import { Mail, Lock, LogIn, Loader2, AlertCircle, ArrowLeft } from 'lucide-react';
import { UserRole } from '../types';

interface LoginViewProps {
  onLoginSuccess: (user: any) => void;
  onBack: () => void;
}

const LoginView: React.FC<LoginViewProps> = ({ onLoginSuccess, onBack }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSignIn = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
      // 1. Autenticação no Supabase Auth
      const { data: authData, error: authError } = await supabase.auth.signInWithPassword({
        email,
        password,
      });

      if (authError) throw authError;

      // 2. Buscar perfil do funcionário para obter o Cargo (Role)
      const { data: empData, error: empError } = await supabase
        .from('employees')
        .select('*')
        .eq('email', email)
        .single();

      if (empError) {
        console.warn("Perfil de funcionário não encontrado, usando role padrão.");
      }

      const userData = {
        id: authData.user?.id,
        name: empData?.name || authData.user?.email?.split('@')[0],
        email: authData.user?.email,
        role: empData?.role || UserRole.EMPLOYEE,
        avatar: empData?.avatar || `https://picsum.photos/seed/${authData.user?.id}/100`,
      };

      onLoginSuccess(userData);
    } catch (err: any) {
      setError(err.message === 'Invalid login credentials' ? 'E-mail ou senha incorretos.' : err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 p-4 animate-in fade-in duration-500">
      <div className="bg-white rounded-[3rem] shadow-2xl p-10 md:p-16 max-w-md w-full border border-slate-100 relative overflow-hidden">
        {/* Decorative background */}
        <div className="absolute top-0 right-0 w-32 h-32 bg-blue-600/5 rounded-full -translate-y-1/2 translate-x-1/2 blur-2xl"></div>

        <div className="text-center mb-10">
          <div className="w-20 h-20 bg-blue-600 rounded-3xl flex items-center justify-center mx-auto mb-6 shadow-xl shadow-blue-500/20">
            <img src="https://raw.githubusercontent.com/filipe-beira/static-assets/main/monte-chaisa-logo.png" alt="Monte Imobiliária" className="w-12 h-12 object-contain brightness-0 invert" />
          </div>
          <h2 className="text-3xl font-black text-slate-900 tracking-tight">Monte Imobiliária</h2>
          <p className="text-slate-500 font-medium text-sm mt-2">Área Restrita do Colaborador</p>
        </div>

        {error && (
          <div className="mb-6 bg-red-50 border-l-4 border-red-500 p-4 rounded-xl flex items-center gap-3 text-red-700 text-xs font-bold animate-shake">
            <AlertCircle size={18} /> {error}
          </div>
        )}

        <form onSubmit={handleSignIn} className="space-y-6">
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">E-mail Corporativo</label>
            <div className="relative">
              <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                required
                type="email" 
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="w-full pl-12 pr-4 py-4 bg-slate-50 rounded-2xl border-none focus:ring-2 focus:ring-blue-600 font-bold text-sm transition-all"
                placeholder="exemplo@monte-imobiliaria.com"
              />
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Senha de Acesso</label>
            <div className="relative">
              <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                required
                type="password" 
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full pl-12 pr-4 py-4 bg-slate-50 rounded-2xl border-none focus:ring-2 focus:ring-blue-600 font-bold text-sm transition-all"
                placeholder="••••••••"
              />
            </div>
          </div>

          <button 
            disabled={loading}
            type="submit" 
            className="w-full py-5 bg-blue-600 text-white rounded-[2rem] font-black text-sm flex items-center justify-center gap-3 hover:bg-blue-700 transition-all shadow-xl shadow-blue-500/20 disabled:opacity-50 active:scale-95"
          >
            {loading ? <Loader2 className="animate-spin" size={20} /> : <><LogIn size={20} /> Entrar no ERP</>}
          </button>
        </form>

        <div className="mt-10 text-center">
          <button onClick={onBack} className="text-slate-400 hover:text-blue-600 font-black text-[10px] uppercase tracking-widest flex items-center justify-center gap-2 mx-auto transition-colors">
            <ArrowLeft size={14} /> Voltar para o Site
          </button>
        </div>
      </div>
    </div>
  );
};

export default LoginView;

import React, { useState, useEffect } from 'react';
import { 
  TrendingUp, Users, Sparkles, Zap, ShieldCheck, 
  FilePlus, Building2, Wallet, UserEdit, Plus, 
  X, Save, Loader2, ChevronRight, Settings2,
  ArrowUpCircle, ArrowDownCircle, Tags
} from 'lucide-react';
import { getStrategicInsight } from '../geminiService';
import { supabase } from '../supabaseClient';
import { Employee, Transaction } from '../types';

const DashboardView: React.FC = () => {
  const [insight, setInsight] = useState<string>('Analisando inteligência de mercado...');
  const [stats, setStats] = useState({
    employees: 0, properties: 0, transactions: 0, revenue: 0, expenses: 0
  });
  const [staff, setStaff] = useState<Employee[]>([]);
  const [categories, setCategories] = useState<string[]>(['Vendas', 'Aluguel', 'Manutenção', 'Marketing', 'Administrativo']);
  const [loading, setLoading] = useState(true);

  // Modals state
  const [showFinanceModal, setShowFinanceModal] = useState(false);
  const [showStaffModal, setShowStaffModal] = useState(false);
  const [showCategoryModal, setShowCategoryModal] = useState(false);
  const [editingStaff, setEditingStaff] = useState<Employee | null>(null);

  const [newTransaction, setNewTransaction] = useState({
    description: '', amount: '', type: 'RECEITA' as 'RECEITA' | 'DESPESA', category: 'Vendas'
  });
  const [newCategory, setNewCategory] = useState('');

  useEffect(() => {
    fetchCoreData();
    const fetchInsight = async () => {
      const msg = await getStrategicInsight("Mercado imobiliário da Beira em 2024, foco em expansão da Monte Imobiliária.");
      setInsight(msg);
    };
    fetchInsight();
  }, []);

  async function fetchCoreData() {
    setLoading(true);
    const [emp, prop, trans] = await Promise.all([
      supabase.from('employees').select('*').order('name'),
      supabase.from('properties').select('id', { count: 'exact' }),
      supabase.from('transactions').select('*')
    ]);

    const txs = trans.data || [];
    const rev = txs.filter(t => t.type === 'RECEITA').reduce((a, b) => a + Number(b.amount), 0);
    const exp = txs.filter(t => t.type === 'DESPESA').reduce((a, b) => a + Number(b.amount), 0);

    setStats({
      employees: emp.data?.length || 0,
      properties: prop.count || 0,
      transactions: txs.length,
      revenue: rev,
      expenses: exp
    });
    setStaff(emp.data || []);

    // Extrair categorias únicas do banco de dados para complementar as padrão
    const uniqueCats = Array.from(new Set([...categories, ...txs.map(t => t.category)]));
    setCategories(uniqueCats);
    setLoading(false);
  }

  const handleSaveTransaction = async (e: React.FormEvent) => {
    e.preventDefault();
    const { error } = await supabase.from('transactions').insert([{
      ...newTransaction,
      amount: Number(newTransaction.amount),
      date: new Date().toISOString().split('T')[0]
    }]);
    if (!error) {
      setShowFinanceModal(false);
      fetchCoreData();
    }
  };

  const handleUpdateStaff = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingStaff) return;
    const { error } = await supabase.from('employees').update(editingStaff).eq('id', editingStaff.id);
    if (!error) {
      setShowStaffModal(false);
      fetchCoreData();
    }
  };

  const handleAddCategory = () => {
    if (newCategory && !categories.includes(newCategory)) {
      setCategories([...categories, newCategory]);
      setNewCategory('');
      setShowCategoryModal(false);
    }
  };

  return (
    <div className="space-y-8 pb-12 animate-in fade-in duration-700">
      {/* Header com Branding Atualizado */}
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div className="flex items-center gap-5">
          <div className="w-16 h-16 bg-blue-600 rounded-3xl flex items-center justify-center shadow-2xl shadow-blue-500/30 overflow-hidden p-2">
            <img src="https://i.ibb.co/LzfNdf7Y/building-logo.png" className="w-full h-full object-contain brightness-0 invert" alt="Monte Logo" />
          </div>
          <div>
            <h1 className="text-4xl font-black text-slate-900 tracking-tight">Monte Hub</h1>
            <p className="text-slate-500 font-bold text-xs uppercase tracking-widest flex items-center gap-2">
              <ShieldCheck size={14} className="text-green-500" /> Comando Centralizado
            </p>
          </div>
        </div>
        <div className="flex gap-3">
           <button onClick={() => setShowFinanceModal(true)} className="flex items-center gap-2 px-6 py-3.5 bg-blue-600 text-white rounded-2xl font-black text-xs shadow-xl shadow-blue-500/20 hover:scale-105 transition-all">
             <Plus size={16} /> Lançar Valor
           </button>
           <button onClick={() => setShowCategoryModal(true)} className="flex items-center gap-2 px-6 py-3.5 bg-slate-900 text-white rounded-2xl font-black text-xs hover:bg-slate-800 transition-all">
             <Tags size={16} /> Categorias
           </button>
        </div>
      </div>

      {/* Strategic Stats */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-6">
        {[
          { label: 'Fluxo Mensal', value: stats.revenue - stats.expenses, icon: <Wallet size={20} />, color: 'emerald', detail: 'Saldo' },
          { label: 'Imóveis Ativos', value: stats.properties, icon: <Building2 size={20} />, color: 'blue', detail: 'Catálogo' },
          { label: 'Corpo Docente', value: stats.employees, icon: <Users size={20} />, color: 'indigo', detail: 'Staff' },
          { label: 'Despesas', value: stats.expenses, icon: <ArrowDownCircle size={20} />, color: 'rose', detail: 'Saídas' },
        ].map((tile, i) => (
          <div key={i} className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm hover:shadow-md transition-all">
            <div className={`w-12 h-12 bg-${tile.color}-50 text-${tile.color}-600 rounded-2xl flex items-center justify-center mb-6`}>
              {tile.icon}
            </div>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{tile.label}</p>
            <p className="text-3xl font-black text-slate-900">{tile.value.toLocaleString()} {i === 1 || i === 2 ? '' : 'MT'}</p>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
        {/* Gestão de Staff Integrada */}
        <div className="xl:col-span-2 space-y-8">
          <div className="bg-white p-10 rounded-[3.5rem] border border-slate-100 shadow-sm">
            <div className="flex items-center justify-between mb-10">
              <div>
                <h3 className="text-2xl font-black text-slate-900">Gestão de Equipa</h3>
                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-1">Status e Edição de Perfil</p>
              </div>
              <Settings2 className="text-slate-300" />
            </div>

            <div className="space-y-4">
              {staff.map((member) => (
                <div key={member.id} className="p-6 bg-slate-50 rounded-[2rem] flex items-center justify-between group hover:bg-white hover:shadow-xl transition-all border border-transparent hover:border-slate-100">
                  <div className="flex items-center gap-5">
                    <img src={member.avatar} className="w-14 h-14 rounded-2xl object-cover shadow-sm" alt={member.name} />
                    <div>
                      <p className="text-base font-black text-slate-900">{member.name}</p>
                      <p className="text-[10px] font-bold text-slate-400 uppercase">{member.role}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-6">
                    <div className="text-right hidden md:block">
                      <p className="text-xs font-black text-slate-900">{Number(member.salary).toLocaleString()} MT</p>
                      <span className="text-[9px] font-black text-green-600 bg-green-50 px-2 py-0.5 rounded-lg">ATIVO</span>
                    </div>
                    <button 
                      onClick={() => { setEditingStaff(member); setShowStaffModal(true); }}
                      className="p-3 bg-white text-slate-400 rounded-xl hover:text-blue-600 hover:shadow-md transition-all"
                    >
                      <UserEdit size={20} />
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* AI Strategy Hub */}
          <div className="bg-slate-900 p-12 rounded-[3.5rem] text-white shadow-2xl relative overflow-hidden group">
            <div className="absolute top-0 right-0 w-64 h-64 bg-blue-500/10 rounded-full blur-[100px] -translate-y-1/2 translate-x-1/2"></div>
            <div className="flex items-center gap-5 mb-8">
              <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center shadow-lg shadow-blue-500/40">
                <Sparkles size={24} className="text-white" />
              </div>
              <div>
                <h2 className="text-2xl font-black">Monte Brain IA</h2>
                <p className="text-[10px] text-slate-500 font-black uppercase tracking-[0.2em]">Visão Estratégica</p>
              </div>
            </div>
            <p className="text-blue-50 leading-relaxed text-xl font-medium border-l-4 border-blue-600 pl-8 italic">
              "{insight}"
            </p>
          </div>
        </div>

        {/* Lateral: Quick Finance & Categories */}
        <div className="space-y-8">
          <div className="bg-white p-10 rounded-[3.5rem] border border-slate-100 shadow-sm">
            <h3 className="text-xl font-black text-slate-900 mb-8 flex items-center gap-2">
              <TrendingUp className="text-blue-600" size={20} /> Fluxo Financeiro
            </h3>
            <div className="space-y-6">
               <div className="flex justify-between items-center p-5 bg-green-50 rounded-2xl border border-green-100">
                  <div className="flex items-center gap-3">
                    <ArrowUpCircle className="text-green-600" />
                    <div>
                      <p className="text-[10px] font-black text-green-600 uppercase">Receita Bruta</p>
                      <p className="text-lg font-black text-green-900">{stats.revenue.toLocaleString()} MT</p>
                    </div>
                  </div>
               </div>
               <div className="flex justify-between items-center p-5 bg-rose-50 rounded-2xl border border-rose-100">
                  <div className="flex items-center gap-3">
                    <ArrowDownCircle className="text-rose-600" />
                    <div>
                      <p className="text-[10px] font-black text-rose-600 uppercase">Custo Staff/Oper.</p>
                      <p className="text-lg font-black text-rose-900">{stats.expenses.toLocaleString()} MT</p>
                    </div>
                  </div>
               </div>
            </div>

            <div className="mt-8">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Categorias de Operação</p>
              <div className="flex flex-wrap gap-2">
                {categories.slice(0, 8).map(cat => (
                  <span key={cat} className="px-3 py-1.5 bg-slate-50 border border-slate-100 rounded-lg text-[10px] font-bold text-slate-600">
                    {cat}
                  </span>
                ))}
              </div>
            </div>
          </div>

          <div className="bg-blue-600 p-10 rounded-[3.5rem] text-white shadow-xl shadow-blue-500/20 text-center">
            <Zap size={32} className="mx-auto mb-4" />
            <h4 className="text-lg font-black">Performance Total</h4>
            <p className="text-blue-100 text-sm mt-2 font-medium">Sistema sincronizado com Cloud Moçambique.</p>
          </div>
        </div>
      </div>

      {/* MODAL: Financeiro (Lançamento) */}
      {showFinanceModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white rounded-[3rem] p-10 max-w-lg w-full shadow-2xl relative">
            <button onClick={() => setShowFinanceModal(false)} className="absolute top-8 right-8 text-slate-400"><X size={24} /></button>
            <h2 className="text-2xl font-black text-slate-900 mb-6">Novo Lançamento Monte</h2>
            <form onSubmit={handleSaveTransaction} className="space-y-6">
              <div className="flex p-1 bg-slate-100 rounded-2xl">
                <button type="button" onClick={() => setNewTransaction({...newTransaction, type: 'RECEITA'})} className={`flex-1 py-3 text-sm font-bold rounded-xl ${newTransaction.type === 'RECEITA' ? 'bg-white text-green-600 shadow-sm' : 'text-slate-500'}`}>Receita</button>
                <button type="button" onClick={() => setNewTransaction({...newTransaction, type: 'DESPESA'})} className={`flex-1 py-3 text-sm font-bold rounded-xl ${newTransaction.type === 'DESPESA' ? 'bg-white text-red-600 shadow-sm' : 'text-slate-500'}`}>Despesa</button>
              </div>
              <div className="space-y-4">
                <input required placeholder="Descrição do Movimento" value={newTransaction.description} onChange={e => setNewTransaction({...newTransaction, description: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100 focus:ring-2 focus:ring-blue-500" />
                <div className="grid grid-cols-2 gap-4">
                  <input required type="number" placeholder="Valor (MT)" value={newTransaction.amount} onChange={e => setNewTransaction({...newTransaction, amount: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100" />
                  <select value={newTransaction.category} onChange={e => setNewTransaction({...newTransaction, category: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100">
                    {categories.map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                </div>
              </div>
              <button type="submit" className="w-full py-5 bg-blue-600 text-white font-black rounded-3xl shadow-xl hover:bg-blue-700 transition-all">Confirmar Lançamento</button>
            </form>
          </div>
        </div>
      )}

      {/* MODAL: Edição de Staff */}
      {showStaffModal && editingStaff && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white rounded-[3rem] p-10 max-w-lg w-full shadow-2xl relative">
            <button onClick={() => setShowStaffModal(false)} className="absolute top-8 right-8 text-slate-400"><X size={24} /></button>
            <h2 className="text-2xl font-black text-slate-900 mb-6">Editar Colaborador</h2>
            <form onSubmit={handleUpdateStaff} className="space-y-5">
              <div className="flex justify-center mb-6">
                <img src={editingStaff.avatar} className="w-24 h-24 rounded-[2rem] object-cover ring-4 ring-slate-50" />
              </div>
              <div className="space-y-4">
                <input required value={editingStaff.name} onChange={e => setEditingStaff({...editingStaff, name: e.target.value})} placeholder="Nome Completo" className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none" />
                <div className="grid grid-cols-2 gap-4">
                   <input type="number" value={editingStaff.salary} onChange={e => setEditingStaff({...editingStaff, salary: Number(e.target.value)})} placeholder="Salário Base" className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none" />
                   <input value={editingStaff.department} onChange={e => setEditingStaff({...editingStaff, department: e.target.value})} placeholder="Departamento" className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none" />
                </div>
              </div>
              <button type="submit" className="w-full py-5 bg-slate-900 text-white font-black rounded-3xl shadow-xl hover:bg-slate-800 transition-all flex items-center justify-center gap-2">
                <Save size={20} /> Salvar Alterações
              </button>
            </form>
          </div>
        </div>
      )}

      {/* MODAL: Adição de Categoria */}
      {showCategoryModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white rounded-[3rem] p-10 max-w-sm w-full shadow-2xl relative">
            <button onClick={() => setShowCategoryModal(false)} className="absolute top-8 right-8 text-slate-400"><X size={24} /></button>
            <h2 className="text-xl font-black text-slate-900 mb-6">Nova Categoria</h2>
            <div className="space-y-6">
              <input value={newCategory} onChange={e => setNewCategory(e.target.value)} placeholder="Ex: Manutenção Elétrica" className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none" />
              <button onClick={handleAddCategory} className="w-full py-4 bg-blue-600 text-white font-black rounded-2xl shadow-xl hover:bg-blue-700 transition-all">Adicionar ao Sistema</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default DashboardView;

import React from 'react';
import { ERP_NAVIGATION } from '../constants';
import { UserRole } from '../types';
import { X } from 'lucide-react';

interface SidebarProps {
  currentPath: string;
  onNavigate: (path: string) => void;
  userRole: UserRole;
  isOpen: boolean;
  toggleSidebar: () => void;
}

const Sidebar: React.FC<SidebarProps> = ({ currentPath, onNavigate, userRole, isOpen, toggleSidebar }) => {
  const filteredNav = ERP_NAVIGATION.filter(item => item.roles.includes(userRole));

  return (
    <div className={`fixed inset-y-0 left-0 z-50 transform ${isOpen ? 'translate-x-0' : '-translate-x-full'} md:relative md:translate-x-0 transition duration-300 ease-in-out bg-slate-900 text-slate-300 w-64 flex flex-col`}>
      <div className="p-6 flex items-center justify-between border-b border-slate-800">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center p-1.5 shadow-lg shadow-blue-500/20">
            <img src="https://i.ibb.co/LzfNdf7Y/building-logo.png" alt="Monte Imobiliária" className="w-full h-full object-contain brightness-0 invert" />
          </div>
          <span className="text-xl font-bold text-white tracking-tight">Monte Hub</span>
        </div>
        <button onClick={toggleSidebar} className="md:hidden text-slate-400 hover:text-white">
          <X size={24} />
        </button>
      </div>

      <nav className="flex-1 px-4 py-6 space-y-2 overflow-y-auto">
        {filteredNav.map((item) => (
          <button
            key={item.path}
            onClick={() => {
              onNavigate(item.path);
              if (window.innerWidth < 768) toggleSidebar();
            }}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-200 group ${
              currentPath === item.path 
              ? 'bg-blue-600 text-white shadow-lg shadow-blue-600/20' 
              : 'hover:bg-slate-800 hover:text-white'
            }`}
          >
            <span className={`${currentPath === item.path ? 'text-white' : 'text-slate-500 group-hover:text-blue-400'}`}>
              {item.icon}
            </span>
            <span className="font-medium text-sm">{item.name}</span>
          </button>
        ))}
      </nav>

      <div className="p-6 border-t border-slate-800">
        <div className="bg-slate-800 rounded-2xl p-4">
          <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2">Segurança</p>
          <div className="flex justify-between items-center mb-1">
            <span className="text-xs font-bold text-white">Full Access</span>
            <span className="text-[9px] font-black text-green-400 uppercase">Online</span>
          </div>
          <div className="w-full bg-slate-700 h-1 rounded-full">
            <div className="bg-blue-500 h-full rounded-full w-full"></div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Sidebar;

import React, { useState } from 'react';
import { Menu, X, Phone, Mail, MapPin, User as UserIcon } from 'lucide-react';

