              <img src="https://i.ibb.co/LzfNdf7Y/building-logo.png" alt="Monte Logo" className="w-full h-full object-contain brightness-0 invert" />
            </div>
            <div className="text-left">
              <span className="block text-xl font-black text-slate-900 leading-none tracking-tighter uppercase">MONTE</span>
              <span className="block text-[10px] font-black text-blue-600 tracking-widest uppercase">Imobiliária</span>
            </div>
          </button>

          {/* Desktop Nav */}
          <div className="hidden md:flex items-center gap-6">
            {navLinks.map((link) => (
              <button
                key={link.path}
                onClick={() => onNavigate(link.path)}
                className={`text-sm font-semibold transition-colors ${
                  currentPath === link.path ? 'text-blue-600' : 'text-slate-600 hover:text-blue-500'
                }`}
              >
                {link.name}
              </button>
            ))}
            <button
              onClick={() => onNavigate(isLoggedIn ? 'dashboard' : 'login')}
