            >
              <UserIcon size={16} />
              {isLoggedIn ? 'Aceder Hub' : 'Login Staff'}
            </button>
          </div>

          {/* Mobile Toggle */}
          <button className="md:hidden text-slate-600" onClick={() => setIsMenuOpen(!isMenuOpen)}>
            {isMenuOpen ? <X size={24} /> : <Menu size={24} />}
          </button>
        </div>

        {/* Mobile Menu */}
        {isMenuOpen && (
          <div className="md:hidden pt-4 pb-2 space-y-1">
            {navLinks.map((link) => (
              <button
                key={link.path}
                onClick={() => { onNavigate(link.path); setIsMenuOpen(false); }}
                className="block w-full text-left px-4 py-3 text-base font-medium text-slate-700 hover:bg-slate-50 hover:text-blue-600 rounded-lg"
              >
                {link.name}
              </button>
            ))}
          </div>
        )}
      </nav>
    </div>
  );
};

export default Navbar;

import React, { useState } from 'react';
import { supabase } from '../supabaseClient';
import { Mail, Lock, LogIn, Loader2, AlertCircle, ArrowLeft } from 'lucide-react';
import { UserRole } from '../types';

interface LoginViewProps {
  onLoginSuccess: (user: any) => void;
  onBack: () => void;
}

const LoginView: React.FC<LoginViewProps> = ({ onLoginSuccess, onBack }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSignIn = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
      const { data: authData, error: authError } = await supabase.auth.signInWithPassword({
        email, password,
      });
      if (authError) throw authError;

      const { data: empData } = await supabase
        .from('employees')
        .select('*')
        .eq('email', email)
        .single();

      const userData = {
        id: authData.user?.id,
        name: empData?.name || authData.user?.email?.split('@')[0],
        email: authData.user?.email,
        role: empData?.role || UserRole.EMPLOYEE,
        avatar: empData?.avatar || `https://picsum.photos/seed/${authData.user?.id}/100`,
      };

      onLoginSuccess(userData);
    } catch (err: any) {
      setError(err.message === 'Invalid login credentials' ? 'E-mail ou senha incorretos.' : err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 p-4 animate-in fade-in duration-500">
      <div className="bg-white rounded-[4rem] shadow-2xl p-10 md:p-16 max-w-md w-full border border-slate-100 relative overflow-hidden">
        <div className="absolute top-0 right-0 w-32 h-32 bg-blue-600/5 rounded-full -translate-y-1/2 translate-x-1/2 blur-2xl"></div>

        <div className="text-center mb-10">
          <div className="w-24 h-24 bg-blue-600 rounded-[2.5rem] flex items-center justify-center mx-auto mb-8 shadow-2xl shadow-blue-500/30 p-4">
            <img src="https://i.ibb.co/LzfNdf7Y/building-logo.png" alt="Monte Logo" className="w-full h-full object-contain brightness-0 invert" />
          </div>
          <h2 className="text-3xl font-black text-slate-900 tracking-tight uppercase">MONTE HUB</h2>
          <p className="text-slate-500 font-bold text-[10px] uppercase tracking-widest mt-2 px-4 py-1 bg-slate-50 rounded-full inline-block">Sincronização Cloud Ativa</p>
        </div>

        {error && (
          <div className="mb-6 bg-red-50 border-l-4 border-red-500 p-4 rounded-xl flex items-center gap-3 text-red-700 text-xs font-bold animate-shake">
            <AlertCircle size={18} /> {error}
          </div>
        )}

        <form onSubmit={handleSignIn} className="space-y-6">
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">E-mail Staff</label>
            <div className="relative">
              <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                required type="email" value={email} onChange={(e) => setEmail(e.target.value)}
                className="w-full pl-12 pr-4 py-5 bg-slate-50 rounded-[1.5rem] border-none focus:ring-2 focus:ring-blue-600 font-bold text-sm"
                placeholder="nome@monte-imobiliaria.com"
              />
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Chave de Segurança</label>
            <div className="relative">
              <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                required type="password" value={password} onChange={(e) => setPassword(e.target.value)}
                className="w-full pl-12 pr-4 py-5 bg-slate-50 rounded-[1.5rem] border-none focus:ring-2 focus:ring-blue-600 font-bold text-sm"
                placeholder="••••••••"
              />
            </div>
          </div>

          <button 
            disabled={loading} type="submit" 
            className="w-full py-6 bg-blue-600 text-white rounded-[2rem] font-black text-xs uppercase tracking-widest flex items-center justify-center gap-3 hover:bg-blue-700 transition-all shadow-xl shadow-blue-500/20 active:scale-95"
          >
            {loading ? <Loader2 className="animate-spin" size={20} /> : <><LogIn size={20} /> Aceder ao ERP</>}
          </button>
        </form>

        <div className="mt-10 text-center">
          <button onClick={onBack} className="text-slate-400 hover:text-blue-600 font-black text-[10px] uppercase tracking-widest flex items-center justify-center gap-2 mx-auto transition-colors">
            <ArrowLeft size={14} /> Voltar ao Portal Público
          </button>
        </div>
      </div>
    </div>
  );
};

