                      <p className="text-xs font-black text-slate-900">{Number(member.salary).toLocaleString()} MT</p>
                      <span className="text-[9px] font-black text-blue-600 bg-blue-50 px-2 py-0.5 rounded-lg">ATIVO</span>
                    </div>
                    <button 
