                </div>
              </div>
              <button type="submit" className="w-full py-5 bg-slate-900 text-white font-black rounded-[2rem] shadow-xl hover:bg-slate-800 transition-all flex items-center justify-center gap-2 mt-4">
                <Save size={20} /> Guardar Alterações
              </button>
            </form>
          </div>
        </div>
      )}

      {/* MODAL: Nova Categoria */}
      {showCategoryModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white rounded-[3rem] p-10 max-w-sm w-full shadow-2xl relative">
            <button onClick={() => setShowCategoryModal(false)} className="absolute top-8 right-8 text-slate-400"><X size={24} /></button>
            <h2 className="text-xl font-black text-slate-900 mb-6 flex items-center gap-2"><Tags className="text-blue-600" /> Nova Categoria</h2>
            <div className="space-y-6">
              <input value={newCategory} onChange={e => setNewCategory(e.target.value)} placeholder="Ex: Limpeza Jardim" className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none" />
              <button onClick={handleAddCategory} className="w-full py-4 bg-blue-600 text-white font-black rounded-2xl shadow-xl hover:bg-blue-700 transition-all">Sincronizar Categoria</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

