import React, { useState, useEffect } from 'react';
import { 
  Plus, Users, DollarSign, UserCheck, AlertCircle, Clock, 
  Loader2, X, CheckCircle, Trash2, LayoutDashboard,
  Lock, Save, UserCog, Mail, Phone
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { Employee, UserRole } from '../types';

const HRView: React.FC = () => {
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAddModal, setShowAddModal] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [newEmp, setNewEmp] = useState<Partial<Employee>>({
    name: '', role: UserRole.EMPLOYEE, department: 'Vendas', salary: 0, email: '', phone: ''
  });

  useEffect(() => {
    fetchData();
  }, []);

  async function fetchData() {
    setLoading(true);
    const { data } = await supabase.from('employees').select('*').order('name');
    setEmployees(data || []);
    setLoading(false);
  }

  const validateEmail = (email: string) => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  };

  const validatePhone = (phone: string) => {
    // Remove espaços para validação
    const cleanPhone = phone.replace(/\s/g, '');
    // Regex para números de Moçambique: Opcional +258 seguido de 82, 83, 84, 85, 86 ou 87 e mais 7 dígitos.
    return /^(\+258)?8[2-7][0-9]{7}$/.test(cleanPhone);
  };

  const handleAddEmployee = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    if (!newEmp.email || !validateEmail(newEmp.email)) {
      setError('O formato do e-mail introduzido é inválido.');
      return;
    }

    if (!newEmp.phone || !validatePhone(newEmp.phone)) {
      setError('O formato do telefone é inválido. Use o padrão moçambicano (Ex: 841234567 ou +258 841234567).');
      return;
    }

    const { error: sbError } = await supabase.from('employees').insert([{
      ...newEmp,
      avatar: `https://picsum.photos/seed/${newEmp.name}/100`,
      status: 'Ativo',
      join_date: new Date().toISOString().split('T')[0]
    }]);

    if (sbError) {
      setError('Erro ao salvar no banco de dados: ' + sbError.message);
    } else {
      setShowAddModal(false);
      setError(null);
      setNewEmp({ name: '', role: UserRole.EMPLOYEE, department: 'Vendas', salary: 0, email: '', phone: '' });
      fetchData();
    }
  };

  const removeEmployee = async (id: string) => {
    if (confirm('Deseja rescindir o contrato deste colaborador?')) {
      const { error } = await supabase.from('employees').delete().eq('id', id);
      if (!error) fetchData();
    }
  };

  if (loading) return <div className="flex justify-center py-20"><Loader2 className="animate-spin text-blue-600" size={40} /></div>;

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-4">
           <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-indigo-500/20">
             <Users size={24} />
           </div>
           <div>
             <h1 className="text-3xl font-black text-slate-900 tracking-tight">Gestão de Capital Humano</h1>
             <p className="text-slate-500 font-medium">Controlo centralizado de staff Monte Imobiliária.</p>
           </div>
        </div>
        <button onClick={() => { setError(null); setShowAddModal(true); }} className="flex items-center gap-2 px-8 py-4 bg-indigo-600 text-white rounded-[2rem] font-black text-sm shadow-xl hover:bg-indigo-700 transition-all">
          <Plus size={20} /> Novo Colaborador
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
        {employees.map(emp => (
          <div key={emp.id} className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm relative group hover:shadow-2xl transition-all">
            <button onClick={() => removeEmployee(emp.id)} className="absolute top-8 right-8 p-2 text-slate-200 hover:text-red-500 transition-colors">
              <Trash2 size={18} />
            </button>
            <img src={emp.avatar} className="w-24 h-24 rounded-[2.5rem] object-cover mb-6 ring-4 ring-slate-50" alt={emp.name} />
            <h3 className="text-lg font-black text-slate-900 mb-1">{emp.name}</h3>
            <p className="text-[10px] font-black text-indigo-600 uppercase tracking-widest mb-4">{emp.role}</p>

            <div className="space-y-3 mb-6">
              <div className="flex items-center gap-2 text-xs text-slate-500 font-medium"><Mail size={14} /> {emp.email}</div>
              <div className="flex items-center gap-2 text-xs text-slate-500 font-medium"><Phone size={14} /> {emp.phone}</div>
            </div>

            <div className="pt-6 border-t border-slate-50 flex justify-between items-end">
              <div>
                <p className="text-[9px] font-black text-slate-400 uppercase mb-1">Vencimento</p>
                <p className="text-base font-black text-slate-900">{Number(emp.salary).toLocaleString()} MT</p>
              </div>
              <span className="text-[9px] font-black px-2.5 py-1 bg-green-50 text-green-600 rounded-lg">{emp.status}</span>
            </div>
          </div>
        ))}
      </div>

      {showAddModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-12 max-w-lg w-full shadow-2xl relative">
            <button onClick={() => setShowAddModal(false)} className="absolute top-10 right-10 text-slate-400"><X size={24} /></button>
            <h2 className="text-2xl font-black text-slate-900 mb-8 flex items-center gap-3">
              <UserCog className="text-indigo-600" /> Registar Staff
            </h2>

            {error && (
              <div className="mb-6 p-4 bg-red-50 border-l-4 border-red-500 rounded-xl flex items-center gap-3 text-red-700 text-xs font-bold animate-in fade-in slide-in-from-top-2">
                <AlertCircle size={18} /> {error}
              </div>
            )}

            <form onSubmit={handleAddEmployee} className="space-y-6">
              <input required placeholder="Nome Completo" value={newEmp.name} onChange={e => setNewEmp({...newEmp, name: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100 focus:ring-2 focus:ring-indigo-600" />
              <div className="grid grid-cols-2 gap-4">
                <input required type="email" placeholder="E-mail" value={newEmp.email} onChange={e => setNewEmp({...newEmp, email: e.target.value})} className={`w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border ${error && error.includes('e-mail') ? 'border-red-300 ring-1 ring-red-100' : 'border-slate-100'}`} />
                <input required placeholder="Telefone" value={newEmp.phone} onChange={e => setNewEmp({...newEmp, phone: e.target.value})} className={`w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border ${error && error.includes('telefone') ? 'border-red-300 ring-1 ring-red-100' : 'border-slate-100'}`} />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <select value={newEmp.role} onChange={e => setNewEmp({...newEmp, role: e.target.value as any})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100">
                  {Object.values(UserRole).map(r => <option key={r} value={r}>{r}</option>)}
                </select>
                <input type="number" placeholder="Salário Base" value={newEmp.salary} onChange={e => setNewEmp({...newEmp, salary: Number(e.target.value)})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100" />
              </div>
              <button type="submit" className="w-full py-5 bg-indigo-600 text-white font-black rounded-[2rem] shadow-xl hover:bg-indigo-700 transition-all">Sincronizar Cloud Staff</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

