  useEffect(() => {
    fetchData();
    const fetchInsight = async () => {
      const msg = await getStrategicInsight("Análise de crescimento para Monte Imobiliária na Beira.");
      setInsight(msg);
    };
    fetchInsight();
  }, []);

  async function fetchData() {
    setLoading(true);
    setDbError(null);
    try {
      const [emp, prop, trans, cont] = await Promise.all([
        supabase.from('employees').select('*').order('name'),
        supabase.from('properties').select('id', { count: 'exact' }),
        supabase.from('transactions').select('*'),
        supabase.from('contact_requests').select('*').order('created_at', { ascending: false })
      ]);

      // Verificar erros específicos de tabelas não encontradas
      if (cont.error && cont.error.message.includes('contact_requests')) {
        setDbError('A tabela "contact_requests" não foi encontrada. Por favor, crie-a no painel do Supabase para ativar os contactos.');
      }

      const txs = trans.data || [];
      const rev = txs.filter(t => t.type === 'RECEITA').reduce((a, b) => a + Number(b.amount || 0), 0);
      const exp = txs.filter(t => t.type === 'DESPESA').reduce((a, b) => a + Number(b.amount || 0), 0);

      setStats({
        employees: emp.data?.length || 0,
        properties: prop.count || 0,
        revenue: rev,
        expenses: exp,
        contacts: cont.data?.length || 0
      });
      setStaff(emp.data || []);
      setContacts(cont.data || []);

      const uniqueCats = Array.from(new Set([...categories, ...txs.map(t => t.category)]));
      setCategories(uniqueCats);
    } catch (err: any) {
      console.error("Dashboard Fetch Error:", err);
      setDbError(err.message || 'Erro inesperado ao carregar dados do Dashboard.');
    } finally {
      setLoading(false);
    }
  }

  const deleteContact = async (id: string) => {
