              <div className="flex p-1 bg-slate-100 rounded-2xl">
                <button type="button" onClick={() => setNewTransaction({...newTransaction, type: 'RECEITA'})} className={`flex-1 py-3 text-sm font-bold rounded-xl ${newTransaction.type === 'RECEITA' ? 'bg-white text-green-600 shadow-sm' : 'text-slate-500'}`}>Receita</button>
                <button type="button" onClick={() => setNewTransaction({...newTransaction, type: 'DESPESA'})} className={`flex-1 py-3 text-sm font-bold rounded-xl ${newTransaction.type === 'DESPESA' ? 'bg-white text-red-600 shadow-sm' : 'text-slate-500'}`}>Despesa</button>
              </div>
              <div className="space-y-4">
                <input required placeholder="Descrição" value={newTransaction.description} onChange={e => setNewTransaction({...newTransaction, description: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100 focus:ring-2 focus:ring-blue-500" />
                <div className="grid grid-cols-2 gap-4">
                  <input required type="number" placeholder="Valor (MT)" value={newTransaction.amount} onChange={e => setNewTransaction({...newTransaction, amount: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100" />
                  <select value={newTransaction.category} onChange={e => setNewTransaction({...newTransaction, category: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100">
                    {categories.map(c => <option key={c} value={c}>{c}</option>)}
                  </select>
                </div>
              </div>
              <button type="submit" className="w-full py-5 bg-blue-600 text-white font-black rounded-[2rem] shadow-xl hover:bg-blue-700 transition-all flex items-center justify-center gap-2">
                <Save size={20} /> Confirmar Lançamento
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

