              <button disabled={status === 'loading'} type="submit" className="w-full bg-blue-600 hover:bg-blue-700 text-white p-6 rounded-[2rem] font-black flex items-center justify-center gap-3 transition-all shadow-xl shadow-blue-500/20 active:scale-95 disabled:opacity-70">
