import React, { useState, useEffect } from 'react';
import { 
  Plus, Users, DollarSign, UserCheck, AlertCircle, Clock, 
  Loader2, X, CheckCircle, Trash2, LayoutDashboard,
  Lock, Save, UserCog, Mail, Phone, CreditCard, Calendar as CalendarIcon, FileText
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { Employee, UserRole } from '../types';

const HRView: React.FC = () => {
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAddModal, setShowAddModal] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Estado inicial atualizado com novos campos
  const [newEmp, setNewEmp] = useState<Partial<Employee>>({
    name: '', 
    role: UserRole.EMPLOYEE, 
    department: 'Vendas', 
    salary: 0, 
    email: '', 
    phone: '',
    document_type: 'BI',
    document_number: '',
    document_expiry: '',
    payment_method: 'M-Pesa',
    contract_start: ''
  });

  useEffect(() => {
    fetchData();
  }, []);

  async function fetchData() {
    setLoading(true);
    try {
      const { data, error: sbError } = await supabase.from('employees').select('*').order('name');
      if (sbError) {
        if (sbError.message.includes('schema cache')) {
           setError('Erro de Cache no Supabase. Por favor, vá à Administração TI e execute o script SQL atualizado.');
        } else {
           setError(sbError.message);
        }
      }
      setEmployees(data || []);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }

  const validateEmail = (email: string) => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  };

  const validatePhone = (phone: string) => {
    const cleanPhone = phone.replace(/\s/g, '');
    return /^(\+258)?8[2-7][0-9]{7}$/.test(cleanPhone);
  };

  const handleAddEmployee = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    if (!newEmp.email || !validateEmail(newEmp.email)) {
      setError('O formato do e-mail introduzido é inválido.');
      return;
    }

    if (!newEmp.phone || !validatePhone(newEmp.phone)) {
      setError('O formato do telefone é inválido (Ex: 841234567).');
      return;
    }

    // Preparar payload para inserção
    const payload = {
      name: newEmp.name,
      email: newEmp.email,
      phone: newEmp.phone,
      role: newEmp.role,
      department: newEmp.department,
      salary: Number(newEmp.salary),
      avatar: `https://picsum.photos/seed/${newEmp.name}/100`,
      status: 'Ativo',
      join_date: new Date().toISOString().split('T')[0],
      // Novos campos moçambicanos
      document_type: newEmp.document_type,
      document_number: newEmp.document_number,
      document_expiry: newEmp.document_expiry || null,
      payment_method: newEmp.payment_method,
      contract_start: newEmp.contract_start || null
    };

    const { error: sbError } = await supabase.from('employees').insert([payload]);

    if (sbError) {
      setError('Erro Supabase: ' + sbError.message);
      // Se for erro de cache, sugerir recarregamento
      if (sbError.message.includes('schema cache')) {
        setError('O Supabase ainda não reconheceu as novas colunas. Por favor, execute o script SQL na aba "Administração TI".');
      }
    } else {
      setShowAddModal(false);
      setError(null);
      // Reset completo
      setNewEmp({ 
        name: '', role: UserRole.EMPLOYEE, department: 'Vendas', salary: 0, email: '', phone: '',
        document_type: 'BI', document_number: '', document_expiry: '', payment_method: 'M-Pesa', contract_start: ''
      });
      fetchData();
    }
  };

  const removeEmployee = async (id: string) => {
    if (confirm('Deseja rescindir o contrato deste colaborador?')) {
      const { error } = await supabase.from('employees').delete().eq('id', id);
      if (!error) fetchData();
    }
  };

  if (loading) return <div className="flex justify-center py-20"><Loader2 className="animate-spin text-blue-600" size={40} /></div>;

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-4">
           <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-indigo-500/20">
             <Users size={24} />
           </div>
           <div>
             <h1 className="text-3xl font-black text-slate-900 tracking-tight">Gestão de Capital Humano</h1>
             <p className="text-slate-500 font-medium">Controlo centralizado de staff Monte Imobiliária.</p>
           </div>
        </div>
        <button onClick={() => { setError(null); setShowAddModal(true); }} className="flex items-center gap-2 px-8 py-4 bg-indigo-600 text-white rounded-[2rem] font-black text-sm shadow-xl hover:bg-indigo-700 transition-all">
          <Plus size={20} /> Novo Colaborador
        </button>
      </div>

      {error && (
        <div className="p-4 bg-amber-50 border-l-4 border-amber-500 rounded-xl flex items-center gap-3 text-amber-800 text-xs font-bold animate-in slide-in-from-top-2">
          <AlertCircle size={20} /> {error}
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
        {employees.length === 0 ? (
          <div className="col-span-full py-20 text-center text-slate-400 font-bold italic">Nenhum colaborador registado no momento.</div>
        ) : employees.map(emp => (
          <div key={emp.id} className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm relative group hover:shadow-2xl transition-all">
            <button onClick={() => removeEmployee(emp.id)} className="absolute top-8 right-8 p-2 text-slate-200 hover:text-red-500 transition-colors">
              <Trash2 size={18} />
            </button>
            <img src={emp.avatar} className="w-24 h-24 rounded-[2.5rem] object-cover mb-6 ring-4 ring-slate-50 shadow-sm" alt={emp.name} />
            <h3 className="text-lg font-black text-slate-900 mb-1">{emp.name}</h3>
            <p className="text-[10px] font-black text-indigo-600 uppercase tracking-widest mb-4">{emp.role}</p>

            <div className="space-y-3 mb-6">
              <div className="flex items-center gap-2 text-[10px] text-slate-500 font-bold uppercase"><Mail size={12} className="text-slate-300"/> {emp.email}</div>
              <div className="flex items-center gap-2 text-[10px] text-slate-500 font-bold uppercase"><Phone size={12} className="text-slate-300"/> {emp.phone}</div>
              <div className="flex items-center gap-2 text-[10px] text-slate-500 font-bold uppercase"><CreditCard size={12} className="text-slate-300"/> {emp.payment_method || 'N/A'}</div>
            </div>

            <div className="pt-6 border-t border-slate-50 flex justify-between items-end">
              <div>
                <p className="text-[9px] font-black text-slate-400 uppercase mb-1">Base Mensal</p>
                <p className="text-base font-black text-slate-900">{Number(emp.salary).toLocaleString()} MT</p>
              </div>
              <span className={`text-[9px] font-black px-2.5 py-1 rounded-lg ${emp.status === 'Ativo' ? 'bg-green-50 text-green-600' : 'bg-slate-50 text-slate-400'}`}>
                {emp.status}
              </span>
            </div>
          </div>
        ))}
      </div>

      {showAddModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/70 backdrop-blur-sm animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-10 max-w-2xl w-full shadow-2xl relative overflow-y-auto max-h-[95vh]">
            <button onClick={() => setShowAddModal(false)} className="absolute top-10 right-10 text-slate-400 p-2 hover:bg-slate-50 rounded-xl"><X size={24} /></button>

            <div className="flex items-center gap-4 mb-8">
               <div className="w-12 h-12 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-600">
                  <UserCog size={24} />
               </div>
               <div>
                  <h2 className="text-2xl font-black text-slate-900">Novo Cadastro Staff</h2>
                  <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Sincronização Cloud em tempo real</p>
               </div>
            </div>

            {error && (
              <div className="mb-8 p-5 bg-red-50 border-l-4 border-red-500 rounded-2xl flex items-center gap-3 text-red-700 text-xs font-black animate-in fade-in slide-in-from-top-2">
                <AlertCircle size={20} /> {error}
              </div>
            )}

            <form onSubmit={handleAddEmployee} className="space-y-8">
              {/* Informações Pessoais */}
              <div className="space-y-4">
                <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100 pb-2">Informação Básica</h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <input required placeholder="Nome Completo" value={newEmp.name} onChange={e => setNewEmp({...newEmp, name: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100 focus:ring-2 focus:ring-indigo-600 transition-all" />
                  <input required type="email" placeholder="E-mail Institucional" value={newEmp.email} onChange={e => setNewEmp({...newEmp, email: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100 focus:ring-2 focus:ring-indigo-600 transition-all" />
                  <input required placeholder="Telefone (Moçambique)" value={newEmp.phone} onChange={e => setNewEmp({...newEmp, phone: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100 focus:ring-2 focus:ring-indigo-600 transition-all" />
                  <input type="number" placeholder="Salário Base (MT)" value={newEmp.salary} onChange={e => setNewEmp({...newEmp, salary: Number(e.target.value)})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100 focus:ring-2 focus:ring-indigo-600 transition-all" />
                </div>
              </div>

              {/* Documentação */}
              <div className="space-y-4">
                <div className="flex items-center gap-2 text-slate-400 border-b border-slate-100 pb-2">
                   <FileText size={14} />
                   <h3 className="text-[10px] font-black uppercase tracking-widest">Documentação & Identificação</h3>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  <div>
                    <select value={newEmp.document_type} onChange={e => setNewEmp({...newEmp, document_type: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100">
                      <option value="BI">Bilhete de Identidade (BI)</option>
                      <option value="Passaporte">Passaporte</option>
                      <option value="DIRE">DIRE</option>
                      <option value="Cartão Eleitor">Cartão de Eleitor</option>
                    </select>
                  </div>
                  <input placeholder="Número do Documento" value={newEmp.document_number} onChange={e => setNewEmp({...newEmp, document_number: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100" />
                  <div className="relative">
                    <input type="date" value={newEmp.document_expiry} onChange={e => setNewEmp({...newEmp, document_expiry: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100 text-xs" />
                    <span className="absolute -top-3 left-3 bg-white px-1 text-[8px] font-black text-slate-400 uppercase">Validade</span>
                  </div>
                </div>
              </div>

              {/* Profissional e Pagamento */}
              <div className="space-y-4">
                <div className="flex items-center gap-2 text-slate-400 border-b border-slate-100 pb-2">
                   <CreditCard size={14} />
                   <h3 className="text-[10px] font-black uppercase tracking-widest">Contrato & Pagamento</h3>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                  <select value={newEmp.role} onChange={e => setNewEmp({...newEmp, role: e.target.value as any})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100">
                    {Object.values(UserRole).map(r => <option key={r} value={r}>{r}</option>)}
                  </select>

                  <select value={newEmp.payment_method} onChange={e => setNewEmp({...newEmp, payment_method: e.target.value as any})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100">
                    <option value="M-Pesa">Carteira M-Pesa</option>
                    <option value="e-Mola">Carteira e-Mola</option>
                    <option value="mKesh">mKesh</option>
                    <option value="Banco">Transferência Bancária</option>
                  </select>

                  <div className="relative">
                    <input type="date" value={newEmp.contract_start} onChange={e => setNewEmp({...newEmp, contract_start: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100 text-xs" />
                    <span className="absolute -top-3 left-3 bg-white px-1 text-[8px] font-black text-slate-400 uppercase">Início Contrato</span>
                  </div>
                </div>
              </div>

              <div className="pt-4">
                <button type="submit" className="w-full py-6 bg-indigo-600 text-white font-black rounded-[2.5rem] shadow-xl shadow-indigo-500/20 hover:bg-indigo-700 hover:scale-[1.02] transition-all flex items-center justify-center gap-3">
                  <Save size={24} /> Finalizar e Sincronizar Staff
                </button>
                <p className="text-[9px] text-center text-slate-400 font-bold uppercase mt-4 tracking-tighter">Os dados de identificação e contrato são opcionais para cadastro rápido.</p>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

