-- SCRIPT DE ATUALIZAÇÃO MONTE HUB v2
-- Se você já tem as tabelas, execute isto para adicionar as novas colunas
-- Ou execute tudo se for a primeira vez.

CREATE TABLE IF NOT EXISTS public.employees (
    id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
    name text NOT NULL,
    email text UNIQUE NOT NULL,
    role text NOT NULL,
    department text,
    salary numeric DEFAULT 0,
    status text DEFAULT 'Ativo',
    avatar text,
    phone text,
    join_date date DEFAULT CURRENT_DATE,
    permissions text[] DEFAULT '{}'::text[],
    -- Novos campos Moçambique
    document_type text, -- BI, Passaporte, DIRE
    document_number text,
    document_expiry date,
    payment_method text, -- Banco, M-Pesa, e-Mola
    contract_start date,
    created_at timestamptz DEFAULT now()
);

-- Garantir que colunas existam se a tabela já foi criada anteriormente
DO $$ 
BEGIN 
    BEGIN
        ALTER TABLE public.employees ADD COLUMN document_type text;
    EXCEPTION WHEN duplicate_column THEN END;

    BEGIN
        ALTER TABLE public.employees ADD COLUMN document_number text;
    EXCEPTION WHEN duplicate_column THEN END;

    BEGIN
        ALTER TABLE public.employees ADD COLUMN document_expiry date;
    EXCEPTION WHEN duplicate_column THEN END;

    BEGIN
        ALTER TABLE public.employees ADD COLUMN payment_method text;
    EXCEPTION WHEN duplicate_column THEN END;

    BEGIN
        ALTER TABLE public.employees ADD COLUMN contract_start date;
    EXCEPTION WHEN duplicate_column THEN END;
END $$;

-- Tabela de Transações Financeiras
CREATE TABLE IF NOT EXISTS public.transactions (
    id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
    description text NOT NULL,
    amount numeric NOT NULL,
    type text NOT NULL,
    category text NOT NULL,
    date date DEFAULT CURRENT_DATE,
    created_at timestamptz DEFAULT now()
);

-- Habilitar RLS e Políticas
ALTER TABLE public.employees ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "Public Access" ON public.employees;
CREATE POLICY "Public Access" ON public.employees FOR ALL USING (true);

ALTER TABLE public.transactions ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "Public Access" ON public.transactions;
CREATE POLICY "Public Access" ON public.transactions FOR ALL USING (true);

-- NOTA IMPORTANTE: Se o erro "Schema Cache" persistir após rodar o SQL,
-- vá em Settings -> API -> e clique em "Reload PostgREST" ou reinicie o projeto.

