  useEffect(() => {
    fetchData();
  }, []);

  async function fetchData() {
    setLoading(true);
    try {
      const { data, error: sbError } = await supabase.from('employees').select('*').order('name');
      if (sbError) {
        if (sbError.message.includes('schema cache') || sbError.message.includes('not found')) {
           setError('⚠️ Erro de Cache: A tabela ou colunas ainda não foram reconhecidas. Vá à aba "Administração TI" e siga o passo de Sincronização.');
        } else {
           setError(sbError.message);
        }
      }
      setEmployees(data || []);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }

  const handleAddEmployee = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    // Payload completo - Campos extras são opcionais (podem ser null)
    const payload = {
      name: newEmp.name,
      email: newEmp.email,
      phone: newEmp.phone,
      role: newEmp.role,
      department: newEmp.department,
      salary: Number(newEmp.salary),
      avatar: `https://picsum.photos/seed/${newEmp.name}/100`,
      status: 'Ativo',
