      // Campos Moçambique
      document_type: newEmp.document_type || null,
      document_number: newEmp.document_number || null,
      document_expiry: newEmp.document_expiry || null,
      payment_method: newEmp.payment_method || null,
      contract_start: newEmp.contract_start || null
