    const { error: sbError } = await supabase.from('employees').insert([payload]);

    if (sbError) {
      if (sbError.message.includes('schema cache')) {
        setError('O Supabase ainda não "viu" as novas colunas. Vá em Administração TI e rode o script de Sincronização.');
      } else {
        setError('Erro ao salvar no banco de dados: ' + sbError.message);
      }
    } else {
      setShowAddModal(false);
      setNewEmp({ 
        name: '', role: UserRole.EMPLOYEE, department: 'Vendas', salary: 0, email: '', phone: '',
        document_type: 'BI', document_number: '', document_expiry: '', payment_method: 'M-Pesa', contract_start: ''
      });
      fetchData();
    }
