      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
        {employees.length === 0 ? (
          <div className="col-span-full py-24 text-center bg-white rounded-[3rem] border-2 border-dashed border-slate-100">
            <Users size={48} className="mx-auto text-slate-200 mb-4" />
            <p className="text-slate-400 font-bold italic">Nenhum colaborador registado no momento.</p>
          </div>
        ) : employees.map(emp => (
          <div key={emp.id} className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm relative group hover:shadow-2xl transition-all border-b-4 hover:border-b-indigo-500">
            <button onClick={() => removeEmployee(emp.id)} className="absolute top-8 right-8 p-2 text-slate-200 hover:text-red-500 transition-colors">
              <Trash2 size={18} />
            </button>
            <div className="relative inline-block mb-6">
              <img src={emp.avatar} className="w-24 h-24 rounded-[2.5rem] object-cover ring-4 ring-slate-50 shadow-sm" alt={emp.name} />
