              </div>
              <div className="text-right">
                 <p className="text-[9px] font-black text-slate-400 uppercase mb-1">Início</p>
                 <p className="text-[10px] font-bold text-slate-900 uppercase tracking-tighter">{emp.contract_start || emp.join_date}</p>
              </div>
            </div>
          </div>
        ))}
