                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Tipo de Documento</label>
                    <select value={newEmp.document_type} onChange={e => setNewEmp({...newEmp, document_type: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100">
                      <option value="BI">Bilhete de Identidade (BI)</option>
