                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Número do Documento</label>
                    <input placeholder="Ex: 0101010101A" value={newEmp.document_number} onChange={e => setNewEmp({...newEmp, document_number: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100" />
