import React, { useState, useEffect } from 'react';
import { 
  Shield, Key, Lock, Settings, UserCog, Save, 
  CheckCircle2, AlertCircle, Loader2, Search,
  ShieldAlert, Fingerprint, Zap, Database, Copy, Check, X,
  RefreshCw
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { UserRole, Employee } from '../types';

const AdminView: React.FC = () => {
  const [users, setUsers] = useState<Employee[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [editingUser, setEditingUser] = useState<Employee | null>(null);
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState<{type: 'success' | 'error', text: string} | null>(null);
  const [copied, setCopied] = useState(false);

  // Script SQL COMPLETO E REPARADOR
  const sqlSchema = `-- SCRIPT DE SINCRONIZAÇÃO MONTE HUB v2
-- 1. Cria ou Atualiza Tabela de Funcionários
CREATE TABLE IF NOT EXISTS public.employees (
    id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
    name text NOT NULL,
    email text UNIQUE NOT NULL,
    role text NOT NULL,
    department text,
    salary numeric DEFAULT 0,
    status text DEFAULT 'Ativo',
    avatar text,
    phone text,
    join_date date DEFAULT CURRENT_DATE,
    permissions text[] DEFAULT '{}'::text[],
    -- Campos Moçambique
    document_type text,
    document_number text,
    document_expiry date,
    payment_method text,
    contract_start date,
    created_at timestamptz DEFAULT now()
);

-- 2. Atualização Forçada de Colunas (Caso a tabela já exista sem elas)
DO $$ 
BEGIN 
    BEGIN
        ALTER TABLE public.employees ADD COLUMN document_type text;
    EXCEPTION WHEN duplicate_column THEN END;

    BEGIN
        ALTER TABLE public.employees ADD COLUMN document_number text;
    EXCEPTION WHEN duplicate_column THEN END;

    BEGIN
        ALTER TABLE public.employees ADD COLUMN document_expiry date;
    EXCEPTION WHEN duplicate_column THEN END;

    BEGIN
        ALTER TABLE public.employees ADD COLUMN payment_method text;
    EXCEPTION WHEN duplicate_column THEN END;

    BEGIN
        ALTER TABLE public.employees ADD COLUMN contract_start date;
    EXCEPTION WHEN duplicate_column THEN END;
END $$;

-- 3. Políticas de Acesso Público (Necessário para o ERP funcionar)
ALTER TABLE public.employees ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "Acesso Total ERP" ON public.employees;
CREATE POLICY "Acesso Total ERP" ON public.employees FOR ALL USING (true);

-- 4. COMANDO CRÍTICO: Recarrega o Cache do PostgREST para o erro 'Could not find table'
NOTIFY pgrst, 'reload schema';
`;

  const availablePermissions = [
    'Ver_Financeiro', 'Editar_Financeiro', 'Gerir_RH', 
    'Acesso_Admin', 'Editar_Catalogo', 'Gerir_Projetos',
    'Relatorios_Avancados', 'Configuracao_TI'
  ];

  useEffect(() => {
    fetchUsers();
  }, []);

  async function fetchUsers() {
    setLoading(true);
    try {
      const { data, error } = await supabase.from('employees').select('*').order('name');
      if (!error) setUsers(data || []);
    } catch (e) {
      console.warn("Tabela 'employees' ainda não foi criada.");
    } finally {
      setLoading(false);
    }
  }

  const copySql = () => {
    navigator.clipboard.writeText(sqlSchema);
    setCopied(true);
    setTimeout(() => setCopied(false), 3000);
  };

  const handleUpdatePermissions = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!editingUser) return;

    setSaving(true);
    const { error } = await supabase
      .from('employees')
      .update({ 
        role: editingUser.role,
        permissions: editingUser.permissions 
      })
      .eq('id', editingUser.id);

    if (error) {
      setMsg({ type: 'error', text: 'Falha: ' + error.message });
    } else {
      setMsg({ type: 'success', text: 'Privilégios aplicados!' });
      fetchUsers();
    }
    setSaving(false);
    setTimeout(() => setMsg(null), 3000);
  };

  const togglePermission = (perm: string) => {
    if (!editingUser) return;
    const current = editingUser.permissions || [];
    const newPerms = current.includes(perm) 
      ? current.filter(p => p !== perm) 
      : [...current, perm];
    setEditingUser({ ...editingUser, permissions: newPerms });
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-12">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">Administração & TI</h1>
          <p className="text-slate-500 font-medium">Sincronização Cloud e Gestão de Contas.</p>
        </div>
        <div className="flex items-center gap-3">
           <button onClick={fetchUsers} className="p-4 bg-white text-slate-400 hover:text-blue-600 rounded-2xl shadow-sm border border-slate-100 transition-all">
             <RefreshCw size={20} className={loading ? 'animate-spin' : ''} />
           </button>
           <div className="px-4 py-2 bg-blue-50 text-blue-700 rounded-full text-[10px] font-black uppercase tracking-widest border border-blue-100 flex items-center gap-2">
             <Fingerprint size={14} /> Sistema Ativo
           </div>
        </div>
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
        <div className="xl:col-span-2 space-y-8">

          {/* SQL Sincronizador Tool */}
          <div className="bg-slate-900 rounded-[3rem] p-10 text-white shadow-2xl relative overflow-hidden">
            <div className="absolute top-0 right-0 w-64 h-64 bg-blue-600/10 rounded-full blur-[80px]"></div>

            <div className="flex items-center gap-4 mb-8 relative z-10">
              <div className="w-14 h-14 bg-blue-600 rounded-2xl flex items-center justify-center shadow-lg">
                <Database size={28} />
              </div>
              <div>
                <h3 className="text-xl font-black">Sincronização de Banco de Dados</h3>
                <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Corrige erros de 'Schema Cache' e cria colunas em falta</p>
              </div>
            </div>

            <div className="bg-slate-800 rounded-[2rem] p-6 mb-8 relative group border border-slate-700">
              <pre className="text-[10px] text-blue-300 font-mono overflow-x-auto max-h-60 custom-scrollbar leading-relaxed">
                {sqlSchema}
              </pre>
              <button 
                onClick={copySql}
                className="absolute top-4 right-4 bg-blue-600 hover:bg-blue-700 text-white p-3 rounded-xl transition-all flex items-center gap-2 text-[10px] font-black uppercase tracking-widest shadow-xl active:scale-95"
              >
                {copied ? <Check size={14} /> : <Copy size={14} />}
                {copied ? 'Copiado!' : 'Copiar Script de Reparação'}
              </button>
            </div>

            <div className="flex items-start gap-4 p-6 bg-blue-600/10 rounded-3xl border border-blue-600/20">
              <AlertCircle className="text-blue-400 shrink-0 mt-1" size={24} />
              <div className="space-y-3">
                <p className="text-xs text-blue-100 font-bold leading-relaxed uppercase">
                  Como corrigir o erro de Tabela Não Encontrada:
                </p>
                <ol className="text-[11px] text-slate-300 list-decimal ml-4 space-y-2 font-medium">
                  <li>Clique no botão acima para copiar o script de rearação.</li>
                  <li>No seu painel do <strong>Supabase</strong>, vá ao <strong>SQL Editor</strong>.</li>
                  <li>Cole o código e clique em <strong>Run</strong>.</li>
                  <li>Se o erro persistir, vá em <strong>Settings -> API</strong> e clique em <strong>"Reload PostgREST"</strong> para limpar o cache manual.</li>
                </ol>
              </div>
            </div>
          </div>

          {/* User Table */}
          <div className="bg-white rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden">
            <div className="p-8 border-b border-slate-50 flex items-center gap-4">
              <Search className="text-slate-400" size={18} />
              <input 
                value={searchTerm}
                onChange={e => setSearchTerm(e.target.value)}
