                <button 
                  disabled={saving}
                  type="submit" 
                  className="w-full py-6 bg-slate-900 text-white rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-xl flex items-center justify-center gap-3 hover:bg-blue-600 transition-all active:scale-95"
                >
                  {saving ? <Loader2 className="animate-spin" size={18} /> : <><Save size={18} /> Aplicar Alterações</>}
