  const handleAddRole = async () => {
    if (!newRoleName) return;
    const { error } = await supabase.from('roles').insert([{ name: newRoleName }]);
    if (!error) {
      setNewRoleName('');
      fetchRoles();
    } else {
      alert("Erro ao adicionar cargo: " + error.message);
    }
  };

  const handleDeleteRole = async (roleName: string) => {
    if (confirm(`Eliminar o cargo "${roleName}"? Isso não afetará usuários já atribuídos, mas o cargo não estará mais disponível para seleção.`)) {
      const { error } = await supabase.from('roles').delete().eq('name', roleName);
      if (!error) fetchRoles();
    }
  };

  const handleRenameRole = async () => {
    if (!editingRole || !editingRole.new) return;
    const { error } = await supabase.from('roles').update({ name: editingRole.new }).eq('name', editingRole.old);
    if (!error) {
      setEditingRole(null);
      fetchRoles();
    }
  };

  const togglePermission = (permId: string) => {
    if (!editingUser) return;
    const current = editingUser.permissions || [];
    const newPerms = current.includes(permId) 
      ? current.filter(p => p !== permId) 
      : [...current, permId];
    setEditingUser({ ...editingUser, permissions: newPerms });
  };

  const groupByCategory = (perms: PermissionDefinition[]) => {
    return perms.reduce((acc, curr) => {
      if (!acc[curr.category]) acc[curr.category] = [];
      acc[curr.category].push(curr);
      return acc;
    }, {} as Record<string, PermissionDefinition[]>);
  };

  const groupedPermissions = groupByCategory(GRANULAR_PERMISSIONS);

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-12">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tight">Administração TI</h1>
          <p className="text-slate-500 font-medium">Controlo de acessos, cargos e infraestrutura Cloud.</p>
        </div>
        <div className="flex items-center gap-3">
           <button onClick={() => { fetchUsers(); fetchRoles(); }} className="p-4 bg-white text-slate-400 hover:text-blue-600 rounded-3xl shadow-sm border border-slate-100 transition-all active:scale-95">
             <RefreshCw size={20} className={loading ? 'animate-spin' : ''} />
           </button>
           <div className="px-6 py-2.5 bg-indigo-600 text-white rounded-full text-[10px] font-black uppercase tracking-widest flex items-center gap-2 shadow-xl shadow-indigo-500/20">
             <Fingerprint size={16} /> Hub Autenticado
           </div>
        </div>
      </div>

      {/* SQL Script Info Box */}
      <div className="bg-slate-900 rounded-[3.5rem] p-10 text-white shadow-2xl relative overflow-hidden mb-8">
        <div className="flex items-center gap-4 mb-6">
          <Database size={24} className="text-indigo-400" />
          <div>
            <h3 className="text-xl font-black">Sincronização de Cargos</h3>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Execute este SQL para habilitar a gestão dinâmica de cargos</p>
          </div>
        </div>
        <pre className="bg-slate-800 p-6 rounded-3xl text-[10px] text-indigo-300 font-mono overflow-x-auto mb-6 max-h-40 custom-scrollbar">
          {sqlSchema}
        </pre>
        <button 
          onClick={() => { navigator.clipboard.writeText(sqlSchema); setCopied(true); setTimeout(() => setCopied(false), 2000); }}
          className="flex items-center gap-2 px-6 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all"
        >
          {copied ? <Check size={14} /> : <Copy size={14} />} {copied ? 'Copiado!' : 'Copiar Script SQL'}
        </button>
      </div>

      <div className="bg-white rounded-[3.5rem] border border-slate-100 shadow-sm overflow-hidden">
        <div className="p-8 border-b border-slate-50 flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div className="relative flex-1 max-w-md">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
              placeholder="Pesquisar staff por nome ou e-mail..." 
              className="w-full pl-12 pr-4 py-4 bg-slate-50 rounded-2xl border-none font-bold text-sm outline-none placeholder:text-slate-300"
            />
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50/50 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                <th className="px-10 py-6">Staff Monte</th>
                <th className="px-10 py-6">Cargo Oficial</th>
                <th className="px-10 py-6">Privilégios Ativos</th>
                <th className="px-10 py-6 text-right">Acções</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {loading ? (
                <tr><td colSpan={4} className="py-24 text-center"><Loader2 className="animate-spin mx-auto text-blue-600" size={32} /></td></tr>
              ) : users.filter(u => u.name.toLowerCase().includes(searchTerm.toLowerCase())).map(user => (
                <tr key={user.id} className="hover:bg-slate-50/50 transition-all group">
                  <td className="px-10 py-8">
                    <div className="flex items-center gap-5">
                      <div className="relative">
                        <img src={user.avatar} className="w-12 h-12 rounded-[1.2rem] object-cover ring-2 ring-slate-100" />
                        <div className="absolute -bottom-1 -right-1 w-4 h-4 bg-green-500 border-2 border-white rounded-full"></div>
                      </div>
                      <div>
                        <p className="text-sm font-black text-slate-900">{user.name}</p>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tight">{user.email}</p>
                      </div>
                    </div>
                  </td>
                  <td className="px-10 py-8">
                    <span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-lg uppercase tracking-wider border border-indigo-100">{user.role}</span>
                  </td>
                  <td className="px-10 py-8">
                    <div className="flex flex-wrap gap-1.5 max-w-[250px]">
                      {(user.permissions || []).length > 0 ? (
                        user.permissions?.slice(0, 3).map(p => (
                          <span key={p} className="text-[8px] font-black bg-slate-100 text-slate-500 px-2 py-0.5 rounded uppercase">{p.split('.')[1] || p}</span>
                        ))
                      ) : (
                        <span className="text-[8px] font-black text-slate-300 uppercase italic">Nenhum</span>
                      )}
                    </div>
                  </td>
                  <td className="px-10 py-8 text-right">
                    <button 
                      onClick={() => setEditingUser(user)}
                      className="p-3 bg-white text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 border border-slate-100 rounded-2xl transition-all shadow-sm hover:shadow-indigo-500/10 active:scale-90"
                    >
                      <UserCog size={22} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* MODAL DE PERMISSÕES GRANULARES */}
      {editingUser && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white rounded-[4rem] p-12 max-w-4xl w-full shadow-2xl relative overflow-y-auto max-h-[90vh] border border-white/20">
            <button 
              onClick={() => setEditingUser(null)}
              className="absolute top-10 right-10 text-slate-400 p-2 hover:bg-slate-50 rounded-xl transition-all"
            >
              <X size={24} />
            </button>

            <div className="flex items-center gap-5 mb-12">
               <div className="w-16 h-16 bg-indigo-600 rounded-[1.8rem] flex items-center justify-center text-white shadow-2xl shadow-indigo-500/30">
                  <Shield size={32} />
               </div>
               <div>
                  <h2 className="text-3xl font-black text-slate-900 tracking-tight">Configurar Privilégios</h2>
                  <p className="text-sm font-bold text-slate-400 uppercase tracking-widest mt-1">Ajuste de acesso para: <span className="text-indigo-600">{editingUser.name}</span></p>
               </div>
            </div>

            <form onSubmit={handleUpdatePermissions} className="space-y-12">
              {/* Função ERP com Botão Gerir Cargos */}
              <div className="bg-slate-50 p-8 rounded-[2.5rem] border border-slate-100">
                <div className="flex items-center justify-between mb-3">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 block">Função de Acesso Master</label>
                  <button 
                    type="button" 
                    onClick={() => setShowRolesModal(true)}
                    className="flex items-center gap-2 text-[10px] font-black text-indigo-600 uppercase hover:text-indigo-700 transition-colors"
                  >
                    <Settings2 size={14} /> Gerir Cargos
                  </button>
                </div>
                <select 
                  value={editingUser.role}
                  onChange={e => setEditingUser({...editingUser, role: e.target.value as any})}
                  className="w-full bg-white border border-slate-200 rounded-2xl p-4 text-sm font-bold text-slate-900 outline-none focus:ring-4 focus:ring-indigo-100 transition-all appearance-none cursor-pointer"
                >
                  {roles.map(r => <option key={r} value={r}>{r}</option>)}
                </select>
              </div>

              {/* Grid de Permissões Agrupadas */}
              <div className="space-y-10">
                {Object.entries(groupedPermissions).map(([category, perms]) => (
                  <div key={category} className="space-y-4">
                    <div className="flex items-center gap-3 px-2">
                       <div className="w-2 h-2 bg-indigo-600 rounded-full"></div>
                       <h3 className="text-xs font-black uppercase tracking-widest text-slate-900">{category}</h3>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                      {perms.map(p => {
                        const isActive = editingUser.permissions?.includes(p.id);
                        return (
                          <button
                            key={p.id}
                            type="button"
                            onClick={() => togglePermission(p.id)}
                            className={`flex flex-col p-5 rounded-3xl border-2 text-left transition-all relative overflow-hidden group ${
                              isActive 
                              ? 'bg-indigo-600 border-indigo-600 text-white shadow-xl shadow-indigo-500/20' 
                              : 'bg-white border-slate-100 text-slate-500 hover:border-indigo-200'
                            }`}
                          >
                            <div className="flex items-center justify-between mb-3">
                               <div className={`p-2 rounded-xl ${isActive ? 'bg-white/10' : 'bg-slate-50 group-hover:bg-indigo-50 text-indigo-600'}`}>
                                 {p.icon}
                               </div>
                               {isActive && <CheckCircle2 size={16} className="text-indigo-200" />}
                            </div>
                            <span className="text-[11px] font-black uppercase tracking-tight mb-1">{p.label}</span>
                            <span className={`text-[9px] font-medium leading-tight ${isActive ? 'text-indigo-100' : 'text-slate-400'}`}>
                               {p.description}
                            </span>
                          </button>
                        );
                      })}
                    </div>
                  </div>
                ))}
              </div>

              {msg && (
                <div className={`p-6 rounded-3xl text-[10px] font-black uppercase text-center animate-in zoom-in slide-in-from-bottom-4 ${msg.type === 'success' ? 'bg-green-50 text-green-600 border border-green-100' : 'bg-red-50 text-red-600 border border-red-100'}`}>
                  {msg.text}
                </div>
              )}

              <div className="flex flex-col sm:flex-row gap-4 pt-6 border-t border-slate-50">
                <button 
                  disabled={saving}
                  type="submit" 
                  className="flex-1 py-6 bg-slate-900 text-white rounded-[2rem] font-black text-xs uppercase tracking-widest shadow-2xl hover:bg-indigo-600 transition-all active:scale-95 flex items-center justify-center gap-3 disabled:opacity-50"
                >
                  {saving ? <Loader2 className="animate-spin" size={20} /> : <><Save size={20} /> Sincronizar Privilégios Cloud</>}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* MODAL DE GESTÃO DE CARGOS */}
      {showRolesModal && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-xl animate-in fade-in duration-200">
          <div className="bg-white rounded-[3rem] p-10 max-w-xl w-full shadow-2xl relative overflow-hidden">
            <button 
              onClick={() => setShowRolesModal(false)}
              className="absolute top-8 right-8 text-slate-400 hover:text-slate-900 transition-colors"
            >
              <X size={24} />
            </button>

            <div className="flex items-center gap-4 mb-8">
              <div className="w-12 h-12 bg-indigo-100 rounded-2xl flex items-center justify-center text-indigo-600">
                <Settings2 size={24} />
              </div>
              <div>
                <h3 className="text-xl font-black text-slate-900">Gestão de Cargos</h3>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Personalize os papéis de acesso do ERP</p>
              </div>
            </div>

            {/* Adicionar Novo Cargo */}
            <div className="flex gap-2 mb-8">
              <input 
                value={newRoleName}
                onChange={e => setNewRoleName(e.target.value)}
                placeholder="Ex: Supervisor de Obras"
                className="flex-1 bg-slate-50 border border-slate-100 rounded-2xl px-5 py-4 font-bold text-sm outline-none focus:ring-2 focus:ring-indigo-600"
              />
              <button 
                onClick={handleAddRole}
                className="bg-indigo-600 text-white p-4 rounded-2xl hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-500/20 active:scale-95"
              >
                <Plus size={20} />
              </button>
            </div>

            {/* Lista de Cargos */}
            <div className="space-y-3 max-h-80 overflow-y-auto pr-2 custom-scrollbar">
              {roles.map(role => (
                <div key={role} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100 group">
                  {editingRole?.old === role ? (
                    <div className="flex-1 flex gap-2">
                      <input 
                        autoFocus
                        value={editingRole.new}
                        onChange={e => setEditingRole({...editingRole, new: e.target.value})}
                        className="flex-1 bg-white border border-indigo-200 rounded-xl px-3 py-1 font-bold text-xs"
                      />
                      <button onClick={handleRenameRole} className="text-green-600 hover:scale-110 transition-transform"><Check size={16}/></button>
                      <button onClick={() => setEditingRole(null)} className="text-red-600 hover:scale-110 transition-transform"><X size={16}/></button>
                    </div>
                  ) : (
                    <>
                      <span className="text-xs font-black text-slate-700 uppercase tracking-tight">{role}</span>
                      <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button 
                          onClick={() => setEditingRole({old: role, new: role})}
                          className="p-1.5 text-slate-400 hover:text-indigo-600 transition-colors"
                        >
                          <Edit size={14} />
                        </button>
                        <button 
                          onClick={() => handleDeleteRole(role)}
                          className="p-1.5 text-slate-400 hover:text-red-500 transition-colors"
                        >
                          <Trash2 size={14} />
                        </button>
                      </div>
                    </>
                  )}
                </div>
              ))}
            </div>

            <button 
              onClick={() => setShowRolesModal(false)}
              className="w-full mt-8 py-4 bg-slate-900 text-white rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest hover:bg-indigo-600 transition-all"
            >
              Concluir Alterações
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminView;

import React, { useState, useEffect } from 'react';
import { 
  Shield, Key, Lock, Settings, UserCog, Save, 
  CheckCircle2, AlertCircle, Loader2, Search,
  ShieldAlert, Fingerprint, Zap, Database, Copy, Check, X,
  RefreshCw, Eye, Edit, Trash2, LayoutGrid, Briefcase, 
  Wallet, Users as UsersIcon, Terminal, Plus, Settings2
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { UserRole, Employee } from '../types';

interface PermissionDefinition {
  id: string;
  label: string;
  category: 'Financeiro' | 'RH' | 'Operações' | 'Sistema';
  description: string;
  icon: React.ReactNode;
}

const GRANULAR_PERMISSIONS: PermissionDefinition[] = [
  // Financeiro
  { id: 'finance.view', label: 'Visualizar Financeiro', category: 'Financeiro', description: 'Acesso a relatórios e balanços.', icon: <Eye size={14} /> },
  { id: 'finance.edit', label: 'Lançamentos Financeiros', category: 'Financeiro', description: 'Criar receitas e despesas.', icon: <Edit size={14} /> },
  { id: 'finance.delete', label: 'Eliminar Registos', category: 'Financeiro', description: 'Remover transações do sistema.', icon: <Trash2 size={14} /> },

  // RH & Staff
  { id: 'hr.view', label: 'Ver Staff', category: 'RH', description: 'Visualizar lista de colaboradores.', icon: <Eye size={14} /> },
  { id: 'hr.manage', label: 'Gerir RH', category: 'RH', description: 'Contratar e editar dados de staff.', icon: <UsersIcon size={14} /> },

  // Operações & Projetos
  { id: 'projects.manage', label: 'Gerir Obras', category: 'Operações', description: 'Criar e editar projetos e obras.', icon: <Briefcase size={14} /> },
  { id: 'catalog.edit', label: 'Editar Catálogo', category: 'Operações', description: 'Adicionar e remover imóveis.', icon: <LayoutGrid size={14} /> },

  // Sistema & TI
  { id: 'admin.access', label: 'Acesso Admin', category: 'Sistema', description: 'Acesso total ao painel de TI.', icon: <Shield size={14} /> },
  { id: 'system.logs', label: 'Ver Auditoria', category: 'Sistema', description: 'Visualizar logs de alterações.', icon: <Terminal size={14} /> },
];

const AdminView: React.FC = () => {
  const [users, setUsers] = useState<Employee[]>([]);
  const [roles, setRoles] = useState<string[]>(Object.values(UserRole));
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [editingUser, setEditingUser] = useState<Employee | null>(null);
  const [showRolesModal, setShowRolesModal] = useState(false);
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState<{type: 'success' | 'error', text: string} | null>(null);
  const [copied, setCopied] = useState(false);

  // Role Manager state
  const [newRoleName, setNewRoleName] = useState('');
  const [editingRole, setEditingRole] = useState<{old: string, new: string} | null>(null);

  const sqlSchema = `-- SCRIPT DE ATUALIZAÇÃO GLOBAL (CARGOS, PERMISSÕES & SERVIÇOS)
-- 1. Tabela de Cargos
CREATE TABLE IF NOT EXISTS public.roles (
    id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
    name text UNIQUE NOT NULL,
    created_at timestamptz DEFAULT now()
);

-- Inserir cargos padrão se não existirem
INSERT INTO public.roles (name) 
VALUES 
('Administrador de Sistema'),
('Director Executivo (CEO)'),
('Gestor Geral Operacional'),
('Director Financeiro'),
('Gestor de Recursos Humanos'),
('Consultor Imobiliário'),
('Colaborador Geral')
ON CONFLICT (name) DO NOTHING;

-- 2. Tabela de Serviços
CREATE TABLE IF NOT EXISTS public.services (
    id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
    title text NOT NULL,
    description text,
    icon text,
    created_at timestamptz DEFAULT now()
);

-- 3. Segurança e Políticas
ALTER TABLE public.roles ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "Public Roles Access" ON public.roles;
CREATE POLICY "Public Roles Access" ON public.roles FOR ALL USING (true);

ALTER TABLE public.services ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "Public Services Access" ON public.services;
CREATE POLICY "Public Services Access" ON public.services FOR ALL USING (true);

-- Notificar recarregamento de schema
NOTIFY pgrst, 'reload schema';
`;

  useEffect(() => {
    fetchUsers();
    fetchRoles();
  }, []);

  async function fetchRoles() {
    try {
      const { data, error } = await supabase.from('roles').select('name').order('name');
      if (!error && data) {
        setRoles(data.map(r => r.name));
      }
    } catch (e) {
      console.warn("Tabela de cargos não encontrada. Usando padrão do enum.");
    }
  }

  async function fetchUsers() {
    setLoading(true);
    try {
      const { data, error } = await supabase.from('employees').select('*').order('name');
      if (!error) setUsers(data || []);
    } catch (e) {
      console.warn("Erro ao buscar usuários");
    } finally {
      setLoading(false);
    }
  }

  const handleUpdatePermissions = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingUser) return;

    setSaving(true);
    const { error } = await supabase
      .from('employees')
      .update({ 
        role: editingUser.role,
        permissions: editingUser.permissions || []
      })
      .eq('id', editingUser.id);

    if (error) {
      setMsg({ type: 'error', text: 'Erro ao sincronizar: ' + error.message });
    } else {
      setMsg({ type: 'success', text: 'Privilégios atualizados com sucesso!' });
      fetchUsers();
      setTimeout(() => setEditingUser(null), 1000);
    }
    setSaving(false);
    setTimeout(() => setMsg(null), 3000);
  };

  const handleAddRole = async () => {
    if (!newRoleName) return;
    const { error } = await supabase.from('roles').insert([{ name: newRoleName }]);
    if (!error) {
      setNewRoleName('');
      fetchRoles();
    } else {
      alert("Erro ao adicionar cargo: " + error.message);
    }
  };

  const handleDeleteRole = async (roleName: string) => {
    if (confirm(`Eliminar o cargo "${roleName}"? Isso não afetará usuários já atribuídos, mas o cargo não estará mais disponível para seleção.`)) {
      const { error } = await supabase.from('roles').delete().eq('name', roleName);
      if (!error) fetchRoles();
    }
  };

  const handleRenameRole = async () => {
    if (!editingRole || !editingRole.new) return;
    const { error } = await supabase.from('roles').update({ name: editingRole.new }).eq('name', editingRole.old);
    if (!error) {
      setEditingRole(null);
      fetchRoles();
    }
  };

  const togglePermission = (permId: string) => {
    if (!editingUser) return;
    const current = editingUser.permissions || [];
    const newPerms = current.includes(permId) 
      ? current.filter(p => p !== permId) 
      : [...current, permId];
    setEditingUser({ ...editingUser, permissions: newPerms });
  };

  const groupByCategory = (perms: PermissionDefinition[]) => {
    return perms.reduce((acc, curr) => {
      if (!acc[curr.category]) acc[curr.category] = [];
      acc[curr.category].push(curr);
      return acc;
    }, {} as Record<string, PermissionDefinition[]>);
  };

  const groupedPermissions = groupByCategory(GRANULAR_PERMISSIONS);

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-12">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tight">Administração TI</h1>
          <p className="text-slate-500 font-medium">Controlo de acessos, cargos e infraestrutura Cloud.</p>
        </div>
        <div className="flex items-center gap-3">
           <button onClick={() => { fetchUsers(); fetchRoles(); }} className="p-4 bg-white text-slate-400 hover:text-blue-600 rounded-3xl shadow-sm border border-slate-100 transition-all active:scale-95">
             <RefreshCw size={20} className={loading ? 'animate-spin' : ''} />
           </button>
