  const [errorMessage, setErrorMessage] = useState<string>('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setStatus('loading');
    setErrorMessage('');

    // Validação de nome
    if (!formData.name.trim()) {
      setStatus('error');
      setErrorMessage('O campo Nome é obrigatório para processar o seu pedido.');
      return;
    }

    try {
      const { error } = await supabase
        .from('contact_requests')
        .insert([
          { 
            name: formData.name.trim(), 
            email: formData.email, 
            subject: formData.subject, 
            message: formData.message,
            destination_email: 'monteimobiliario@gmail.com',
            created_at: new Date().toISOString()
          }
        ]);

      if (error) {
        // Se o Supabase retornar erro, garantimos que pegamos apenas a mensagem (string)
        const msg = error.message || 'Erro desconhecido no banco de dados.';
        if (msg.includes('contact_requests') && msg.includes('not found')) {
          throw new Error('A base de dados de contactos ainda não foi criada no Supabase. Por favor, crie a tabela "contact_requests" no seu painel Supabase.');
        }
        throw new Error(msg);
      }

      setStatus('success');
      setFormData({ name: '', email: '', subject: 'Interesse em Imóvel', message: '' });

      setTimeout(() => setStatus('idle'), 5000);
    } catch (err: any) {
      console.error("Submission Error:", err);
      setStatus('error');
      // Garantir que errorMessage receba SEMPRE uma string, nunca o objeto de erro bruto
      setErrorMessage(err instanceof Error ? err.message : String(err));
