              </div>
            </div>

            <div className="flex gap-6 group">
              <div className="w-14 h-14 bg-blue-50 rounded-2xl flex items-center justify-center text-blue-600 shrink-0 group-hover:bg-blue-600 group-hover:text-white transition-all duration-300 shadow-sm">
                <Mail size={24} />
              </div>
              <div>
                <h4 className="font-black text-slate-900 mb-1">Email Direto</h4>
                <p className="text-slate-600 text-lg font-bold">monteimobiliario@gmail.com</p>
              </div>
            </div>

            <div className="flex gap-6 group">
              <div className="w-14 h-14 bg-blue-50 rounded-2xl flex items-center justify-center text-blue-600 shrink-0 group-hover:bg-blue-600 group-hover:text-white transition-all duration-300 shadow-sm">
                <MapPin size={24} />
