import React, { useState, useEffect } from 'react';
import { 
  Plus, Users, DollarSign, UserCheck, AlertCircle, Clock, 
  Loader2, X, CheckCircle, Trash2, LayoutDashboard,
  Lock, Save, UserCog, Mail, Phone, CreditCard, Calendar as CalendarIcon, FileText,
  BadgeCheck, Wallet
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { Employee, UserRole } from '../types';

const HRView: React.FC = () => {
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAddModal, setShowAddModal] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const [newEmp, setNewEmp] = useState<Partial<Employee>>({
    name: '', 
    role: UserRole.EMPLOYEE, 
    department: 'Vendas', 
    salary: 0, 
    email: '', 
    phone: '',
    document_type: 'BI',
    document_number: '',
    document_expiry: '',
    payment_method: 'M-Pesa',
    contract_start: ''
  });

  useEffect(() => {
    fetchData();
  }, []);

  async function fetchData() {
    setLoading(true);
    try {
      const { data, error: sbError } = await supabase.from('employees').select('*').order('name');
      if (sbError) {
        if (sbError.message.includes('schema cache') || sbError.message.includes('not found')) {
           setError('⚠️ Erro de Cache: A tabela ou colunas ainda não foram reconhecidas. Vá à aba "Administração TI" e siga o passo de Sincronização.');
        } else {
           setError(sbError.message);
        }
      }
      setEmployees(data || []);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }

  const handleAddEmployee = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    // Validações Obrigatórias
    if (!newEmp.name?.trim()) {
      setError('O nome do colaborador é obrigatório.');
      return;
    }

    if (!newEmp.document_number?.trim()) {
      setError('O número do documento é obrigatório.');
      return;
    }

    // Validar se o documento contém ao menos alguns números (campo "numérico" solicitado)
    const hasNumbers = /\d/.test(newEmp.document_number);
    if (!hasNumbers) {
      setError('O número do documento deve conter algarismos numéricos.');
      return;
    }

    if (!newEmp.document_expiry) {
      setError('A data de validade do documento é obrigatória.');
      return;
    }

    if (!newEmp.contract_start) {
      setError('A data de início do contrato é obrigatória.');
      return;
    }

    // Verificar se a validade do documento não expirou
    const today = new Date().toISOString().split('T')[0];
    if (newEmp.document_expiry < today) {
      setError('O documento de identidade indicado já expirou.');
      return;
    }

    const payload = {
      name: newEmp.name,
      email: newEmp.email,
      phone: newEmp.phone,
      role: newEmp.role,
      department: newEmp.department,
      salary: Number(newEmp.salary),
      avatar: `https://picsum.photos/seed/${newEmp.name}/100`,
      status: 'Ativo',
      join_date: newEmp.contract_start, // Sincroniza join_date com o início do contrato
      document_type: newEmp.document_type || 'BI',
      document_number: newEmp.document_number,
      document_expiry: newEmp.document_expiry,
      payment_method: newEmp.payment_method || 'M-Pesa',
      contract_start: newEmp.contract_start
    };

    const { error: sbError } = await supabase.from('employees').insert([payload]);

    if (sbError) {
      if (sbError.message.includes('schema cache')) {
        setError('O servidor ainda não reconheceu as novas colunas. Execute o script SQL em Administração TI.');
      } else {
        setError('Erro ao salvar no banco de dados: ' + sbError.message);
      }
    } else {
      setShowAddModal(false);
      setNewEmp({ 
        name: '', role: UserRole.EMPLOYEE, department: 'Vendas', salary: 0, email: '', phone: '',
        document_type: 'BI', document_number: '', document_expiry: '', payment_method: 'M-Pesa', contract_start: ''
      });
      fetchData();
    }
  };

  const removeEmployee = async (id: string) => {
    if (confirm('Deseja rescindir o contrato deste colaborador?')) {
      const { error } = await supabase.from('employees').delete().eq('id', id);
      if (!error) fetchData();
    }
  };

  if (loading) return <div className="flex justify-center py-20"><Loader2 className="animate-spin text-blue-600" size={40} /></div>;

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-4">
           <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-indigo-500/20">
             <Users size={24} />
           </div>
           <div>
             <h1 className="text-3xl font-black text-slate-900 tracking-tight">Gestão de Staff</h1>
             <p className="text-slate-500 font-medium">Controlo de capital humano e documentação.</p>
           </div>
        </div>
        <button onClick={() => { setError(null); setShowAddModal(true); }} className="flex items-center gap-2 px-8 py-4 bg-indigo-600 text-white rounded-[2rem] font-black text-sm shadow-xl hover:bg-indigo-700 transition-all active:scale-95">
          <Plus size={20} /> Novo Colaborador
        </button>
      </div>

      {error && (
        <div className="p-5 bg-amber-50 border-l-4 border-amber-500 rounded-2xl flex items-center gap-4 text-amber-800 text-xs font-bold shadow-sm animate-shake">
          <AlertCircle size={24} className="shrink-0" /> 
          <div>
            <p className="uppercase mb-1">Validação do Sistema</p>
            <p className="opacity-80 font-medium">{error}</p>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
        {employees.length === 0 ? (
          <div className="col-span-full py-24 text-center bg-white rounded-[3rem] border-2 border-dashed border-slate-100">
            <Users size={48} className="mx-auto text-slate-200 mb-4" />
            <p className="text-slate-400 font-bold italic">Nenhum colaborador registado no momento.</p>
          </div>
        ) : employees.map(emp => (
          <div key={emp.id} className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm relative group hover:shadow-2xl transition-all border-b-4 hover:border-b-indigo-500">
            <button onClick={() => removeEmployee(emp.id)} className="absolute top-8 right-8 p-2 text-slate-200 hover:text-red-500 transition-colors">
              <Trash2 size={18} />
            </button>
            <div className="relative inline-block mb-6">
              <img src={emp.avatar} className="w-24 h-24 rounded-[2.5rem] object-cover ring-4 ring-slate-50 shadow-sm" alt={emp.name} />
              <div className="absolute -bottom-1 -right-1 bg-green-500 w-6 h-6 rounded-full border-4 border-white"></div>
            </div>

            <h3 className="text-lg font-black text-slate-900 mb-1">{emp.name}</h3>
            <p className="text-[10px] font-black text-indigo-600 uppercase tracking-widest mb-6">{emp.role}</p>

            <div className="space-y-4 mb-8">
              <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase">
                <div className="w-6 h-6 bg-slate-50 rounded-lg flex items-center justify-center"><Phone size={12} className="text-slate-400"/></div>
                {emp.phone}
              </div>
              <div className="flex items-center gap-3 text-[10px] text-slate-500 font-bold uppercase">
                <div className="w-6 h-6 bg-slate-50 rounded-lg flex items-center justify-center"><Wallet size={12} className="text-slate-400"/></div>
                {emp.payment_method || 'Não definido'}
              </div>
            </div>

            <div className="pt-6 border-t border-slate-50 flex justify-between items-center">
              <div>
                <p className="text-[9px] font-black text-slate-400 uppercase mb-1">Salário</p>
                <p className="text-sm font-black text-slate-900">{Number(emp.salary).toLocaleString()} MT</p>
              </div>
              <div className="text-right">
                 <p className="text-[9px] font-black text-slate-400 uppercase mb-1">Início</p>
                 <p className="text-[10px] font-bold text-slate-900 uppercase tracking-tighter">{emp.contract_start || emp.join_date}</p>
              </div>
            </div>
          </div>
        ))}
      </div>

      {showAddModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-10 max-w-3xl w-full shadow-2xl relative overflow-y-auto max-h-[90vh] border border-white/20">
            <button onClick={() => setShowAddModal(false)} className="absolute top-10 right-10 text-slate-400 p-2 hover:bg-slate-50 rounded-xl transition-all"><X size={24} /></button>

            <div className="flex items-center gap-4 mb-10">
               <div className="w-14 h-14 bg-indigo-600 rounded-3xl flex items-center justify-center text-white shadow-xl shadow-indigo-500/30">
                  <UserCog size={28} />
               </div>
               <div>
                  <h2 className="text-3xl font-black text-slate-900 tracking-tight">Registo de Colaborador</h2>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1 flex items-center gap-2">
                    <BadgeCheck size={14} className="text-green-500" /> Sincronização em Tempo Real
                  </p>
               </div>
            </div>

            <form onSubmit={handleAddEmployee} className="space-y-10">
              {/* Seção 1: Essencial */}
              <div className="space-y-6">
                <div className="flex items-center gap-2 text-slate-900">
                   <div className="w-1 h-4 bg-indigo-600 rounded-full"></div>
                   <h3 className="text-xs font-black uppercase tracking-widest">Informação de Contacto</h3>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome Completo *</label>
                    <input required placeholder="Ex: Adamo Francisco" value={newEmp.name} onChange={e => setNewEmp({...newEmp, name: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100 focus:ring-2 focus:ring-indigo-600 transition-all" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">E-mail Corporativo *</label>
                    <input required type="email" placeholder="nome@monte.co.mz" value={newEmp.email} onChange={e => setNewEmp({...newEmp, email: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100 focus:ring-2 focus:ring-indigo-600 transition-all" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Contacto Móvel *</label>
                    <input required placeholder="+258 8X XXX XXXX" value={newEmp.phone} onChange={e => setNewEmp({...newEmp, phone: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100 focus:ring-2 focus:ring-indigo-600 transition-all" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Remuneração Base (MT)</label>
                    <input type="number" placeholder="0.00 MT" value={newEmp.salary} onChange={e => setNewEmp({...newEmp, salary: Number(e.target.value)})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100 focus:ring-2 focus:ring-indigo-600 transition-all" />
                  </div>
                </div>
              </div>

              {/* Seção 2: Documentação */}
              <div className="space-y-6">
                <div className="flex items-center gap-2 text-slate-900">
                   <div className="w-1 h-4 bg-blue-500 rounded-full"></div>
                   <h3 className="text-xs font-black uppercase tracking-widest">Documentação (BI/DIRE)</h3>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-5">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Tipo de Documento</label>
                    <select value={newEmp.document_type} onChange={e => setNewEmp({...newEmp, document_type: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100">
                      <option value="BI">Bilhete de Identidade (BI)</option>
                      <option value="Passaporte">Passaporte</option>
                      <option value="DIRE">DIRE</option>
                      <option value="Outro">Outro</option>
                    </select>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Número do Documento *</label>
                    <input required placeholder="Ex: 0101010101A" value={newEmp.document_number} onChange={e => setNewEmp({...newEmp, document_number: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100 focus:ring-2 focus:ring-blue-500" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Data de Validade *</label>
                    <input required type="date" value={newEmp.document_expiry} onChange={e => setNewEmp({...newEmp, document_expiry: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100 text-sm focus:ring-2 focus:ring-blue-500" />
                  </div>
                </div>
              </div>

              {/* Seção 3: Carteiras & Contrato */}
              <div className="space-y-6">
                <div className="flex items-center gap-2 text-slate-900">
                   <div className="w-1 h-4 bg-emerald-500 rounded-full"></div>
                   <h3 className="text-xs font-black uppercase tracking-widest">Financeiro & Contrato</h3>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-5">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Cargo ERP</label>
                    <select value={newEmp.role} onChange={e => setNewEmp({...newEmp, role: e.target.value as any})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100">
                      {Object.values(UserRole).map(r => <option key={r} value={r}>{r}</option>)}
                    </select>
                  </div>

                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Método de Recebimento</label>
                    <select value={newEmp.payment_method} onChange={e => setNewEmp({...newEmp, payment_method: e.target.value as any})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100">
                      <option value="M-Pesa">Carteira M-Pesa</option>
                      <option value="e-Mola">Carteira e-Mola</option>
                      <option value="mKesh">Carteira mKesh</option>
                      <option value="Banco">Transferência Bancária</option>
                    </select>
                  </div>

                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Início do Contrato *</label>
                    <input required type="date" value={newEmp.contract_start} onChange={e => setNewEmp({...newEmp, contract_start: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold outline-none border border-slate-100 text-sm focus:ring-2 focus:ring-emerald-500" />
                  </div>
                </div>
              </div>

              <div className="pt-6">
                <button type="submit" className="w-full py-6 bg-indigo-600 text-white font-black rounded-[2.5rem] shadow-2xl shadow-indigo-500/30 hover:bg-indigo-700 hover:scale-[1.01] transition-all flex items-center justify-center gap-4">
                  <Save size={24} /> Concluir Cadastro de Staff
                </button>
                <p className="text-[9px] text-center text-slate-400 font-bold uppercase mt-6 tracking-widest leading-relaxed">
                  Todos os campos marcados com (*) são de preenchimento obrigatório para segurança jurídica.
                </p>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default HRView;

import React, { useState, useEffect } from 'react';
import { 
  Shield, Key, Lock, Settings, UserCog, Save, 
  CheckCircle2, AlertCircle, Loader2, Search,
  ShieldAlert, Fingerprint, Zap, Database, Copy, Check, X,
  RefreshCw, Eye, Edit, Trash2, LayoutGrid, Briefcase, 
  Wallet, Users as UsersIcon, Terminal, Plus, Settings2
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { UserRole, Employee } from '../types';

interface PermissionDefinition {
  id: string;
  label: string;
  category: 'Financeiro' | 'RH' | 'Operações' | 'Sistema';
  description: string;
  icon: React.ReactNode;
}

const GRANULAR_PERMISSIONS: PermissionDefinition[] = [
  // Financeiro
  { id: 'finance.view', label: 'Visualizar Financeiro', category: 'Financeiro', description: 'Acesso a relatórios e balanços.', icon: <Eye size={14} /> },
  { id: 'finance.edit', label: 'Lançamentos Financeiros', category: 'Financeiro', description: 'Criar receitas e despesas.', icon: <Edit size={14} /> },
  { id: 'finance.delete', label: 'Eliminar Registos', category: 'Financeiro', description: 'Remover transações do sistema.', icon: <Trash2 size={14} /> },

  // RH & Staff
  { id: 'hr.view', label: 'Ver Staff', category: 'RH', description: 'Visualizar lista de colaboradores.', icon: <Eye size={14} /> },
  { id: 'hr.manage', label: 'Gerir RH', category: 'RH', description: 'Contratar e editar dados de staff.', icon: <UsersIcon size={14} /> },

  // Operações & Projetos
  { id: 'projects.manage', label: 'Gerir Obras', category: 'Operações', description: 'Criar e editar projetos e obras.', icon: <Briefcase size={14} /> },
  { id: 'catalog.edit', label: 'Editar Catálogo', category: 'Operações', description: 'Adicionar e remover imóveis.', icon: <LayoutGrid size={14} /> },

  // Sistema & TI
  { id: 'admin.access', label: 'Acesso Admin', category: 'Sistema', description: 'Acesso total ao painel de TI.', icon: <Shield size={14} /> },
  { id: 'system.logs', label: 'Ver Auditoria', category: 'Sistema', description: 'Visualizar logs de alterações.', icon: <Terminal size={14} /> },
];

const AdminView: React.FC = () => {
  const [users, setUsers] = useState<Employee[]>([]);
  const [roles, setRoles] = useState<string[]>(Object.values(UserRole));
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [editingUser, setEditingUser] = useState<Employee | null>(null);
  const [showRolesModal, setShowRolesModal] = useState(false);
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState<{type: 'success' | 'error', text: string} | null>(null);
  const [copied, setCopied] = useState(false);

  // Role Manager state
  const [newRoleName, setNewRoleName] = useState('');
  const [editingRole, setEditingRole] = useState<{old: string, new: string} | null>(null);

  const sqlSchema = `-- SCRIPT DE ATUALIZAÇÃO GLOBAL MONTE HUB
-- 1. Tabela de Cargos Dinâmicos
CREATE TABLE IF NOT EXISTS public.roles (
    id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
    name text UNIQUE NOT NULL,
    created_at timestamptz DEFAULT now()
);

-- Inserir cargos padrão
INSERT INTO public.roles (name) 
VALUES 
('Administrador de Sistema'),
('Director Executivo (CEO)'),
('Gestor Geral Operacional'),
('Director Financeiro'),
('Gestor de Recursos Humanos'),
('Consultor Imobiliário'),
('Colaborador Geral')
ON CONFLICT (name) DO NOTHING;

-- 2. Tabela de Serviços (Pintura, AC, etc)
CREATE TABLE IF NOT EXISTS public.services (
    id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
    title text NOT NULL,
    description text,
    icon text,
    created_at timestamptz DEFAULT now()
);

-- 3. Segurança RLS (Row Level Security)
ALTER TABLE public.roles ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "Public Roles Access" ON public.roles;
CREATE POLICY "Public Roles Access" ON public.roles FOR ALL USING (true);

ALTER TABLE public.services ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "Public Services Access" ON public.services;
CREATE POLICY "Public Services Access" ON public.services FOR ALL USING (true);

-- Forçar recarregamento do cache do PostgREST
NOTIFY pgrst, 'reload schema';
`;

  useEffect(() => {
    fetchUsers();
    fetchRoles();
  }, []);

  async function fetchRoles() {
    try {
      const { data, error } = await supabase.from('roles').select('name').order('name');
      if (!error && data) {
        setRoles(data.map(r => r.name));
      }
    } catch (e) {
      console.warn("Tabela de cargos não encontrada. Usando padrão do enum.");
    }
  }

  async function fetchUsers() {
    setLoading(true);
    try {
      const { data, error } = await supabase.from('employees').select('*').order('name');
      if (!error) setUsers(data || []);
    } catch (e) {
      console.warn("Erro ao buscar usuários");
    } finally {
      setLoading(false);
    }
  }

  const handleUpdatePermissions = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingUser) return;

    setSaving(true);
    const { error } = await supabase
      .from('employees')
      .update({ 
        role: editingUser.role,
        permissions: editingUser.permissions || []
      })
      .eq('id', editingUser.id);

    if (error) {
      setMsg({ type: 'error', text: 'Erro ao sincronizar: ' + error.message });
    } else {
      setMsg({ type: 'success', text: 'Privilégios atualizados com sucesso!' });
      fetchUsers();
      setTimeout(() => setEditingUser(null), 1000);
    }
    setSaving(false);
    setTimeout(() => setMsg(null), 3000);
  };

  const handleAddRole = async () => {
    if (!newRoleName) return;
    const { error } = await supabase.from('roles').insert([{ name: newRoleName }]);
    if (!error) {
      setNewRoleName('');
      fetchRoles();
    } else {
      alert("Erro ao adicionar cargo: " + error.message);
    }
  };

  const handleDeleteRole = async (roleName: string) => {
    if (confirm(`Eliminar o cargo "${roleName}"?`)) {
      const { error } = await supabase.from('roles').delete().eq('name', roleName);
      if (!error) fetchRoles();
    }
  };

  const handleRenameRole = async () => {
    if (!editingRole || !editingRole.new) return;
    const { error } = await supabase.from('roles').update({ name: editingRole.new }).eq('name', editingRole.old);
    if (!error) {
      setEditingRole(null);
      fetchRoles();
    }
  };

  const togglePermission = (permId: string) => {
    if (!editingUser) return;
    const current = editingUser.permissions || [];
    const newPerms = current.includes(permId) 
      ? current.filter(p => p !== permId) 
      : [...current, permId];
    setEditingUser({ ...editingUser, permissions: newPerms });
  };

  const groupByCategory = (perms: PermissionDefinition[]) => {
    return perms.reduce((acc, curr) => {
      if (!acc[curr.category]) acc[curr.category] = [];
      acc[curr.category].push(curr);
      return acc;
    }, {} as Record<string, PermissionDefinition[]>);
  };

  const groupedPermissions = groupByCategory(GRANULAR_PERMISSIONS);

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-12">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tight">Administração TI</h1>
          <p className="text-slate-500 font-medium">Controlo de acessos, cargos dinâmicos e infraestrutura Cloud.</p>
        </div>
        <div className="flex items-center gap-3">
           <button onClick={() => { fetchUsers(); fetchRoles(); }} className="p-4 bg-white text-slate-400 hover:text-blue-600 rounded-3xl shadow-sm border border-slate-100 transition-all active:scale-95">
             <RefreshCw size={20} className={loading ? 'animate-spin' : ''} />
           </button>
           <div className="px-6 py-2.5 bg-indigo-600 text-white rounded-full text-[10px] font-black uppercase tracking-widest flex items-center gap-2 shadow-xl shadow-indigo-500/20">
             <Fingerprint size={16} /> Hub Autenticado
           </div>
        </div>
      </div>

      {/* SQL Script Box - Centralizado aqui para fácil configuração do Admin */}
      <div className="bg-slate-900 rounded-[3.5rem] p-10 text-white shadow-2xl relative overflow-hidden mb-8">
        <div className="flex items-center gap-4 mb-6">
          <Database size={24} className="text-indigo-400" />
          <div>
            <h3 className="text-xl font-black text-white">Configuração Cloud Global</h3>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Execute este script no Editor SQL do Supabase para sincronizar as tabelas</p>
          </div>
        </div>
        <pre className="bg-slate-800 p-6 rounded-3xl text-[10px] text-indigo-300 font-mono overflow-x-auto mb-6 max-h-48 custom-scrollbar">
          {sqlSchema}
        </pre>
        <button 
          onClick={() => { navigator.clipboard.writeText(sqlSchema); setCopied(true); setTimeout(() => setCopied(false), 2000); }}
