            </div>

            <div className="space-y-3 max-h-80 overflow-y-auto pr-2 custom-scrollbar">
              {roles.map(role => (
                <div key={role} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100 group">
                  {editingRole?.old === role ? (
                    <div className="flex-1 flex gap-2">
                      <input value={editingRole.new} onChange={e => setEditingRole({...editingRole, new: e.target.value})} className="flex-1 bg-white border border-indigo-200 rounded-xl px-3 py-1 font-bold text-xs" />
                      <button onClick={handleRenameRole} className="text-green-600"><Check size={16}/></button>
                      <button onClick={() => setEditingRole(null)} className="text-red-600"><X size={16}/></button>
                    </div>
                  ) : (
                    <>
                      <span className="text-xs font-black text-slate-700 uppercase tracking-tight">{role}</span>
                      <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button onClick={() => setEditingRole({old: role, new: role})} className="p-1.5 text-slate-400 hover:text-indigo-600 transition-colors"><Edit size={14} /></button>
                        <button onClick={() => handleDeleteRole(role)} className="p-1.5 text-slate-400 hover:text-red-500 transition-colors"><Trash2 size={14} /></button>
                      </div>
                    </>
                  )}
                </div>
              ))}
            </div>

            <button onClick={() => setShowRolesModal(false)} className="w-full mt-8 py-4 bg-slate-900 text-white rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest hover:bg-indigo-600 transition-all">Concluir Alterações</button>
          </div>
        </div>
      )}
    </div>
  );
};

