const ContactView: React.FC = () => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    subject: 'Interesse em Imóvel',
    message: ''
  });
  const [status, setStatus] = useState<'idle' | 'loading' | 'success' | 'error'>('idle');
  const [errorMessage, setErrorMessage] = useState<string>('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    // Validação de nome obrigatória antes de qualquer chamada
    if (!formData.name.trim()) {
      setStatus('error');
      setErrorMessage('O campo Nome é obrigatório para identificarmos o seu pedido.');
      return;
    }

    setStatus('loading');
    setErrorMessage('');

    try {
      const { error } = await supabase
        .from('contact_requests')
        .insert([
          { 
            name: formData.name.trim(), 
            email: formData.email, 
            subject: formData.subject, 
            message: formData.message,
            destination_email: 'monteimobiliario@gmail.com',
            created_at: new Date().toISOString()
          }
        ]);

      if (error) {
        const msg = error.message || 'Erro desconhecido ao enviar mensagem.';
        if (msg.includes('not found')) {
          throw new Error('Sistema em manutenção Cloud. Contacte o administrador para criar a tabela de pedidos.');
        }
        throw new Error(msg);
      }

      setStatus('success');
      setFormData({ name: '', email: '', subject: 'Interesse em Imóvel', message: '' });
      setTimeout(() => setStatus('idle'), 5000);
    } catch (err: any) {
      console.error("Submission Error:", err);
      setStatus('error');
      setErrorMessage(err instanceof Error ? err.message : String(err));
    }
  };

  return (
    <div className="py-20 px-4 md:px-8 max-w-7xl mx-auto animate-in fade-in duration-700">
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-16">
