        <div className="bg-white p-8 md:p-12 rounded-[3.5rem] border border-slate-100 shadow-2xl">
          <h3 className="text-2xl font-black text-slate-900 mb-8 flex items-center gap-3"><MessageSquare className="text-blue-600" /> Nova Solicitação</h3>

          {status === 'success' ? (
