import React, { useState, useEffect } from 'react';
import { 
  Plus, Users, DollarSign, UserCheck, AlertCircle, Clock, 
  Loader2, X, CheckCircle, Trash2, LayoutDashboard,
  Lock, Save, UserCog, Mail, Phone, CreditCard, Calendar as CalendarIcon, FileText,
  BadgeCheck, Wallet
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { Employee, UserRole } from '../types';

const HRView: React.FC = () => {
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAddModal, setShowAddModal] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const [newEmp, setNewEmp] = useState<Partial<Employee>>({
    name: '', role: UserRole.EMPLOYEE, department: 'Vendas', salary: 0, email: '', phone: '',
    document_type: 'BI', document_number: '', document_expiry: '', payment_method: 'M-Pesa', contract_start: ''
  });

  useEffect(() => {
    fetchData();
  }, []);

  async function fetchData() {
    setLoading(true);
    try {
      const { data, error: sbError } = await supabase.from('employees').select('*').order('name');
      if (sbError) setError(sbError.message);
      setEmployees(data || []);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }

  const handleAddEmployee = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    // Validação de Nome
    if (!newEmp.name?.trim()) {
      setError('O nome do colaborador é obrigatório.');
      return;
    }

    // Validação de Documento (Presença e Numérico)
    if (!newEmp.document_number?.trim()) {
      setError('O número do documento é obrigatório.');
      return;
    }
    const hasDigits = /\d/.test(newEmp.document_number);
    if (!hasDigits) {
      setError('O número do documento deve conter algarismos numéricos.');
      return;
    }

    // Validação de Data de Validade
    if (!newEmp.document_expiry) {
      setError('A data de validade do documento é obrigatória.');
      return;
    }
    const today = new Date().toISOString().split('T')[0];
    if (newEmp.document_expiry < today) {
      setError('O documento indicado está expirado ou com validade inválida.');
      return;
    }

    // Validação de Início de Contrato
    if (!newEmp.contract_start) {
      setError('A data de início do contrato é obrigatória para o cadastro.');
      return;
    }

    const payload = {
      name: newEmp.name, email: newEmp.email, phone: newEmp.phone, role: newEmp.role,
      department: newEmp.department, salary: Number(newEmp.salary),
      avatar: `https://picsum.photos/seed/${newEmp.name}/100`, status: 'Ativo',
      join_date: newEmp.contract_start, document_type: newEmp.document_type || 'BI',
      document_number: newEmp.document_number, document_expiry: newEmp.document_expiry,
      payment_method: newEmp.payment_method || 'M-Pesa', contract_start: newEmp.contract_start
    };

    const { error: sbError } = await supabase.from('employees').insert([payload]);

    if (sbError) {
      setError('Falha Cloud: ' + sbError.message);
    } else {
      setShowAddModal(false);
      setNewEmp({ 
        name: '', role: UserRole.EMPLOYEE, department: 'Vendas', salary: 0, email: '', phone: '',
        document_type: 'BI', document_number: '', document_expiry: '', payment_method: 'M-Pesa', contract_start: ''
      });
      fetchData();
    }
  };

  const removeEmployee = async (id: string) => {
    if (confirm('Deseja arquivar este contrato?')) {
      const { error } = await supabase.from('employees').delete().eq('id', id);
      if (!error) fetchData();
    }
  };

  if (loading) return <div className="flex justify-center py-20"><Loader2 className="animate-spin text-blue-600" size={40} /></div>;

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-4">
           <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-indigo-500/20"><Users size={24} /></div>
           <div><h1 className="text-3xl font-black text-slate-900 tracking-tight">Gestão de Staff</h1><p className="text-slate-500 font-medium">Controlo de capital humano Monte.</p></div>
        </div>
        <button onClick={() => { setError(null); setShowAddModal(true); }} className="px-8 py-4 bg-indigo-600 text-white rounded-[2rem] font-black text-sm shadow-xl hover:bg-indigo-700 transition-all active:scale-95"><Plus size={20} /> Novo Colaborador</button>
      </div>

      {error && (
        <div className="p-5 bg-amber-50 border-l-4 border-amber-50 rounded-2xl flex items-center gap-4 text-amber-800 text-xs font-bold shadow-sm animate-shake">
          <AlertCircle size={24} /> <p>{error}</p>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {employees.map(emp => (
          <div key={emp.id} className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm relative group hover:shadow-2xl transition-all">
            <button onClick={() => removeEmployee(emp.id)} className="absolute top-8 right-8 text-slate-200 hover:text-red-500"><Trash2 size={18} /></button>
            <img src={emp.avatar} className="w-20 h-20 rounded-[2rem] object-cover mb-4 ring-4 ring-slate-50" />
            <h3 className="text-lg font-black text-slate-900 mb-1">{emp.name}</h3>
            <p className="text-[10px] font-black text-indigo-600 uppercase tracking-widest mb-6">{emp.role}</p>
            <div className="pt-6 border-t border-slate-50 flex justify-between">
              <div><p className="text-[9px] font-black text-slate-400 uppercase">Salário</p><p className="text-sm font-black text-slate-900">{Number(emp.salary).toLocaleString()} MT</p></div>
              <div className="text-right"><p className="text-[9px] font-black text-slate-400 uppercase">Início</p><p className="text-[10px] font-bold text-slate-900">{emp.contract_start || emp.join_date}</p></div>
            </div>
          </div>
        ))}
      </div>

      {showAddModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-12 max-w-3xl w-full shadow-2xl relative overflow-y-auto max-h-[90vh]">
            <button onClick={() => setShowAddModal(false)} className="absolute top-10 right-10 text-slate-400 p-2 hover:bg-slate-50 rounded-xl"><X size={24} /></button>
            <h2 className="text-3xl font-black text-slate-900 mb-10">Registo de Colaborador</h2>
            <form onSubmit={handleAddEmployee} className="space-y-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <input required placeholder="Nome Completo *" value={newEmp.name} onChange={e => setNewEmp({...newEmp, name: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold border-none" />
                <input required type="email" placeholder="E-mail Corporativo *" value={newEmp.email} onChange={e => setNewEmp({...newEmp, email: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold border-none" />
                <input required placeholder="Contacto Móvel *" value={newEmp.phone} onChange={e => setNewEmp({...newEmp, phone: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold border-none" />
