import React, { useState, useEffect } from 'react';
import { 
  Plus, Users, DollarSign, UserCheck, AlertCircle, Clock, 
  Loader2, X, CheckCircle, Trash2, LayoutDashboard,
  Lock, Save, UserCog, Mail, Phone, CreditCard, Calendar as CalendarIcon, FileText,
  BadgeCheck, Wallet, Edit3
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { Employee, UserRole } from '../types';

const HRView: React.FC = () => {
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAddModal, setShowAddModal] = useState(false);
  const [editingEmpId, setEditingEmpId] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [saving, setSaving] = useState(false);

  const initialFormState: Partial<Employee> = {
    name: '', role: UserRole.EMPLOYEE, department: 'Vendas', salary: 0, email: '', phone: '',
    document_type: 'BI', document_number: '', document_expiry: '', payment_method: 'M-Pesa', contract_start: ''
  };

  const [formState, setFormState] = useState<Partial<Employee>>(initialFormState);

  useEffect(() => {
    fetchData();
  }, []);

  async function fetchData() {
    setLoading(true);
    try {
      const { data, error: sbError } = await supabase.from('employees').select('*').order('name');
      if (sbError) setError(sbError.message);
      setEmployees(data || []);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }

  const handleOpenEdit = (emp: Employee) => {
    setEditingEmpId(emp.id);
    setFormState({
      name: emp.name,
      email: emp.email,
      phone: emp.phone,
      role: emp.role,
      department: emp.department,
      salary: emp.salary,
      document_type: emp.document_type || 'BI',
      document_number: emp.document_number || '',
      document_expiry: emp.document_expiry || '',
      payment_method: emp.payment_method || 'M-Pesa',
      contract_start: emp.contract_start || emp.join_date
    });
    setShowAddModal(true);
    setError(null);
  };

  const handleSaveEmployee = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setSaving(true);

    // Validação de Nome
    if (!formState.name?.trim()) {
      setError('O nome do colaborador é obrigatório.');
      setSaving(false);
      return;
    }

    // Validação de Documento (Presença e Numérico)
    if (!formState.document_number?.trim()) {
      setError('O número do documento é obrigatório.');
      setSaving(false);
      return;
    }
    const hasDigits = /\d/.test(formState.document_number);
    if (!hasDigits) {
      setError('O número do documento deve conter algarismos numéricos.');
      setSaving(false);
      return;
    }

    // Validação de Data de Validade
    if (!formState.document_expiry) {
      setError('A data de validade do documento é obrigatória.');
      setSaving(false);
      return;
    }
    const today = new Date().toISOString().split('T')[0];
    if (formState.document_expiry < today) {
      setError('O documento indicado está expirado ou com validade inválida.');
      setSaving(false);
      return;
    }

    // Validação de Início de Contrato
    if (!formState.contract_start) {
      setError('A data de início do contrato é obrigatória.');
      setSaving(false);
      return;
    }

    const payload = {
      name: formState.name, 
      email: formState.email, 
      phone: formState.phone, 
      role: formState.role,
      department: formState.department, 
      salary: Number(formState.salary),
      avatar: `https://picsum.photos/seed/${formState.name}/100`, 
      status: 'Ativo',
      join_date: formState.contract_start, 
      document_type: formState.document_type || 'BI',
      document_number: formState.document_number, 
      document_expiry: formState.document_expiry,
      payment_method: formState.payment_method || 'M-Pesa', 
      contract_start: formState.contract_start
    };

    try {
      if (editingEmpId) {
        const { error: sbError } = await supabase
          .from('employees')
          .update(payload)
          .eq('id', editingEmpId);

        if (sbError) throw sbError;
      } else {
        const { error: sbError } = await supabase
          .from('employees')
          .insert([payload]);

        if (sbError) throw sbError;
      }

      setShowAddModal(false);
      setEditingEmpId(null);
      setFormState(initialFormState);
      fetchData();
    } catch (err: any) {
      setError('Falha Cloud: ' + err.message);
    } finally {
      setSaving(false);
    }
  };

  const removeEmployee = async (id: string) => {
    if (confirm('Deseja arquivar este contrato?')) {
      const { error } = await supabase.from('employees').delete().eq('id', id);
      if (!error) fetchData();
    }
  };

  const closeModal = () => {
    setShowAddModal(false);
    setEditingEmpId(null);
    setFormState(initialFormState);
    setError(null);
  };

  if (loading) return <div className="flex justify-center py-20"><Loader2 className="animate-spin text-blue-600" size={40} /></div>;

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-4">
           <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-indigo-500/20"><Users size={24} /></div>
           <div><h1 className="text-3xl font-black text-slate-900 tracking-tight">Gestão de Staff</h1><p className="text-slate-500 font-medium">Controlo de capital humano Monte.</p></div>
        </div>
        <button onClick={() => setShowAddModal(true)} className="px-8 py-4 bg-indigo-600 text-white rounded-[2rem] font-black text-sm shadow-xl hover:bg-indigo-700 transition-all active:scale-95"><Plus size={20} /> Novo Colaborador</button>
      </div>

      {error && (
        <div className="p-5 bg-amber-50 border-l-4 border-amber-500 rounded-2xl flex items-center gap-4 text-amber-800 text-xs font-bold shadow-sm animate-shake">
          <AlertCircle size={24} /> <p>{error}</p>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {employees.map(emp => (
          <div key={emp.id} className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm relative group hover:shadow-2xl transition-all">
            <div className="absolute top-8 right-8 flex gap-2">
              <button onClick={() => handleOpenEdit(emp)} className="p-2 text-slate-200 hover:text-indigo-600 transition-colors" title="Editar">
                <Edit3 size={18} />
              </button>
              <button onClick={() => removeEmployee(emp.id)} className="p-2 text-slate-200 hover:text-red-500 transition-colors" title="Eliminar">
                <Trash2 size={18} />
              </button>
            </div>
            <img src={emp.avatar} className="w-20 h-20 rounded-[2rem] object-cover mb-4 ring-4 ring-slate-50" />
            <h3 className="text-lg font-black text-slate-900 mb-1">{emp.name}</h3>
            <p className="text-[10px] font-black text-indigo-600 uppercase tracking-widest mb-6">{emp.role}</p>
            <div className="pt-6 border-t border-slate-50 flex justify-between">
              <div><p className="text-[9px] font-black text-slate-400 uppercase">Salário</p><p className="text-sm font-black text-slate-900">{Number(emp.salary).toLocaleString()} MT</p></div>
              <div className="text-right"><p className="text-[9px] font-black text-slate-400 uppercase">Início</p><p className="text-[10px] font-bold text-slate-900">{emp.contract_start || emp.join_date}</p></div>
            </div>
          </div>
        ))}
      </div>

      {showAddModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-12 max-w-3xl w-full shadow-2xl relative overflow-y-auto max-h-[90vh]">
            <button onClick={closeModal} className="absolute top-10 right-10 text-slate-400 p-2 hover:bg-slate-50 rounded-xl transition-all"><X size={24} /></button>
            <h2 className="text-3xl font-black text-slate-900 mb-10">{editingEmpId ? 'Editar Colaborador' : 'Registo de Colaborador'}</h2>
            <form onSubmit={handleSaveEmployee} className="space-y-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome Completo *</label>
                  <input required placeholder="Nome Completo *" value={formState.name} onChange={e => setFormState({...formState, name: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold border-none" />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">E-mail Corporativo *</label>
                  <input required type="email" placeholder="E-mail Corporativo *" value={formState.email} onChange={e => setFormState({...formState, email: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold border-none" />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Contacto Móvel *</label>
                  <input required placeholder="Contacto Móvel *" value={formState.phone} onChange={e => setFormState({...formState, phone: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold border-none" />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Salário Base (MT)</label>
                  <input type="number" placeholder="Salário Base (MT)" value={formState.salary} onChange={e => setFormState({...formState, salary: Number(e.target.value)})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold border-none" />
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-6 pt-4 border-t border-slate-50">
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Documento *</label>
                  <input required placeholder="Número BI/DIRE" value={formState.document_number} onChange={e => setFormState({...formState, document_number: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold" />
                </div>
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Validade *</label>
                  <input required type="date" value={formState.document_expiry} onChange={e => setFormState({...formState, document_expiry: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold" />
                </div>
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Início Contrato *</label>
                  <input required type="date" value={formState.contract_start} onChange={e => setFormState({...formState, contract_start: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-4 font-bold" />
                </div>
              </div>

              <button disabled={saving} type="submit" className="w-full py-6 bg-indigo-600 text-white font-black rounded-[2.5rem] shadow-xl hover:bg-indigo-700 transition-all flex items-center justify-center gap-4 active:scale-95 disabled:opacity-70">
                {saving ? <Loader2 className="animate-spin" size={24} /> : (editingEmpId ? <><Save size={24} /> Guardar Alterações</> : <><Save size={24} /> Concluir Cadastro Staff</>)}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default HRView;

import React, { useState, useEffect } from 'react';
import { 
  Calendar, Users, DollarSign, ArrowRight, Clock, 
