              {/* Project Cover */}
              <div className="h-52 relative overflow-hidden">
                <img 
                  src={project.image || 'https://images.unsplash.com/photo-1541888946425-d81bb19480c5?auto=format&fit=crop&q=80&w=800'} 
                  className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" 
                  alt={project.name} 
