                {/* Financials */}
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Orçamento Total (MT)</label>
                  <input 
                    required 
                    type="number" 
                    value={formData.budget} 
                    onChange={e => setFormData({...formData, budget: Number(e.target.value)})} 
                    className="w-full bg-slate-50 rounded-2xl p-5 border-none focus:ring-2 focus:ring-blue-600 font-bold outline-none" 
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Valor Gasto Atual (MT)</label>
                  <input 
                    required 
                    type="number" 
                    value={formData.spent} 
                    onChange={e => setFormData({...formData, spent: Number(e.target.value)})} 
                    className="w-full bg-slate-50 rounded-2xl p-5 border-none focus:ring-2 focus:ring-blue-600 font-bold outline-none" 
                  />
                </div>

                {/* Status & Date */}
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Status Atual</label>
                  <select 
                    value={formData.status} 
                    onChange={e => setFormData({...formData, status: e.target.value as any})} 
                    className="w-full bg-slate-50 rounded-2xl p-5 border-none font-bold outline-none cursor-pointer"
                  >
                    <option>Planejado</option>
                    <option>Em Andamento</option>
                    <option>Pausado</option>
                    <option>Concluído</option>
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Data de Entrega</label>
                  <input 
                    required 
                    type="date" 
                    value={formData.deadline} 
                    onChange={e => setFormData({...formData, deadline: e.target.value})} 
                    className="w-full bg-slate-50 rounded-2xl p-5 border-none focus:ring-2 focus:ring-blue-600 font-bold outline-none" 
                  />
                </div>
              </div>

              <button 
                type="submit" 
                disabled={isSubmitting}
                className={`w-full py-6 bg-gradient-to-r from-blue-600 to-indigo-600 text-white font-black rounded-[2.5rem] shadow-2xl shadow-blue-500/40 transition-all flex items-center justify-center ${
                  isSubmitting ? 'opacity-70 scale-95' : 'hover:scale-[1.02] active:scale-95'
                }`}
              >
                {isSubmitting ? (
                  <Loader2 className="animate-spin mr-2" size={20} />
                ) : null}
                {isSubmitting ? 'Processando...' : (editingProject ? 'Guardar Alterações' : 'Iniciar Projeto na Cloud')}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

