import React, { useState, useEffect, useMemo } from 'react';
import { ArrowUpCircle, ArrowDownCircle, Plus, DollarSign, X, Loader2, BarChart3, TrendingUp } from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  Legend, 
  ResponsiveContainer,
  Cell
} from 'recharts';
import { supabase } from '../supabaseClient';
import { Transaction } from '../types';

const FinanceView: React.FC = () => {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [newLaunch, setNewLaunch] = useState({
    description: '',
    category: 'Vendas',
    amount: '',
    type: 'DESPESA' as 'RECEITA' | 'DESPESA',
  });

  useEffect(() => {
    fetchTransactions();
  }, []);

  async function fetchTransactions() {
    setLoading(true);
    const { data, error } = await supabase.from('transactions').select('*').order('date', { ascending: false });
    if (!error) setTransactions(data || []);
    setLoading(false);
  }

  const handleLaunch = async (e: React.FormEvent) => {
    e.preventDefault();
    const payload = {
      description: newLaunch.description,
      category: newLaunch.category,
      amount: Number(newLaunch.amount),
      type: newLaunch.type,
      date: new Date().toISOString().split('T')[0]
    };

    const { error } = await supabase.from('transactions').insert([payload]);
    if (!error) {
      setShowModal(false);
      setNewLaunch({ description: '', category: 'Vendas', amount: '', type: 'DESPESA' });
      fetchTransactions();
    }
  };

  const totals = transactions.reduce((acc, curr) => {
    if (curr.type === 'RECEITA') acc.receita += Number(curr.amount);
    else acc.despesa += Number(curr.amount);
    return acc;
  }, { receita: 0, despesa: 0 });

  // Processamento de dados para o gráfico (Últimos 6 meses)
  const chartData = useMemo(() => {
    const months = [];
    const date = new Date();

    // Gerar chaves para os últimos 6 meses
    for (let i = 5; i >= 0; i--) {
      const d = new Date(date.getFullYear(), date.getMonth() - i, 1);
      const monthName = d.toLocaleString('pt-BR', { month: 'short' });
      months.push({
        key: `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`,
        name: monthName.charAt(0).toUpperCase() + monthName.slice(1),
        receita: 0,
        despesa: 0
      });
    }

    // Distribuir transações nos meses correspondentes
    transactions.forEach(t => {
      const tMonth = t.date.substring(0, 7); // yyyy-mm
      const monthObj = months.find(m => m.key === tMonth);
      if (monthObj) {
        if (t.type === 'RECEITA') monthObj.receita += Number(t.amount);
        else monthObj.despesa += Number(t.amount);
      }
    });

    return months;
  }, [transactions]);

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-12">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 bg-emerald-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-emerald-500/20">
            <BarChart3 size={24} />
          </div>
          <div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">Fluxo Financeiro</h1>
            <p className="text-slate-500 font-medium">Análise de performance e balanço cloud.</p>
          </div>
        </div>
        <button onClick={() => setShowModal(true)} className="flex items-center gap-2 px-8 py-4 bg-emerald-600 text-white rounded-[2rem] font-black text-sm shadow-xl shadow-emerald-500/20 hover:scale-105 transition-all">
          <Plus size={20} /> Novo Lançamento
        </button>
      </div>

      {loading ? (
        <div className="flex justify-center py-20"><Loader2 className="animate-spin text-blue-600" size={40} /></div>
      ) : (
        <>
          {/* Cards de Resumo */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Receitas Acumuladas</p>
              <div className="flex items-center justify-between">
                <p className="text-3xl font-black text-emerald-600">{totals.receita.toLocaleString()} MT</p>
                <ArrowUpCircle className="text-emerald-500" size={24} />
              </div>
            </div>
            <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Despesas Acumuladas</p>
              <div className="flex items-center justify-between">
                <p className="text-3xl font-black text-rose-600">{totals.despesa.toLocaleString()} MT</p>
                <ArrowDownCircle className="text-rose-500" size={24} />
              </div>
            </div>
            <div className="bg-slate-900 p-8 rounded-[2.5rem] shadow-2xl relative overflow-hidden group">
              <div className="absolute top-0 right-0 w-32 h-32 bg-white/5 rounded-full -translate-y-1/2 translate-x-1/2 blur-2xl group-hover:bg-white/10 transition-all"></div>
              <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2">Saldo em Caixa</p>
              <p className="text-3xl font-black text-white">{(totals.receita - totals.despesa).toLocaleString()} MT</p>
            </div>
          </div>

          {/* Gráfico de Barras Mensal */}
          <div className="bg-white p-10 rounded-[3.5rem] border border-slate-100 shadow-sm">
            <div className="flex items-center justify-between mb-8">
              <div>
                <h3 className="text-xl font-black text-slate-900">Histórico de Performance</h3>
                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-1">Últimos 6 meses de operações</p>
              </div>
              <div className="flex items-center gap-4 text-[10px] font-black uppercase tracking-widest">
                <div className="flex items-center gap-2">
                  <span className="w-3 h-3 bg-emerald-500 rounded-full"></span> Receitas
                </div>
                <div className="flex items-center gap-2">
                  <span className="w-3 h-3 bg-rose-500 rounded-full"></span> Despesas
                </div>
              </div>
            </div>

            <div className="h-[350px] w-full">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={chartData} margin={{ top: 10, right: 10, left: 0, bottom: 0 }}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                  <XAxis 
                    dataKey="name" 
                    axisLine={false} 
                    tickLine={false} 
                    tick={{ fill: '#94a3b8', fontSize: 11, fontWeight: 700 }}
                    dy={10}
                  />
                  <YAxis 
                    axisLine={false} 
                    tickLine={false} 
                    tick={{ fill: '#94a3b8', fontSize: 11, fontWeight: 700 }}
                    tickFormatter={(value) => `${value / 1000}k`}
                  />
                  <Tooltip 
                    cursor={{ fill: '#f8fafc' }}
                    contentStyle={{ borderRadius: '20px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)', fontWeight: 'bold' }}
                    formatter={(value: any) => [`${value.toLocaleString()} MT`]}
                  />
                  <Bar 
                    dataKey="receita" 
                    name="Receitas" 
                    fill="#10b981" 
                    radius={[10, 10, 0, 0]} 
                    barSize={40}
                  />
                  <Bar 
                    dataKey="despesa" 
                    name="Despesas" 
                    fill="#f43f5e" 
                    radius={[10, 10, 0, 0]} 
                    barSize={40}
                  />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </div>

          {/* Tabela de Transações */}
          <div className="bg-white rounded-[3.5rem] border border-slate-100 overflow-hidden shadow-sm">
            <div className="px-10 py-6 border-b border-slate-50 flex items-center justify-between">
              <h3 className="text-lg font-black text-slate-900">Extrato Recente</h3>
              <div className="flex gap-2">
                <span className="text-[10px] font-black bg-slate-100 text-slate-500 px-3 py-1 rounded-full uppercase">Sincronizado</span>
              </div>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead>
                  <tr className="bg-slate-50/50 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                    <th className="px-10 py-5">Descrição</th>
                    <th className="px-10 py-5">Categoria</th>
                    <th className="px-10 py-5">Data</th>
                    <th className="px-10 py-5 text-right">Valor</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {transactions.length === 0 ? (
                    <tr>
                      <td colSpan={4} className="px-10 py-20 text-center text-slate-400 font-medium italic">
                        Nenhuma transação registada até ao momento.
                      </td>
                    </tr>
                  ) : (
                    transactions.map((t) => (
                      <tr key={t.id} className="hover:bg-slate-50/50 transition-all group">
                        <td className="px-10 py-6 font-bold text-slate-900">{t.description}</td>
                        <td className="px-10 py-6">
                          <span className="text-[10px] font-black bg-slate-100 text-slate-500 px-3 py-1 rounded-lg uppercase tracking-wider">{t.category}</span>
                        </td>
                        <td className="px-10 py-6 text-sm text-slate-500 font-medium">{t.date}</td>
                        <td className={`px-10 py-6 text-right font-black ${t.type === 'RECEITA' ? 'text-emerald-600' : 'text-rose-600'}`}>
                          {t.type === 'RECEITA' ? '+' : '-'} {t.amount.toLocaleString()} MT
                        </td>
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </>
      )}

      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white rounded-[3.5rem] p-12 max-w-lg w-full shadow-2xl relative">
            <button onClick={() => setShowModal(false)} className="absolute top-10 right-10 text-slate-400 hover:text-slate-900 transition-colors"><X size={28} /></button>
            <h2 className="text-2xl font-black text-slate-900 mb-8 flex items-center gap-3">
              <DollarSign className="text-emerald-600" /> Novo Lançamento
            </h2>
            <form onSubmit={handleLaunch} className="space-y-6">
              <div className="flex p-1.5 bg-slate-100 rounded-[1.5rem]">
                <button type="button" onClick={() => setNewLaunch({...newLaunch, type: 'RECEITA'})} className={`flex-1 py-4 text-xs font-black uppercase tracking-widest rounded-2xl transition-all ${newLaunch.type === 'RECEITA' ? 'bg-white text-emerald-600 shadow-md' : 'text-slate-500'}`}>Receita</button>
                <button type="button" onClick={() => setNewLaunch({...newLaunch, type: 'DESPESA'})} className={`flex-1 py-4 text-xs font-black uppercase tracking-widest rounded-2xl transition-all ${newLaunch.type === 'DESPESA' ? 'bg-white text-rose-600 shadow-md' : 'text-slate-500'}`}>Despesa</button>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Descrição</label>
                <input required placeholder="Ex: Pagamento Fornecedor AC" value={newLaunch.description} onChange={e => setNewLaunch({...newLaunch, description: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold border-none outline-none focus:ring-2 focus:ring-emerald-500 transition-all" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Categoria</label>
                <select value={newLaunch.category} onChange={e => setNewLaunch({...newLaunch, category: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold border-none outline-none focus:ring-2 focus:ring-emerald-500 transition-all cursor-pointer">
                  <option>Vendas</option><option>Aluguel</option><option>Manutenção</option><option>Salários</option><option>Marketing</option><option>TI</option><option>Logística</option>
                </select>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Montante (MT)</label>
                <input required type="number" placeholder="0.00" value={newLaunch.amount} onChange={e => setNewLaunch({...newLaunch, amount: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-black outline-none border-none text-2xl focus:ring-2 focus:ring-emerald-500 transition-all" />
              </div>
              <button type="submit" className="w-full py-6 bg-emerald-600 text-white font-black rounded-[2rem] shadow-xl shadow-emerald-500/20 hover:bg-emerald-700 transition-all active:scale-95 flex items-center justify-center gap-3">
                <Plus size={20} /> Confirmar Lançamento Cloud
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default FinanceView;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Shield, Key, Lock, Settings, UserCog, Save, 
  CheckCircle2, AlertCircle, Loader2, Search,
  ShieldAlert, Fingerprint, Zap, Database, Copy, Check, X,
  RefreshCw, Eye, Edit, Trash2, LayoutGrid, Briefcase, 
  Wallet, Users as UsersIcon, Terminal, Plus, Settings2,
  ChevronRight
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { UserRole, Employee } from '../types';

interface PermissionDefinition {
  id: string;
  label: string;
  category: 'Financeiro' | 'RH' | 'Operações' | 'Sistema';
  description: string;
  icon: React.ReactNode;
}

const GRANULAR_PERMISSIONS: PermissionDefinition[] = [
  // Financeiro
  { id: 'finance.view', label: 'Visualizar Financeiro', category: 'Financeiro', description: 'Acesso a relatórios e balanços.', icon: <Eye size={14} /> },
  { id: 'finance.edit', label: 'Lançamentos Financeiros', category: 'Financeiro', description: 'Criar receitas e despesas.', icon: <Edit size={14} /> },
  { id: 'finance.delete', label: 'Eliminar Registos', category: 'Financeiro', description: 'Remover transações do sistema.', icon: <Trash2 size={14} /> },

  // RH & Staff
  { id: 'hr.view', label: 'Ver Staff', category: 'RH', description: 'Visualizar lista de colaboradores.', icon: <Eye size={14} /> },
  { id: 'hr.manage', label: 'Gerir RH', category: 'RH', description: 'Contratar e editar dados de staff.', icon: <UsersIcon size={14} /> },

  // Operações & Projetos
  { id: 'projects.manage', label: 'Gerir Obras', category: 'Operações', description: 'Criar e editar projetos e obras.', icon: <Briefcase size={14} /> },
  { id: 'catalog.edit', label: 'Editar Catálogo', category: 'Operações', description: 'Adicionar e remover imóveis.', icon: <LayoutGrid size={14} /> },

  // Sistema & TI
  { id: 'admin.access', label: 'Acesso Admin', category: 'Sistema', description: 'Acesso total ao painel de TI.', icon: <Shield size={14} /> },
  { id: 'system.logs', label: 'Ver Auditoria', category: 'Sistema', description: 'Visualizar logs de alterações.', icon: <Terminal size={14} /> },
];

const AdminView: React.FC = () => {
  const [users, setUsers] = useState<Employee[]>([]);
  const [roles, setRoles] = useState<string[]>(Object.values(UserRole));
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [editingUser, setEditingUser] = useState<Employee | null>(null);
  const [showRolesModal, setShowRolesModal] = useState(false);
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState<{type: 'success' | 'error', text: string} | null>(null);
  const [copied, setCopied] = useState(false);

  const [newRoleName, setNewRoleName] = useState('');
  const [editingRole, setEditingRole] = useState<{old: string, new: string} | null>(null);

  const sqlSchema = `-- SCRIPT DE ATUALIZAÇÃO GLOBAL MONTE HUB
CREATE TABLE IF NOT EXISTS public.roles (
    id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
    name text UNIQUE NOT NULL,
    created_at timestamptz DEFAULT now()
);

INSERT INTO public.roles (name) 
VALUES 
('Administrador de Sistema'),
('Director Executivo (CEO)'),
('Gestor Geral Operacional'),
('Director Financeiro'),
('Gestor de Recursos Humanos'),
('Consultor Imobiliário'),
('Colaborador Geral')
ON CONFLICT (name) DO NOTHING;

ALTER TABLE public.roles ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Public Roles Access" ON public.roles FOR ALL USING (true);
`;

  useEffect(() => {
    fetchUsers();
    fetchRoles();
  }, []);

  async function fetchRoles() {
    try {
      const { data, error } = await supabase.from('roles').select('name').order('name');
      if (!error && data) {
        setRoles(data.map(r => r.name));
      }
    } catch (e) {
      console.warn("Tabela de cargos não encontrada.");
    }
  }

  async function fetchUsers() {
    setLoading(true);
    try {
      const { data, error } = await supabase.from('employees').select('*').order('name');
      if (!error) setUsers(data || []);
    } catch (e) {
      console.warn("Erro ao buscar usuários");
    } finally {
      setLoading(false);
    }
  }

  const handleUpdatePermissions = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingUser) return;

    setSaving(true);
    const { error } = await supabase
      .from('employees')
      .update({ 
        role: editingUser.role,
        permissions: editingUser.permissions || []
      })
      .eq('id', editingUser.id);

    if (error) {
      setMsg({ type: 'error', text: 'Erro ao sincronizar: ' + error.message });
    } else {
      setMsg({ type: 'success', text: 'Privilégios atualizados com sucesso!' });
      fetchUsers();
      setTimeout(() => setEditingUser(null), 1000);
    }
    setSaving(false);
    setTimeout(() => setMsg(null), 3000);
  };

  const togglePermission = (permId: string) => {
    if (!editingUser) return;
    const current = editingUser.permissions || [];
    const newPerms = current.includes(permId) 
      ? current.filter(p => p !== permId) 
      : [...current, permId];
    setEditingUser({ ...editingUser, permissions: newPerms });
  };

  const toggleCategory = (category: string, permsInCategory: PermissionDefinition[]) => {
    if (!editingUser) return;
    const currentPerms = editingUser.permissions || [];
    const idsInCategory = permsInCategory.map(p => p.id);
    const allSelected = idsInCategory.every(id => currentPerms.includes(id));

    let newPerms: string[];
    if (allSelected) {
      newPerms = currentPerms.filter(id => !idsInCategory.includes(id));
    } else {
      newPerms = Array.from(new Set([...currentPerms, ...idsInCategory]));
    }
    setEditingUser({ ...editingUser, permissions: newPerms });
  };

  const groupedPermissions = useMemo(() => {
    return GRANULAR_PERMISSIONS.reduce((acc, curr) => {
      if (!acc[curr.category]) acc[curr.category] = [];
      acc[curr.category].push(curr);
      return acc;
    }, {} as Record<string, PermissionDefinition[]>);
  }, []);

  const handleAddRole = async () => {
    if (!newRoleName) return;
    const { error } = await supabase.from('roles').insert([{ name: newRoleName }]);
    if (!error) {
      setNewRoleName('');
      fetchRoles();
    }
  };

  const handleDeleteRole = async (roleName: string) => {
    if (confirm(`Eliminar o cargo "${roleName}"?`)) {
      const { error } = await supabase.from('roles').delete().eq('name', roleName);
      if (!error) fetchRoles();
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-12">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tight">Administração TI</h1>
          <p className="text-slate-500 font-medium">Controlo de acessos, cargos dinâmicos e infraestrutura Cloud.</p>
        </div>
        <div className="flex items-center gap-3">
           <button onClick={() => { fetchUsers(); fetchRoles(); }} className="p-4 bg-white text-slate-400 hover:text-blue-600 rounded-3xl shadow-sm border border-slate-100 transition-all active:scale-95">
             <RefreshCw size={20} className={loading ? 'animate-spin' : ''} />
           </button>
           <div className="px-6 py-2.5 bg-indigo-600 text-white rounded-full text-[10px] font-black uppercase tracking-widest flex items-center gap-2 shadow-xl shadow-indigo-500/20">
             <Fingerprint size={16} /> Hub Autenticado
           </div>
        </div>
      </div>

      {/* SQL Script Box */}
      <div className="bg-slate-900 rounded-[3.5rem] p-10 text-white shadow-2xl relative overflow-hidden mb-8">
        <div className="flex items-center gap-4 mb-6">
          <Database size={24} className="text-indigo-400" />
          <div>
            <h3 className="text-xl font-black text-white">Sincronização Cloud</h3>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Execute este script no Supabase para atualizar as tabelas do sistema</p>
          </div>
        </div>
        <pre className="bg-slate-800 p-6 rounded-3xl text-[10px] text-indigo-300 font-mono overflow-x-auto mb-6 max-h-48 custom-scrollbar">
          {sqlSchema}
        </pre>
        <button 
          onClick={() => { navigator.clipboard.writeText(sqlSchema); setCopied(true); setTimeout(() => setCopied(false), 2000); }}
          className="flex items-center gap-2 px-6 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all"
        >
          {copied ? <Check size={14} /> : <Copy size={14} />} {copied ? 'Copiado!' : 'Copiar Script SQL'}
        </button>
      </div>

      {/* Users Table */}
      <div className="bg-white rounded-[3.5rem] border border-slate-100 shadow-sm overflow-hidden">
        <div className="p-8 border-b border-slate-50">
          <div className="relative flex-1 max-w-md">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
              placeholder="Pesquisar por nome ou email..." 
              className="w-full pl-12 pr-4 py-4 bg-slate-50 rounded-2xl border-none font-bold text-sm outline-none placeholder:text-slate-300"
            />
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50/50 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                <th className="px-10 py-6">Utilizador</th>
                <th className="px-10 py-6">Cargo</th>
                <th className="px-10 py-6">Privilégios</th>
                <th className="px-10 py-6 text-right">Acções</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {loading ? (
                <tr><td colSpan={4} className="py-24 text-center"><Loader2 className="animate-spin mx-auto text-blue-600" size={32} /></td></tr>
              ) : users.filter(u => (u.name + u.email).toLowerCase().includes(searchTerm.toLowerCase())).map(user => (
                <tr key={user.id} className="hover:bg-slate-50/50 transition-all group">
                  <td className="px-10 py-8">
                    <div className="flex items-center gap-5">
                      <img src={user.avatar} className="w-12 h-12 rounded-2xl object-cover shadow-sm" alt={user.name} />
                      <div>
                        <p className="text-sm font-black text-slate-900">{user.name}</p>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tight">{user.email}</p>
                      </div>
                    </div>
                  </td>
                  <td className="px-10 py-8">
                    <span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-lg uppercase tracking-wider border border-indigo-100">{user.role}</span>
                  </td>
                  <td className="px-10 py-8">
                    <div className="flex flex-wrap gap-1.5 max-w-[200px]">
                      {(user.permissions || []).length > 0 ? (
                        user.permissions?.slice(0, 3).map(p => (
                          <span key={p} className="text-[8px] font-black bg-slate-100 text-slate-500 px-2 py-0.5 rounded uppercase">{p.split('.')[1] || p}</span>
                        ))
                      ) : (
                        <span className="text-[8px] font-black text-slate-300 uppercase italic">Sem permissões</span>
                      )}
                      {(user.permissions || []).length > 3 && (
                        <span className="text-[8px] font-black bg-blue-50 text-blue-400 px-2 py-0.5 rounded uppercase">+{user.permissions!.length - 3}</span>
                      )}
                    </div>
                  </td>
                  <td className="px-10 py-8 text-right">
                    <button 
                      onClick={() => setEditingUser(user)}
                      className="p-3 bg-white text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 border border-slate-100 rounded-2xl transition-all shadow-sm active:scale-90"
                    >
                      <UserCog size={22} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* MODAL DE PERMISSÕES GRANULARES */}
      {editingUser && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white rounded-[4rem] p-12 max-w-4xl w-full shadow-2xl relative overflow-y-auto max-h-[90vh] border border-white/20">
            <button onClick={() => setEditingUser(null)} className="absolute top-10 right-10 text-slate-400 p-2 hover:bg-slate-50 rounded-xl transition-all"><X size={24} /></button>

            {/* Modal Header */}
            <div className="flex items-center gap-6 mb-12 border-b border-slate-100 pb-10">
               <div className="relative">
                 <img src={editingUser.avatar} className="w-20 h-20 rounded-[2rem] object-cover ring-4 ring-indigo-50" alt={editingUser.name} />
                 <div className="absolute -bottom-2 -right-2 w-8 h-8 bg-indigo-600 rounded-xl flex items-center justify-center text-white border-4 border-white">
                   <Shield size={16} />
                 </div>
               </div>
               <div>
                  <h2 className="text-3xl font-black text-slate-900 tracking-tight">{editingUser.name}</h2>
                  <p className="text-sm font-bold text-slate-400 uppercase tracking-widest mt-1 flex items-center gap-2">
                    <Fingerprint size={14} className="text-indigo-400" /> ID: {editingUser.id.substring(0, 8)} | {editingUser.email}
                  </p>
               </div>
            </div>

            <form onSubmit={handleUpdatePermissions} className="space-y-12">
              {/* Role Selection */}
              <div className="bg-slate-50 p-8 rounded-[2.5rem] border border-slate-100 flex flex-col md:flex-row md:items-center justify-between gap-6">
                <div className="flex-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 block mb-2">Cargo Principal no Hub</label>
                  <div className="relative group">
                    <select 
                      value={editingUser.role}
                      onChange={e => setEditingUser({...editingUser, role: e.target.value as any})}
                      className="w-full bg-white border border-slate-200 rounded-2xl p-4 text-sm font-bold text-slate-900 outline-none focus:ring-4 focus:ring-indigo-100 transition-all appearance-none cursor-pointer"
                    >
                      {roles.map(r => <option key={r} value={r}>{r}</option>)}
                    </select>
                    <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
                      <ChevronRight size={18} className="rotate-90" />
                    </div>
                  </div>
                </div>
                <button type="button" onClick={() => setShowRolesModal(true)} className="px-6 py-4 bg-white text-indigo-600 border border-indigo-100 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-50 transition-all flex items-center gap-2">
                  <Settings2 size={16} /> Configurar Cargos
                </button>
              </div>

              {/* Permissions Groups */}
              <div className="space-y-12">
                {Object.entries(groupedPermissions).map(([category, perms]) => {
                  const allSelected = perms.every(p => editingUser.permissions?.includes(p.id));
                  return (
                    <div key={category} className="space-y-6">
                      <div className="flex items-center justify-between px-2">
                        <h3 className="text-xs font-black uppercase tracking-widest text-slate-900 flex items-center gap-2">
                          <span className="w-1.5 h-1.5 bg-indigo-600 rounded-full"></span> {category}
                        </h3>
                        <button 
                          type="button" 
                          onClick={() => toggleCategory(category, perms)}
                          className="text-[9px] font-black uppercase tracking-widest text-indigo-600 hover:text-indigo-800 transition-colors bg-indigo-50 px-3 py-1 rounded-full"
                        >
                          {allSelected ? 'Desmarcar Tudo' : 'Selecionar Tudo'}
                        </button>
                      </div>

                      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                        {perms.map(p => {
                          const isActive = editingUser.permissions?.includes(p.id);
                          return (
                            <button
                              key={p.id} 
                              type="button" 
                              onClick={() => togglePermission(p.id)}
                              className={`flex flex-col p-6 rounded-[2rem] border-2 text-left transition-all relative group overflow-hidden ${
                                isActive 
                                ? 'bg-indigo-600 border-indigo-600 text-white shadow-xl shadow-indigo-500/20' 
                                : 'bg-white border-slate-100 text-slate-600 hover:border-indigo-200 hover:bg-slate-50'
                              }`}
                            >
                              <div className="flex items-center justify-between mb-3">
                                <div className={`p-2 rounded-xl ${isActive ? 'bg-white/20' : 'bg-slate-100 text-indigo-600'}`}>
                                  {p.icon}
                                </div>
                                {isActive && <CheckCircle2 size={16} className="text-white" />}
                              </div>
                              <span className="text-[11px] font-black uppercase tracking-tight mb-1">{p.label}</span>
                              <span className={`text-[9px] font-medium leading-tight line-clamp-2 ${isActive ? 'text-indigo-100' : 'text-slate-400'}`}>
                                {p.description}
                              </span>
                            </button>
                          );
                        })}
                      </div>
                    </div>
                  );
                })}
              </div>

              {msg && (
                <div className={`p-6 rounded-[2rem] text-[10px] font-black uppercase text-center animate-in zoom-in ${
                  msg.type === 'success' ? 'bg-green-50 text-green-600' : 'bg-red-50 text-red-600'
                }`}>
                  {msg.text}
                </div>
              )}

              <button 
                disabled={saving} 
                type="submit" 
                className="w-full py-6 bg-slate-900 text-white rounded-[2.5rem] font-black text-xs uppercase tracking-widest shadow-2xl hover:bg-indigo-600 transition-all active:scale-95 flex items-center justify-center gap-3 disabled:opacity-50"
              >
                {saving ? (
                  <Loader2 className="animate-spin" size={20} />
                ) : (
                  <><Save size={20} /> Sincronizar Privilégios no Supabase</>
                )}
              </button>
            </form>
          </div>
        </div>
      )}

      {/* Role Management Modal */}
      {showRolesModal && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-xl animate-in fade-in duration-200">
          <div className="bg-white rounded-[3rem] p-10 max-w-xl w-full shadow-2xl relative overflow-hidden">
            <button onClick={() => setShowRolesModal(false)} className="absolute top-8 right-8 text-slate-400 hover:text-slate-900"><X size={24} /></button>
            <div className="flex items-center gap-4 mb-8">
              <div className="w-12 h-12 bg-indigo-100 rounded-2xl flex items-center justify-center text-indigo-600"><Settings2 size={24} /></div>
              <div>
                <h3 className="text-xl font-black text-slate-900">Gestão de Cargos</h3>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Defina as funções master do ERP</p>
              </div>
            </div>

            <div className="flex gap-2 mb-8">
              <input 
                value={newRoleName} onChange={e => setNewRoleName(e.target.value)}
                placeholder="Ex: Supervisor Geral" 
                className="flex-1 bg-slate-50 border border-slate-100 rounded-2xl px-5 py-4 font-bold text-sm outline-none focus:ring-2 focus:ring-indigo-600"
              />
              <button onClick={handleAddRole} className="bg-indigo-600 text-white p-4 rounded-2xl hover:bg-indigo-700 transition-all active:scale-95"><Plus size={20} /></button>
            </div>

            <div className="space-y-3 max-h-80 overflow-y-auto pr-2 custom-scrollbar">
              {roles.map(role => (
                <div key={role} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100 group">
                  <span className="text-xs font-black text-slate-700 uppercase tracking-tight">{role}</span>
                  <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                    <button onClick={() => handleDeleteRole(role)} className="p-1.5 text-slate-400 hover:text-red-500 transition-colors"><Trash2 size={14} /></button>
                  </div>
                </div>
              ))}
            </div>

            <button onClick={() => setShowRolesModal(false)} className="w-full mt-8 py-4 bg-slate-900 text-white rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest hover:bg-indigo-600 transition-all">Fechar Gestor</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminView;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Shield, Key, Lock, Settings, UserCog, Save, 
  CheckCircle2, AlertCircle, Loader2, Search,
  ShieldAlert, Fingerprint, Zap, Database, Copy, Check, X,
  RefreshCw, Eye, Edit, Trash2, LayoutGrid, Briefcase, 
  Wallet, Users as UsersIcon, Terminal, Plus, Settings2,
  ChevronRight
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { UserRole, Employee } from '../types';

interface PermissionDefinition {
  id: string;
  label: string;
  category: 'Financeiro' | 'RH' | 'Operações' | 'Sistema';
  description: string;
  icon: React.ReactNode;
}

const GRANULAR_PERMISSIONS: PermissionDefinition[] = [
  // Financeiro
  { id: 'finance.view', label: 'Visualizar Financeiro', category: 'Financeiro', description: 'Acesso a relatórios e balanços.', icon: <Eye size={14} /> },
  { id: 'finance.edit', label: 'Lançamentos Financeiros', category: 'Financeiro', description: 'Criar receitas e despesas.', icon: <Edit size={14} /> },
  { id: 'finance.delete', label: 'Eliminar Registos', category: 'Financeiro', description: 'Remover transações do sistema.', icon: <Trash2 size={14} /> },

  // RH & Staff
  { id: 'hr.view', label: 'Ver Staff', category: 'RH', description: 'Visualizar lista de colaboradores.', icon: <Eye size={14} /> },
  { id: 'hr.manage', label: 'Gerir RH', category: 'RH', description: 'Contratar e editar dados de staff.', icon: <UsersIcon size={14} /> },

  // Operações & Projetos
  { id: 'projects.manage', label: 'Gerir Obras', category: 'Operações', description: 'Criar e editar projetos e obras.', icon: <Briefcase size={14} /> },
  { id: 'catalog.edit', label: 'Editar Catálogo', category: 'Operações', description: 'Adicionar e remover imóveis.', icon: <LayoutGrid size={14} /> },

  // Sistema & TI
  { id: 'admin.access', label: 'Acesso Admin', category: 'Sistema', description: 'Acesso total ao painel de TI.', icon: <Shield size={14} /> },
  { id: 'system.logs', label: 'Ver Auditoria', category: 'Sistema', description: 'Visualizar logs de alterações.', icon: <Terminal size={14} /> },
];

const AdminView: React.FC = () => {
  const [users, setUsers] = useState<Employee[]>([]);
  const [roles, setRoles] = useState<string[]>(Object.values(UserRole));
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [editingUser, setEditingUser] = useState<Employee | null>(null);
  const [showRolesModal, setShowRolesModal] = useState(false);
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState<{type: 'success' | 'error', text: string} | null>(null);
  const [copied, setCopied] = useState(false);

  const [newRoleName, setNewRoleName] = useState('');
  const [editingRole, setEditingRole] = useState<{old: string, new: string} | null>(null);

  const sqlSchema = `-- SCRIPT DE ATUALIZAÇÃO GLOBAL MONTE HUB
CREATE TABLE IF NOT EXISTS public.roles (
    id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
    name text UNIQUE NOT NULL,
    created_at timestamptz DEFAULT now()
);

INSERT INTO public.roles (name) 
VALUES 
('Administrador de Sistema'),
('Director Executivo (CEO)'),
('Gestor Geral Operacional'),
('Director Financeiro'),
('Gestor de Recursos Humanos'),
('Consultor Imobiliário'),
('Colaborador Geral')
ON CONFLICT (name) DO NOTHING;

ALTER TABLE public.roles ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Public Roles Access" ON public.roles FOR ALL USING (true);
`;

  useEffect(() => {
    fetchUsers();
    fetchRoles();
  }, []);

  async function fetchRoles() {
    try {
      const { data, error } = await supabase.from('roles').select('name').order('name');
      if (!error && data) {
        setRoles(data.map(r => r.name));
      }
    } catch (e) {
      console.warn("Tabela de cargos não encontrada.");
    }
  }

  async function fetchUsers() {
    setLoading(true);
    try {
      const { data, error } = await supabase.from('employees').select('*').order('name');
      if (!error) setUsers(data || []);
    } catch (e) {
      console.warn("Erro ao buscar usuários");
    } finally {
      setLoading(false);
    }
  }

  const handleUpdatePermissions = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingUser) return;

    setSaving(true);
    const { error } = await supabase
      .from('employees')
      .update({ 
        role: editingUser.role,
        permissions: editingUser.permissions || []
      })
      .eq('id', editingUser.id);

    if (error) {
      setMsg({ type: 'error', text: 'Erro ao sincronizar: ' + error.message });
    } else {
      setMsg({ type: 'success', text: 'Privilégios atualizados com sucesso!' });
      fetchUsers();
      setTimeout(() => setEditingUser(null), 1000);
    }
    setSaving(false);
    setTimeout(() => setMsg(null), 3000);
  };

  const togglePermission = (permId: string) => {
    if (!editingUser) return;
    const current = editingUser.permissions || [];
    const newPerms = current.includes(permId) 
      ? current.filter(p => p !== permId) 
      : [...current, permId];
    setEditingUser({ ...editingUser, permissions: newPerms });
  };

  const toggleCategory = (category: string, permsInCategory: PermissionDefinition[]) => {
    if (!editingUser) return;
    const currentPerms = editingUser.permissions || [];
    const idsInCategory = permsInCategory.map(p => p.id);
    const allSelected = idsInCategory.every(id => currentPerms.includes(id));

    let newPerms: string[];
    if (allSelected) {
      newPerms = currentPerms.filter(id => !idsInCategory.includes(id));
    } else {
      newPerms = Array.from(new Set([...currentPerms, ...idsInCategory]));
    }
    setEditingUser({ ...editingUser, permissions: newPerms });
  };

  const groupedPermissions = useMemo(() => {
    return GRANULAR_PERMISSIONS.reduce((acc, curr) => {
      if (!acc[curr.category]) acc[curr.category] = [];
      acc[curr.category].push(curr);
      return acc;
    }, {} as Record<string, PermissionDefinition[]>);
  }, []);

  const handleAddRole = async () => {
    if (!newRoleName) return;
    const { error } = await supabase.from('roles').insert([{ name: newRoleName }]);
    if (!error) {
      setNewRoleName('');
      fetchRoles();
    }
  };

  const handleDeleteRole = async (roleName: string) => {
    if (confirm(`Eliminar o cargo "${roleName}"?`)) {
      const { error } = await supabase.from('roles').delete().eq('name', roleName);
      if (!error) fetchRoles();
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-12">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tight">Administração TI</h1>
          <p className="text-slate-500 font-medium">Controlo de acessos, cargos dinâmicos e infraestrutura Cloud.</p>
        </div>
        <div className="flex items-center gap-3">
           <button onClick={() => { fetchUsers(); fetchRoles(); }} className="p-4 bg-white text-slate-400 hover:text-blue-600 rounded-3xl shadow-sm border border-slate-100 transition-all active:scale-95">
             <RefreshCw size={20} className={loading ? 'animate-spin' : ''} />
           </button>
           <div className="px-6 py-2.5 bg-indigo-600 text-white rounded-full text-[10px] font-black uppercase tracking-widest flex items-center gap-2 shadow-xl shadow-indigo-500/20">
             <Fingerprint size={16} /> Hub Autenticado
           </div>
        </div>
      </div>

      {/* SQL Script Box */}
      <div className="bg-slate-900 rounded-[3.5rem] p-10 text-white shadow-2xl relative overflow-hidden mb-8">
        <div className="flex items-center gap-4 mb-6">
          <Database size={24} className="text-indigo-400" />
          <div>
            <h3 className="text-xl font-black text-white">Sincronização Cloud</h3>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Execute este script no Supabase para atualizar as tabelas do sistema</p>
          </div>
        </div>
        <pre className="bg-slate-800 p-6 rounded-3xl text-[10px] text-indigo-300 font-mono overflow-x-auto mb-6 max-h-48 custom-scrollbar">
          {sqlSchema}
        </pre>
        <button 
          onClick={() => { navigator.clipboard.writeText(sqlSchema); setCopied(true); setTimeout(() => setCopied(false), 2000); }}
          className="flex items-center gap-2 px-6 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all"
        >
          {copied ? <Check size={14} /> : <Copy size={14} />} {copied ? 'Copiado!' : 'Copiar Script SQL'}
        </button>
      </div>

      {/* Users Table */}
      <div className="bg-white rounded-[3.5rem] border border-slate-100 shadow-sm overflow-hidden">
        <div className="p-8 border-b border-slate-50">
          <div className="relative flex-1 max-w-md">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
              placeholder="Pesquisar por nome ou email..." 
              className="w-full pl-12 pr-4 py-4 bg-slate-50 rounded-2xl border-none font-bold text-sm outline-none placeholder:text-slate-300"
            />
          </div>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50/50 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                <th className="px-10 py-6">Utilizador</th>
                <th className="px-10 py-6">Cargo</th>
                <th className="px-10 py-6">Privilégios</th>
                <th className="px-10 py-6 text-right">Acções</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {loading ? (
                <tr><td colSpan={4} className="py-24 text-center"><Loader2 className="animate-spin mx-auto text-blue-600" size={32} /></td></tr>
              ) : users.filter(u => (u.name + u.email).toLowerCase().includes(searchTerm.toLowerCase())).map(user => (
                <tr key={user.id} className="hover:bg-slate-50/50 transition-all group">
                  <td className="px-10 py-8">
                    <div className="flex items-center gap-5">
                      <img src={user.avatar} className="w-12 h-12 rounded-2xl object-cover shadow-sm" alt={user.name} />
                      <div>
                        <p className="text-sm font-black text-slate-900">{user.name}</p>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tight">{user.email}</p>
                      </div>
                    </div>
                  </td>
                  <td className="px-10 py-8">
                    <span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-lg uppercase tracking-wider border border-indigo-100">{user.role}</span>
                  </td>
                  <td className="px-10 py-8">
                    <div className="flex flex-wrap gap-1.5 max-w-[200px]">
                      {(user.permissions || []).length > 0 ? (
                        user.permissions?.slice(0, 3).map(p => (
                          <span key={p} className="text-[8px] font-black bg-slate-100 text-slate-500 px-2 py-0.5 rounded uppercase">{p.split('.')[1] || p}</span>
                        ))
                      ) : (
                        <span className="text-[8px] font-black text-slate-300 uppercase italic">Sem permissões</span>
                      )}
                      {(user.permissions || []).length > 3 && (
                        <span className="text-[8px] font-black bg-blue-50 text-blue-400 px-2 py-0.5 rounded uppercase">+{user.permissions!.length - 3}</span>
                      )}
                    </div>
                  </td>
                  <td className="px-10 py-8 text-right">
                    <button 
                      onClick={() => setEditingUser(user)}
                      className="p-3 bg-white text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 border border-slate-100 rounded-2xl transition-all shadow-sm active:scale-90"
                    >
                      <UserCog size={22} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* MODAL DE PERMISSÕES GRANULARES */}
      {editingUser && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white rounded-[4rem] p-12 max-w-4xl w-full shadow-2xl relative overflow-y-auto max-h-[90vh] border border-white/20">
            <button onClick={() => setEditingUser(null)} className="absolute top-10 right-10 text-slate-400 p-2 hover:bg-slate-50 rounded-xl transition-all"><X size={24} /></button>

            {/* Modal Header */}
            <div className="flex items-center gap-6 mb-12 border-b border-slate-100 pb-10">
               <div className="relative">
                 <img src={editingUser.avatar} className="w-20 h-20 rounded-[2rem] object-cover ring-4 ring-indigo-50" alt={editingUser.name} />
                 <div className="absolute -bottom-2 -right-2 w-8 h-8 bg-indigo-600 rounded-xl flex items-center justify-center text-white border-4 border-white">
                   <Shield size={16} />
                 </div>
               </div>
               <div>
                  <h2 className="text-3xl font-black text-slate-900 tracking-tight">{editingUser.name}</h2>
                  <p className="text-sm font-bold text-slate-400 uppercase tracking-widest mt-1 flex items-center gap-2">
                    <Fingerprint size={14} className="text-indigo-400" /> ID: {editingUser.id.substring(0, 8)} | {editingUser.email}
                  </p>
               </div>
            </div>

            <form onSubmit={handleUpdatePermissions} className="space-y-12">
              {/* Role Selection */}
              <div className="bg-slate-50 p-8 rounded-[2.5rem] border border-slate-100 flex flex-col md:flex-row md:items-center justify-between gap-6">
                <div className="flex-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 block mb-2">Cargo Principal no Hub</label>
                  <div className="relative group">
                    <select 
                      value={editingUser.role}
                      onChange={e => setEditingUser({...editingUser, role: e.target.value as any})}
                      className="w-full bg-white border border-slate-200 rounded-2xl p-4 text-sm font-bold text-slate-900 outline-none focus:ring-4 focus:ring-indigo-100 transition-all appearance-none cursor-pointer"
                    >
                      {roles.map(r => <option key={r} value={r}>{r}</option>)}
                    </select>
                    <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
                      <ChevronRight size={18} className="rotate-90" />
                    </div>
                  </div>
                </div>
                <button type="button" onClick={() => setShowRolesModal(true)} className="px-6 py-4 bg-white text-indigo-600 border border-indigo-100 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-50 transition-all flex items-center gap-2">
                  <Settings2 size={16} /> Configurar Cargos
                </button>
              </div>

              {/* Permissions Groups */}
              <div className="space-y-12">
                {/* Fix: Explicitly cast entries to handle unknown value types and fix TS errors (perms as PermissionDefinition[]) */}
                {(Object.entries(groupedPermissions) as [string, PermissionDefinition[]][]).map(([category, perms]) => {
                  const allSelected = perms.every(p => editingUser.permissions?.includes(p.id));
                  return (
                    <div key={category} className="space-y-6">
                      <div className="flex items-center justify-between px-2">
                        <h3 className="text-xs font-black uppercase tracking-widest text-slate-900 flex items-center gap-2">
                          <span className="w-1.5 h-1.5 bg-indigo-600 rounded-full"></span> {category}
                        </h3>
                        <button 
                          type="button" 
                          onClick={() => toggleCategory(category, perms)}
                          className="text-[9px] font-black uppercase tracking-widest text-indigo-600 hover:text-indigo-800 transition-colors bg-indigo-50 px-3 py-1 rounded-full"
                        >
                          {allSelected ? 'Desmarcar Tudo' : 'Selecionar Tudo'}
                        </button>
                      </div>

                      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                        {perms.map(p => {
                          const isActive = editingUser.permissions?.includes(p.id);
                          return (
                            <button
                              key={p.id} 
                              type="button" 
                              onClick={() => togglePermission(p.id)}
                              className={`flex flex-col p-6 rounded-[2rem] border-2 text-left transition-all relative group overflow-hidden ${
                                isActive 
                                ? 'bg-indigo-600 border-indigo-600 text-white shadow-xl shadow-indigo-500/20' 
                                : 'bg-white border-slate-100 text-slate-600 hover:border-indigo-200 hover:bg-slate-50'
                              }`}
                            >
                              <div className="flex items-center justify-between mb-3">
                                <div className={`p-2 rounded-xl ${isActive ? 'bg-white/20' : 'bg-slate-100 text-indigo-600'}`}>
                                  {p.icon}
                                </div>
                                {isActive && <CheckCircle2 size={16} className="text-white" />}
                              </div>
                              <span className="text-[11px] font-black uppercase tracking-tight mb-1">{p.label}</span>
                              <span className={`text-[9px] font-medium leading-tight line-clamp-2 ${isActive ? 'text-indigo-100' : 'text-slate-400'}`}>
                                {p.description}
                              </span>
                            </button>
                          );
                        })}
                      </div>
                    </div>
                  );
                })}
              </div>

              {msg && (
                <div className={`p-6 rounded-[2rem] text-[10px] font-black uppercase text-center animate-in zoom-in ${
                  msg.type === 'success' ? 'bg-green-50 text-green-600' : 'bg-red-50 text-red-600'
                }`}>
                  {msg.text}
                </div>
              )}

              <button 
                disabled={saving} 
                type="submit" 
                className="w-full py-6 bg-slate-900 text-white rounded-[2.5rem] font-black text-xs uppercase tracking-widest shadow-2xl hover:bg-indigo-600 transition-all active:scale-95 flex items-center justify-center gap-3 disabled:opacity-50"
              >
                {saving ? (
                  <Loader2 className="animate-spin" size={20} />
                ) : (
                  <><Save size={20} /> Sincronizar Privilégios no Supabase</>
                )}
              </button>
            </form>
          </div>
        </div>
      )}

      {/* Role Management Modal */}
      {showRolesModal && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-xl animate-in fade-in duration-200">
          <div className="bg-white rounded-[3rem] p-10 max-w-xl w-full shadow-2xl relative overflow-hidden">
            <button onClick={() => setShowRolesModal(false)} className="absolute top-8 right-8 text-slate-400 hover:text-slate-900"><X size={24} /></button>
            <div className="flex items-center gap-4 mb-8">
              <div className="w-12 h-12 bg-indigo-100 rounded-2xl flex items-center justify-center text-indigo-600"><Settings2 size={24} /></div>
              <div>
                <h3 className="text-xl font-black text-slate-900">Gestão de Cargos</h3>
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Defina as funções master do ERP</p>
              </div>
            </div>

            <div className="flex gap-2 mb-8">
              <input 
                value={newRoleName} onChange={e => setNewRoleName(e.target.value)}
                placeholder="Ex: Supervisor Geral" 
                className="flex-1 bg-slate-50 border border-slate-100 rounded-2xl px-5 py-4 font-bold text-sm outline-none focus:ring-2 focus:ring-indigo-600"
              />
              <button onClick={handleAddRole} className="bg-indigo-600 text-white p-4 rounded-2xl hover:bg-indigo-700 transition-all active:scale-95"><Plus size={20} /></button>
            </div>

            <div className="space-y-3 max-h-80 overflow-y-auto pr-2 custom-scrollbar">
              {roles.map(role => (
                <div key={role} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100 group">
                  <span className="text-xs font-black text-slate-700 uppercase tracking-tight">{role}</span>
                  <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                    <button onClick={() => handleDeleteRole(role)} className="p-1.5 text-slate-400 hover:text-red-500 transition-colors"><Trash2 size={14} /></button>
                  </div>
                </div>
              ))}
            </div>

            <button onClick={() => setShowRolesModal(false)} className="w-full mt-8 py-4 bg-slate-900 text-white rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest hover:bg-indigo-600 transition-all">Fechar Gestor</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminView;

import React, { useState, useEffect } from 'react';
import { 
  Plus, Users, DollarSign, UserCheck, AlertCircle, Clock, 
  Loader2, X, CheckCircle, Trash2, LayoutDashboard,
  Lock, Save, UserCog, Mail, Phone, CreditCard, Calendar as CalendarIcon, FileText,
  BadgeCheck, Wallet, Edit3, ShieldCheck, AlertTriangle
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { Employee, UserRole } from '../types';

const HRView: React.FC = () => {
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAddModal, setShowAddModal] = useState(false);
  const [editingEmpId, setEditingEmpId] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [saving, setSaving] = useState(false);

