import React, { useState, useEffect, useMemo } from 'react';
import { 
  Shield, Key, UserCog, Save, 
  CheckCircle2, Loader2, Search,
  Fingerprint, Database, Copy, Check, X,
  RefreshCw, Eye, Edit, Trash2, LayoutGrid, Briefcase, 
  Users as UsersIcon, Terminal, Plus, Settings2,
  ChevronRight
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { UserRole, Employee } from '../types';

interface PermissionDefinition {
  id: string;
  label: string;
  category: 'Financeiro' | 'RH' | 'Operações' | 'Sistema';
  description: string;
  icon: React.ReactNode;
}

const GRANULAR_PERMISSIONS: PermissionDefinition[] = [
  { id: 'finance.view', label: 'Ver Finanças', category: 'Financeiro', description: 'Consultar relatórios e saldos.', icon: <Eye size={14} /> },
  { id: 'finance.edit', label: 'Criar Lançamentos', category: 'Financeiro', description: 'Adicionar receitas e despesas.', icon: <Edit size={14} /> },
  { id: 'finance.delete', label: 'Remover Registos', category: 'Financeiro', description: 'Eliminar transações do fluxo.', icon: <Trash2 size={14} /> },
  { id: 'hr.view', label: 'Ver Staff', category: 'RH', description: 'Visualizar lista e status de contratos.', icon: <Eye size={14} /> },
  { id: 'hr.manage', label: 'Gerir RH', category: 'RH', description: 'Contratar e editar dados de staff.', icon: <UsersIcon size={14} /> },
  { id: 'projects.manage', label: 'Gerir Obras', category: 'Operações', description: 'Controlar projetos e orçamentos.', icon: <Briefcase size={14} /> },
  { id: 'catalog.edit', label: 'Editar Catálogo', category: 'Operações', description: 'Gerir imóveis e portfólio.', icon: <LayoutGrid size={14} /> },
  { id: 'admin.access', label: 'Full TI Admin', category: 'Sistema', description: 'Acesso total às ferramentas TI.', icon: <Shield size={14} /> },
  { id: 'system.logs', label: 'Logs Auditoria', category: 'Sistema', description: 'Rastrear todas as mudanças.', icon: <Terminal size={14} /> },
];

const AdminView: React.FC = () => {
  const [users, setUsers] = useState<Employee[]>([]);
  const [roles, setRoles] = useState<string[]>(Object.values(UserRole));
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [editingUser, setEditingUser] = useState<Employee | null>(null);
  const [showRolesModal, setShowRolesModal] = useState(false);
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState<{type: 'success' | 'error', text: string} | null>(null);
  const [copied, setCopied] = useState(false);

  const [newRoleName, setNewRoleName] = useState('');

  const sqlSchema = `-- SCRIPT MONTE HUB CLOUD
CREATE TABLE IF NOT EXISTS public.roles (
    id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
    name text UNIQUE NOT NULL,
    created_at timestamptz DEFAULT now()
);

INSERT INTO public.roles (name) 
VALUES 
('Administrador de Sistema'),
('Director Executivo (CEO)'),
('Gestor Geral Operacional'),
('Director Financeiro'),
('Gestor de Recursos Humanos'),
('Consultor Imobiliário'),
('Colaborador Geral')
ON CONFLICT (name) DO NOTHING;
`;

  useEffect(() => {
    fetchUsers();
    fetchRoles();
  }, []);

  async function fetchRoles() {
    try {
      const { data, error } = await supabase.from('roles').select('name').order('name');
      if (!error && data) setRoles(data.map(r => r.name));
    } catch (e) { console.warn("Roles table not found."); }
  }

  async function fetchUsers() {
    setLoading(true);
    try {
      const { data, error } = await supabase.from('employees').select('*').order('name');
      if (!error) setUsers(data || []);
    } catch (e) { console.warn("Error fetching users"); }
    finally { setLoading(false); }
  }

  const handleUpdatePermissions = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingUser) return;

    setSaving(true);
    const { error } = await supabase
      .from('employees')
      .update({ 
        role: editingUser.role,
        permissions: editingUser.permissions || []
      })
      .eq('id', editingUser.id);

    if (error) {
      setMsg({ type: 'error', text: 'Erro Cloud: ' + error.message });
    } else {
      setMsg({ type: 'success', text: 'Permissões sincronizadas com sucesso!' });
      fetchUsers();
      setTimeout(() => setEditingUser(null), 1200);
    }
    setSaving(false);
    setTimeout(() => setMsg(null), 3000);
  };

  const togglePermission = (permId: string) => {
    if (!editingUser) return;
    const current = editingUser.permissions || [];
    const newPerms = current.includes(permId) 
      ? current.filter(p => p !== permId) 
      : [...current, permId];
    setEditingUser({ ...editingUser, permissions: newPerms });
  };

  const toggleCategory = (category: string, permsInCategory: PermissionDefinition[]) => {
    if (!editingUser) return;
    const currentPerms = editingUser.permissions || [];
    const idsInCategory = permsInCategory.map(p => p.id);
    const allSelected = idsInCategory.every(id => currentPerms.includes(id));

    let newPerms: string[];
    if (allSelected) {
      newPerms = currentPerms.filter(id => !idsInCategory.includes(id));
    } else {
      newPerms = Array.from(new Set([...currentPerms, ...idsInCategory]));
    }
    setEditingUser({ ...editingUser, permissions: newPerms });
  };

  const groupedPermissions = useMemo(() => {
    return GRANULAR_PERMISSIONS.reduce((acc, curr) => {
      if (!acc[curr.category]) acc[curr.category] = [];
      acc[curr.category].push(curr);
      return acc;
    }, {} as Record<string, PermissionDefinition[]>);
  }, []);

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-16">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tight">Administração TI</h1>
          <p className="text-slate-500 font-medium italic">Monitorização e governança de privilégios cloud.</p>
        </div>
        <div className="flex items-center gap-3">
           <button onClick={() => { fetchUsers(); fetchRoles(); }} className="p-4 bg-white text-slate-400 hover:text-indigo-600 rounded-2xl shadow-sm border border-slate-100 transition-all active:scale-95">
             <RefreshCw size={20} className={loading ? 'animate-spin' : ''} />
           </button>
           <div className="px-6 py-2.5 bg-indigo-600 text-white rounded-full text-[10px] font-black uppercase tracking-widest flex items-center gap-2 shadow-xl shadow-indigo-500/20">
             <Fingerprint size={16} /> Monte Auth Ativo
           </div>
        </div>
      </div>

      {/* SQL Script Box */}
      <div className="bg-slate-900 rounded-[3rem] p-10 text-white shadow-2xl relative overflow-hidden group">
        <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-500/10 rounded-full blur-[100px] -translate-y-1/2 translate-x-1/2"></div>
        <div className="flex items-center gap-4 mb-6">
          <Database size={24} className="text-indigo-400" />
          <h3 className="text-xl font-black">Infraestrutura Supabase</h3>
        </div>
        <pre className="bg-slate-800 p-6 rounded-2xl text-[10px] text-indigo-200 font-mono overflow-x-auto mb-6 max-h-40 custom-scrollbar border border-white/5">
          {sqlSchema}
        </pre>
        <button 
          onClick={() => { navigator.clipboard.writeText(sqlSchema); setCopied(true); setTimeout(() => setCopied(false), 2000); }}
          className="flex items-center gap-2 px-6 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-black text-[10px] uppercase tracking-widest transition-all"
        >
          {copied ? <Check size={14} /> : <Copy size={14} />} {copied ? 'Copiado!' : 'Copiar Script SQL'}
        </button>
      </div>

      {/* Users Management */}
      <div className="bg-white rounded-[3.5rem] border border-slate-100 shadow-sm overflow-hidden">
        <div className="p-8 border-b border-slate-50 flex items-center justify-between">
          <div className="relative flex-1 max-w-md">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              value={searchTerm} onChange={e => setSearchTerm(e.target.value)}
              placeholder="Localizar utilizador por nome..." 
              className="w-full pl-12 pr-4 py-4 bg-slate-50 rounded-2xl border-none font-bold text-sm outline-none focus:ring-4 focus:ring-indigo-50 transition-all"
            />
          </div>
          <button onClick={() => setShowRolesModal(true)} className="px-6 py-3 bg-white text-indigo-600 border border-indigo-100 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-50 transition-all flex items-center gap-2">
            <Settings2 size={16} /> Cargos Master
          </button>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50/50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">
                <th className="px-10 py-6">Perfil do Colaborador</th>
                <th className="px-10 py-6 text-center">Acesso Granular</th>
                <th className="px-10 py-6 text-right">Acção</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {loading ? (
                <tr><td colSpan={3} className="py-24 text-center"><Loader2 className="animate-spin mx-auto text-indigo-600" size={32} /></td></tr>
              ) : users.filter(u => u.name.toLowerCase().includes(searchTerm.toLowerCase())).map(user => (
                <tr key={user.id} className="hover:bg-slate-50/50 transition-all group">
                  <td className="px-10 py-8">
                    <div className="flex items-center gap-5">
                      <img src={user.avatar} className="w-14 h-14 rounded-[1.5rem] object-cover shadow-sm ring-4 ring-white" alt={user.name} />
                      <div>
                        <p className="text-base font-black text-slate-900 leading-none mb-1">{user.name}</p>
                        <span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded-md uppercase tracking-wider">{user.role}</span>
                      </div>
                    </div>
                  </td>
                  <td className="px-10 py-8">
                    <div className="flex flex-wrap justify-center gap-1.5">
                      {user.permissions?.length ? user.permissions.slice(0, 3).map(p => (
                        <span key={p} className="text-[8px] font-black bg-slate-100 text-slate-500 px-2 py-0.5 rounded uppercase tracking-tighter">{p.split('.')[1] || p}</span>
                      )) : <span className="text-[9px] font-black text-slate-300 italic uppercase">Padrão</span>}
                      {user.permissions && user.permissions.length > 3 && <span className="text-[8px] font-black bg-indigo-600 text-white px-2 py-0.5 rounded uppercase">+{user.permissions.length - 3}</span>}
                    </div>
                  </td>
                  <td className="px-10 py-8 text-right">
                    <button onClick={() => setEditingUser(user)} className="p-3 bg-white text-slate-300 hover:text-indigo-600 hover:bg-indigo-50 border border-slate-100 rounded-xl transition-all shadow-sm active:scale-90">
                      <UserCog size={22} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Permissions Modal */}
      {editingUser && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-xl animate-in fade-in duration-300">
          <div className="bg-white rounded-[4rem] p-12 max-w-4xl w-full shadow-2xl relative overflow-y-auto max-h-[90vh]">
            <button onClick={() => setEditingUser(null)} className="absolute top-10 right-10 text-slate-400 p-2 hover:bg-slate-50 rounded-xl transition-all"><X size={28} /></button>

            <div className="flex items-center gap-6 mb-12 border-b border-slate-100 pb-10">
               <img src={editingUser.avatar} className="w-20 h-20 rounded-[2rem] object-cover ring-4 ring-indigo-50 shadow-lg" alt={editingUser.name} />
               <div>
                  <h2 className="text-3xl font-black text-slate-900 tracking-tight">{editingUser.name}</h2>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1 flex items-center gap-2">
                    <Shield size={14} className="text-indigo-600" /> Configuração de Privilégios Corporativos
                  </p>
               </div>
            </div>

            <form onSubmit={handleUpdatePermissions} className="space-y-12">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8 bg-slate-50 p-8 rounded-[2.5rem] border border-slate-100">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Cargo Principal</label>
                  <select 
                    value={editingUser.role}
                    onChange={e => setEditingUser({...editingUser, role: e.target.value as any})}
                    className="w-full bg-white border border-slate-200 rounded-2xl p-4 text-sm font-bold text-slate-900 outline-none focus:ring-4 focus:ring-indigo-100 transition-all appearance-none cursor-pointer"
                  >
                    {roles.map(r => <option key={r} value={r}>{r}</option>)}
                  </select>
                </div>
                <div className="flex items-end">
                   <div className="p-4 bg-indigo-600 rounded-2xl text-white text-[10px] font-black uppercase tracking-widest flex items-center gap-3 shadow-xl shadow-indigo-500/20 w-full justify-center">
                     <Fingerprint size={18} /> Modificando ID: {editingUser.id.substring(0, 8)}
                   </div>
                </div>
              </div>

              <div className="space-y-14">
                {(Object.entries(groupedPermissions) as [string, PermissionDefinition[]][]).map(([category, perms]) => {
                  const allSelected = perms.every(p => editingUser.permissions?.includes(p.id));
                  return (
                    <div key={category} className="space-y-6">
                      <div className="flex items-center justify-between px-2">
                        <h3 className="text-xs font-black uppercase tracking-widest text-slate-900 flex items-center gap-2">
                          <span className="w-2 h-2 bg-indigo-600 rounded-full"></span> {category}
                        </h3>
                        <button 
                          type="button" 
                          onClick={() => toggleCategory(category, perms)}
                          className="text-[9px] font-black uppercase tracking-widest text-indigo-600 hover:text-indigo-800 transition-colors bg-indigo-50 px-4 py-1.5 rounded-full"
                        >
                          {allSelected ? 'Remover Todos' : 'Ativar Todos'}
                        </button>
                      </div>

                      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                        {perms.map(p => {
                          const isActive = editingUser.permissions?.includes(p.id);
                          return (
                            <button
                              key={p.id} type="button" onClick={() => togglePermission(p.id)}
                              className={`flex flex-col p-6 rounded-[2rem] border-2 text-left transition-all relative group ${
                                isActive 
                                ? 'bg-indigo-600 border-indigo-600 text-white shadow-xl shadow-indigo-500/20' 
                                : 'bg-white border-slate-100 text-slate-600 hover:border-indigo-200'
                              }`}
                            >
                              <div className="flex items-center justify-between mb-3">
                                <div className={`p-2 rounded-xl ${isActive ? 'bg-white/20' : 'bg-slate-50 text-indigo-600'}`}>{p.icon}</div>
                                {isActive && <CheckCircle2 size={16} className="text-white" />}
                              </div>
                              <span className="text-[11px] font-black uppercase tracking-tighter mb-1">{p.label}</span>
                              <span className={`text-[9px] font-medium leading-tight line-clamp-2 ${isActive ? 'text-indigo-100' : 'text-slate-400'}`}>{p.description}</span>
                            </button>
                          );
                        })}
                      </div>
                    </div>
                  );
                })}
              </div>

              {msg && <div className={`p-6 rounded-[2rem] text-xs font-black uppercase tracking-widest text-center animate-in zoom-in ${msg.type === 'success' ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>{msg.text}</div>}

              <button disabled={saving} type="submit" className="w-full py-7 bg-slate-900 text-white rounded-[2.5rem] font-black text-xs uppercase tracking-widest shadow-2xl hover:bg-indigo-600 transition-all flex items-center justify-center gap-3 disabled:opacity-50 group">
                {saving ? <Loader2 className="animate-spin" size={20} /> : <><Save size={20} className="group-hover:scale-110 transition-transform" /> Sincronizar Permissões na Cloud</>}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminView;

import React, { useState, useEffect } from 'react';
import { 
  TrendingUp, Users, Sparkles, ShieldCheck, 
  Plus, X, Save, ArrowUpCircle, 
  ArrowDownCircle, Building2, Wallet,
  MessageSquare, Mail, Trash2, Clock, AlertTriangle,
  Tag, Loader2
} from 'lucide-react';
import { getStrategicInsight } from '../geminiService';
import { supabase } from '../supabaseClient';
import { Employee } from '../types';

const DashboardView: React.FC = () => {
  const [insight, setInsight] = useState<string>('Gerando análise estratégica...');
  const [stats, setStats] = useState({
    employees: 0, properties: 0, revenue: 0, expenses: 0, contacts: 0
  });
  const [dbError, setDbError] = useState<string | null>(null);
  const [staff, setStaff] = useState<Employee[]>([]);
  const [contacts, setContacts] = useState<any[]>([]);
  const [categories, setCategories] = useState<string[]>(['Vendas', 'Aluguel', 'Manutenção', 'Marketing', 'Limpeza', 'TI']);
  const [loading, setLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);

  // Modals
  const [showFinanceModal, setShowFinanceModal] = useState(false);
  const [viewingContact, setViewingContact] = useState<any>(null);
  const [isAddingCategory, setIsAddingCategory] = useState(false);
  const [newCategoryName, setNewCategoryName] = useState('');

  const [newTransaction, setNewTransaction] = useState({
    description: '', amount: '', type: 'RECEITA' as 'RECEITA' | 'DESPESA', category: 'Vendas'
  });

  useEffect(() => {
    fetchData();
    const fetchInsight = async () => {
      try {
        const msg = await getStrategicInsight("Análise de crescimento para Monte Imobiliária na Beira.");
        setInsight(typeof msg === 'string' ? msg : 'Análise gerada com sucesso.');
      } catch (e) {
        setInsight('IA Temporariamente indisponível.');
      }
    };
    fetchInsight();
  }, []);

  async function fetchData() {
    setLoading(true);
    setDbError(null);
    try {
      const [emp, prop, trans, cont] = await Promise.all([
        supabase.from('employees').select('*').order('name'),
        supabase.from('properties').select('id', { count: 'exact' }),
        supabase.from('transactions').select('*'),
        supabase.from('contact_requests').select('*').order('created_at', { ascending: false })
      ]);

      const txs = trans.data || [];
      const rev = txs.filter(t => t.type === 'RECEITA').reduce((a, b) => a + Number(b.amount || 0), 0);
      const exp = txs.filter(t => t.type === 'DESPESA').reduce((a, b) => a + Number(b.amount || 0), 0);

      setStats({
        employees: emp.data?.length || 0,
        properties: prop.count || 0,
        revenue: rev,
        expenses: exp,
        contacts: cont.data?.length || 0
      });
      setStaff(emp.data || []);
      setContacts(cont.data || []);

      const uniqueCats = Array.from(new Set([...categories, ...txs.map(t => t.category)]));
      setCategories(uniqueCats);
    } catch (err: any) {
      console.error("Dashboard Fetch Error:", err);
      setDbError(err.message || 'Erro inesperado ao carregar dados.');
    } finally {
      setLoading(false);
    }
  }

  const deleteContact = async (id: string) => {
    if (confirm('Deseja arquivar esta mensagem?')) {
      const { error } = await supabase.from('contact_requests').delete().eq('id', id);
      if (!error) fetchData();
    }
  };

  const handleSaveTransaction = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSaving(true);

    const finalCategory = isAddingCategory ? newCategoryName.trim() : newTransaction.category;

    if (!finalCategory) {
      alert("Por favor, selecione ou defina uma categoria.");
      setIsSaving(false);
      return;
    }

    const { error } = await supabase.from('transactions').insert([{
      description: newTransaction.description,
      amount: Number(newTransaction.amount),
      type: newTransaction.type,
      category: finalCategory,
      date: new Date().toISOString().split('T')[0]
    }]);

    if (!error) {
      // Se era uma nova categoria, adiciona à lista local
      if (isAddingCategory && !categories.includes(finalCategory)) {
        setCategories(prev => [...prev, finalCategory]);
      }

      setShowFinanceModal(false);
      setIsAddingCategory(false);
      setNewCategoryName('');
      setNewTransaction({ description: '', amount: '', type: 'RECEITA', category: 'Vendas' });
      fetchData();
    } else {
      alert("Erro ao salvar: " + error.message);
    }
    setIsSaving(false);
  };

  return (
    <div className="space-y-8 pb-12 animate-in fade-in duration-700">
      {/* Top Branding Bar */}
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div className="flex items-center gap-5">
          <div className="w-16 h-16 bg-blue-600 rounded-3xl flex items-center justify-center shadow-2xl shadow-blue-500/30 p-2">
            <img src="https://i.ibb.co/LzfNdf7Y/building-logo.png" className="w-full h-full object-contain brightness-0 invert" alt="Monte Logo" />
          </div>
          <div>
            <h1 className="text-4xl font-black text-slate-900 tracking-tight">Monte Hub</h1>
            <p className="text-slate-500 font-bold text-xs uppercase tracking-widest flex items-center gap-2">
              <ShieldCheck size={14} className="text-green-500" /> Comando Integrado
            </p>
          </div>
        </div>
        <div className="flex gap-3">
           <button onClick={() => setShowFinanceModal(true)} className="flex items-center gap-2 px-6 py-4 bg-blue-600 text-white rounded-2xl font-black text-xs shadow-xl shadow-blue-500/20 hover:scale-105 transition-all">
             <Plus size={16} /> Lançamento Rápido
           </button>
        </div>
      </div>

      {/* Database Setup Alert */}
      {dbError && (
        <div className="p-6 bg-red-50 border-l-4 border-red-500 rounded-3xl flex flex-col md:flex-row items-center gap-4 text-red-700 animate-in slide-in-from-top-4">
          <AlertTriangle size={32} className="shrink-0" />
          <div className="flex-1">
            <h4 className="font-black text-sm uppercase">Configuração Cloud Pendente</h4>
            <p className="text-xs font-bold leading-relaxed">{dbError}</p>
          </div>
          <button onClick={() => fetchData()} className="px-6 py-2 bg-red-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-red-700">Recarregar</button>
        </div>
      )}

      {/* KPI Tiles */}
      <div className="grid grid-cols-2 lg:grid-cols-5 gap-6">
        {[
          { label: 'Balanço Geral', value: stats.revenue - stats.expenses, icon: <Wallet size={20} />, color: 'emerald' },
          { label: 'Património Catálogo', value: stats.properties, icon: <Building2 size={20} />, color: 'blue' },
          { label: 'Total Staff', value: stats.employees, icon: <Users size={20} />, color: 'indigo' },
          { label: 'Mensagens Pendentes', value: stats.contacts, icon: <MessageSquare size={20} />, color: 'amber' },
          { label: 'Saídas Operacionais', value: stats.expenses, icon: <ArrowDownCircle size={20} />, color: 'rose' },
        ].map((tile, i) => (
          <div key={i} className="bg-white p-6 rounded-[2.5rem] border border-slate-100 shadow-sm hover:shadow-lg transition-all">
            <div className={`w-10 h-10 rounded-xl flex items-center justify-center mb-4 ${
              tile.color === 'emerald' ? 'bg-emerald-50 text-emerald-600' :
              tile.color === 'blue' ? 'bg-blue-50 text-blue-600' :
              tile.color === 'indigo' ? 'bg-indigo-50 text-indigo-600' :
              tile.color === 'amber' ? 'bg-amber-50 text-amber-600' :
              'bg-rose-50 text-rose-600'
            }`}>
              {tile.icon}
            </div>
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">{tile.label}</p>
            <p className="text-2xl font-black text-slate-900">
              {Number(tile.value).toLocaleString()} {i === 1 || i === 2 || i === 3 ? '' : 'MT'}
            </p>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
        <div className="xl:col-span-2 space-y-8">

          {/* Messages Center */}
          <div className="bg-white p-10 rounded-[3.5rem] border border-slate-100 shadow-sm">
            <div className="flex items-center justify-between mb-10">
              <div>
                <h3 className="text-2xl font-black text-slate-900">Central de Contactos</h3>
                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-1">Inbox do Site Público</p>
              </div>
            </div>

            <div className="space-y-4 max-h-[500px] overflow-y-auto pr-2 custom-scrollbar">
              {contacts.length === 0 ? (
                <div className="py-12 text-center text-slate-400 italic text-sm">
                  {dbError ? 'Tabelas não configuradas.' : 'Nenhuma mensagem disponível.'}
                </div>
              ) : contacts.map((msg) => (
                <div key={msg.id} className="p-6 bg-slate-50 rounded-[2.5rem] flex items-center justify-between group hover:bg-white hover:shadow-xl transition-all border border-transparent hover:border-slate-100">
                  <div className="flex items-center gap-5">
                    <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center text-blue-600 shadow-sm font-black text-lg uppercase">
                      {String(msg.name || 'U').charAt(0)}
                    </div>
                    <div>
                      <div className="flex items-center gap-2">
                        <p className="text-sm font-black text-slate-900">{msg.name}</p>
                        <span className="text-[8px] font-black bg-blue-600 text-white px-1.5 py-0.5 rounded-md uppercase">{msg.subject}</span>
                      </div>
                      <p className="text-[10px] font-bold text-slate-400 truncate max-w-[200px] md:max-w-md">{msg.message}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-4">
                    <button onClick={() => setViewingContact(msg)} className="p-3 bg-white text-blue-600 rounded-xl hover:bg-blue-600 hover:text-white transition-all shadow-sm">
                      <Mail size={16} />
                    </button>
                    <button onClick={() => deleteContact(msg.id)} className="p-3 bg-white text-slate-300 hover:text-red-500 rounded-xl transition-all">
                      <Trash2 size={16} />
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Strategy Section */}
          <div className="bg-slate-900 p-10 rounded-[3.5rem] text-white shadow-2xl relative overflow-hidden">
            <div className="flex items-center gap-4 mb-6">
              <Sparkles size={24} className="text-blue-400" />
              <h2 className="text-xl font-black">Monte Strategy Insights</h2>
            </div>
            <p className="text-blue-50 leading-relaxed text-base italic border-l-2 border-blue-600 pl-6">
              "{String(insight)}"
            </p>
          </div>
        </div>

        {/* Sidebar Summary */}
        <div className="space-y-8">
          <div className="bg-white p-10 rounded-[3.5rem] border border-slate-100 shadow-sm">
            <h3 className="text-xl font-black text-slate-900 mb-8 flex items-center gap-2">
              <TrendingUp className="text-blue-600" size={20} /> Finanças Cloud
            </h3>
            <div className="space-y-5">
               <div className="p-5 bg-green-50 rounded-2xl border border-green-100 flex items-center justify-between">
                  <div>
                    <p className="text-[10px] font-black text-green-600 uppercase">Receitas</p>
                    <p className="text-lg font-black text-green-900">{stats.revenue.toLocaleString()} MT</p>
                  </div>
                  <ArrowUpCircle className="text-green-600" />
               </div>
               <div className="p-5 bg-rose-50 rounded-2xl border border-rose-100 flex items-center justify-between">
                  <div>
                    <p className="text-[10px] font-black text-rose-600 uppercase">Despesas</p>
                    <p className="text-lg font-black text-rose-900">{stats.expenses.toLocaleString()} MT</p>
                  </div>
                  <ArrowDownCircle className="text-rose-600" />
               </div>
            </div>
          </div>
        </div>
      </div>

      {/* Quick Launch Finance Modal */}
      {showFinanceModal && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-900/70 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white rounded-[3.5rem] p-12 max-w-xl w-full shadow-2xl relative">
            <button onClick={() => setShowFinanceModal(false)} className="absolute top-10 right-10 text-slate-400 p-2 hover:bg-slate-50 rounded-xl transition-all"><X size={24} /></button>
            <h2 className="text-3xl font-black text-slate-900 mb-8 flex items-center gap-3"><Wallet className="text-blue-600" /> Lançamento Rápido</h2>

            <form onSubmit={handleSaveTransaction} className="space-y-6">
              <div className="flex bg-slate-100 p-1.5 rounded-2xl">
                <button 
                  type="button"
                  onClick={() => setNewTransaction({...newTransaction, type: 'RECEITA'})}
                  className={`flex-1 py-3 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${newTransaction.type === 'RECEITA' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}
                >Receita</button>
                <button 
                  type="button"
                  onClick={() => setNewTransaction({...newTransaction, type: 'DESPESA'})}
                  className={`flex-1 py-3 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${newTransaction.type === 'DESPESA' ? 'bg-white text-rose-600 shadow-sm' : 'text-slate-500'}`}
                >Despesa</button>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Descrição</label>
                <input 
                  required
                  placeholder="Ex: Consultoria de Venda..."
                  value={newTransaction.description}
                  onChange={e => setNewTransaction({...newTransaction, description: e.target.value})}
                  className="w-full bg-slate-50 border border-slate-100 p-4 rounded-2xl font-bold"
                />
              </div>

              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Montante (MT)</label>
                  <input 
                    required
                    type="number"
                    placeholder="0.00"
                    value={newTransaction.amount}
                    onChange={e => setNewTransaction({...newTransaction, amount: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-100 p-4 rounded-2xl font-black text-blue-600"
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex justify-between items-center">
                    Categoria
                    <button 
                      type="button" 
                      onClick={() => setIsAddingCategory(!isAddingCategory)}
                      className={`p-1 rounded-md transition-colors ${isAddingCategory ? 'bg-blue-600 text-white' : 'text-blue-600 hover:bg-blue-50'}`}
                    >
                      <Plus size={14} />
                    </button>
                  </label>

                  {isAddingCategory ? (
                    <div className="relative">
                      <Tag className="absolute left-4 top-1/2 -translate-y-1/2 text-blue-400" size={16} />
                      <input 
                        autoFocus
                        placeholder="Nova Categoria..."
                        value={newCategoryName}
                        onChange={e => setNewCategoryName(e.target.value)}
                        className="w-full bg-slate-50 border border-blue-200 p-4 pl-12 rounded-2xl font-bold text-blue-600 placeholder:text-blue-300"
                      />
                    </div>
                  ) : (
                    <select 
                      value={newTransaction.category}
                      onChange={e => setNewTransaction({...newTransaction, category: e.target.value})}
                      className="w-full bg-slate-50 border border-slate-100 p-4 rounded-2xl font-bold outline-none cursor-pointer"
                    >
                      {categories.map(cat => <option key={cat} value={cat}>{cat}</option>)}
                    </select>
                  )}
                </div>
              </div>

              <button 
                disabled={isSaving}
                type="submit" 
                className="w-full bg-slate-900 text-white p-6 rounded-[2.5rem] font-black flex items-center justify-center gap-3 hover:bg-blue-600 transition-all shadow-xl active:scale-95 disabled:opacity-50"
              >
                {isSaving ? <Loader2 className="animate-spin" /> : <><Save size={20} /> Guardar Lançamento</>}
              </button>
            </form>
          </div>
        </div>
      )}

      {/* Message View Modal */}
      {viewingContact && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-900/70 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white rounded-[3.5rem] p-12 max-w-xl w-full shadow-2xl relative">
            <button onClick={() => setViewingContact(null)} className="absolute top-10 right-10 text-slate-400 p-2 hover:bg-slate-50 rounded-xl transition-all"><X size={24} /></button>
            <span className="text-[10px] font-black text-blue-600 uppercase tracking-widest bg-blue-50 px-3 py-1 rounded-lg mb-4 inline-block">{viewingContact.subject}</span>
            <h2 className="text-3xl font-black text-slate-900 mb-2">{viewingContact.name}</h2>
            <p className="text-slate-500 font-bold text-sm mb-8 flex items-center gap-2"><Mail size={16} /> {viewingContact.email}</p>
            <div className="p-8 bg-slate-50 rounded-[2.5rem] mb-8 border border-slate-100">
               <p className="text-slate-700 leading-relaxed font-medium whitespace-pre-wrap">{viewingContact.message}</p>
            </div>
            <div className="flex gap-4">
              <a href={`mailto:${viewingContact.email}`} className="flex-1 bg-blue-600 text-white py-5 rounded-[2rem] font-black text-center shadow-xl shadow-blue-500/20 hover:bg-blue-700 transition-all">Responder</a>
              <button onClick={() => setViewingContact(null)} className="flex-1 bg-slate-100 text-slate-600 py-5 rounded-[2rem] font-black hover:bg-slate-200 transition-all">Fechar</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default DashboardView;

import React, { useState, useEffect } from 'react';
import { 
  TrendingUp, Users, Sparkles, ShieldCheck, 
  Plus, X, Save, ArrowUpCircle, 
  ArrowDownCircle, Building2, Wallet,
  MessageSquare, Mail, Trash2, Clock, AlertTriangle,
  Tag, Loader2, ChevronLeft, ChevronRight, UserCircle
} from 'lucide-react';
import { getStrategicInsight } from '../geminiService';
import { supabase } from '../supabaseClient';
import { Employee } from '../types';

const ITEMS_PER_PAGE = 10;

const DashboardView: React.FC = () => {
  const [insight, setInsight] = useState<string>('Gerando análise estratégica...');
  const [stats, setStats] = useState({
    employees: 0, properties: 0, revenue: 0, expenses: 0, contacts: 0
  });
  const [dbError, setDbError] = useState<string | null>(null);

  // Lists Data
  const [staff, setStaff] = useState<Employee[]>([]);
  const [contacts, setContacts] = useState<any[]>([]);
  const [categories, setCategories] = useState<string[]>(['Vendas', 'Aluguel', 'Manutenção', 'Marketing', 'Limpeza', 'TI']);

  // Pagination State
  const [contactsPage, setContactsPage] = useState(1);
  const [staffPage, setStaffPage] = useState(1);
  const [totalContacts, setTotalContacts] = useState(0);
  const [totalStaff, setTotalStaff] = useState(0);

  const [loading, setLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);

  // Modals
  const [showFinanceModal, setShowFinanceModal] = useState(false);
  const [viewingContact, setViewingContact] = useState<any>(null);
  const [isAddingCategory, setIsAddingCategory] = useState(false);
  const [newCategoryName, setNewCategoryName] = useState('');

  const [newTransaction, setNewTransaction] = useState({
    description: '', amount: '', type: 'RECEITA' as 'RECEITA' | 'DESPESA', category: 'Vendas'
  });

  useEffect(() => {
    fetchGlobalStats();
    fetchInsight();
  }, []);

  useEffect(() => {
    fetchContacts();
  }, [contactsPage]);

  useEffect(() => {
    fetchStaff();
  }, [staffPage]);

  const fetchInsight = async () => {
    try {
      const msg = await getStrategicInsight("Análise de crescimento para Monte Imobiliária na Beira.");
      setInsight(typeof msg === 'string' ? msg : 'Análise gerada com sucesso.');
    } catch (e) {
      setInsight('IA Temporariamente indisponível.');
    }
  };

  async function fetchGlobalStats() {
    try {
      const [prop, trans, contCount, empCount] = await Promise.all([
        supabase.from('properties').select('id', { count: 'exact' }),
        supabase.from('transactions').select('*'),
        supabase.from('contact_requests').select('id', { count: 'exact', head: true }),
        supabase.from('employees').select('id', { count: 'exact', head: true })
      ]);

      const txs = trans.data || [];
      const rev = txs.filter(t => t.type === 'RECEITA').reduce((a, b) => a + Number(b.amount || 0), 0);
      const exp = txs.filter(t => t.type === 'DESPESA').reduce((a, b) => a + Number(b.amount || 0), 0);

      setStats({
        employees: empCount.count || 0,
        properties: prop.count || 0,
        revenue: rev,
        expenses: exp,
        contacts: contCount.count || 0
      });
      setTotalContacts(contCount.count || 0);
      setTotalStaff(empCount.count || 0);

      const uniqueCats = Array.from(new Set([...categories, ...txs.map(t => t.category)]));
      setCategories(uniqueCats);
    } catch (err: any) {
      setDbError(err.message);
    }
  }

  async function fetchContacts() {
    const from = (contactsPage - 1) * ITEMS_PER_PAGE;
    const to = from + ITEMS_PER_PAGE - 1;

    const { data, count, error } = await supabase
      .from('contact_requests')
      .select('*', { count: 'exact' })
      .order('created_at', { ascending: false })
      .range(from, to);

    if (!error) {
      setContacts(data || []);
      if (count !== null) setTotalContacts(count);
    }
  }

  async function fetchStaff() {
    setLoading(true);
    const from = (staffPage - 1) * ITEMS_PER_PAGE;
    const to = from + ITEMS_PER_PAGE - 1;

    const { data, count, error } = await supabase
      .from('employees')
      .select('*', { count: 'exact' })
      .order('name')
      .range(from, to);

    if (!error) {
      setStaff(data || []);
      if (count !== null) setTotalStaff(count);
    }
    setLoading(false);
  }

  const deleteContact = async (id: string) => {
    if (confirm('Deseja arquivar esta mensagem?')) {
      const { error } = await supabase.from('contact_requests').delete().eq('id', id);
      if (!error) fetchContacts();
    }
  };

  const handleSaveTransaction = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSaving(true);

    const finalCategory = isAddingCategory ? newCategoryName.trim() : newTransaction.category;

    if (!finalCategory) {
      alert("Por favor, selecione ou defina uma categoria.");
      setIsSaving(false);
      return;
    }

    const { error } = await supabase.from('transactions').insert([{
      description: newTransaction.description,
      amount: Number(newTransaction.amount),
      type: newTransaction.type,
      category: finalCategory,
      date: new Date().toISOString().split('T')[0]
    }]);

    if (!error) {
      if (isAddingCategory && !categories.includes(finalCategory)) {
        setCategories(prev => [...prev, finalCategory]);
      }
      setShowFinanceModal(false);
      setIsAddingCategory(false);
      setNewCategoryName('');
      setNewTransaction({ description: '', amount: '', type: 'RECEITA', category: 'Vendas' });
      fetchGlobalStats();
    } else {
      alert("Erro ao salvar: " + error.message);
    }
    setIsSaving(false);
  };

  const totalContactsPages = Math.ceil(totalContacts / ITEMS_PER_PAGE);
  const totalStaffPages = Math.ceil(totalStaff / ITEMS_PER_PAGE);

  return (
    <div className="space-y-8 pb-12 animate-in fade-in duration-700">
      {/* Top Branding Bar */}
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
        <div className="flex items-center gap-5">
          <div className="w-16 h-16 bg-blue-600 rounded-3xl flex items-center justify-center shadow-2xl shadow-blue-500/30 p-2">
            <img src="https://i.ibb.co/LzfNdf7Y/building-logo.png" className="w-full h-full object-contain brightness-0 invert" alt="Monte Logo" />
          </div>
          <div>
            <h1 className="text-4xl font-black text-slate-900 tracking-tight">Monte Hub</h1>
            <p className="text-slate-500 font-bold text-xs uppercase tracking-widest flex items-center gap-2">
              <ShieldCheck size={14} className="text-green-500" /> Comando Integrado
            </p>
          </div>
        </div>
        <div className="flex gap-3">
           <button onClick={() => setShowFinanceModal(true)} className="flex items-center gap-2 px-6 py-4 bg-blue-600 text-white rounded-2xl font-black text-xs shadow-xl shadow-blue-500/20 hover:scale-105 transition-all">
             <Plus size={16} /> Lançamento Rápido
           </button>
        </div>
      </div>

      {dbError && (
        <div className="p-6 bg-red-50 border-l-4 border-red-500 rounded-3xl flex flex-col md:flex-row items-center gap-4 text-red-700 animate-in slide-in-from-top-4">
          <AlertTriangle size={32} className="shrink-0" />
          <div className="flex-1">
            <h4 className="font-black text-sm uppercase">Configuração Cloud Pendente</h4>
            <p className="text-xs font-bold leading-relaxed">{dbError}</p>
          </div>
          <button onClick={() => { fetchGlobalStats(); fetchContacts(); fetchStaff(); }} className="px-6 py-2 bg-red-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-red-700">Recarregar</button>
        </div>
      )}

      {/* KPI Tiles */}
      <div className="grid grid-cols-2 lg:grid-cols-5 gap-6">
        {[
          { label: 'Balanço Geral', value: stats.revenue - stats.expenses, icon: <Wallet size={20} />, color: 'emerald' },
          { label: 'Património Catálogo', value: stats.properties, icon: <Building2 size={20} />, color: 'blue' },
          { label: 'Total Staff', value: stats.employees, icon: <Users size={20} />, color: 'indigo' },
          { label: 'Mensagens Pendentes', value: stats.contacts, icon: <MessageSquare size={20} />, color: 'amber' },
          { label: 'Saídas Operacionais', value: stats.expenses, icon: <ArrowDownCircle size={20} />, color: 'rose' },
        ].map((tile, i) => (
          <div key={i} className="bg-white p-6 rounded-[2.5rem] border border-slate-100 shadow-sm hover:shadow-lg transition-all">
            <div className={`w-10 h-10 rounded-xl flex items-center justify-center mb-4 ${
              tile.color === 'emerald' ? 'bg-emerald-50 text-emerald-600' :
              tile.color === 'blue' ? 'bg-blue-50 text-blue-600' :
              tile.color === 'indigo' ? 'bg-indigo-50 text-indigo-600' :
              tile.color === 'amber' ? 'bg-amber-50 text-amber-600' :
              'bg-rose-50 text-rose-600'
            }`}>
              {tile.icon}
            </div>
            <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">{tile.label}</p>
            <p className="text-2xl font-black text-slate-900">
              {Number(tile.value).toLocaleString()} {i === 1 || i === 2 || i === 3 ? '' : 'MT'}
            </p>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
        <div className="xl:col-span-2 space-y-8">

          {/* Messages Center */}
          <div className="bg-white p-10 rounded-[3.5rem] border border-slate-100 shadow-sm">
            <div className="flex items-center justify-between mb-10">
              <div>
                <h3 className="text-2xl font-black text-slate-900">Central de Contactos</h3>
                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-1">Inbox do Site Público</p>
              </div>
              <div className="flex items-center gap-3">
                <button 
                  disabled={contactsPage === 1}
                  onClick={() => setContactsPage(p => Math.max(1, p - 1))}
                  className="p-2 bg-slate-50 text-slate-400 hover:text-blue-600 rounded-xl disabled:opacity-30 transition-all"
                >
                  <ChevronLeft size={20} />
                </button>
                <span className="text-[10px] font-black uppercase text-slate-400">Pág. {contactsPage} de {totalContactsPages || 1}</span>
                <button 
                  disabled={contactsPage >= totalContactsPages}
                  onClick={() => setContactsPage(p => p + 1)}
                  className="p-2 bg-slate-50 text-slate-400 hover:text-blue-600 rounded-xl disabled:opacity-30 transition-all"
                >
                  <ChevronRight size={20} />
                </button>
              </div>
            </div>

            <div className="space-y-4 max-h-[600px] overflow-y-auto pr-2 custom-scrollbar">
              {contacts.length === 0 ? (
                <div className="py-20 text-center text-slate-400 italic text-sm">
                   Nenhuma mensagem nesta página.
                </div>
              ) : contacts.map((msg) => (
                <div key={msg.id} className="p-6 bg-slate-50 rounded-[2.5rem] flex items-center justify-between group hover:bg-white hover:shadow-xl transition-all border border-transparent hover:border-slate-100">
                  <div className="flex items-center gap-5">
                    <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center text-blue-600 shadow-sm font-black text-lg uppercase">
                      {String(msg.name || 'U').charAt(0)}
                    </div>
                    <div>
                      <div className="flex items-center gap-2">
                        <p className="text-sm font-black text-slate-900">{msg.name}</p>
                        <span className="text-[8px] font-black bg-blue-600 text-white px-1.5 py-0.5 rounded-md uppercase">{msg.subject}</span>
                      </div>
                      <p className="text-[10px] font-bold text-slate-400 truncate max-w-[200px] md:max-w-md">{msg.message}</p>
                    </div>
                  </div>
                  <div className="flex items-center gap-4">
                    <button onClick={() => setViewingContact(msg)} className="p-3 bg-white text-blue-600 rounded-xl hover:bg-blue-600 hover:text-white transition-all shadow-sm">
                      <Mail size={16} />
                    </button>
                    <button onClick={() => deleteContact(msg.id)} className="p-3 bg-white text-slate-300 hover:text-red-500 rounded-xl transition-all">
                      <Trash2 size={16} />
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Strategy Section */}
          <div className="bg-slate-900 p-10 rounded-[3.5rem] text-white shadow-2xl relative overflow-hidden">
            <div className="flex items-center gap-4 mb-6">
              <Sparkles size={24} className="text-blue-400" />
              <h2 className="text-xl font-black">Monte Strategy Insights</h2>
            </div>
            <p className="text-blue-50 leading-relaxed text-base italic border-l-2 border-blue-600 pl-6">
              "{String(insight)}"
            </p>
          </div>
        </div>

        {/* Sidebar Summary & Staff List */}
        <div className="space-y-8">
          <div className="bg-white p-10 rounded-[3.5rem] border border-slate-100 shadow-sm">
            <div className="flex items-center justify-between mb-8">
              <h3 className="text-xl font-black text-slate-900 flex items-center gap-2">
                <UserCircle className="text-indigo-600" size={20} /> Staff Monte
              </h3>
              <div className="flex items-center gap-2">
                <button 
                  disabled={staffPage === 1}
                  onClick={() => setStaffPage(p => Math.max(1, p - 1))}
                  className="p-1.5 bg-slate-50 text-slate-400 hover:text-indigo-600 rounded-lg disabled:opacity-30"
                >
                  <ChevronLeft size={16} />
                </button>
                <span className="text-[9px] font-black text-slate-400 uppercase">{staffPage}/{totalStaffPages || 1}</span>
                <button 
                  disabled={staffPage >= totalStaffPages}
                  onClick={() => setStaffPage(p => p + 1)}
                  className="p-1.5 bg-slate-50 text-slate-400 hover:text-indigo-600 rounded-lg disabled:opacity-30"
                >
                  <ChevronRight size={16} />
                </button>
              </div>
            </div>

            <div className="space-y-4">
              {staff.length === 0 ? (
                <div className="py-10 text-center text-slate-400 italic text-xs">Carregando staff...</div>
              ) : staff.map(member => (
                <div key={member.id} className="flex items-center justify-between p-3 bg-slate-50 rounded-2xl hover:bg-white hover:shadow-md transition-all">
                   <div className="flex items-center gap-3">
                      <img src={member.avatar} className="w-10 h-10 rounded-xl object-cover" alt={member.name} />
                      <div>
                        <p className="text-[11px] font-black text-slate-900 leading-none mb-1">{member.name}</p>
                        <p className="text-[8px] font-bold text-indigo-600 uppercase tracking-widest">{member.role}</p>
                      </div>
                   </div>
                   <div className={`w-2 h-2 rounded-full ${member.status === 'Ativo' ? 'bg-emerald-500' : 'bg-amber-500'}`}></div>
                </div>
              ))}
            </div>
          </div>

          <div className="bg-white p-10 rounded-[3.5rem] border border-slate-100 shadow-sm">
            <h3 className="text-xl font-black text-slate-900 mb-8 flex items-center gap-2">
              <TrendingUp className="text-blue-600" size={20} /> Finanças Cloud
            </h3>
            <div className="space-y-5">
               <div className="p-5 bg-green-50 rounded-2xl border border-green-100 flex items-center justify-between">
                  <div>
                    <p className="text-[10px] font-black text-green-600 uppercase">Receitas</p>
                    <p className="text-lg font-black text-green-900">{stats.revenue.toLocaleString()} MT</p>
                  </div>
                  <ArrowUpCircle className="text-green-600" />
               </div>
               <div className="p-5 bg-rose-50 rounded-2xl border border-rose-100 flex items-center justify-between">
                  <div>
                    <p className="text-[10px] font-black text-rose-600 uppercase">Despesas</p>
                    <p className="text-lg font-black text-rose-900">{stats.expenses.toLocaleString()} MT</p>
                  </div>
                  <ArrowDownCircle className="text-rose-600" />
               </div>
            </div>
          </div>
        </div>
      </div>

      {/* Quick Launch Finance Modal */}
      {showFinanceModal && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 bg-slate-900/70 backdrop-blur-md animate-in fade-in duration-300">
          <div className="bg-white rounded-[3.5rem] p-12 max-w-xl w-full shadow-2xl relative">
            <button onClick={() => setShowFinanceModal(false)} className="absolute top-10 right-10 text-slate-400 p-2 hover:bg-slate-50 rounded-xl transition-all"><X size={24} /></button>
            <h2 className="text-3xl font-black text-slate-900 mb-8 flex items-center gap-3"><Wallet className="text-blue-600" /> Lançamento Rápido</h2>

            <form onSubmit={handleSaveTransaction} className="space-y-6">
              <div className="flex bg-slate-100 p-1.5 rounded-2xl">
                <button 
                  type="button"
                  onClick={() => setNewTransaction({...newTransaction, type: 'RECEITA'})}
                  className={`flex-1 py-3 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${newTransaction.type === 'RECEITA' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}
                >Receita</button>
                <button 
                  type="button"
                  onClick={() => setNewTransaction({...newTransaction, type: 'DESPESA'})}
                  className={`flex-1 py-3 text-[10px] font-black uppercase tracking-widest rounded-xl transition-all ${newTransaction.type === 'DESPESA' ? 'bg-white text-rose-600 shadow-sm' : 'text-slate-500'}`}
                >Despesa</button>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Descrição</label>
                <input 
                  required
                  placeholder="Ex: Consultoria de Venda..."
                  value={newTransaction.description}
                  onChange={e => setNewTransaction({...newTransaction, description: e.target.value})}
                  className="w-full bg-slate-50 border border-slate-100 p-4 rounded-2xl font-bold outline-none focus:ring-2 focus:ring-blue-600"
                />
              </div>

              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Montante (MT)</label>
                  <input 
                    required
                    type="number"
                    placeholder="0.00"
                    value={newTransaction.amount}
                    onChange={e => setNewTransaction({...newTransaction, amount: e.target.value})}
                    className="w-full bg-slate-50 border border-slate-100 p-4 rounded-2xl font-black text-blue-600 outline-none focus:ring-2 focus:ring-blue-600"
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex justify-between items-center">
                    Categoria
                    <button 
                      type="button" 
