                    <button onClick={() => startEditing(user)} className="p-3 bg-white text-slate-300 hover:text-indigo-600 hover:bg-indigo-50 border border-slate-100 rounded-xl transition-all shadow-sm active:scale-90">
                      <UserCog size={22} />
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Permissions Modal */}
      {editingUser && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-xl animate-in fade-in duration-300">
          <div className="bg-white rounded-[4rem] p-12 max-w-4xl w-full shadow-2xl relative overflow-y-auto max-h-[90vh]">
            <button onClick={() => {setEditingUser(null); setOriginalUserState(null);}} className="absolute top-10 right-10 text-slate-400 p-2 hover:bg-slate-50 rounded-xl transition-all"><X size={28} /></button>

            <div className="flex items-center gap-6 mb-12 border-b border-slate-100 pb-10">
               <img src={editingUser.avatar} className="w-20 h-20 rounded-[2rem] object-cover ring-4 ring-indigo-50 shadow-lg" alt={editingUser.name} />
               <div>
                  <h2 className="text-3xl font-black text-slate-900 tracking-tight">{editingUser.name}</h2>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1 flex items-center gap-2">
                    <Shield size={14} className="text-indigo-600" /> Configuração de Privilégios Corporativos
                  </p>
               </div>
            </div>

            <form onSubmit={handleUpdatePermissions} className="space-y-12">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8 bg-slate-50 p-8 rounded-[2.5rem] border border-slate-100">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Cargo Principal</label>
                  <select 
                    value={editingUser.role}
                    onChange={e => setEditingUser({...editingUser, role: e.target.value as any})}
                    className="w-full bg-white border border-slate-200 rounded-2xl p-4 text-sm font-bold text-slate-900 outline-none focus:ring-4 focus:ring-indigo-100 transition-all appearance-none cursor-pointer"
                  >
                    {roles.map(r => <option key={r} value={r}>{r}</option>)}
                  </select>
                </div>
                <div className="flex items-end">
                   <div className="p-4 bg-indigo-600 rounded-2xl text-white text-[10px] font-black uppercase tracking-widest flex items-center gap-3 shadow-xl shadow-indigo-500/20 w-full justify-center">
                     <Fingerprint size={18} /> Modificando ID: {editingUser.id.substring(0, 8)}
                   </div>
                </div>
              </div>

              <div className="space-y-14">
                {(Object.entries(groupedPermissions) as [string, PermissionDefinition[]][]).map(([category, perms]) => {
                  const allSelected = perms.every(p => editingUser.permissions?.includes(p.id));
                  return (
                    <div key={category} className="space-y-6">
                      <div className="flex items-center justify-between px-2">
                        <h3 className="text-xs font-black uppercase tracking-widest text-slate-900 flex items-center gap-2">
                          <span className="w-2 h-2 bg-indigo-600 rounded-full"></span> {category}
                        </h3>
                        <button 
                          type="button" 
                          onClick={() => toggleCategory(category, perms)}
                          className="text-[9px] font-black uppercase tracking-widest text-indigo-600 hover:text-indigo-800 transition-colors bg-indigo-50 px-4 py-1.5 rounded-full"
                        >
                          {allSelected ? 'Remover Todos' : 'Ativar Todos'}
                        </button>
                      </div>

                      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                        {perms.map(p => {
                          const isActive = editingUser.permissions?.includes(p.id);
                          return (
                            <button
                              key={p.id} type="button" onClick={() => togglePermission(p.id)}
                              className={`flex flex-col p-6 rounded-[2rem] border-2 text-left transition-all relative group ${
                                isActive 
                                ? 'bg-indigo-600 border-indigo-600 text-white shadow-xl shadow-indigo-500/20' 
                                : 'bg-white border-slate-100 text-slate-600 hover:border-indigo-200'
                              }`}
                            >
                              <div className="flex items-center justify-between mb-3">
                                <div className={`p-2 rounded-xl ${isActive ? 'bg-white/20' : 'bg-slate-50 text-indigo-600'}`}>{p.icon}</div>
                                {isActive && <CheckCircle2 size={16} className="text-white" />}
                              </div>
                              <span className="text-[11px] font-black uppercase tracking-tighter mb-1">{p.label}</span>
                              <span className={`text-[9px] font-medium leading-tight line-clamp-2 ${isActive ? 'text-indigo-100' : 'text-slate-400'}`}>{p.description}</span>
                            </button>
                          );
                        })}
                      </div>
                    </div>
                  );
                })}
              </div>

              {msg && <div className={`p-6 rounded-[2rem] text-xs font-black uppercase tracking-widest text-center animate-in zoom-in ${msg.type === 'success' ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>{msg.text}</div>}

              <button disabled={saving} type="submit" className="w-full py-7 bg-slate-900 text-white rounded-[2.5rem] font-black text-xs uppercase tracking-widest shadow-2xl hover:bg-indigo-600 transition-all flex items-center justify-center gap-3 disabled:opacity-50 group">
                {saving ? <Loader2 className="animate-spin" size={20} /> : <><Save size={20} className="group-hover:scale-110 transition-transform" /> Sincronizar Permissões na Cloud</>}
              </button>
            </form>
          </div>
        </div>
      )}

      {/* Audit Logs Modal */}
      {showAuditModal && (
        <div className="fixed inset-0 z-[160] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-md animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-12 max-w-5xl w-full shadow-2xl relative overflow-hidden flex flex-col max-h-[90vh]">
            <button onClick={() => setShowAuditModal(false)} className="absolute top-10 right-10 text-slate-400 p-2 hover:bg-slate-50 rounded-xl transition-all"><X size={28} /></button>

            <div className="flex items-center gap-4 mb-10">
               <div className="w-12 h-12 bg-indigo-50 text-indigo-600 rounded-2xl flex items-center justify-center">
                  <Activity size={24} />
               </div>
               <div>
                  <h2 className="text-3xl font-black text-slate-900 tracking-tight">Histórico de Auditoria</h2>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Registo Cloud de Alterações Administrativas</p>
               </div>
            </div>

            <div className="flex-1 overflow-y-auto pr-4 custom-scrollbar space-y-4">
              {loadingLogs ? (
                <div className="py-20 flex justify-center"><Loader2 className="animate-spin text-indigo-600" size={32} /></div>
              ) : auditLogs.length === 0 ? (
                <div className="py-20 text-center text-slate-400 italic font-medium">Nenhum log de auditoria registado até ao momento.</div>
              ) : auditLogs.map((log) => (
                <div key={log.id} className="p-6 bg-slate-50 rounded-[2.5rem] border border-slate-100 hover:bg-white hover:shadow-xl transition-all group">
                   <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-4">
                      <div className="flex items-center gap-3">
                         <div className="px-3 py-1 bg-indigo-600 text-white rounded-lg text-[9px] font-black uppercase tracking-widest">{log.action_type}</div>
                         <div className="flex items-center gap-2 text-slate-900 font-bold text-sm">
                            <span className="text-slate-400">Por:</span> {log.admin_name}
                            <ChevronRight size={14} className="text-slate-300" />
                            <span className="text-slate-400">Para:</span> {log.target_user_name}
                         </div>
                      </div>
                      <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-tighter">
                         <Calendar size={14} /> {new Date(log.created_at).toLocaleString('pt-MZ')}
                      </div>
                   </div>
                   <div className="p-4 bg-white rounded-2xl border border-slate-100 text-[11px] font-medium text-slate-600 leading-relaxed italic">
                      {log.change_details.split(' | ').map((detail, idx) => (
                        <div key={idx} className="flex items-start gap-2 mb-1">
                           <div className="w-1.5 h-1.5 bg-indigo-300 rounded-full mt-1.5 shrink-0"></div>
                           {detail}
                        </div>
                      ))}
                   </div>
                </div>
              ))}
            </div>

            <div className="mt-8 pt-8 border-t border-slate-100 text-center">
               <button onClick={() => setShowAuditModal(false)} className="px-10 py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-indigo-600 transition-all">Fechar Auditoria</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminView;

import React, { useState, useEffect } from 'react';
import { 
  Plus, Users, AlertCircle, Clock, 
  Loader2, X, Trash2, Save, Mail, Phone, 
  Edit3, ShieldCheck, AlertTriangle
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { Employee, UserRole } from '../types';

const HRView: React.FC = () => {
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAddModal, setShowAddModal] = useState(false);
  const [editingEmpId, setEditingEmpId] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [saving, setSaving] = useState(false);

  const initialFormState: Partial<Employee> = {
    name: '', role: UserRole.EMPLOYEE, department: 'Geral', salary: 0, email: '', phone: '',
    document_type: 'BI', document_number: '', document_expiry: '', payment_method: 'M-Pesa', contract_start: ''
  };

  const [formState, setFormState] = useState<Partial<Employee>>(initialFormState);

  useEffect(() => {
    fetchData();
  }, []);

  async function fetchData() {
    setLoading(true);
    try {
      const { data, error: sbError } = await supabase.from('employees').select('*').order('name');
      if (sbError) setError(sbError.message);
      setEmployees(data || []);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }

  const getExpiryStatus = (expiryDate?: string) => {
    if (!expiryDate) return { label: 'Sem Info', color: 'bg-slate-100 text-slate-400 border-slate-200', icon: <AlertCircle size={10} />, pulse: false };

    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const expiry = new Date(expiryDate);
    expiry.setHours(0, 0, 0, 0);

    const thirtyDaysFromNow = new Date();
    thirtyDaysFromNow.setDate(today.getDate() + 30);

    if (expiry < today) {
      return { label: 'Expirado', color: 'bg-rose-50 text-rose-600 border-rose-100', icon: <AlertTriangle size={10} />, pulse: true };
    } else if (expiry <= thirtyDaysFromNow) {
      return { label: 'A Vencer', color: 'bg-amber-50 text-amber-600 border-amber-100', icon: <Clock size={10} />, pulse: false };
    } else {
      return { label: 'Ativo', color: 'bg-emerald-50 text-emerald-600 border-emerald-100', icon: <ShieldCheck size={10} />, pulse: false };
    }
  };

  const handleOpenEdit = (emp: Employee) => {
    setEditingEmpId(emp.id);
    setFormState({
      name: emp.name,
      email: emp.email,
      phone: emp.phone,
      role: emp.role,
      department: emp.department,
      salary: emp.salary,
      document_type: emp.document_type || 'BI',
      document_number: emp.document_number || '',
      document_expiry: emp.document_expiry || '',
      payment_method: emp.payment_method || 'M-Pesa',
      contract_start: emp.contract_start || emp.join_date
    });
    setShowAddModal(true);
    setError(null);
  };

  const handleSaveEmployee = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setSaving(true);

    // Validações Obrigatórias
    if (!formState.name?.trim()) {
      setError('O nome completo do colaborador é obrigatório.');
      setSaving(false);
      return;
    }

    if (!formState.email?.trim() || !formState.email.includes('@')) {
      setError('Insira um e-mail corporativo válido (@monte-imobiliaria.com).');
      setSaving(false);
      return;
    }

    if (!formState.phone?.trim()) {
      setError('O contacto móvel é indispensável para o registo.');
      setSaving(false);
      return;
    }

    const docNum = formState.document_number?.trim();
    if (!docNum || !/\d/.test(docNum)) {
      setError('Número de documento inválido ou ausente. Insira o BI ou DIRE.');
      setSaving(false);
      return;
    }

    // NOVA VALIDAÇÃO: Verificar se o número de documento já existe
    try {
      let query = supabase
        .from('employees')
        .select('id, name')
        .eq('document_number', docNum);

      if (editingEmpId) {
        query = query.neq('id', editingEmpId);
      }

      const { data: existingDocs, error: checkError } = await query;

      if (checkError) throw checkError;

      if (existingDocs && existingDocs.length > 0) {
        setError(`Erro de Duplicidade: O documento ${docNum} já está registado para o colaborador "${existingDocs[0].name}".`);
        setSaving(false);
        return;
      }
    } catch (err: any) {
      console.error("Erro na verificação de documento:", err);
    }

    if (!formState.document_expiry) {
      setError('A data de validade do documento é obrigatória para o sistema de alertas.');
      setSaving(false);
      return;
    }

    if (!formState.contract_start) {
      setError('A data de início de contrato deve ser especificada.');
      setSaving(false);
      return;
    }

    const payload = {
      name: formState.name, 
      email: formState.email, 
      phone: formState.phone, 
      role: formState.role,
      department: formState.department, 
      salary: Number(formState.salary),
      avatar: `https://picsum.photos/seed/${formState.name}/100`, 
      status: 'Ativo',
      join_date: formState.contract_start, 
      document_type: formState.document_type || 'BI',
      document_number: docNum, 
      document_expiry: formState.document_expiry,
      payment_method: formState.payment_method || 'M-Pesa', 
      contract_start: formState.contract_start
    };

    try {
      if (editingEmpId) {
        const { error: sbError } = await supabase
          .from('employees')
          .update(payload)
          .eq('id', editingEmpId);

        if (sbError) throw sbError;
      } else {
        const { error: sbError } = await supabase
          .from('employees')
          .insert([payload]);

        if (sbError) throw sbError;
      }

      setShowAddModal(false);
      setEditingEmpId(null);
      setFormState(initialFormState);
      fetchData();
    } catch (err: any) {
      setError('Erro ao sincronizar com Cloud: ' + err.message);
    } finally {
      setSaving(false);
    }
  };

  const removeEmployee = async (id: string) => {
    if (confirm('Deseja arquivar este contrato no sistema Monte?')) {
      const { error } = await supabase.from('employees').delete().eq('id', id);
      if (!error) fetchData();
    }
  };

  const closeModal = () => {
    setShowAddModal(false);
    setEditingEmpId(null);
    setFormState(initialFormState);
    setError(null);
  };

  if (loading) return <div className="flex justify-center py-24"><Loader2 className="animate-spin text-indigo-600" size={48} /></div>;

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-4">
           <div className="w-14 h-14 bg-indigo-600 rounded-[1.5rem] flex items-center justify-center text-white shadow-xl shadow-indigo-500/20"><Users size={28} /></div>
           <div>
             <h1 className="text-3xl font-black text-slate-900 tracking-tight">Gestão de Staff</h1>
             <p className="text-slate-500 font-medium">Controlo centralizado de capital humano e contratos.</p>
           </div>
        </div>
        <button onClick={() => setShowAddModal(true)} className="px-10 py-4 bg-indigo-600 text-white rounded-[2rem] font-black text-sm shadow-xl hover:bg-indigo-700 transition-all active:scale-95 flex items-center gap-2">
          <Plus size={20} /> Registar Colaborador
        </button>
      </div>

      {error && (
        <div className="p-6 bg-rose-50 border-l-4 border-rose-500 rounded-3xl flex items-center gap-4 text-rose-800 text-xs font-bold shadow-sm animate-shake">
          <AlertCircle size={24} className="shrink-0" />
          <p>{error}</p>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
        {employees.map(emp => {
          const docStatus = getExpiryStatus(emp.document_expiry);
          return (
            <div key={emp.id} className="bg-white p-8 rounded-[3.5rem] border border-slate-100 shadow-sm relative group hover:shadow-2xl transition-all border-b-4 border-b-transparent hover:border-b-indigo-500">
              {/* Expiry Status Badge */}
              <div className={`absolute top-6 left-6 px-4 py-1.5 rounded-full border text-[9px] font-black uppercase tracking-widest flex items-center gap-2 z-10 transition-colors ${docStatus.color}`}>
                {docStatus.icon}
                {docStatus.label}
                {docStatus.pulse && (
                  <span className="flex h-1.5 w-1.5 relative">
                    <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-rose-400 opacity-75"></span>
                    <span className="relative inline-flex rounded-full h-1.5 w-1.5 bg-rose-500"></span>
                  </span>
                )}
              </div>

              <div className="absolute top-6 right-6 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                <button onClick={() => handleOpenEdit(emp)} className="p-2.5 bg-white text-slate-400 hover:text-indigo-600 rounded-xl shadow-sm border border-slate-50 transition-all"><Edit3 size={18} /></button>
                <button onClick={() => removeEmployee(emp.id)} className="p-2.5 bg-white text-slate-400 hover:text-rose-600 rounded-xl shadow-sm border border-slate-100 transition-all"><Trash2 size={18} /></button>
              </div>

              <div className="mt-8 flex flex-col items-center">
                <div className="relative">
                  <img src={emp.avatar} className="w-24 h-24 rounded-[2.5rem] object-cover mb-5 ring-8 ring-slate-50 shadow-inner" alt={emp.name} />
                  <div className={`absolute bottom-5 right-0 w-5 h-5 border-4 border-white rounded-full ${emp.status === 'Ativo' ? 'bg-emerald-500' : 'bg-slate-300'}`}></div>
                </div>
                <h3 className="text-xl font-black text-slate-900 mb-1 text-center">{emp.name}</h3>
                <p className="text-[10px] font-black text-indigo-600 uppercase tracking-widest mb-6 text-center bg-indigo-50 px-3 py-1 rounded-lg">{emp.role}</p>
              </div>

              <div className="pt-6 border-t border-slate-50 flex justify-between items-center">
                <div>
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-tighter">Salário Base</p>
                  <p className="text-base font-black text-slate-900 leading-none">{Number(emp.salary).toLocaleString()} MT</p>
                </div>
                <div className="text-right">
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-tighter">Validade Doc.</p>
                  <p className={`text-[11px] font-black ${docStatus.label === 'Expirado' ? 'text-rose-600' : 'text-slate-900'}`}>
                    {emp.document_expiry || 'Sem Data'}
                  </p>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {showAddModal && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-12 max-w-4xl w-full shadow-2xl relative overflow-y-auto max-h-[90vh]">
            <button onClick={closeModal} className="absolute top-10 right-10 text-slate-400 p-2 hover:bg-slate-50 rounded-xl transition-all"><X size={28} /></button>

            <div className="flex items-center gap-4 mb-10">
               <div className="w-12 h-12 bg-indigo-50 text-indigo-600 rounded-2xl flex items-center justify-center">
                  {editingEmpId ? <Edit3 size={24} /> : <Plus size={24} />}
               </div>
               <h2 className="text-3xl font-black text-slate-900 tracking-tight">
                 {editingEmpId ? 'Ficha do Colaborador' : 'Novo Contrato Monte'}
               </h2>
            </div>

            <form onSubmit={handleSaveEmployee} className="space-y-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome Completo do Colaborador *</label>
                  <input required placeholder="Ex: João Baptista..." value={formState.name} onChange={e => setFormState({...formState, name: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold border-none outline-none focus:ring-4 focus:ring-indigo-100 transition-all" />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">E-mail de Trabalho *</label>
                  <div className="relative">
                    <Mail className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
                    <input required type="email" placeholder="email@monte-imobiliaria.com" value={formState.email} onChange={e => setFormState({...formState, email: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 pl-14 font-bold border-none outline-none focus:ring-4 focus:ring-indigo-100 transition-all" />
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Contacto Telefónico *</label>
                  <div className="relative">
                    <Phone className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
                    <input required placeholder="+258 8X XXX XXXX" value={formState.phone} onChange={e => setFormState({...formState, phone: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 pl-14 font-bold border-none outline-none focus:ring-4 focus:ring-indigo-100 transition-all" />
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Vencimento Mensal (MT)</label>
                  <input type="number" placeholder="0.00" value={formState.salary} onChange={e => setFormState({...formState, salary: Number(e.target.value)})} className="w-full bg-slate-50 rounded-2xl p-5 font-black border-none outline-none focus:ring-4 focus:ring-indigo-100 transition-all text-xl text-indigo-600" />
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-3 gap-6 pt-10 border-t border-slate-100">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1">Documento (BI/DIRE) *</label>
                  <input required placeholder="Nr. Documento" value={formState.document_number} onChange={e => setFormState({...formState, document_number: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold border-none outline-none focus:ring-4 focus:ring-indigo-100 transition-all" />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1">Validade do Doc. *</label>
                  <input required type="date" value={formState.document_expiry} onChange={e => setFormState({...formState, document_expiry: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold border-none outline-none focus:ring-4 focus:ring-indigo-100 transition-all" />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1">Início das Funções *</label>
                  <input required type="date" value={formState.contract_start} onChange={e => setFormState({...formState, contract_start: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold border-none outline-none focus:ring-4 focus:ring-indigo-100 transition-all" />
                </div>
              </div>

              <button disabled={saving} type="submit" className="w-full py-6 bg-indigo-600 text-white font-black rounded-[2.5rem] shadow-2xl hover:bg-indigo-700 transition-all flex items-center justify-center gap-4 active:scale-95 disabled:opacity-70 disabled:cursor-not-allowed group">
                {saving ? (
                  <Loader2 className="animate-spin" size={24} />
                ) : (
                  <>
                    <Save size={24} className="group-hover:scale-110 transition-transform" /> 
                    {editingEmpId ? 'Confirmar Atualização de Dados' : 'Validar e Ativar Novo Colaborador'}
                  </>
                )}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default HRView;

import React, { useState, useEffect } from 'react';
import { 
  Plus, Search, Edit3, Trash2, X, Check, Camera, 
