  const sqlSchema = `-- SCRIPT MONTE HUB CLOUD v3.0
-- Tabelas de Governança e Recrutamento
CREATE TABLE IF NOT EXISTS public.roles (
    id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
    name text UNIQUE NOT NULL,
    created_at timestamptz DEFAULT now()
);

CREATE TABLE IF NOT EXISTS public.audit_logs (
    id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
    admin_id uuid,
    admin_name text,
    target_user_id uuid,
    target_user_name text,
    action_type text,
    change_details text,
    created_at timestamptz DEFAULT now()
);

CREATE TABLE IF NOT EXISTS public.job_vacancies (
    id uuid DEFAULT gen_random_uuid() PRIMARY KEY,
    title text NOT NULL,
    area text NOT NULL,
    type text NOT NULL,
    location text NOT NULL,
    salary text,
    description text,
    status text DEFAULT 'Open',
    created_at timestamptz DEFAULT now()
);

-- Seed de Roles
INSERT INTO public.roles (name) 
VALUES 
('Administrador de Sistema'),
('Director Executivo (CEO)'),
('Gestor Geral Operacional'),
('Director Financeiro'),
('Gestor de Recursos Humanos'),
('Consultor Imobiliário'),
('Colaborador Geral')
ON CONFLICT (name) DO NOTHING;
`;

  useEffect(() => {
    fetchUsers();
    fetchRoles();
  }, []);

  async function fetchRoles() {
    try {
      const { data, error } = await supabase.from('roles').select('name').order('name');
      if (!error && data) setRoles(data.map(r => r.name));
    } catch (e) { console.warn("Roles table not found."); }
  }

  async function fetchUsers() {
    setLoading(true);
    try {
      const { data, error } = await supabase.from('employees').select('*').order('name');
      if (!error) setUsers(data || []);
    } catch (e) { console.warn("Error fetching users"); }
    finally { setLoading(false); }
  }

  async function fetchAuditLogs() {
    setLoadingLogs(true);
    try {
      const { data, error } = await supabase
        .from('audit_logs')
        .select('*')
        .order('created_at', { ascending: false })
        .limit(50);
      if (!error) setAuditLogs(data || []);
    } catch (e) { console.warn("Error fetching logs"); }
    finally { setLoadingLogs(false); }
  }

  const handleUpdatePermissions = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingUser || !originalUserState) return;
    setSaving(true);
    const changes = [];
    if (editingUser.role !== originalUserState.role) changes.push(`Cargo: [${originalUserState.role}] -> [${editingUser.role}]`);
    const oldPerms = originalUserState.permissions || [];
    const newPerms = editingUser.permissions || [];
    const added = newPerms.filter(p => !oldPerms.includes(p));
    const removed = oldPerms.filter(p => !newPerms.includes(p));
    if (added.length > 0) changes.push(`+ Permissões: ${added.join(', ')}`);
    if (removed.length > 0) changes.push(`- Permissões: ${removed.join(', ')}`);

    try {
      const { error } = await supabase.from('employees').update({ role: editingUser.role, permissions: editingUser.permissions || [] }).eq('id', editingUser.id);
      if (error) throw error;
      if (changes.length > 0 && currentUser) {
        await supabase.from('audit_logs').insert([{
          admin_id: currentUser.id, admin_name: currentUser.name,
          target_user_id: editingUser.id, target_user_name: editingUser.name,
          action_type: editingUser.role !== originalUserState.role ? 'PERFIL_CARGO' : 'PRIVILEGIOS',
          change_details: changes.join(' | ')
        }]);
      }
      setMsg({ type: 'success', text: 'Sincronizado!' });
      fetchUsers();
      setTimeout(() => setEditingUser(null), 1200);
    } catch (error: any) { setMsg({ type: 'error', text: error.message }); } finally { setSaving(false); setTimeout(() => setMsg(null), 3000); }
  };

  const togglePermission = (permId: string) => {
    if (!editingUser) return;
    const current = editingUser.permissions || [];
    const newPerms = current.includes(permId) ? current.filter(p => p !== permId) : [...current, permId];
    setEditingUser({ ...editingUser, permissions: newPerms });
  };

  const toggleCategory = (category: string, permsInCategory: PermissionDefinition[]) => {
    if (!editingUser) return;
    const currentPerms = editingUser.permissions || [];
    const idsInCategory = permsInCategory.map(p => p.id);
    const allSelected = idsInCategory.every(id => currentPerms.includes(id));
    const newPerms = allSelected ? currentPerms.filter(id => !idsInCategory.includes(id)) : Array.from(new Set([...currentPerms, ...idsInCategory]));
    setEditingUser({ ...editingUser, permissions: newPerms });
  };

  const groupedPermissions = useMemo(() => {
    return GRANULAR_PERMISSIONS.reduce((acc, curr) => {
      if (!acc[curr.category]) acc[curr.category] = [];
      acc[curr.category].push(curr);
      return acc;
    }, {} as Record<string, PermissionDefinition[]>);
  }, []);

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-16">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tight">Administração TI</h1>
          <p className="text-slate-500 font-medium italic">Monitorização e governança de privilégios cloud.</p>
        </div>
        <div className="flex items-center gap-3">
           <button onClick={() => { fetchAuditLogs(); setShowAuditModal(true); }} className="px-6 py-3 bg-white text-slate-600 border border-slate-200 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-50 transition-all flex items-center gap-2 shadow-sm">
             <History size={16} className="text-indigo-600" /> Histórico de Auditoria
           </button>
           <button onClick={() => { fetchUsers(); fetchRoles(); }} className="p-4 bg-white text-slate-400 hover:text-indigo-600 rounded-2xl shadow-sm border border-slate-100 transition-all active:scale-95">
             <RefreshCw size={20} className={loading ? 'animate-spin' : ''} />
           </button>
        </div>
      </div>

      {/* SQL Script Box */}
      <div className="bg-slate-900 rounded-[3rem] p-10 text-white shadow-2xl relative overflow-hidden group">
        <div className="flex items-center gap-4 mb-6"><Database size={24} className="text-indigo-400" /><h3 className="text-xl font-black">Infraestrutura Supabase</h3></div>
        <pre className="bg-slate-800 p-6 rounded-2xl text-[10px] text-indigo-200 font-mono overflow-x-auto mb-6 max-h-40 custom-scrollbar border border-white/5">{sqlSchema}</pre>
        <button onClick={() => { navigator.clipboard.writeText(sqlSchema); setCopied(true); setTimeout(() => setCopied(false), 2000); }} className="flex items-center gap-2 px-6 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-black text-[10px] uppercase tracking-widest transition-all">
          {copied ? <Check size={14} /> : <Copy size={14} />} {copied ? 'Copiado!' : 'Copiar Script SQL'}
        </button>
      </div>

      {/* Users Management */}
      <div className="bg-white rounded-[3.5rem] border border-slate-100 shadow-sm overflow-hidden">
        <div className="p-8 border-b border-slate-50 flex items-center justify-between">
          <div className="relative flex-1 max-w-md">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input value={searchTerm} onChange={e => setSearchTerm(e.target.value)} placeholder="Localizar utilizador..." className="w-full pl-12 pr-4 py-4 bg-slate-50 rounded-2xl border-none font-bold text-sm outline-none focus:ring-4 focus:ring-indigo-50" />
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50/50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">
                <th className="px-10 py-6">Perfil do Colaborador</th>
                <th className="px-10 py-6 text-center">Acesso Granular</th>
                <th className="px-10 py-6 text-right">Acção</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {loading ? (
                <tr><td colSpan={3} className="py-24 text-center"><Loader2 className="animate-spin mx-auto text-indigo-600" size={32} /></td></tr>
              ) : users.filter(u => u.name.toLowerCase().includes(searchTerm.toLowerCase())).map(user => (
                <tr key={user.id} className="hover:bg-slate-50/50 transition-all group">
                  <td className="px-10 py-8"><div className="flex items-center gap-5"><img src={user.avatar} className="w-14 h-14 rounded-[1.5rem] object-cover" alt="" /><div><p className="text-base font-black text-slate-900 leading-none mb-1">{user.name}</p><span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded-md uppercase tracking-wider">{user.role}</span></div></div></td>
                  <td className="px-10 py-8"><div className="flex flex-wrap justify-center gap-1.5">{user.permissions?.length ? user.permissions.slice(0, 3).map(p => (<span key={p} className="text-[8px] font-black bg-slate-100 text-slate-500 px-2 py-0.5 rounded uppercase">{p.split('.')[1] || p}</span>)) : <span className="text-[9px] font-black text-slate-300 italic uppercase">Padrão</span>}</div></td>
                  <td className="px-10 py-8 text-right"><button onClick={() => { setEditingUser({...user}); setOriginalUserState({...user}); }} className="p-3 bg-white text-slate-300 hover:text-indigo-600 rounded-xl border border-slate-100"><UserCog size={22} /></button></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Permissions Modal */}
      {editingUser && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-xl animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-12 max-w-4xl w-full shadow-2xl relative overflow-y-auto max-h-[90vh]">
            <button onClick={() => setEditingUser(null)} className="absolute top-10 right-10 text-slate-400"><X size={28} /></button>
            <div className="flex items-center gap-6 mb-12 border-b border-slate-100 pb-10"><img src={editingUser.avatar} className="w-20 h-20 rounded-[2rem] object-cover shadow-lg" alt="" /><div><h2 className="text-3xl font-black text-slate-900 tracking-tight">{editingUser.name}</h2><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Sincronização Cloud de Privilégios</p></div></div>
            <form onSubmit={handleUpdatePermissions} className="space-y-12">
              <select value={editingUser.role} onChange={e => setEditingUser({...editingUser, role: e.target.value as any})} className="w-full bg-slate-50 border-none rounded-2xl p-5 font-bold outline-none">{roles.map(r => <option key={r} value={r}>{r}</option>)}</select>
              <div className="space-y-14">
                {(Object.entries(groupedPermissions) as [string, PermissionDefinition[]][]).map(([category, perms]) => (
                    <div key={category} className="space-y-6">
                      <div className="flex items-center justify-between px-2"><h3 className="text-xs font-black uppercase text-slate-900">{category}</h3><button type="button" onClick={() => toggleCategory(category, perms)} className="text-[9px] font-black uppercase text-indigo-600 bg-indigo-50 px-4 py-1.5 rounded-full">Alternar Grupo</button></div>
                      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">{perms.map(p => {
                          const isActive = editingUser.permissions?.includes(p.id);
                          return (<button key={p.id} type="button" onClick={() => togglePermission(p.id)} className={`flex flex-col p-6 rounded-[2rem] border-2 transition-all ${isActive ? 'bg-indigo-600 border-indigo-600 text-white shadow-xl' : 'bg-white border-slate-100 text-slate-600 hover:border-indigo-200'}`}><div className="flex items-center justify-between mb-3"><div className={`p-2 rounded-xl ${isActive ? 'bg-white/20' : 'bg-slate-50 text-indigo-600'}`}>{p.icon}</div></div><span className="text-[11px] font-black uppercase mb-1">{p.label}</span><span className={`text-[9px] font-medium leading-tight line-clamp-2 ${isActive ? 'text-indigo-100' : 'text-slate-400'}`}>{p.description}</span></button>);
                        })}</div>
                    </div>
                ))}
              </div>
              <button disabled={saving} type="submit" className="w-full py-7 bg-slate-900 text-white rounded-[2.5rem] font-black text-xs uppercase tracking-widest shadow-2xl hover:bg-indigo-600 transition-all flex items-center justify-center gap-3">
                {saving ? <Loader2 className="animate-spin" /> : <><Save size={20} /> Sincronizar Permissões</>}
              </button>
            </form>
          </div>
        </div>
      )}

      {/* Audit Logs Modal */}
      {showAuditModal && (
        <div className="fixed inset-0 z-[160] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-md animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-12 max-w-5xl w-full shadow-2xl relative overflow-hidden flex flex-col max-h-[90vh]">
            <button onClick={() => setShowAuditModal(false)} className="absolute top-10 right-10 text-slate-400"><X size={28} /></button>
            <div className="flex items-center gap-4 mb-10"><Activity size={24} className="text-indigo-600" /><div><h2 className="text-3xl font-black text-slate-900 tracking-tight">Auditoria Cloud</h2></div></div>
            <div className="flex-1 overflow-y-auto pr-4 custom-scrollbar space-y-4">
              {loadingLogs ? <div className="py-20 flex justify-center"><Loader2 className="animate-spin text-indigo-600" size={32} /></div> : auditLogs.map((log) => (
                <div key={log.id} className="p-6 bg-slate-50 rounded-[2.5rem] border border-slate-100"><div className="flex justify-between gap-4 mb-4"><div className="flex items-center gap-3"><div className="px-3 py-1 bg-indigo-600 text-white rounded-lg text-[9px] font-black uppercase">{log.action_type}</div><div className="text-slate-900 font-bold text-sm">Por: {log.admin_name} -> {log.target_user_name}</div></div><div className="text-[10px] font-black text-slate-400 uppercase tracking-tighter">{new Date(log.created_at).toLocaleString('pt-MZ')}</div></div><div className="p-4 bg-white rounded-2xl border border-slate-100 text-[11px] text-slate-600 leading-relaxed italic">{log.change_details}</div></div>
              ))}
            </div>
            <div className="mt-8 pt-8 border-t border-slate-100 text-center"><button onClick={() => setShowAuditModal(false)} className="px-10 py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase hover:bg-indigo-600 transition-all">Fechar Histórico</button></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminView;

import React, { useState, useEffect } from 'react';
import { 
  Plus, Users, AlertCircle, Clock, 
  Loader2, X, Trash2, Save, Mail, Phone, 
  Edit3, ShieldCheck, AlertTriangle, Briefcase, 
  Search, MapPin, DollarSign, LayoutList
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { Employee, UserRole, JobVacancy } from '../types';

const HRView: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'employees' | 'vacancies'>('employees');
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [vacancies, setVacancies] = useState<JobVacancy[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAddModal, setShowAddModal] = useState(false);
  const [showVacancyModal, setShowVacancyModal] = useState(false);
  const [editingEmpId, setEditingEmpId] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [saving, setSaving] = useState(false);

  const initialFormState: Partial<Employee> = {
    name: '', role: UserRole.EMPLOYEE, department: 'Geral', salary: 0, email: '', phone: '',
    document_type: 'BI', document_number: '', document_expiry: '', payment_method: 'M-Pesa', contract_start: ''
  };

  const initialVacancyState: Partial<JobVacancy> = {
    title: '', area: 'Vendas', type: 'Full-time', location: 'Beira', salary: '', status: 'Open'
  };

  const [formState, setFormState] = useState<Partial<Employee>>(initialFormState);
  const [vacancyForm, setVacancyForm] = useState<Partial<JobVacancy>>(initialVacancyState);

  useEffect(() => {
    fetchData();
    fetchVacancies();
  }, []);

  async function fetchData() {
    setLoading(true);
    try {
      const { data, error: sbError } = await supabase.from('employees').select('*').order('name');
      if (sbError) setError(sbError.message);
      setEmployees(data || []);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }

  async function fetchVacancies() {
    try {
      const { data, error: sbError } = await supabase.from('job_vacancies').select('*').order('created_at', { ascending: false });
      if (!sbError) setVacancies(data || []);
    } catch (err) { console.warn("Job vacancies table might not exist yet."); }
  }

  const handleSaveVacancy = async (e: React.FormEvent) => {
    e.preventDefault();
    setSaving(true);
    try {
      const { error: sbError } = await supabase.from('job_vacancies').insert([vacancyForm]);
      if (sbError) throw sbError;
      setShowVacancyModal(false);
      setVacancyForm(initialVacancyState);
      fetchVacancies();
    } catch (err: any) {
      alert("Erro ao salvar vaga: " + err.message);
    } finally {
      setSaving(false);
    }
  };

  const deleteVacancy = async (id: string) => {
    if (confirm('Deseja remover esta oferta de emprego do sistema?')) {
      await supabase.from('job_vacancies').delete().eq('id', id);
      fetchVacancies();
    }
  };

  // Added removeEmployee function to handle employee deletion from Supabase
  const removeEmployee = async (id: string) => {
    if (confirm('Deseja remover este colaborador permanentemente?')) {
      const { error: sbError } = await supabase.from('employees').delete().eq('id', id);
      if (!sbError) fetchData();
      else alert("Erro ao remover: " + sbError.message);
    }
  };

  const getExpiryStatus = (expiryDate?: string) => {
    if (!expiryDate) return { label: 'Sem Info', color: 'bg-slate-100 text-slate-400 border-slate-200', icon: <AlertCircle size={10} />, pulse: false };
    const today = new Date();
    today.setHours(0,0,0,0);
    const expiry = new Date(expiryDate);
    const thirtyDaysFromNow = new Date();
    thirtyDaysFromNow.setDate(today.getDate() + 30);

    if (expiry < today) return { label: 'Expirado', color: 'bg-rose-50 text-rose-600 border-rose-100', icon: <AlertTriangle size={10} />, pulse: true };
    if (expiry <= thirtyDaysFromNow) return { label: 'A Vencer', color: 'bg-amber-50 text-amber-600 border-amber-100', icon: <Clock size={10} />, pulse: false };
    return { label: 'Ativo', color: 'bg-emerald-50 text-emerald-600 border-emerald-100', icon: <ShieldCheck size={10} />, pulse: false };
  };

  const handleSaveEmployee = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setSaving(true);

    const docNum = formState.document_number?.trim();
    if (!docNum) { setError('Número de documento obrigatório.'); setSaving(false); return; }

    try {
      let query = supabase.from('employees').select('id, name').eq('document_number', docNum);
      if (editingEmpId) query = query.neq('id', editingEmpId);
      const { data: existingDocs } = await query;
      if (existingDocs && existingDocs.length > 0) {
        setError(`O documento ${docNum} já existe para "${existingDocs[0].name}".`);
        setSaving(false); return;
      }

      const payload = { ...formState, salary: Number(formState.salary), status: 'Ativo', avatar: `https://picsum.photos/seed/${formState.name}/100` };
      if (editingEmpId) {
        await supabase.from('employees').update(payload).eq('id', editingEmpId);
      } else {
        await supabase.from('employees').insert([payload]);
      }
      setShowAddModal(false);
      setEditingEmpId(null);
      setFormState(initialFormState);
      fetchData();
    } catch (err: any) { setError(err.message); } finally { setSaving(false); }
  };

  if (loading) return <div className="flex justify-center py-24"><Loader2 className="animate-spin text-indigo-600" size={48} /></div>;

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-4">
           <div className="w-14 h-14 bg-indigo-600 rounded-[1.5rem] flex items-center justify-center text-white shadow-xl shadow-indigo-500/20"><Users size={28} /></div>
           <div>
             <h1 className="text-3xl font-black text-slate-900 tracking-tight">Recursos Humanos</h1>
             <p className="text-slate-500 font-medium">Gestão de capital humano e recrutamento dinâmico.</p>
           </div>
        </div>
        <div className="flex gap-3">
          {activeTab === 'employees' ? (
            <button onClick={() => setShowAddModal(true)} className="px-8 py-4 bg-indigo-600 text-white rounded-[2rem] font-black text-sm shadow-xl hover:bg-indigo-700 transition-all active:scale-95 flex items-center gap-2">
              <Plus size={20} /> Novo Colaborador
            </button>
          ) : (
            <button onClick={() => setShowVacancyModal(true)} className="px-8 py-4 bg-blue-600 text-white rounded-[2rem] font-black text-sm shadow-xl hover:bg-blue-700 transition-all active:scale-95 flex items-center gap-2">
              <Plus size={20} /> Publicar Vaga
            </button>
          )}
        </div>
      </div>

      {/* Tabs */}
      <div className="flex p-1.5 bg-slate-100 rounded-[2rem] w-full max-w-md mx-auto">
        <button 
          onClick={() => setActiveTab('employees')}
          className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-[1.5rem] text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'employees' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}
        >
          <Users size={16} /> Staff Ativo
        </button>
        <button 
          onClick={() => setActiveTab('vacancies')}
          className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-[1.5rem] text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'vacancies' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}
        >
          <Briefcase size={16} /> Vagas Abertas
        </button>
      </div>

      {activeTab === 'employees' ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
          {employees.map(emp => {
            const docStatus = getExpiryStatus(emp.document_expiry);
            return (
              <div key={emp.id} className="bg-white p-8 rounded-[3.5rem] border border-slate-100 shadow-sm relative group hover:shadow-2xl transition-all border-b-4 border-b-transparent hover:border-b-indigo-500">
                <div className={`absolute top-6 left-6 px-4 py-1.5 rounded-full border text-[9px] font-black uppercase tracking-widest flex items-center gap-2 z-10 ${docStatus.color}`}>
                  {docStatus.icon} {docStatus.label}
                </div>
                <div className="absolute top-6 right-6 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button onClick={() => { setEditingEmpId(emp.id); setFormState(emp); setShowAddModal(true); }} className="p-2.5 bg-white text-slate-400 hover:text-indigo-600 rounded-xl shadow-sm border border-slate-50 transition-all"><Edit3 size={18} /></button>
                </div>
                <div className="mt-8 flex flex-col items-center">
                  <img src={emp.avatar} className="w-24 h-24 rounded-[2.5rem] object-cover mb-5 ring-8 ring-slate-50 shadow-inner" alt={emp.name} />
                  <h3 className="text-xl font-black text-slate-900 mb-1 text-center">{emp.name}</h3>
                  <p className="text-[10px] font-black text-indigo-600 uppercase tracking-widest mb-6 text-center bg-indigo-50 px-3 py-1 rounded-lg">{emp.role}</p>
                </div>
                <div className="pt-6 border-t border-slate-50 flex justify-between items-center">
                  <div>
                    <p className="text-[9px] font-black text-slate-400 uppercase tracking-tighter">Salário</p>
                    <p className="text-base font-black text-slate-900">{Number(emp.salary).toLocaleString()} MT</p>
                  </div>
                  <button onClick={() => removeEmployee(emp.id)} className="text-slate-300 hover:text-rose-600 transition-colors"><Trash2 size={18} /></button>
                </div>
              </div>
            );
          })}
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {vacancies.length === 0 ? (
            <div className="col-span-full py-24 text-center bg-white rounded-[3rem] border border-dashed border-slate-200">
               <Briefcase size={48} className="mx-auto text-slate-200 mb-4" />
               <p className="text-slate-400 font-bold uppercase tracking-widest text-xs">Nenhuma vaga publicada</p>
            </div>
          ) : vacancies.map(v => (
            <div key={v.id} className="bg-white p-8 rounded-[3.5rem] border border-slate-100 shadow-sm hover:shadow-xl transition-all relative">
              <div className="flex justify-between items-start mb-6">
                 <div className="p-3 bg-blue-50 text-blue-600 rounded-2xl"><Briefcase size={20} /></div>
                 <button onClick={() => deleteVacancy(v.id)} className="text-slate-200 hover:text-rose-600 transition-colors"><Trash2 size={20} /></button>
              </div>
              <h3 className="text-xl font-black text-slate-900 mb-2">{v.title}</h3>
              <div className="space-y-3 mb-8">
                 <div className="flex items-center gap-2 text-xs font-bold text-slate-500"><MapPin size={14} className="text-blue-500" /> {v.location}</div>
                 <div className="flex items-center gap-2 text-xs font-bold text-slate-500"><LayoutList size={14} className="text-blue-500" /> {v.area}</div>
                 <div className="flex items-center gap-2 text-xs font-bold text-slate-500"><DollarSign size={14} className="text-blue-500" /> {v.salary || 'A combinar'}</div>
              </div>
              <div className="pt-6 border-t border-slate-50 flex items-center justify-between">
                 <span className="text-[10px] font-black text-blue-600 bg-blue-50 px-3 py-1 rounded-full uppercase tracking-widest">{v.type}</span>
                 <span className="text-[9px] font-bold text-slate-400 uppercase tracking-tighter">Publicado em {new Date(v.created_at).toLocaleDateString()}</span>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Vacancy Modal */}
      {showVacancyModal && (
        <div className="fixed inset-0 z-[130] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-12 max-w-xl w-full shadow-2xl relative">
            <button onClick={() => setShowVacancyModal(false)} className="absolute top-10 right-10 text-slate-400 hover:text-slate-900"><X size={28} /></button>
            <h2 className="text-3xl font-black text-slate-900 mb-8 flex items-center gap-3"><Briefcase className="text-blue-600" /> Nova Oferta de Emprego</h2>
            <form onSubmit={handleSaveVacancy} className="space-y-6">
               <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Título da Vaga</label>
                  <input required value={vacancyForm.title} onChange={e => setVacancyForm({...vacancyForm, title: e.target.value})} className="w-full bg-slate-50 p-5 rounded-2xl font-bold border-none outline-none focus:ring-4 focus:ring-blue-100" placeholder="Ex: Consultor Imobiliário Sénior" />
               </div>
               <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Localização</label>
                    <input required value={vacancyForm.location} onChange={e => setVacancyForm({...vacancyForm, location: e.target.value})} className="w-full bg-slate-50 p-5 rounded-2xl font-bold border-none outline-none focus:ring-4 focus:ring-blue-100" placeholder="Beira" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Tipo</label>
                    <select value={vacancyForm.type} onChange={e => setVacancyForm({...vacancyForm, type: e.target.value})} className="w-full bg-slate-50 p-5 rounded-2xl font-bold border-none outline-none focus:ring-4 focus:ring-blue-100">
                       <option>Full-time</option><option>Part-time</option><option>Consultoria</option><option>Estágio</option>
                    </select>
                  </div>
               </div>
               <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Compensação (Opcional)</label>
                  <input value={vacancyForm.salary} onChange={e => setVacancyForm({...vacancyForm, salary: e.target.value})} className="w-full bg-slate-50 p-5 rounded-2xl font-bold border-none outline-none focus:ring-4 focus:ring-blue-100" placeholder="Ex: 25.000 MT + Comissões" />
               </div>
               <button type="submit" className="w-full py-6 bg-blue-600 text-white rounded-[2rem] font-black shadow-xl hover:bg-blue-700 transition-all flex items-center justify-center gap-3">
                  {saving ? <Loader2 className="animate-spin" /> : <><Save size={20} /> Publicar no Portal</>}
               </button>
            </form>
          </div>
        </div>
      )}

      {/* Staff Modal */}
      {showAddModal && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-12 max-w-4xl w-full shadow-2xl relative overflow-y-auto max-h-[90vh]">
            <button onClick={() => { setShowAddModal(false); setEditingEmpId(null); setFormState(initialFormState); }} className="absolute top-10 right-10 text-slate-400 p-2 hover:bg-slate-50 rounded-xl transition-all"><X size={28} /></button>
            <div className="flex items-center gap-4 mb-10">
               <div className="w-12 h-12 bg-indigo-50 text-indigo-600 rounded-2xl flex items-center justify-center">
                  {editingEmpId ? <Edit3 size={24} /> : <Plus size={24} />}
               </div>
               <h2 className="text-3xl font-black text-slate-900 tracking-tight">{editingEmpId ? 'Editar Colaborador' : 'Novo Contrato Monte'}</h2>
            </div>
            {error && <div className="mb-6 p-4 bg-rose-50 text-rose-700 rounded-xl font-bold text-xs border-l-4 border-rose-500">{error}</div>}
            <form onSubmit={handleSaveEmployee} className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <input required placeholder="Nome Completo" value={formState.name} onChange={e => setFormState({...formState, name: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold border-none outline-none focus:ring-4 focus:ring-indigo-100" />
                <input required type="email" placeholder="E-mail" value={formState.email} onChange={e => setFormState({...formState, email: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold border-none outline-none focus:ring-4 focus:ring-indigo-100" />
                <input required placeholder="Telefone" value={formState.phone} onChange={e => setFormState({...formState, phone: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold border-none outline-none focus:ring-4 focus:ring-indigo-100" />
                <input required type="number" placeholder="Salário (MT)" value={formState.salary} onChange={e => setFormState({...formState, salary: Number(e.target.value)})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold border-none outline-none focus:ring-4 focus:ring-indigo-100" />
                <input required placeholder="Número de Documento" value={formState.document_number} onChange={e => setFormState({...formState, document_number: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold border-none outline-none focus:ring-4 focus:ring-indigo-100" />
                <input required type="date" value={formState.document_expiry} onChange={e => setFormState({...formState, document_expiry: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold border-none outline-none focus:ring-4 focus:ring-indigo-100" />
                <button disabled={saving} type="submit" className="md:col-span-2 py-6 bg-indigo-600 text-white rounded-[2.5rem] font-black shadow-xl hover:bg-indigo-700 transition-all flex items-center justify-center gap-4">
                  {saving ? <Loader2 className="animate-spin" /> : <><Save size={24} /> Confirmar Dados</>}
                </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default HRView;

