import { GoogleGenAI } from "@google/genai";

export const getStrategicInsight = async (context: string) => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `Como um consultor empresarial experiente, analise estes dados e forneça uma sugestão curta e impactante para o negócio: ${context}. Responda em Português.`
    });
    return response.text || "Não foi possível gerar insights no momento.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Erro ao conectar com o serviço de IA.";
  }
};

export const generateJobDescription = async (jobTitle: string, area: string, location: string) => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Gere UMA DESCRIÇÃO PROFISSIONAL E COMPLETA para a vaga: "${jobTitle}" na área de "${area}", em "${location}".
      REGRAS CRÍTICAS: 
      1. NÃO inclua saudações, introduções ou comentários (ex: "Aqui está...", "Espero que ajude").
      2. Comece DIRETAMENTE com o título ou resumo.
      3. Use Markdown para estruturar: ### Resumo, ### Responsabilidades, ### Requisitos e ### Benefícios.
      4. Empresa: Monte Imobiliária (Moçambique).
      5. O texto deve estar PRONTO para publicar.`
    });
    return response.text?.trim() || "Erro ao gerar descrição.";
  } catch (error) {
    console.error("Gemini AI Error (Jobs):", error);
    return "Não foi possível gerar a descrição via IA neste momento.";
  }
};

import React, { useState, useEffect } from 'react';
import { 
  Plus, Users, AlertCircle, Clock, 
  Loader2, X, Trash2, Save, Mail, Phone, 
  Edit3, ShieldCheck, AlertTriangle, Briefcase, 
  Search, MapPin, DollarSign, LayoutList, Sparkles, Camera, AlignLeft, RefreshCcw
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { Employee, UserRole, JobVacancy } from '../types';
import { generateJobDescription } from '../geminiService';

const SUGGESTED_ROLES = [
  'Estagiário de Digitador de Dados',
  'Gerente de Produção',
  'Agente de Campo',
  'Marketing',
  'Gerente de Campo',
  'Revisor de Dados',
  'Consultor Imobiliário Sénior',
  'Recepcionista / Front Desk'
];

const HRView: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'employees' | 'vacancies'>('employees');
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [vacancies, setVacancies] = useState<JobVacancy[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAddModal, setShowAddModal] = useState(false);
  const [showVacancyModal, setShowVacancyModal] = useState(false);
  const [editingEmpId, setEditingEmpId] = useState<string | null>(null);
  const [editingVacancyId, setEditingVacancyId] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [saving, setSaving] = useState(false);
  const [isAiLoading, setIsAiLoading] = useState(false);

  const initialFormState: Partial<Employee> = {
    name: '', role: UserRole.EMPLOYEE, department: 'Geral', salary: 0, email: '', phone: '',
    document_type: 'BI', document_number: '', document_expiry: '', payment_method: 'M-Pesa', contract_start: ''
  };

  const initialVacancyState: Partial<JobVacancy> = {
    title: '', area: 'Operações', type: 'Full-time', location: 'Beira', salary: '', status: 'Open', description: '', image: ''
  };

  const [formState, setFormState] = useState<Partial<Employee>>(initialFormState);
  const [vacancyForm, setVacancyForm] = useState<Partial<JobVacancy>>(initialVacancyState);

  useEffect(() => {
    fetchData();
    fetchVacancies();
  }, []);

  async function fetchData() {
    setLoading(true);
    try {
      const { data, error: sbError } = await supabase.from('employees').select('*').order('name');
      if (sbError) setError(sbError.message);
      setEmployees(data || []);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }

  async function fetchVacancies() {
    try {
      const { data, error: sbError } = await supabase.from('job_vacancies').select('*').order('created_at', { ascending: false });
      if (!sbError) setVacancies(data || []);
    } catch (err) { console.warn("Job vacancies table error or missing."); }
  }

  const handleAiOptimize = async () => {
    if (!vacancyForm.title) {
      alert("Por favor, defina o Cargo para a IA gerar a descrição.");
      return;
    }
    setIsAiLoading(true);
    try {
      const optimizedText = await generateJobDescription(
        vacancyForm.title || '', 
        vacancyForm.area || '', 
        vacancyForm.location || ''
      );
      setVacancyForm(prev => ({ ...prev, description: optimizedText }));
    } finally {
      setIsAiLoading(false);
    }
  };

  const handleSaveVacancy = async (e: React.FormEvent) => {
    e.preventDefault();
    setSaving(true);
    try {
      const payload = { ...vacancyForm };

      let res;
      if (editingVacancyId) {
        res = await supabase.from('job_vacancies').update(payload).eq('id', editingVacancyId);
      } else {
        res = await supabase.from('job_vacancies').insert([payload]);
      }

      if (res.error) throw res.error;

      setShowVacancyModal(false);
      setEditingVacancyId(null);
      setVacancyForm(initialVacancyState);
      fetchVacancies();
    } catch (err: any) {
      alert("Erro ao gravar vaga: " + err.message);
    } finally {
      setSaving(false);
    }
  };

  const handleEditVacancy = (vacancy: JobVacancy) => {
    setEditingVacancyId(vacancy.id);
    setVacancyForm(vacancy);
    setShowVacancyModal(true);
  };

  const deleteVacancy = async (id: string) => {
    if (confirm('Deseja remover esta oferta permanentemente?')) {
      await supabase.from('job_vacancies').delete().eq('id', id);
      fetchVacancies();
    }
  };

  const removeEmployee = async (id: string) => {
    if (confirm('Deseja remover este colaborador permanentemente?')) {
      const { error: sbError } = await supabase.from('employees').delete().eq('id', id);
      if (!sbError) fetchData();
      else alert("Erro ao remover: " + sbError.message);
    }
  };

  const getExpiryStatus = (expiryDate?: string) => {
    if (!expiryDate) return { label: 'Sem Info', color: 'bg-slate-100 text-slate-400 border-slate-200', icon: <AlertCircle size={10} />, pulse: false };
    const today = new Date();
    today.setHours(0,0,0,0);
    const expiry = new Date(expiryDate);
    const thirtyDaysFromNow = new Date();
    thirtyDaysFromNow.setDate(today.getDate() + 30);

    if (expiry < today) return { label: 'Expirado', color: 'bg-rose-50 text-rose-600 border-rose-100', icon: <AlertTriangle size={10} />, pulse: true };
    if (expiry <= thirtyDaysFromNow) return { label: 'A Vencer', color: 'bg-amber-50 text-amber-600 border-amber-100', icon: <Clock size={10} />, pulse: false };
    return { label: 'Ativo', color: 'bg-emerald-50 text-emerald-600 border-emerald-100', icon: <ShieldCheck size={10} />, pulse: false };
  };

  const handleSaveEmployee = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setSaving(true);

    try {
      const payload = { ...formState, salary: Number(formState.salary), status: 'Ativo', avatar: `https://picsum.photos/seed/${formState.name}/100` };
      if (editingEmpId) {
        await supabase.from('employees').update(payload).eq('id', editingEmpId);
      } else {
        await supabase.from('employees').insert([payload]);
      }
      setShowAddModal(false);
      setEditingEmpId(null);
      setFormState(initialFormState);
      fetchData();
    } catch (err: any) { setError(err.message); } finally { setSaving(false); }
  };

  if (loading) return <div className="flex justify-center py-24"><Loader2 className="animate-spin text-indigo-600" size={48} /></div>;

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-4">
           <div className="w-14 h-14 bg-indigo-600 rounded-[1.5rem] flex items-center justify-center text-white shadow-xl shadow-indigo-500/20"><Users size={28} /></div>
           <div>
             <h1 className="text-3xl font-black text-slate-900 tracking-tight">Gestão de Talentos</h1>
             <p className="text-slate-500 font-medium">Controle de staff e recrutamento inteligente.</p>
           </div>
        </div>
        <div className="flex gap-3">
          {activeTab === 'employees' ? (
            <button onClick={() => { setEditingEmpId(null); setFormState(initialFormState); setShowAddModal(true); }} className="px-8 py-4 bg-indigo-600 text-white rounded-[2rem] font-black text-sm shadow-xl hover:bg-indigo-700 transition-all active:scale-95 flex items-center gap-2">
              <Plus size={20} /> Novo Colaborador
            </button>
          ) : (
            <button onClick={() => { setEditingVacancyId(null); setVacancyForm(initialVacancyState); setShowVacancyModal(true); }} className="px-8 py-4 bg-blue-600 text-white rounded-[2rem] font-black text-sm shadow-xl hover:bg-blue-700 transition-all active:scale-95 flex items-center gap-2">
              <Plus size={20} /> Criar Nova Vaga
            </button>
          )}
        </div>
      </div>

      {/* Tabs */}
      <div className="flex p-1.5 bg-slate-100 rounded-[2rem] w-full max-w-md mx-auto">
        <button 
          onClick={() => setActiveTab('employees')}
          className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-[1.5rem] text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'employees' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}
        >
          <Users size={16} /> Colaboradores
        </button>
        <button 
          onClick={() => setActiveTab('vacancies')}
          className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-[1.5rem] text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'vacancies' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}
        >
          <Briefcase size={16} /> Recrutamento
        </button>
      </div>

      {activeTab === 'employees' ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
          {employees.map(emp => {
            const docStatus = getExpiryStatus(emp.document_expiry);
            return (
              <div key={emp.id} className="bg-white p-8 rounded-[3.5rem] border border-slate-100 shadow-sm relative group hover:shadow-2xl transition-all border-b-4 border-b-transparent hover:border-b-indigo-500">
                <div className={`absolute top-6 left-6 px-4 py-1.5 rounded-full border text-[9px] font-black uppercase tracking-widest flex items-center gap-2 z-10 ${docStatus.color}`}>
                  {docStatus.icon} {docStatus.label}
                </div>
                <div className="absolute top-6 right-6 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button onClick={() => { setEditingEmpId(emp.id); setFormState(emp); setShowAddModal(true); }} className="p-2.5 bg-white text-slate-400 hover:text-indigo-600 rounded-xl shadow-sm border border-slate-100 transition-all"><Edit3 size={18} /></button>
                </div>
                <div className="mt-8 flex flex-col items-center">
                  <img src={emp.avatar} className="w-24 h-24 rounded-[2.5rem] object-cover mb-5 ring-8 ring-slate-50 shadow-inner" alt={emp.name} />
                  <h3 className="text-xl font-black text-slate-900 mb-1 text-center">{emp.name}</h3>
                  <p className="text-[10px] font-black text-indigo-600 uppercase tracking-widest mb-6 text-center bg-indigo-50 px-3 py-1 rounded-lg">{emp.role}</p>
                </div>
                <div className="pt-6 border-t border-slate-50 flex justify-between items-center">
                  <div>
                    <p className="text-[9px] font-black text-slate-400 uppercase tracking-tighter">Salário</p>
                    <p className="text-base font-black text-slate-900">{Number(emp.salary).toLocaleString()} MT</p>
                  </div>
                  <button onClick={() => removeEmployee(emp.id)} className="text-slate-300 hover:text-rose-600 transition-colors"><Trash2 size={18} /></button>
                </div>
              </div>
            );
          })}
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {vacancies.length === 0 ? (
            <div className="col-span-full py-24 text-center bg-white rounded-[3rem] border border-dashed border-slate-200">
               <Briefcase size={48} className="mx-auto text-slate-200 mb-4" />
               <p className="text-slate-400 font-bold uppercase tracking-widest text-xs">Sem vagas publicadas</p>
            </div>
          ) : vacancies.map(v => (
            <div key={v.id} className="bg-white rounded-[3rem] border border-slate-100 shadow-sm hover:shadow-xl transition-all relative overflow-hidden flex flex-col group">
              {v.image && (
                <div className="h-32 w-full overflow-hidden">
                  <img src={v.image} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" alt={v.title} />
                </div>
              )}
              <div className="p-8 flex-1 flex flex-col">
                <div className="flex justify-between items-start mb-4">
                  <div className="p-3 bg-blue-50 text-blue-600 rounded-2xl"><Briefcase size={20} /></div>
                  <div className="flex gap-2">
                    <button onClick={() => handleEditVacancy(v)} className="p-2 text-slate-300 hover:text-blue-600 transition-colors"><Edit3 size={18} /></button>
                    <button onClick={() => deleteVacancy(v.id)} className="p-2 text-slate-300 hover:text-rose-600 transition-colors"><Trash2 size={18} /></button>
                  </div>
                </div>
                <h3 className="text-xl font-black text-slate-900 mb-2">{v.title}</h3>
                <div className="space-y-2 mb-6">
                  <div className="flex items-center gap-2 text-xs font-bold text-slate-500"><MapPin size={14} className="text-blue-500" /> {v.location}</div>
                  <div className="flex items-center gap-2 text-xs font-bold text-slate-500"><LayoutList size={14} className="text-blue-500" /> {v.area}</div>
                </div>
                <div className="mt-auto pt-6 border-t border-slate-50 flex items-center justify-between">
                  <span className="text-[10px] font-black text-blue-600 bg-blue-50 px-3 py-1 rounded-full uppercase tracking-widest">{v.type}</span>
                  <span className="text-[9px] font-bold text-slate-400 uppercase tracking-tighter">{new Date(v.created_at).toLocaleDateString()}</span>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Vacancy Modal - Optimized */}
      {showVacancyModal && (
        <div className="fixed inset-0 z-[130] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-10 md:p-14 max-w-4xl w-full shadow-2xl relative overflow-y-auto max-h-[95vh] custom-scrollbar">
            <button onClick={() => setShowVacancyModal(false)} className="absolute top-10 right-10 text-slate-400 hover:text-slate-900 p-2"><X size={28} /></button>

            <div className="flex items-center gap-4 mb-8">
               <div className="w-12 h-12 bg-blue-50 text-blue-600 rounded-2xl flex items-center justify-center">
                  {editingVacancyId ? <Edit3 size={24} /> : <Plus size={24} />}
               </div>
               <h2 className="text-3xl font-black text-slate-900 tracking-tight">
                {editingVacancyId ? 'Editar Oportunidade' : 'Publicar Vaga Cloud'}
               </h2>
            </div>

            <form onSubmit={handleSaveVacancy} className="space-y-6">
               <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Cargo da Vaga</label>
                    <input 
                      list="roles-list"
                      required 
                      value={vacancyForm.title} 
                      onChange={e => setVacancyForm({...vacancyForm, title: e.target.value})} 
                      className="w-full bg-slate-50 p-5 rounded-2xl font-bold border-none outline-none focus:ring-4 focus:ring-blue-100" 
                      placeholder="Ex: Agente de Campo" 
                    />
                    <datalist id="roles-list">
                      {SUGGESTED_ROLES.map(role => <option key={role} value={role} />)}
                    </datalist>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Área / Departamento</label>
                    <select value={vacancyForm.area} onChange={e => setVacancyForm({...vacancyForm, area: e.target.value})} className="w-full bg-slate-50 p-5 rounded-2xl font-bold border-none outline-none focus:ring-4 focus:ring-blue-100">
                       <option>Operações & Campo</option>
                       <option>Vendas Imobiliárias</option>
                       <option>Produção & Obras</option>
                       <option>Recursos Humanos</option>
                       <option>TI & Dados</option>
                       <option>Marketing</option>
                    </select>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Localização</label>
                    <input required value={vacancyForm.location} onChange={e => setVacancyForm({...vacancyForm, location: e.target.value})} className="w-full bg-slate-50 p-5 rounded-2xl font-bold border-none outline-none focus:ring-4 focus:ring-blue-100" placeholder="Beira" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Compensação</label>
                    <input value={vacancyForm.salary} onChange={e => setVacancyForm({...vacancyForm, salary: e.target.value})} className="w-full bg-slate-50 p-5 rounded-2xl font-bold border-none outline-none focus:ring-4 focus:ring-blue-100" placeholder="Ex: 25.000 MT" />
                  </div>
               </div>

               <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">URL da Imagem de Capa (Opcional)</label>
                  <div className="relative">
                    <Camera className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
                    <input value={vacancyForm.image} onChange={e => setVacancyForm({...vacancyForm, image: e.target.value})} className="w-full bg-slate-50 p-5 pl-14 rounded-2xl font-bold border-none outline-none focus:ring-4 focus:ring-blue-100" placeholder="https://images.unsplash.com/..." />
                  </div>
               </div>

               <div className="space-y-2">
                  <div className="flex items-center justify-between px-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                       <AlignLeft size={14} className="text-blue-500" /> Descrição da Vaga (Pronta p/ Publicar)
                    </label>
                    <div className="flex gap-2">
                      <button 
                        type="button" 
                        onClick={() => setVacancyForm({...vacancyForm, description: ''})}
                        className="text-[9px] font-black uppercase text-slate-400 hover:text-slate-600 flex items-center gap-1 bg-slate-50 px-3 py-1.5 rounded-full transition-all"
                      >
                        <RefreshCcw size={10} /> Limpar
                      </button>
                      <button 
                        type="button" 
                        onClick={handleAiOptimize}
                        disabled={isAiLoading}
                        className="text-[10px] font-black uppercase text-indigo-600 flex items-center gap-1.5 bg-indigo-50 px-4 py-1.5 rounded-full hover:bg-indigo-100 transition-all disabled:opacity-50 shadow-sm"
                      >
                        {isAiLoading ? <Loader2 size={12} className="animate-spin" /> : <Sparkles size={12} />}
                        Otimizar com IA
                      </button>
                    </div>
                  </div>
                  <textarea 
                    value={vacancyForm.description} 
                    onChange={e => setVacancyForm({...vacancyForm, description: e.target.value})} 
                    rows={8}
                    className="w-full bg-slate-50 p-8 rounded-[2.5rem] font-medium border-none outline-none focus:ring-4 focus:ring-blue-100 text-sm leading-relaxed custom-scrollbar" 
                    placeholder="Escreva os detalhes ou deixe a IA gerar o conteúdo profissional..."
                  />
               </div>

               <div className="flex gap-4">
                 <button 
                  type="submit" 
                  disabled={saving}
                  className="flex-1 py-6 bg-blue-600 text-white rounded-[2rem] font-black shadow-xl hover:bg-blue-700 transition-all flex items-center justify-center gap-3 active:scale-95 disabled:opacity-50"
                 >
                    {saving ? <Loader2 className="animate-spin" /> : <><Save size={20} /> {editingVacancyId ? 'Salvar Alterações' : 'Ativar Anúncio Cloud'}</>}
                 </button>
                 <button 
                  type="button"
                  onClick={() => setShowVacancyModal(false)}
                  className="px-10 py-6 bg-slate-100 text-slate-500 rounded-[2rem] font-black hover:bg-slate-200 transition-all"
                 >
                   Cancelar
                 </button>
               </div>
            </form>
          </div>
        </div>
      )}

      {/* Staff Modal */}
      {showAddModal && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-12 max-w-4xl w-full shadow-2xl relative overflow-y-auto max-h-[90vh]">
            <button onClick={() => { setShowAddModal(false); setEditingEmpId(null); setFormState(initialFormState); }} className="absolute top-10 right-10 text-slate-400 p-2 hover:bg-slate-50 rounded-xl transition-all"><X size={28} /></button>
            <div className="flex items-center gap-4 mb-10">
               <div className="w-12 h-12 bg-indigo-50 text-indigo-600 rounded-2xl flex items-center justify-center">
                  {editingEmpId ? <Edit3 size={24} /> : <Plus size={24} />}
               </div>
               <h2 className="text-3xl font-black text-slate-900 tracking-tight">{editingEmpId ? 'Editar Colaborador' : 'Novo Contrato Monte'}</h2>
            </div>
            {error && <div className="mb-6 p-4 bg-rose-50 text-rose-700 rounded-xl font-bold text-xs border-l-4 border-rose-500">{error}</div>}
            <form onSubmit={handleSaveEmployee} className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <input required placeholder="Nome Completo" value={formState.name} onChange={e => setFormState({...formState, name: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold border-none outline-none focus:ring-4 focus:ring-indigo-100" />
                <input required type="email" placeholder="E-mail" value={formState.email} onChange={e => setFormState({...formState, email: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold border-none outline-none focus:ring-4 focus:ring-indigo-100" />
                <input required placeholder="Telefone" value={formState.phone} onChange={e => setFormState({...formState, phone: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold border-none outline-none focus:ring-4 focus:ring-indigo-100" />
                <input required type="number" placeholder="Salário (MT)" value={formState.salary} onChange={e => setFormState({...formState, salary: Number(e.target.value)})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold border-none outline-none focus:ring-4 focus:ring-indigo-100" />
                <input required placeholder="Número de Documento" value={formState.document_number} onChange={e => setFormState({...formState, document_number: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold border-none outline-none focus:ring-4 focus:ring-indigo-100" />
                <input required type="date" value={formState.document_expiry} onChange={e => setFormState({...formState, document_expiry: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 font-bold border-none outline-none focus:ring-4 focus:ring-indigo-100" />
                <button disabled={saving} type="submit" className="md:col-span-2 py-6 bg-indigo-600 text-white rounded-[2.5rem] font-black shadow-xl hover:bg-indigo-700 transition-all flex items-center justify-center gap-4">
                  {saving ? <Loader2 className="animate-spin" /> : <><Save size={24} /> Confirmar Dados</>}
                </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default HRView;

import { GoogleGenAI } from "@google/genai";

export const getStrategicInsight = async (context: string) => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `Como um consultor empresarial experiente, analise estes dados e forneça uma sugestão curta e impactante para o negócio: ${context}. Responda em Português.`
    });
    return response.text || "Não foi possível gerar insights no momento.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Erro ao conectar com o serviço de IA.";
  }
};

export const generateJobDescription = async (jobTitle: string, area: string, location: string) => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Gere uma descrição de vaga de emprego PROFISSIONAL e COMPLETA para o cargo de "${jobTitle}" na área de "${area}", em "${location}".

      REGRAS OBRIGATÓRIAS:
      1. NÃO inclua nenhuma introdução ou saudação (ex: "Aqui está...", "Com certeza...", "Olá").
      2. NÃO inclua comentários finais.
      3. Use Markdown para estruturar o texto: ## Resumo, ## Responsabilidades, ## Requisitos e ## Benefícios.
      4. Empresa: Monte Imobiliária (Beira, Moçambique).
      5. O texto deve começar DIRETAMENTE com o conteúdo da vaga e estar PRONTO para envio/publicação.`
    });
    return response.text?.trim() || "Erro ao gerar descrição.";
  } catch (error) {
    console.error("Gemini AI Error (Jobs):", error);
    return "Não foi possível gerar a descrição via IA neste momento.";
  }
};

import React, { useState, useEffect } from 'react';
import { 
  Plus, Users, AlertCircle, Clock, 
  Loader2, X, Trash2, Save, Mail, Phone, 
  Edit3, ShieldCheck, AlertTriangle, Briefcase, 
  Search, MapPin, DollarSign, LayoutList, Sparkles, AlignLeft, RefreshCcw
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { Employee, UserRole, JobVacancy } from '../types';
import { generateJobDescription } from '../geminiService';

const SUGGESTED_ROLES = [
  'Estagiário de Digitador de Dados',
  'Gerente de Produção',
  'Agente de Campo',
  'Marketing',
  'Gerente de Campo',
  'Revisor de Dados'
];

const HRView: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'employees' | 'vacancies'>('employees');
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [vacancies, setVacancies] = useState<JobVacancy[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAddModal, setShowAddModal] = useState(false);
  const [showVacancyModal, setShowVacancyModal] = useState(false);
  const [editingEmpId, setEditingEmpId] = useState<string | null>(null);
  const [editingVacancyId, setEditingVacancyId] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [saving, setSaving] = useState(false);
  const [isAiLoading, setIsAiLoading] = useState(false);

  const initialFormState: Partial<Employee> = {
    name: '', role: UserRole.EMPLOYEE, department: 'Geral', salary: 0, email: '', phone: '',
    document_type: 'BI', document_number: '', document_expiry: '', payment_method: 'M-Pesa', contract_start: ''
  };

  const initialVacancyState: Partial<JobVacancy> = {
    title: '', area: 'Operações', type: 'Full-time', location: 'Beira', salary: '', status: 'Open', description: ''
  };

  const [formState, setFormState] = useState<Partial<Employee>>(initialFormState);
  const [vacancyForm, setVacancyForm] = useState<Partial<JobVacancy>>(initialVacancyState);

  useEffect(() => {
    fetchData();
    fetchVacancies();
  }, []);

  async function fetchData() {
    setLoading(true);
    try {
      const { data, error: sbError } = await supabase.from('employees').select('*').order('name');
      if (sbError) setError(sbError.message);
      setEmployees(data || []);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }

  async function fetchVacancies() {
    try {
      const { data, error: sbError } = await supabase.from('job_vacancies').select('*').order('created_at', { ascending: false });
      if (!sbError) setVacancies(data || []);
    } catch (err) { console.warn("Job vacancies table error."); }
  }

  const handleAiOptimize = async () => {
    if (!vacancyForm.title) {
      alert("Por favor, digite o Cargo primeiro.");
      return;
    }
    setIsAiLoading(true);
    try {
      const optimizedText = await generateJobDescription(
        vacancyForm.title || '', 
        vacancyForm.area || '', 
        vacancyForm.location || ''
      );
      setVacancyForm(prev => ({ ...prev, description: optimizedText }));
    } finally {
      setIsAiLoading(false);
    }
  };

  const handleSaveVacancy = async (e: React.FormEvent) => {
    e.preventDefault();
    setSaving(true);
    try {
      const payload = { 
        title: vacancyForm.title,
        area: vacancyForm.area,
        type: vacancyForm.type,
        location: vacancyForm.location,
        salary: vacancyForm.salary,
        description: vacancyForm.description,
        status: vacancyForm.status || 'Open'
      };

      let res;
      if (editingVacancyId) {
        res = await supabase.from('job_vacancies').update(payload).eq('id', editingVacancyId);
      } else {
        res = await supabase.from('job_vacancies').insert([payload]);
      }

      if (res.error) throw res.error;

      setShowVacancyModal(false);
      setEditingVacancyId(null);
      setVacancyForm(initialVacancyState);
      fetchVacancies();
    } catch (err: any) {
      alert("Erro ao gravar: " + err.message);
    } finally {
      setSaving(false);
    }
  };

  const handleEditVacancy = (vacancy: JobVacancy) => {
    setEditingVacancyId(vacancy.id);
    setVacancyForm(vacancy);
    setShowVacancyModal(true);
  };

  const deleteVacancy = async (id: string) => {
    if (confirm('Deseja remover esta vaga permanentemente?')) {
      await supabase.from('job_vacancies').delete().eq('id', id);
      fetchVacancies();
    }
  };

  const removeEmployee = async (id: string) => {
    if (confirm('Deseja remover este colaborador permanentemente?')) {
      const { error: sbError } = await supabase.from('employees').delete().eq('id', id);
      if (!sbError) fetchData();
    }
  };

  const getExpiryStatus = (expiryDate?: string) => {
    if (!expiryDate) return { label: 'Sem Info', color: 'bg-slate-100 text-slate-400 border-slate-200', icon: <AlertCircle size={10} />, pulse: false };
    const today = new Date();
    today.setHours(0,0,0,0);
    const expiry = new Date(expiryDate);
    const thirtyDaysFromNow = new Date();
    thirtyDaysFromNow.setDate(today.getDate() + 30);

    if (expiry < today) return { label: 'Expirado', color: 'bg-rose-50 text-rose-600 border-rose-100', icon: <AlertTriangle size={10} />, pulse: true };
    if (expiry <= thirtyDaysFromNow) return { label: 'A Vencer', color: 'bg-amber-50 text-amber-600 border-amber-100', icon: <Clock size={10} />, pulse: false };
    return { label: 'Ativo', color: 'bg-emerald-50 text-emerald-600 border-emerald-100', icon: <ShieldCheck size={10} />, pulse: false };
  };

  const handleSaveEmployee = async (e: React.FormEvent) => {
    e.preventDefault();
    setSaving(true);
    try {
      const payload = { ...formState, salary: Number(formState.salary), status: 'Ativo', avatar: `https://picsum.photos/seed/${formState.name}/100` };
      if (editingEmpId) {
        await supabase.from('employees').update(payload).eq('id', editingEmpId);
      } else {
        await supabase.from('employees').insert([payload]);
      }
      setShowAddModal(false);
      setEditingEmpId(null);
      setFormState(initialFormState);
      fetchData();
    } catch (err: any) { alert(err.message); } finally { setSaving(false); }
  };

  if (loading) return <div className="flex justify-center py-24"><Loader2 className="animate-spin text-indigo-600" size={48} /></div>;

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-4">
           <div className="w-14 h-14 bg-indigo-600 rounded-[1.5rem] flex items-center justify-center text-white shadow-xl shadow-indigo-500/20"><Users size={28} /></div>
           <div>
             <h1 className="text-3xl font-black text-slate-900 tracking-tight">Gestão de Talentos</h1>
             <p className="text-slate-500 font-medium">Controle de staff e recrutamento.</p>
           </div>
        </div>
        <div className="flex gap-3">
          {activeTab === 'employees' ? (
            <button onClick={() => { setEditingEmpId(null); setFormState(initialFormState); setShowAddModal(true); }} className="px-8 py-4 bg-indigo-600 text-white rounded-[2rem] font-black text-sm shadow-xl hover:bg-indigo-700 transition-all active:scale-95 flex items-center gap-2">
              <Plus size={20} /> Novo Colaborador
            </button>
          ) : (
            <button onClick={() => { setEditingVacancyId(null); setVacancyForm(initialVacancyState); setShowVacancyModal(true); }} className="px-8 py-4 bg-blue-600 text-white rounded-[2rem] font-black text-sm shadow-xl hover:bg-blue-700 transition-all active:scale-95 flex items-center gap-2">
              <Plus size={20} /> Criar Nova Vaga
            </button>
          )}
        </div>
      </div>

      {/* Tabs */}
      <div className="flex p-1.5 bg-slate-100 rounded-[2rem] w-full max-w-md mx-auto">
        <button 
          onClick={() => setActiveTab('employees')}
          className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-[1.5rem] text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'employees' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}
        >
          <Users size={16} /> Colaboradores
        </button>
        <button 
          onClick={() => setActiveTab('vacancies')}
          className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-[1.5rem] text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'vacancies' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}
        >
          <Briefcase size={16} /> Recrutamento
        </button>
      </div>

      {activeTab === 'employees' ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
          {employees.map(emp => {
            const docStatus = getExpiryStatus(emp.document_expiry);
            return (
              <div key={emp.id} className="bg-white p-8 rounded-[3.5rem] border border-slate-100 shadow-sm relative group hover:shadow-2xl transition-all border-b-4 border-b-transparent hover:border-b-indigo-500">
                <div className={`absolute top-6 left-6 px-4 py-1.5 rounded-full border text-[9px] font-black uppercase tracking-widest flex items-center gap-2 z-10 ${docStatus.color}`}>
                  {docStatus.icon} {docStatus.label}
                </div>
                <div className="absolute top-6 right-6 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button onClick={() => { setEditingEmpId(emp.id); setFormState(emp); setShowAddModal(true); }} className="p-2.5 bg-white text-slate-400 hover:text-indigo-600 rounded-xl shadow-sm border border-slate-100 transition-all"><Edit3 size={18} /></button>
                </div>
                <div className="mt-8 flex flex-col items-center">
                  <img src={emp.avatar} className="w-24 h-24 rounded-[2.5rem] object-cover mb-5 ring-8 ring-slate-50 shadow-inner" alt={emp.name} />
                  <h3 className="text-xl font-black text-slate-900 mb-1 text-center">{emp.name}</h3>
                  <p className="text-[10px] font-black text-indigo-600 uppercase tracking-widest mb-6 text-center bg-indigo-50 px-3 py-1 rounded-lg">{emp.role}</p>
                </div>
                <div className="pt-6 border-t border-slate-50 flex justify-between items-center">
                  <div>
                    <p className="text-[9px] font-black text-slate-400 uppercase tracking-tighter">Salário</p>
                    <p className="text-base font-black text-slate-900">{Number(emp.salary).toLocaleString()} MT</p>
                  </div>
                  <button onClick={() => removeEmployee(emp.id)} className="text-slate-300 hover:text-rose-600 transition-colors"><Trash2 size={18} /></button>
                </div>
              </div>
            );
          })}
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {vacancies.length === 0 ? (
            <div className="col-span-full py-24 text-center bg-white rounded-[3rem] border border-dashed border-slate-200">
               <Briefcase size={48} className="mx-auto text-slate-200 mb-4" />
               <p className="text-slate-400 font-bold uppercase tracking-widest text-xs">Sem vagas publicadas</p>
            </div>
          ) : vacancies.map(v => (
            <div key={v.id} className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm hover:shadow-xl transition-all relative overflow-hidden flex flex-col group">
              <div className="flex justify-between items-start mb-4">
                <div className="p-3 bg-blue-50 text-blue-600 rounded-2xl"><Briefcase size={20} /></div>
                <div className="flex gap-2">
                  <button onClick={() => handleEditVacancy(v)} className="p-2 text-slate-300 hover:text-blue-600 transition-colors"><Edit3 size={18} /></button>
                  <button onClick={() => deleteVacancy(v.id)} className="p-2 text-slate-300 hover:text-rose-600 transition-colors"><Trash2 size={18} /></button>
                </div>
              </div>
              <h3 className="text-xl font-black text-slate-900 mb-2">{v.title}</h3>
              <div className="space-y-2 mb-6">
                <div className="flex items-center gap-2 text-xs font-bold text-slate-500"><MapPin size={14} className="text-blue-500" /> {v.location}</div>
                <div className="flex items-center gap-2 text-xs font-bold text-slate-500"><LayoutList size={14} className="text-blue-500" /> {v.area}</div>
