          <div className="bg-white rounded-[4rem] p-12 max-w-4xl w-full shadow-2xl relative overflow-y-auto max-h-[90vh] custom-scrollbar">
            <button onClick={() => { setShowAddModal(false); setEditingEmpId(null); setFormState(initialFormState); setError(null); }} className="absolute top-10 right-10 text-slate-400 p-2 hover:bg-slate-50 rounded-xl transition-all"><X size={28} /></button>
            <div className="flex items-center gap-4 mb-8">
               <div className="w-12 h-12 bg-indigo-50 text-indigo-600 rounded-2xl flex items-center justify-center">
                  {editingEmpId ? <Edit3 size={24} /> : <Plus size={24} />}
               </div>
               <h2 className="text-3xl font-black text-slate-900 tracking-tight">{editingEmpId ? 'Editar Colaborador' : 'Novo Contrato Monte'}</h2>
            </div>

            {error && (
              <div className="mb-8 p-6 bg-rose-50 border-l-4 border-rose-500 rounded-[1.5rem] flex items-center gap-4 animate-in slide-in-from-top-2">
                <AlertTriangle size={24} className="text-rose-600" />
                <div className="flex-1">
                   <p className="text-[10px] font-black uppercase text-rose-500 tracking-widest mb-1">Erro de Validação</p>
