                    <input 
                      required 
                      placeholder="Ex: João Silva" 
                      value={formState.name} 
                      onChange={e => setFormState({...formState, name: e.target.value})} 
                      className="w-full bg-slate-50 rounded-2xl p-5 font-bold border-none outline-none focus:ring-4 focus:ring-indigo-100 transition-all" 
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">E-mail Staff</label>
                    <div className="relative">
                      <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                      <input 
                        required 
                        type="email" 
                        placeholder="nome@monte-imobiliaria.com" 
                        value={formState.email} 
                        onChange={e => setFormState({...formState, email: e.target.value})} 
                        className="w-full bg-slate-50 rounded-2xl p-5 pl-14 font-bold border-none outline-none focus:ring-4 focus:ring-indigo-100 transition-all" 
                      />
                    </div>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Telefone Moçambique</label>
                    <div className="relative">
                      <Phone className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                      <input 
                        required 
                        placeholder="+258 84 000 0000" 
                        value={formState.phone} 
                        onChange={e => setFormState({...formState, phone: e.target.value})} 
                        className="w-full bg-slate-50 rounded-2xl p-5 pl-14 font-bold border-none outline-none focus:ring-4 focus:ring-indigo-100 transition-all" 
                      />
                    </div>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Salário (MT)</label>
                    <div className="relative">
                      <DollarSign className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
