                      />
                    </div>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Número de BI / Documento</label>
                    <input 
                      required 
                      placeholder="Ex: 1234567890B" 
                      value={formState.document_number} 
                      onChange={e => setFormState({...formState, document_number: e.target.value})} 
                      className="w-full bg-slate-50 rounded-2xl p-5 font-bold border-none outline-none focus:ring-4 focus:ring-indigo-100 transition-all" 
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Validade do Documento</label>
                    <input 
                      required 
                      type="date" 
                      value={formState.document_expiry} 
