                      className="w-full bg-slate-50 rounded-2xl p-5 font-bold border-none outline-none focus:ring-4 focus:ring-indigo-100 transition-all" 
                    />
                  </div>
                </div>

                <div className="flex gap-4">
                  <button 
                    disabled={saving} 
                    type="submit" 
                    className="flex-1 py-6 bg-indigo-600 text-white rounded-[2rem] font-black shadow-xl hover:bg-indigo-700 transition-all flex items-center justify-center gap-4 active:scale-95 disabled:opacity-50"
                  >
                    {saving ? <Loader2 className="animate-spin" /> : <><Save size={24} /> Confirmar Colaborador</>}
                  </button>
                  <button 
                    type="button"
                    onClick={() => { setShowAddModal(false); setEditingEmpId(null); setFormState(initialFormState); setError(null); }}
                    className="px-10 py-6 bg-slate-100 text-slate-500 rounded-[2rem] font-black hover:bg-slate-200 transition-all"
