        </div>
      )}
    </div>
  );
};

export default HRView;

import React, { useState, useEffect } from 'react';
import { 
  Calendar, Users, DollarSign, ArrowRight, Clock, 
  Loader2, Plus, X, Save, Edit3, Trash2, Camera, 
  CheckCircle2, AlertTriangle, Building, AlertCircle,
  UserPlus
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { Project } from '../types';

const ProjectsView: React.FC = () => {
  const [projects, setProjects] = useState<Project[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editingProject, setEditingProject] = useState<Project | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

  const [formData, setFormData] = useState<Partial<Project>>({
    name: '',
    status: 'Planejado',
    budget: 0,
    spent: 0,
    deadline: '',
    image: '',
    team: []
  });

  const [teamInput, setTeamInput] = useState('');

  useEffect(() => {
    fetchProjects();
  }, []);

  async function fetchProjects() {
    setLoading(true);
    const { data, error } = await supabase
      .from('projects')
      .select('*')
      .order('created_at', { ascending: false });

    if (!error) setProjects(data || []);
    setLoading(false);
  }

  const handleOpenModal = (project: Project | null = null) => {
    setMessage(null);
    if (project) {
      setEditingProject(project);
      setFormData(project);
      setTeamInput(project.team ? project.team.join(', ') : '');
    } else {
      setEditingProject(null);
      setFormData({
        name: '',
        status: 'Planejado',
        budget: 0,
        spent: 0,
        deadline: '',
        image: '',
        team: []
      });
      setTeamInput('');
    }
    setShowModal(true);
  };

  const handleSaveProject = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setMessage(null);

    const teamArray = teamInput.split(',').map(name => name.trim()).filter(name => name !== '');

    const payload = {
      ...formData,
      team: teamArray,
      image: formData.image || 'https://images.unsplash.com/photo-1503387762-592dea58ef23?auto=format&fit=crop&q=80&w=800'
    };

    try {
      const { error } = editingProject 
        ? await supabase.from('projects').update(payload).eq('id', editingProject.id)
        : await supabase.from('projects').insert([payload]);

      if (error) throw error;

      setMessage({ 
        type: 'success', 
        text: editingProject ? 'Projeto atualizado com sucesso!' : 'Obra iniciada com sucesso na Cloud.' 
      });
      setShowModal(false);
      fetchProjects();

      setTimeout(() => setMessage(null), 5000);
    } catch (err: any) {
      setMessage({ type: 'error', text: err.message || 'Erro ao processar solicitação.' });
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDeleteProject = async (id: string) => {
    if (confirm('Tem certeza que deseja excluir este projeto e todo o seu histórico financeiro?')) {
      const { error } = await supabase.from('projects').delete().eq('id', id);
      if (!error) {
        setMessage({ type: 'success', text: 'Projeto removido com sucesso.' });
        setTimeout(() => setMessage(null), 3000);
        fetchProjects();
      } else {
        setMessage({ type: 'error', text: 'Erro ao excluir projeto: ' + error.message });
      }
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-12">
      {/* Header Section */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-5">
          <div className="w-14 h-14 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-blue-500/20">
            <Building size={28} />
          </div>
          <div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">Projetos & Obras</h1>
            <p className="text-slate-500 font-medium">Gestão técnica e financeira de intervenções.</p>
          </div>
        </div>
        <button 
          onClick={() => handleOpenModal()}
          className="flex items-center gap-2 px-8 py-4 bg-blue-600 text-white rounded-[2rem] font-black text-sm shadow-xl shadow-blue-500/20 hover:bg-blue-700 transition-all hover:scale-105"
        >
          <Plus size={20} /> Iniciar Obra
        </button>
      </div>

      {/* Global Message Alert */}
      {message && (message.type === 'success' || (message.type === 'error' && !showModal)) && (
        <div className={`p-5 rounded-[2rem] border-l-4 flex items-center justify-between gap-4 animate-in slide-in-from-top-4 ${
          message.type === 'success' 
            ? 'bg-emerald-50 border-emerald-500 text-emerald-800' 
            : 'bg-rose-50 border-rose-500 text-rose-800'
        }`}>
          <div className="flex items-center gap-4">
            {message.type === 'success' ? <CheckCircle2 size={24} /> : <AlertCircle size={24} />}
            <p className="text-sm font-black uppercase tracking-tight">{message.text}</p>
          </div>
          <button onClick={() => setMessage(null)} className="p-2 hover:bg-black/5 rounded-full transition-colors">
            <X size={18} />
          </button>
        </div>
      )}

      {loading ? (
        <div className="flex justify-center py-20"><Loader2 className="animate-spin text-blue-600" size={40} /></div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {projects.map((project) => (
            <div key={project.id} className="bg-white rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden flex flex-col hover:shadow-2xl transition-all group">
              {/* Project Cover */}
              <div className="h-52 relative overflow-hidden">
                <img 
                  src={project.image || 'https://images.unsplash.com/photo-1541888946425-d81bb19480c5?auto=format&fit=crop&q=80&w=800'} 
                  className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" 
                  alt={project.name} 
                />
                <div className="absolute top-4 left-4 bg-white/90 backdrop-blur-md px-4 py-1.5 rounded-xl text-[10px] font-black uppercase text-blue-600 shadow-sm">
                  {project.status}
                </div>
                <div className="absolute top-4 right-4 flex gap-2">
                  <button 
                    onClick={() => handleOpenModal(project)}
                    className="p-2.5 bg-white/90 backdrop-blur-md text-slate-600 hover:text-blue-600 rounded-xl shadow-sm transition-all"
                  >
                    <Edit3 size={16} />
                  </button>
                  <button 
                    onClick={() => handleDeleteProject(project.id)}
                    className="p-2.5 bg-white/90 backdrop-blur-md text-slate-600 hover:text-red-600 rounded-xl shadow-sm transition-all"
                  >
                    <Trash2 size={16} />
                  </button>
                </div>
              </div>

              <div className="p-8 flex-1 flex flex-col">
                {/* Team Avatars - New Section */}
                <div className="flex -space-x-3 mb-6 overflow-hidden">
                  {project.team && project.team.length > 0 ? (
                    project.team.map((member, idx) => (
                      <div 
                        key={idx} 
                        className="inline-block h-10 w-10 rounded-full ring-4 ring-white transition-transform hover:-translate-y-1 hover:z-10 cursor-pointer overflow-hidden bg-slate-100"
                        title={member}
                      >
                        <img 
                          src={`https://picsum.photos/seed/${member}/100`} 
                          alt={member} 
                          className="h-full w-full object-cover"
                        />
                      </div>
                    ))
                  ) : (
                    <div className="flex items-center gap-2 text-[10px] font-bold text-slate-400 uppercase italic">
                      Equipa não definida
                    </div>
                  )}
                  {project.team && project.team.length > 4 && (
                    <div className="flex items-center justify-center h-10 w-10 rounded-full ring-4 ring-white bg-slate-100 text-[10px] font-black text-slate-500">
                      +{project.team.length - 4}
                    </div>
                  )}
                </div>

                <h3 className="text-xl font-black text-slate-900 mb-6 line-clamp-1">{project.name}</h3>

                <div className="grid grid-cols-2 gap-6 mb-8">
                  <div>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Orçamento</p>
                    <p className="text-sm font-black text-slate-900">{Number(project.budget).toLocaleString()} MT</p>
                  </div>
                  <div>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Data Limite</p>
                    <p className="text-sm font-black text-slate-900 flex items-center gap-1.5">
                      <Calendar size={14} className="text-blue-600" /> {project.deadline}
                    </p>
                  </div>
                </div>

                <div className="mt-auto pt-6 border-t border-slate-50">
                  <div className="flex justify-between text-[10px] font-black text-slate-400 uppercase mb-2">
                    <span>Execução Financeira</span>
                    <span className={Number(project.spent) > Number(project.budget) ? 'text-red-600' : 'text-blue-600'}>
                      {project.budget > 0 ? Math.round((Number(project.spent) / Number(project.budget)) * 100) : 0}%
                    </span>
                  </div>
                  <div className="w-full bg-slate-100 h-2.5 rounded-full overflow-hidden">
                    <div 
                      className={`h-full transition-all duration-1000 ${Number(project.spent) > Number(project.budget) ? 'bg-red-500' : 'bg-blue-600'}`} 
                      style={{width: `${project.budget > 0 ? Math.min((Number(project.spent) / Number(project.budget)) * 100, 100) : 0}%`}}
                    ></div>
                  </div>
                  <p className="text-[10px] font-bold text-slate-400 mt-2 text-right">
                    Gasto: <span className="text-slate-900">{Number(project.spent).toLocaleString()} MT</span>
                  </p>
                </div>
              </div>
            </div>
          ))}

          {projects.length === 0 && (
            <div className="col-span-full py-20 text-center bg-white rounded-[3rem] border-2 border-dashed border-slate-100">
              <Building size={48} className="mx-auto text-slate-200 mb-4" />
              <p className="text-slate-400 font-bold">Nenhum projeto em andamento no momento.</p>
            </div>
          )}
        </div>
      )}

      {/* Project Modal */}
      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-12 max-w-2xl w-full shadow-2xl relative overflow-y-auto max-h-[90vh]">
            <button 
              onClick={() => setShowModal(false)} 
              className="absolute top-10 right-10 p-2 text-slate-400 hover:text-slate-900 bg-slate-50 rounded-xl"
            >
              <X size={24} />
            </button>

            <h2 className="text-2xl font-black text-slate-900 mb-10 flex items-center gap-3">
              <Building className="text-blue-600" /> {editingProject ? 'Editar Projeto' : 'Nova Obra Monte'}
            </h2>

            <form onSubmit={handleSaveProject} className="space-y-8">
              {/* Modal Error Message */}
              {message && message.type === 'error' && (
                <div className="p-4 bg-rose-50 border-l-4 border-rose-500 rounded-2xl flex items-center gap-3 text-rose-800 animate-shake">
                  <AlertTriangle size={20} className="shrink-0" />
                  <p className="text-xs font-bold">{message.text}</p>
                </div>
              )}

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {/* Basic Info */}
                <div className="md:col-span-2 space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nome do Projeto</label>
                  <input 
                    required 
                    value={formData.name} 
                    onChange={e => setFormData({...formData, name: e.target.value})} 
                    className="w-full bg-slate-50 rounded-2xl p-5 border-none focus:ring-2 focus:ring-blue-600 font-bold outline-none" 
                    placeholder="Ex: Reforma Condomínio Mar" 
                  />
                </div>

                {/* Team Management */}
                <div className="md:col-span-2 space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex items-center gap-2">
                    <UserPlus size={14} className="text-blue-600" /> Equipa do Projeto (Nomes separados por vírgula)
                  </label>
                  <input 
                    value={teamInput} 
                    onChange={e => setTeamInput(e.target.value)} 
                    className="w-full bg-slate-50 rounded-2xl p-5 border-none focus:ring-2 focus:ring-blue-600 font-bold outline-none" 
                    placeholder="Ex: Ana Silva, Bruno Costa, Filipe Beira" 
                  />
                  <p className="text-[9px] text-slate-400 font-medium italic ml-1">Introduza os nomes dos colaboradores que farão parte desta obra.</p>
                </div>

                {/* Image URL */}
                <div className="md:col-span-2 space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">URL da Imagem da Obra</label>
                  <div className="relative">
                    <Camera className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                    <input 
                      value={formData.image} 
                      onChange={e => setFormData({...formData, image: e.target.value})} 
                      className="w-full bg-slate-50 rounded-2xl p-5 pl-14 border-none focus:ring-2 focus:ring-blue-600 font-bold outline-none" 
                      placeholder="https://images.unsplash.com/..." 
                    />
                  </div>
                </div>

                {/* Financials */}
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Orçamento Total (MT)</label>
                  <input 
                    required 
                    type="number" 
                    value={formData.budget} 
                    onChange={e => setFormData({...formData, budget: Number(e.target.value)})} 
                    className="w-full bg-slate-50 rounded-2xl p-5 border-none focus:ring-2 focus:ring-blue-600 font-bold outline-none" 
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Valor Gasto Atual (MT)</label>
                  <input 
                    required 
                    type="number" 
                    value={formData.spent} 
                    onChange={e => setFormData({...formData, spent: Number(e.target.value)})} 
                    className="w-full bg-slate-50 rounded-2xl p-5 border-none focus:ring-2 focus:ring-blue-600 font-bold outline-none" 
                  />
                </div>

                {/* Status & Date */}
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Status Atual</label>
                  <select 
                    value={formData.status} 
                    onChange={e => setFormData({...formData, status: e.target.value as any})} 
                    className="w-full bg-slate-50 rounded-2xl p-5 border-none font-bold outline-none cursor-pointer"
                  >
                    <option>Planejado</option>
                    <option>Em Andamento</option>
                    <option>Pausado</option>
                    <option>Concluído</option>
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Data de Entrega</label>
                  <input 
                    required 
                    type="date" 
                    value={formData.deadline} 
                    onChange={e => setFormData({...formData, deadline: e.target.value})} 
                    className="w-full bg-slate-50 rounded-2xl p-5 border-none focus:ring-2 focus:ring-blue-600 font-bold outline-none" 
                  />
                </div>
              </div>

              <button 
                type="submit" 
                disabled={isSubmitting}
                className={`w-full py-6 bg-gradient-to-r from-blue-600 to-indigo-600 text-white font-black rounded-[2.5rem] shadow-2xl shadow-blue-500/40 transition-all flex items-center justify-center ${
                  isSubmitting ? 'opacity-70 scale-95' : 'hover:scale-[1.02] active:scale-95'
                }`}
              >
                {isSubmitting ? (
                  <Loader2 className="animate-spin mr-2" size={20} />
                ) : null}
                {isSubmitting ? 'Processando...' : (editingProject ? 'Guardar Alterações' : 'Iniciar Projeto na Cloud')}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default ProjectsView;

