import React, { useState, useEffect, useMemo } from 'react';
import { 
  TrendingUp, TrendingDown, Users, Home, 
  Plus, MessageSquare, Briefcase, 
  Loader2, Wallet, ChevronRight,
  ArrowUpRight, ArrowDownRight, Activity,
  Sparkles
} from 'lucide-react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, 
  ResponsiveContainer, PieChart, Pie, Cell 
} from 'recharts';
import { supabase } from '../supabaseClient';
import { Transaction, Employee, Project, Property } from '../types';
import { getStrategicInsight } from '../geminiService';

const DashboardView: React.FC = () => {
  const [stats, setStats] = useState({ revenue: 0, expenses: 0, employees: 0, properties: 0, contacts: 0 });
  const [recentContacts, setRecentContacts] = useState<any[]>([]);
  const [recentStaff, setRecentStaff] = useState<Employee[]>([]);
  const [loading, setLoading] = useState(true);
  const [aiInsight, setAiInsight] = useState<string>('Analisando pulso da empresa...');
  const [showQuickTransaction, setShowQuickTransaction] = useState(false);
  const [savingTx, setSavingTx] = useState(false);
  const [txForm, setTxForm] = useState({ description: '', amount: '', type: 'DESPESA' as 'RECEITA' | 'DESPESA' });

  useEffect(() => {
    fetchGlobalStats();
  }, []);

  async function fetchGlobalStats() {
    setLoading(true);
    try {
      const [txRes, empRes, propRes, contactRes] = await Promise.all([
        supabase.from('transactions').select('*'),
        supabase.from('employees').select('*').limit(5).order('created_at', { ascending: false }),
        supabase.from('properties').select('*', { count: 'exact', head: true }),
        supabase.from('contact_requests').select('*').limit(5).order('created_at', { ascending: false })
      ]);

      const txs = txRes.data || [];
      const rev = txs.filter(t => t.type === 'RECEITA').reduce((a, b) => a + Number(b.amount || 0), 0);
      const exp = txs.filter(t => t.type === 'DESPESA').reduce((a, b) => a + Number(b.amount || 0), 0);

      setStats({
        revenue: rev,
        expenses: exp,
        employees: (await supabase.from('employees').select('*', { count: 'exact', head: true })).count || 0,
        properties: propRes.count || 0,
        contacts: (await supabase.from('contact_requests').select('*', { count: 'exact', head: true })).count || 0
      });

      setRecentStaff(empRes.data || []);
      setRecentContacts(contactRes.data || []);

      // Solicitar insight da IA com base nos números reais
      const insight = await getStrategicInsight(`Receitas: ${rev}MT, Despesas: ${exp}MT, Imóveis: ${propRes.count}, Staff: ${empRes.data?.length}`);
      setAiInsight(insight);

    } catch (error) {
      console.error("Dashboard error:", error);
    } finally {
      setLoading(false);
    }
  }

  const handleQuickTx = async (e: React.FormEvent) => {
    e.preventDefault();
    setSavingTx(true);
    try {
      const { error } = await supabase.from('transactions').insert([{
        description: txForm.description,
        amount: Number(txForm.amount),
        type: txForm.type,
        category: 'Geral',
        date: new Date().toISOString().split('T')[0]
      }]);
      if (!error) {
        setShowQuickTransaction(false);
        setTxForm({ description: '', amount: '', type: 'DESPESA' });
        fetchGlobalStats();
      }
    } finally {
      setSavingTx(false);
    }
  };

  const chartData = useMemo(() => [
    { name: 'Receitas', value: stats.revenue, color: '#10b981' },
    { name: 'Despesas', value: stats.expenses, color: '#f43f5e' }
  ], [stats]);

  const barData = useMemo(() => [
    { name: 'Financeiro', receitas: stats.revenue, despesas: stats.expenses }
  ], [stats]);

  if (loading) return (
    <div className="h-full flex items-center justify-center py-20">
      <div className="flex flex-col items-center gap-4">
        <Loader2 className="animate-spin text-blue-600" size={48} />
        <p className="text-slate-400 font-black uppercase tracking-widest text-[10px]">Sincronizando Monte Cloud...</p>
      </div>
    </div>
  );

  return (
    <div className="space-y-10 animate-in fade-in duration-700 pb-20">
      {/* KPI Section */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {[
          { label: 'Balanço Cloud', value: `${(stats.revenue - stats.expenses).toLocaleString()} MT`, icon: <Wallet className="text-blue-600" />, trend: 'Performance em Tempo Real', color: 'blue' },
          { label: 'Portfólio Ativo', value: stats.properties, icon: <Home className="text-indigo-600" />, trend: 'Imóveis Registados', color: 'indigo' },
          { label: 'Recursos Humanos', value: stats.employees, icon: <Users className="text-emerald-600" />, trend: 'Colaboradores Activos', color: 'emerald' },
          { label: 'Solicitações', value: stats.contacts, icon: <MessageSquare className="text-amber-600" />, trend: 'Pedidos Pendentes', color: 'amber' },
        ].map((kpi, idx) => (
          <div key={idx} className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm hover:shadow-xl transition-all group overflow-hidden relative">
            <div className={`absolute top-0 right-0 w-24 h-24 bg-${kpi.color}-50 rounded-full translate-x-12 -translate-y-12 group-hover:scale-110 transition-transform`}></div>
            <div className="relative z-10">
              <div className="flex items-center gap-3 mb-4">
                <div className={`p-3 bg-${kpi.color}-50 rounded-2xl`}>{kpi.icon}</div>
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{kpi.label}</span>
              </div>
              <h3 className="text-3xl font-black text-slate-900 tracking-tight mb-1">{kpi.value}</h3>
              <p className="text-[10px] font-bold text-slate-400 uppercase">{kpi.trend}</p>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
        {/* Main Insights and Analytics */}
