                  <button type="button" onClick={() => setTxForm({...txForm, type: 'DESPESA'})} className={`flex-1 py-3 text-[10px] font-black uppercase rounded-xl transition-all ${txForm.type === 'DESPESA' ? 'bg-white text-rose-600 shadow-md' : 'text-slate-500'}`}>Despesa</button>
