      setNewRoleName('');
      fetchRoles();
    } catch (err: any) {
      alert("Erro ao adicionar cargo: " + err.message);
    } finally {
      setRolesLoading(false);
    }
  };

  const handleUpdateRole = async () => {
    if (!editingRoleName || !editingRoleName.new.trim()) return;
    setRolesLoading(true);
    try {
      const { error } = await supabase
        .from('roles')
        .update({ name: editingRoleName.new.trim() })
        .eq('name', editingRoleName.old);
      if (error) throw error;
      setEditingRoleName(null);
      fetchRoles();
    } catch (err: any) {
      alert("Erro ao atualizar cargo: " + err.message);
    } finally {
      setRolesLoading(false);
    }
  };

  const handleDeleteRole = async (name: string) => {
    if (!confirm(`Deseja eliminar o cargo "${name}"? Colaboradores com este cargo manterão o nome até serem editados.`)) return;
    setRolesLoading(true);
    try {
      const { error } = await supabase.from('roles').delete().eq('name', name);
      if (error) throw error;
      fetchRoles();
    } catch (err: any) {
      alert("Erro ao eliminar cargo: " + err.message);
    } finally {
      setRolesLoading(false);
    }
  };

  const handleUpdatePermissions = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingUser || !originalUserState) return;
    setSaving(true);
    const changes = [];
    if (editingUser.role !== originalUserState.role) changes.push(`Cargo: [${originalUserState.role}] -> [${editingUser.role}]`);
    const oldPerms = originalUserState.permissions || [];
    const newPerms = editingUser.permissions || [];
    const added = newPerms.filter(p => !oldPerms.includes(p));
    const removed = oldPerms.filter(p => !newPerms.includes(p));
    if (added.length > 0) changes.push(`+ Permissões: ${added.join(', ')}`);
    if (removed.length > 0) changes.push(`- Permissões: ${removed.join(', ')}`);

    try {
      const { error } = await supabase.from('employees').update({ role: editingUser.role, permissions: editingUser.permissions || [] }).eq('id', editingUser.id);
      if (error) throw error;
      if (changes.length > 0 && currentUser) {
        await supabase.from('audit_logs').insert([{
          admin_id: currentUser.id, admin_name: currentUser.name,
          target_user_id: editingUser.id, target_user_name: editingUser.name,
          action_type: editingUser.role !== originalUserState.role ? 'PERFIL_CARGO' : 'PRIVILEGIOS',
          change_details: changes.join(' | ')
        }]);
      }
      setMsg({ type: 'success', text: 'Sincronizado!' });
      fetchUsers();
      setTimeout(() => setEditingUser(null), 1200);
    } catch (error: any) { setMsg({ type: 'error', text: error.message }); } finally { setSaving(false); setTimeout(() => setMsg(null), 3000); }
  };

  const togglePermission = (permId: string) => {
    if (!editingUser) return;
    const current = editingUser.permissions || [];
    const newPerms = current.includes(permId) ? current.filter(p => p !== permId) : [...current, permId];
    setEditingUser({ ...editingUser, permissions: newPerms });
  };

  const toggleCategory = (category: string, permsInCategory: PermissionDefinition[]) => {
    if (!editingUser) return;
    const currentPerms = editingUser.permissions || [];
    const idsInCategory = permsInCategory.map(p => p.id);
    const allSelected = idsInCategory.every(id => currentPerms.includes(id));
    const newPerms = allSelected ? currentPerms.filter(id => !idsInCategory.includes(id)) : Array.from(new Set([...currentPerms, ...idsInCategory]));
    setEditingUser({ ...editingUser, permissions: newPerms });
  };

  const groupedPermissions = useMemo(() => {
    return GRANULAR_PERMISSIONS.reduce((acc, curr) => {
      if (!acc[curr.category]) acc[curr.category] = [];
      acc[curr.category].push(curr);
      return acc;
    }, {} as Record<string, PermissionDefinition[]>);
  }, []);

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-16">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tight">Administração TI</h1>
          <p className="text-slate-500 font-medium italic">Monitorização e governança de privilégios cloud.</p>
        </div>
        <div className="flex items-center gap-3">
           <button onClick={() => setShowRolesModal(true)} className="px-6 py-3 bg-white text-slate-600 border border-slate-200 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-50 transition-all flex items-center gap-2 shadow-sm">
             <Award size={16} className="text-blue-600" /> Gerir Cargos
           </button>
           <button onClick={() => { fetchAuditLogs(); setShowAuditModal(true); }} className="px-6 py-3 bg-white text-slate-600 border border-slate-200 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-50 transition-all flex items-center gap-2 shadow-sm">
             <History size={16} className="text-indigo-600" /> Histórico Auditoria
           </button>
           <button onClick={() => { fetchUsers(); fetchRoles(); }} className="p-4 bg-white text-slate-400 hover:text-indigo-600 rounded-2xl shadow-sm border border-slate-100 transition-all active:scale-95">
             <RefreshCw size={20} className={loading ? 'animate-spin' : ''} />
           </button>
        </div>
      </div>

      <div className="bg-slate-900 rounded-[3rem] p-10 text-white shadow-2xl relative overflow-hidden group">
        <div className="flex items-center gap-4 mb-6"><Database size={24} className="text-indigo-400" /><h3 className="text-xl font-black">Infraestrutura Supabase</h3></div>
        <p className="text-xs text-slate-400 mb-4">Copie o script abaixo e cole-o no SQL Editor do seu Supabase para garantir que todas as tabelas (incluindo Projetos) existam.</p>
        <pre className="bg-slate-800 p-6 rounded-2xl text-[10px] text-indigo-200 font-mono overflow-x-auto mb-6 max-h-60 custom-scrollbar border border-white/5">{sqlSchema}</pre>
        <button onClick={() => { navigator.clipboard.writeText(sqlSchema); setCopied(true); setTimeout(() => setCopied(false), 2000); }} className="flex items-center gap-2 px-6 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-black text-[10px] uppercase tracking-widest transition-all">
          {copied ? <Check size={14} /> : <Copy size={14} />} {copied ? 'Copiado!' : 'Copiar Script SQL'}
        </button>
      </div>

      <div className="bg-white rounded-[3.5rem] border border-slate-100 shadow-sm overflow-hidden">
        <div className="p-8 border-b border-slate-50 flex items-center justify-between">
          <div className="relative flex-1 max-w-md">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input value={searchTerm} onChange={e => setSearchTerm(e.target.value)} placeholder="Localizar utilizador..." className="w-full pl-12 pr-4 py-4 bg-slate-50 rounded-2xl border-none font-bold text-sm outline-none focus:ring-4 focus:ring-indigo-50" />
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50/50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">
                <th className="px-10 py-6">Perfil do Colaborador</th>
                <th className="px-10 py-6 text-center">Acesso Granular</th>
                <th className="px-10 py-6 text-right">Acção</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {loading ? (
                <tr><td colSpan={3} className="py-24 text-center"><Loader2 className="animate-spin mx-auto text-indigo-600" size={32} /></td></tr>
              ) : users.filter(u => u.name.toLowerCase().includes(searchTerm.toLowerCase())).map(user => (
                <tr key={user.id} className="hover:bg-slate-50/50 transition-all group">
                  <td className="px-10 py-8"><div className="flex items-center gap-5"><img src={user.avatar} className="w-14 h-14 rounded-[1.5rem] object-cover" alt="" /><div><p className="text-base font-black text-slate-900 leading-none mb-1">{user.name}</p><span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded-md uppercase tracking-wider">{user.role}</span></div></div></td>
                  <td className="px-10 py-8"><div className="flex flex-wrap justify-center gap-1.5">{user.permissions?.length ? user.permissions.slice(0, 3).map(p => (<span key={p} className="text-[8px] font-black bg-slate-100 text-slate-500 px-2 py-0.5 rounded uppercase">{p.split('.')[1] || p}</span>)) : <span className="text-[9px] font-black text-slate-300 italic uppercase">Padrão</span>}</div></td>
                  <td className="px-10 py-8 text-right"><button onClick={() => { setEditingUser({...user}); setOriginalUserState({...user}); }} className="p-3 bg-white text-slate-300 hover:text-indigo-600 rounded-xl border border-slate-100"><UserCog size={22} /></button></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {editingUser && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-xl animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-12 max-w-4xl w-full shadow-2xl relative overflow-y-auto max-h-[90vh] custom-scrollbar">
            <button onClick={() => setEditingUser(null)} className="absolute top-10 right-10 text-slate-400"><X size={28} /></button>
            <div className="flex items-center gap-6 mb-12 border-b border-slate-100 pb-10"><img src={editingUser.avatar} className="w-20 h-20 rounded-[2rem] object-cover shadow-lg" alt="" /><div><h2 className="text-3xl font-black text-slate-900 tracking-tight">{editingUser.name}</h2><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Sincronização Cloud de Privilégios</p></div></div>
            <form onSubmit={handleUpdatePermissions} className="space-y-12">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Atribuição de Cargo</label>
                <select value={editingUser.role} onChange={e => setEditingUser({...editingUser, role: e.target.value as any})} className="w-full bg-slate-50 border-none rounded-2xl p-5 font-bold outline-none ring-1 ring-slate-100 focus:ring-2 focus:ring-indigo-600">
                  {roles.map(r => <option key={r} value={r}>{r}</option>)}
                </select>
              </div>

              <div className="space-y-14">
                {(Object.entries(groupedPermissions) as [string, PermissionDefinition[]][]).map(([category, perms]) => (
                    <div key={category} className="space-y-6">
                      <div className="flex items-center justify-between px-2"><h3 className="text-xs font-black uppercase text-slate-900">{category}</h3><button type="button" onClick={() => toggleCategory(category, perms)} className="text-[9px] font-black uppercase text-indigo-600 bg-indigo-50 px-4 py-1.5 rounded-full">Alternar Grupo</button></div>
                      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">{perms.map(p => {
                          const isActive = editingUser.permissions?.includes(p.id);
                          return (<button key={p.id} type="button" onClick={() => togglePermission(p.id)} className={`flex flex-col p-6 rounded-[2rem] border-2 text-left transition-all ${isActive ? 'bg-indigo-600 border-indigo-600 text-white shadow-xl' : 'bg-white border-slate-100 text-slate-600 hover:border-indigo-200'}`}><div className="flex items-center justify-between mb-3"><div className={`p-2 rounded-xl ${isActive ? 'bg-white/20' : 'bg-slate-50 text-indigo-600'}`}>{p.icon}</div></div><span className="text-[11px] font-black uppercase mb-1">{p.label}</span><span className={`text-[9px] font-medium leading-tight line-clamp-2 ${isActive ? 'text-indigo-100' : 'text-slate-400'}`}>{p.description}</span></button>);
                        })}</div>
                    </div>
                ))}
              </div>
              <button disabled={saving} type="submit" className="w-full py-7 bg-slate-900 text-white rounded-[2.5rem] font-black text-xs uppercase tracking-widest shadow-2xl hover:bg-indigo-600 transition-all flex items-center justify-center gap-3">
                {saving ? <Loader2 className="animate-spin" /> : <><Save size={20} /> Sincronizar Permissões</>}
              </button>
            </form>
          </div>
        </div>
      )}

      {showRolesModal && (
        <div className="fixed inset-0 z-[160] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-md animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-12 max-w-2xl w-full shadow-2xl relative flex flex-col max-h-[90vh]">
            <button onClick={() => setShowRolesModal(false)} className="absolute top-10 right-10 text-slate-400"><X size={28} /></button>
            <div className="flex items-center gap-4 mb-10"><Award size={24} className="text-blue-600" /><div><h2 className="text-3xl font-black text-slate-900 tracking-tight">Gestão de Cargos</h2><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Defina a hierarquia da Monte Imobiliária</p></div></div>

            <div className="mb-8 space-y-4">
              <div className="flex gap-4">
                <input 
                  value={newRoleName} 
                  onChange={e => setNewRoleName(e.target.value)}
                  placeholder="Novo Cargo (Ex: Analista de Dados)" 
                  className="flex-1 bg-slate-50 rounded-2xl p-5 font-bold border-none outline-none ring-1 ring-slate-100 focus:ring-2 focus:ring-blue-600"
                />
                <button 
                  onClick={handleAddRole}
                  disabled={rolesLoading || !newRoleName.trim()}
                  className="px-8 py-5 bg-blue-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-blue-700 disabled:opacity-50 transition-all"
                >
                  {rolesLoading ? <Loader2 className="animate-spin" /> : 'Adicionar'}
                </button>
              </div>
            </div>

            <div className="flex-1 overflow-y-auto pr-4 custom-scrollbar space-y-3">
              {roles.map((role) => (
                <div key={role} className="p-5 bg-slate-50 rounded-[1.5rem] border border-slate-100 flex items-center justify-between group">
                  {editingRoleName?.old === role ? (
                    <div className="flex-1 flex gap-3">
                      <input 
                        autoFocus
                        value={editingRoleName.new}
                        onChange={e => setEditingRoleName({...editingRoleName, new: e.target.value})}
                        className="flex-1 bg-white rounded-xl px-4 py-2 font-bold text-sm outline-none ring-2 ring-blue-500"
                      />
                      <button onClick={handleUpdateRole} className="p-2 bg-blue-600 text-white rounded-xl"><Check size={16} /></button>
                      <button onClick={() => setEditingRoleName(null)} className="p-2 bg-slate-200 text-slate-500 rounded-xl"><X size={16} /></button>
                    </div>
                  ) : (
                    <>
                      <div className="flex items-center gap-3">
                        <div className="w-8 h-8 bg-blue-100 text-blue-600 rounded-lg flex items-center justify-center font-black text-xs">
                          {role.charAt(0)}
                        </div>
                        <span className="font-bold text-slate-900 text-sm">{role}</span>
                      </div>
                      <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button onClick={() => setEditingRoleName({old: role, new: role})} className="p-2 text-slate-400 hover:text-blue-600"><Edit size={16} /></button>
                        <button onClick={() => handleDeleteRole(role)} className="p-2 text-slate-400 hover:text-rose-600"><Trash2 size={16} /></button>
                      </div>
                    </>
                  )}
                </div>
              ))}
            </div>
            <div className="mt-8 pt-8 border-t border-slate-100 text-center">
              <button onClick={() => setShowRolesModal(false)} className="px-10 py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-blue-600 transition-all">Concluído</button>
            </div>
          </div>
        </div>
      )}

      {showAuditModal && (
        <div className="fixed inset-0 z-[160] flex items-center justify-center p-4 bg-slate-900/90 backdrop-blur-md animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-12 max-w-5xl w-full shadow-2xl relative flex flex-col max-h-[90vh]">
            <button onClick={() => setShowAuditModal(false)} className="absolute top-10 right-10 text-slate-400"><X size={28} /></button>
            <div className="flex items-center gap-4 mb-10"><Activity size={24} className="text-indigo-600" /><div><h2 className="text-3xl font-black text-slate-900 tracking-tight">Auditoria Cloud</h2><p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Rastreabilidade total do sistema</p></div></div>
            <div className="flex-1 overflow-y-auto pr-4 custom-scrollbar space-y-4">
              {loadingLogs ? <div className="py-20 flex justify-center"><Loader2 className="animate-spin text-indigo-600" size={32} /></div> : auditLogs.map((log) => (
                <div key={log.id} className="p-6 bg-slate-50 rounded-[2.5rem] border border-slate-100"><div className="flex justify-between gap-4 mb-4"><div className="flex items-center gap-3"><div className="px-3 py-1 bg-indigo-600 text-white rounded-lg text-[9px] font-black uppercase">{log.action_type}</div><div className="text-slate-900 font-bold text-sm">Por: {log.admin_name} -> {log.target_user_name}</div></div><div className="text-[10px] font-black text-slate-400 uppercase tracking-tighter">{new Date(log.created_at).toLocaleString('pt-MZ')}</div></div><div className="p-4 bg-white rounded-2xl border border-slate-100 text-[11px] text-slate-600 leading-relaxed italic">{log.change_details}</div></div>
              ))}
            </div>
            <div className="mt-8 pt-8 border-t border-slate-100 text-center"><button onClick={() => setShowAuditModal(false)} className="px-10 py-4 bg-slate-900 text-white rounded-2xl font-black text-xs uppercase hover:bg-indigo-600 transition-all">Fechar Histórico</button></div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminView;

import React, { useState, useEffect } from 'react';
import { 
  Plus, Search, Edit3, Trash2, X, Check, Camera, 
  Loader2, AlertTriangle, Building2, MapPin, Ruler, BedDouble,
  CheckCircle2, AlertCircle
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { Property, PropertyCategory } from '../types';

const CatalogView: React.FC = () => {
  const [properties, setProperties] = useState<Property[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editingItem, setEditingItem] = useState<Property | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

  const defaultPlaceholder = 'https://images.unsplash.com/photo-1564013799919-ab600027ffc6?auto=format&fit=crop&q=80&w=800';

  const [newProp, setNewProp] = useState<Partial<Property>>({
    title: '', type: 'Casa', dealType: 'Venda', price: 0, location: '', beds: 1, baths: 1, area: 0, description: '', image: ''
  });

  useEffect(() => {
    fetchData();
  }, []);

  async function fetchData() {
    setLoading(true);
    try {
      const { data, error } = await supabase.from('properties').select('*').order('created_at', { ascending: false });
      if (error) throw error;
      setProperties(data || []);
    } catch (err: any) {
      setMessage({ type: 'error', text: 'Erro ao carregar catálogo: ' + err.message });
    } finally {
      setLoading(false);
    }
  }

  const handleDeleteProp = async (id: string) => {
    if(confirm('Eliminar este imóvel permanentemente?')) {
      try {
        const { error } = await supabase.from('properties').delete().eq('id', id);
        if (error) throw error;
        setMessage({ type: 'success', text: 'Imóvel removido com sucesso.' });
        setTimeout(() => setMessage(null), 3000);
        fetchData();
      } catch (err: any) {
        setMessage({ type: 'error', text: 'Erro ao eliminar: ' + err.message });
      }
    }
  };

  const handleSaveProperty = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setMessage(null);

    const payload = {
      ...newProp,
      image: newProp.image?.trim() || defaultPlaceholder
    };

    try {
      const { error } = editingItem 
        ? await supabase.from('properties').update(payload).eq('id', editingItem.id)
        : await supabase.from('properties').insert([payload]);

      if (error) throw error;

      setMessage({ 
        type: 'success', 
        text: editingItem ? 'Imóvel atualizado com sucesso!' : 'Novo imóvel registado no catálogo cloud com sucesso.' 
      });

      setShowModal(false);
      setEditingItem(null);
      setNewProp({ title: '', type: 'Casa', dealType: 'Venda', price: 0, location: '', beds: 1, baths: 1, area: 0, description: '', image: '' });
      fetchData();

      // Limpar mensagem após 5 segundos
      setTimeout(() => setMessage(null), 5000);
    } catch (err: any) {
      setMessage({ type: 'error', text: 'Erro ao guardar imóvel: ' + err.message });
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-12">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-4">
           <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-blue-500/20">
             <Building2 size={24} />
           </div>
           <div>
             <h1 className="text-3xl font-black text-slate-900 tracking-tight">Gestão de Portfólio</h1>
             <p className="text-slate-500 font-medium">Controlo de activos imobiliários e hoteleiros.</p>
           </div>
        </div>
        <button onClick={() => { setMessage(null); setEditingItem(null); setNewProp({ title: '', type: 'Casa', dealType: 'Venda', price: 0, location: '', beds: 1, baths: 1, area: 0, description: '', image: '' }); setShowModal(true); }} className="flex items-center gap-2 px-8 py-4 bg-blue-600 text-white rounded-[2rem] font-black text-sm shadow-xl hover:bg-blue-700 transition-all hover:scale-105">
          <Plus size={20} /> Adicionar Imóvel
        </button>
      </div>

      {/* Alertas de Sucesso ou Erro */}
      {message && (
        <div className={`p-5 rounded-[2rem] border-l-4 flex items-center justify-between gap-4 animate-in slide-in-from-top-4 shadow-sm ${
          message.type === 'success' 
            ? 'bg-emerald-50 border-emerald-500 text-emerald-800' 
            : 'bg-rose-50 border-rose-500 text-rose-800'
        }`}>
          <div className="flex items-center gap-4">
            {message.type === 'success' ? <CheckCircle2 size={24} /> : <AlertCircle size={24} />}
            <p className="text-sm font-black uppercase tracking-tight">{message.text}</p>
          </div>
          <button onClick={() => setMessage(null)} className="p-2 hover:bg-black/5 rounded-full transition-colors">
            <X size={18} />
          </button>
        </div>
      )}

      {loading ? (
        <div className="flex justify-center py-20"><Loader2 className="animate-spin text-blue-600" size={40} /></div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
          {properties.length === 0 ? (
            <div className="col-span-full py-24 text-center bg-white rounded-[3rem] border-2 border-dashed border-slate-100">
               <Building2 size={48} className="mx-auto text-slate-200 mb-4" />
               <p className="text-slate-400 font-bold">Nenhum imóvel disponível no catálogo cloud.</p>
            </div>
          ) : properties.map(prop => (
            <div key={prop.id} className="group bg-white rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden hover:shadow-2xl transition-all relative">
              <div className="h-56 relative overflow-hidden">
                <img src={prop.image || defaultPlaceholder} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" alt={prop.title} />
                <div className="absolute top-4 left-4 bg-white/90 backdrop-blur-md px-4 py-1.5 rounded-xl text-[10px] font-black uppercase text-blue-600 shadow-sm">{prop.deal_type || prop.dealType}</div>
              </div>
              <div className="p-8">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{prop.type}</p>
                <h3 className="text-lg font-black text-slate-900 mb-4 truncate">{prop.title}</h3>
                <div className="flex items-center gap-2 text-xs text-slate-500 font-bold mb-6"><MapPin size={14} /> {prop.location || 'Localização não especificada'}</div>

                <div className="flex items-center justify-between pt-6 border-t border-slate-50">
                   <p className="text-blue-600 font-black text-lg">{Number(prop.price).toLocaleString()} MT</p>
                   <div className="flex gap-2">
                     <button onClick={() => { setMessage(null); setEditingItem(prop); setNewProp(prop); setShowModal(true); }} className="p-2.5 bg-slate-50 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl transition-all"><Edit3 size={16} /></button>
                     <button onClick={() => handleDeleteProp(prop.id)} className="p-2.5 bg-slate-50 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all"><Trash2 size={16} /></button>
                   </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-12 max-w-2xl w-full shadow-2xl relative overflow-y-auto max-h-[90vh] custom-scrollbar">
            <button onClick={() => setShowModal(false)} className="absolute top-10 right-10 p-2 text-slate-400 hover:text-slate-900 bg-slate-50 rounded-xl transition-all"><X size={24} /></button>
            <h2 className="text-2xl font-black text-slate-900 mb-10 flex items-center gap-3">
              <Camera className="text-blue-600" /> {editingItem ? 'Editar Imóvel' : 'Registar no Catálogo'}
            </h2>
            <form onSubmit={handleSaveProperty} className="space-y-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="md:col-span-2 space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Título do Anúncio</label>
                  <input required value={newProp.title} onChange={e => setNewProp({...newProp, title: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 border-none focus:ring-2 focus:ring-blue-600 font-bold outline-none" placeholder="Ex: Vivenda Moderna T4..." />
                </div>

                <div className="md:col-span-2 space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">URL da Imagem do Imóvel</label>
                  <div className="relative">
                    <Camera className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                    <input 
                      value={newProp.image} 
                      onChange={e => setNewProp({...newProp, image: e.target.value})} 
                      className="w-full bg-slate-50 rounded-2xl p-5 pl-14 border-none focus:ring-2 focus:ring-blue-600 font-bold outline-none" 
                      placeholder="https://images.unsplash.com/..." 
                    />
                  </div>
                  {newProp.image && (
                    <div className="mt-4 rounded-2xl overflow-hidden h-32 w-full border border-slate-100 bg-slate-50">
                      <img 
                        src={newProp.image} 
                        alt="Preview" 
                        className="w-full h-full object-cover" 
                        onError={(e) => (e.currentTarget.style.display = 'none')} 
                        onLoad={(e) => (e.currentTarget.style.display = 'block')}
                      />
                    </div>
                  )}
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Preço Sugerido (MT)</label>
                  <input type="number" required value={newProp.price} onChange={e => setNewProp({...newProp, price: Number(e.target.value)})} className="w-full bg-slate-50 rounded-2xl p-5 border-none focus:ring-2 focus:ring-blue-600 font-bold outline-none" />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Localização (Bairro)</label>
                  <input required value={newProp.location} onChange={e => setNewProp({...newProp, location: e.target.value})} className="w-full bg-slate-50 rounded-2xl p-5 border-none focus:ring-2 focus:ring-blue-600 font-bold outline-none" placeholder="Ex: Alto da Manga" />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Categoria</label>
                  <select value={newProp.type} onChange={e => setNewProp({...newProp, type: e.target.value as any})} className="w-full bg-slate-50 rounded-2xl p-5 border-none font-bold outline-none cursor-pointer">
                    <option>Casa</option><option>Apartamento</option><option>Hotel</option><option>Terreno</option><option>Condomínio</option>
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Finalidade</label>
                  <select value={newProp.dealType} onChange={e => setNewProp({...newProp, dealType: e.target.value as any})} className="w-full bg-slate-50 rounded-2xl p-5 border-none font-bold outline-none cursor-pointer">
                    <option value="Venda">Venda</option><option value="Aluguel">Aluguel</option>
                  </select>
                </div>
              </div>
              <button disabled={isSubmitting} type="submit" className="w-full py-6 bg-blue-600 text-white font-black rounded-[2.5rem] shadow-xl hover:bg-blue-700 transition-all flex items-center justify-center gap-3 active:scale-95 disabled:opacity-70">
                {isSubmitting ? <Loader2 size={24} className="animate-spin" /> : <><Check size={24} /> Sincronizar Portfólio Cloud</>}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default CatalogView;

import React, { useState, useEffect } from 'react';
import { 
  Plus, Users, AlertCircle, Clock, 
  Loader2, X, Trash2, Save, Mail, Phone, 
  Edit3, ShieldCheck, AlertTriangle, Briefcase, 
  Search, MapPin, DollarSign, LayoutList, Sparkles, AlignLeft, RefreshCcw,
  CheckCircle2, Camera
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { Employee, UserRole, JobVacancy } from '../types';
import { generateJobDescription } from '../geminiService';

const SUGGESTED_ROLES = [
  'Estagiário de Digitador de Dados',
  'Gerente de Produção',
  'Agente de Campo',
  'Marketing',
  'Gerente de Campo',
  'Revisor de Dados',
  'Consultor Imobiliário',
  'Motorista Profissional'
];

const HRView: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'employees' | 'vacancies'>('employees');
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [vacancies, setVacancies] = useState<JobVacancy[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAddModal, setShowAddModal] = useState(false);
  const [showVacancyModal, setShowVacancyModal] = useState(false);
  const [editingEmpId, setEditingEmpId] = useState<string | null>(null);
  const [editingVacancyId, setEditingVacancyId] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [successMsg, setSuccessMsg] = useState<string | null>(null);
  const [saving, setSaving] = useState(false);
  const [isAiLoading, setIsAiLoading] = useState(false);

  const initialFormState: Partial<Employee> = {
    name: '', role: UserRole.EMPLOYEE, department: 'Geral', salary: 0, email: '', phone: '+258 ',
    document_type: 'BI', document_number: '', document_expiry: '', payment_method: 'M-Pesa', contract_start: ''
  };

  const initialVacancyState: Partial<JobVacancy> = {
    title: '', area: 'Operações & Campo', type: 'Full-time', location: 'Beira', salary: '', status: 'Open', description: '', image: ''
  };

  const [formState, setFormState] = useState<Partial<Employee>>(initialFormState);
  const [vacancyForm, setVacancyForm] = useState<Partial<JobVacancy>>(initialVacancyState);

  useEffect(() => {
    fetchData();
    fetchVacancies();
  }, []);

  async function fetchData() {
    setLoading(true);
    try {
      const { data, error: sbError } = await supabase.from('employees').select('*').order('name');
      if (sbError) setError(sbError.message);
      setEmployees(data || []);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }

  async function fetchVacancies() {
    try {
      const { data, error: sbError } = await supabase.from('job_vacancies').select('*').order('created_at', { ascending: false });
      if (!sbError) setVacancies(data || []);
    } catch (err) { console.warn("Erro ao buscar vagas."); }
  }

  const handleAiOptimize = async () => {
    if (!vacancyForm.title) {
      setError("Por favor, digite o Cargo primeiro para a IA trabalhar.");
      setTimeout(() => setError(null), 3000);
      return;
    }
    setIsAiLoading(true);
    try {
      const optimizedText = await generateJobDescription(
        vacancyForm.title || '', 
        vacancyForm.area || '', 
        vacancyForm.location || ''
      );
      setVacancyForm(prev => ({ ...prev, description: optimizedText }));
    } finally {
      setIsAiLoading(false);
    }
  };

  const handleSaveVacancy = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setSuccessMsg(null);

    if (!vacancyForm.title?.trim() || !vacancyForm.description?.trim()) {
      setError("Título e Descrição são obrigatórios para publicar.");
      return;
    }

    setSaving(true);
    try {
      const payload = { 
        title: vacancyForm.title.trim(),
        area: vacancyForm.area,
        type: vacancyForm.type,
        location: vacancyForm.location?.trim() || 'Beira',
        salary: vacancyForm.salary?.trim() || 'A Negociar',
        description: vacancyForm.description.trim(),
        image: vacancyForm.image?.trim() || '',
        status: vacancyForm.status || 'Open'
      };

      let res;
      if (editingVacancyId) {
        res = await supabase.from('job_vacancies').update(payload).eq('id', editingVacancyId);
      } else {
        res = await supabase.from('job_vacancies').insert([payload]);
      }

      if (res.error) throw res.error;

      setSuccessMsg(editingVacancyId ? "Vaga atualizada com sucesso!" : "Vaga publicada no portal cloud!");

      setTimeout(() => {
        setShowVacancyModal(false);
        setEditingVacancyId(null);
        setVacancyForm(initialVacancyState);
        setSuccessMsg(null);
        fetchVacancies();
      }, 1500);

    } catch (err: any) {
      setError("Erro ao processar: " + err.message);
    } finally {
      setSaving(false);
    }
  };

  const handleEditVacancy = (vacancy: JobVacancy) => {
    setError(null);
    setSuccessMsg(null);
    setEditingVacancyId(vacancy.id);
    setVacancyForm(vacancy);
    setShowVacancyModal(true);
  };

  const deleteVacancy = async (id: string) => {
    if (confirm('Deseja remover esta vaga permanentemente?')) {
      const { error } = await supabase.from('job_vacancies').delete().eq('id', id);
      if (!error) fetchVacancies();
      else alert("Erro ao apagar: " + error.message);
    }
  };

  const getExpiryStatus = (expiryDate?: string) => {
    if (!expiryDate) return { label: 'Sem Info', color: 'bg-slate-100 text-slate-400 border-slate-200', icon: <AlertCircle size={10} />, pulse: false };
    const today = new Date();
    today.setHours(0,0,0,0);
    const expiry = new Date(expiryDate);
    const thirtyDaysFromNow = new Date();
    thirtyDaysFromNow.setDate(today.getDate() + 30);

    if (expiry < today) return { label: 'Expirado', color: 'bg-rose-50 text-rose-600 border-rose-100', icon: <AlertTriangle size={10} />, pulse: true };
    if (expiry <= thirtyDaysFromNow) return { label: 'A Vencer', color: 'bg-amber-50 text-amber-600 border-amber-100', icon: <Clock size={10} />, pulse: false };
    return { label: 'Ativo', color: 'bg-emerald-50 text-emerald-600 border-emerald-100', icon: <ShieldCheck size={10} />, pulse: false };
  };

  const handleSaveEmployee = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    if (!formState.name || formState.name.trim().length < 3) {
      setError("Por favor, insira um nome completo válido.");
      return;
    }

    if (!formState.email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formState.email)) {
      setError("Por favor, insira um e-mail corporativo válido.");
      return;
    }

    setSaving(true);
    try {
      const payload = { ...formState, salary: Number(formState.salary), status: 'Ativo', avatar: `https://picsum.photos/seed/${formState.name}/100` };
      if (editingEmpId) {
        await supabase.from('employees').update(payload).eq('id', editingEmpId);
      } else {
        await supabase.from('employees').insert([payload]);
      }
      setShowAddModal(false);
      setEditingEmpId(null);
      setFormState(initialFormState);
      fetchData();
    } catch (err: any) { 
      setError(err.message); 
    } finally { 
      setSaving(false); 
    }
  };

  if (loading) return <div className="flex justify-center py-24"><Loader2 className="animate-spin text-indigo-600" size={48} /></div>;

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-4">
           <div className="w-14 h-14 bg-indigo-600 rounded-[1.5rem] flex items-center justify-center text-white shadow-xl shadow-indigo-500/20"><Users size={28} /></div>
           <div>
             <h1 className="text-3xl font-black text-slate-900 tracking-tight">Gestão de Talentos</h1>
             <p className="text-slate-500 font-medium">Controle de staff e recrutamento.</p>
           </div>
        </div>
        <div className="flex gap-3">
          {activeTab === 'employees' ? (
            <button onClick={() => { setError(null); setEditingEmpId(null); setFormState(initialFormState); setShowAddModal(true); }} className="px-8 py-4 bg-indigo-600 text-white rounded-[2rem] font-black text-sm shadow-xl hover:bg-indigo-700 transition-all active:scale-95 flex items-center gap-2">
              <Plus size={20} /> Novo Colaborador
            </button>
          ) : (
            <button onClick={() => { setError(null); setSuccessMsg(null); setEditingVacancyId(null); setVacancyForm(initialVacancyState); setShowVacancyModal(true); }} className="px-8 py-4 bg-blue-600 text-white rounded-[2rem] font-black text-sm shadow-xl hover:bg-blue-700 transition-all active:scale-95 flex items-center gap-2">
              <Plus size={20} /> Criar Nova Vaga
            </button>
          )}
        </div>
      </div>

      <div className="flex p-1.5 bg-slate-100 rounded-[2rem] w-full max-w-md mx-auto">
        <button 
          onClick={() => setActiveTab('employees')}
          className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-[1.5rem] text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'employees' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}
        >
          <Users size={16} /> Colaboradores
        </button>
        <button 
          onClick={() => setActiveTab('vacancies')}
          className={`flex-1 flex items-center justify-center gap-2 py-3 rounded-[1.5rem] text-xs font-black uppercase tracking-widest transition-all ${activeTab === 'vacancies' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500'}`}
        >
          <Briefcase size={16} /> Recrutamento
        </button>
      </div>

      {activeTab === 'employees' ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
          {employees.map((emp, index) => {
            const docStatus = getExpiryStatus(emp.document_expiry);
            return (
              <div 
                key={emp.id} 
                className="bg-white p-8 rounded-[3.5rem] border border-slate-100 shadow-sm relative group hover:shadow-2xl transition-all border-b-4 border-b-transparent hover:border-b-indigo-500 animate-in fade-in slide-in-from-bottom-4 duration-700"
                style={{ animationDelay: `${index * 50}ms`, animationFillMode: 'backwards' }}
              >
                <div className={`absolute top-6 left-6 px-4 py-1.5 rounded-full border text-[9px] font-black uppercase tracking-widest flex items-center gap-2 z-10 ${docStatus.color}`}>
                  {docStatus.icon} {docStatus.label}
                </div>
                <div className="absolute top-6 right-6 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button onClick={() => { setError(null); setEditingEmpId(emp.id); setFormState(emp); setShowAddModal(true); }} className="p-2.5 bg-white text-slate-400 hover:text-indigo-600 rounded-xl shadow-sm border border-slate-100 transition-all"><Edit3 size={18} /></button>
                </div>
                <div className="mt-8 flex flex-col items-center">
                  <div className="relative mb-5">
                    <img src={emp.avatar} className="w-24 h-24 rounded-[2.5rem] object-cover ring-8 ring-slate-50 shadow-inner group-hover:scale-105 transition-transform duration-500" alt={emp.name} />
                    <div className={`absolute -bottom-1 -right-1 w-5 h-5 rounded-full border-4 border-white ${emp.status === 'Ativo' ? 'bg-green-500' : 'bg-amber-500'}`}></div>
                  </div>
                  <h3 className="text-xl font-black text-slate-900 mb-1 text-center">{emp.name}</h3>
                  <p className="text-[10px] font-black text-indigo-600 uppercase tracking-widest mb-6 text-center bg-indigo-50 px-3 py-1 rounded-lg">{emp.role}</p>
                </div>
                <div className="pt-6 border-t border-slate-50 flex justify-between items-center text-[11px] font-medium text-slate-500">
                  <div className="flex items-center gap-1.5"><Mail size={12} className="text-slate-300" /> {emp.email.split('@')[0]}...</div>
                  <div className="flex items-center gap-1.5"><Phone size={12} className="text-slate-300" /> {emp.phone}</div>
                </div>
              </div>
            );
          })}
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {vacancies.length === 0 ? (
            <div className="col-span-full py-24 text-center bg-white rounded-[3rem] border border-dashed border-slate-200 animate-in fade-in duration-700">
               <Briefcase size={48} className="mx-auto text-slate-200 mb-4" />
               <p className="text-slate-400 font-bold uppercase tracking-widest text-xs">Sem vagas publicadas</p>
            </div>
          ) : vacancies.map((v, index) => (
            <div 
              key={v.id} 
              className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm hover:shadow-xl transition-all relative overflow-hidden flex flex-col group animate-in fade-in slide-in-from-bottom-4 duration-700"
              style={{ animationDelay: `${index * 50}ms`, animationFillMode: 'backwards' }}
            >
              <div className="flex justify-between items-start mb-4">
                <div className="p-3 bg-blue-50 text-blue-600 rounded-2xl">
                  <Briefcase size={20} className={v.status === 'Open' ? 'text-blue-600' : 'text-slate-300'} />
                </div>
                <div className="flex gap-2">
                  <button onClick={() => handleEditVacancy(v)} className="p-2 text-slate-300 hover:text-blue-600 transition-colors"><Edit3 size={18} /></button>
                  <button onClick={() => deleteVacancy(v.id)} className="p-2 text-slate-300 hover:text-rose-600 transition-colors"><Trash2 size={18} /></button>
                </div>
              </div>
              <h3 className="text-xl font-black text-slate-900 mb-2">{v.title}</h3>
              <div className="space-y-2 mb-6">
                <div className="flex items-center gap-2 text-xs font-bold text-slate-500"><MapPin size={14} className="text-blue-500" /> {v.location}</div>
                <div className="flex items-center gap-2 text-xs font-bold text-slate-500"><LayoutList size={14} className="text-blue-500" /> {v.area}</div>
              </div>
              <div className="mt-auto pt-6 border-t border-slate-50 flex items-center justify-between">
                <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-widest ${v.status === 'Open' ? 'bg-blue-50 text-blue-600' : 'bg-slate-50 text-slate-400'}`}>
                  {v.status === 'Open' ? v.type : 'Fechada'}
                </span>
                <span className="text-[9px] font-bold text-slate-400 uppercase tracking-tighter">{new Date(v.created_at).toLocaleDateString()}</span>
              </div>
            </div>
          ))}
        </div>
      )}

      {showVacancyModal && (
        <div className="fixed inset-0 z-[130] flex items-center justify-center p-4 bg-slate-900/80 backdrop-blur-md animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-10 md:p-14 max-w-4xl w-full shadow-2xl relative overflow-y-auto max-h-[95vh] custom-scrollbar">
            <button onClick={() => setShowVacancyModal(false)} className="absolute top-10 right-10 text-slate-400 hover:text-slate-900 p-2"><X size={28} /></button>

            <div className="flex items-center gap-4 mb-8">
               <div className="w-12 h-12 bg-blue-50 text-blue-600 rounded-2xl flex items-center justify-center">
                  {editingVacancyId ? <Edit3 size={24} /> : <Plus size={24} />}
               </div>
               <div>
                  <h2 className="text-3xl font-black text-slate-900 tracking-tight">
                    {editingVacancyId ? 'Editar Oportunidade' : 'Publicar Nova Vaga'}
                  </h2>
                  <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Sincronização Cloud Ativa</p>
               </div>
            </div>

            {error && (
              <div className="mb-6 p-4 bg-rose-50 border-l-4 border-rose-500 rounded-xl flex items-center gap-3 text-rose-700 animate-in slide-in-from-top-2">
                <AlertTriangle size={18} />
                <span className="text-xs font-bold">{error}</span>
              </div>
            )}
            {successMsg && (
              <div className="mb-6 p-4 bg-emerald-50 border-l-4 border-emerald-500 rounded-xl flex items-center gap-3 text-emerald-700 animate-in slide-in-from-top-2">
                <CheckCircle2 size={18} />
                <span className="text-xs font-bold">{successMsg}</span>
              </div>
            )}

            <form onSubmit={handleSaveVacancy} className="space-y-6">
               <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Cargo da Vaga</label>
                    <input 
                      list="roles-list"
                      required 
                      value={vacancyForm.title} 
                      onChange={e => setVacancyForm({...vacancyForm, title: e.target.value})} 
                      className="w-full bg-slate-50 p-5 rounded-2xl font-bold border-none outline-none focus:ring-4 focus:ring-blue-100 transition-all" 
                      placeholder="Ex: Agente de Campo" 
                    />
                    <datalist id="roles-list">
                      {SUGGESTED_ROLES.map(role => <option key={role} value={role} />)}
                    </datalist>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Área / Departamento</label>
                    <select value={vacancyForm.area} onChange={e => setVacancyForm({...vacancyForm, area: e.target.value})} className="w-full bg-slate-50 p-5 rounded-2xl font-bold border-none outline-none focus:ring-4 focus:ring-blue-100">
                       <option>Operações & Campo</option>
                       <option>Vendas Imobiliárias</option>
                       <option>Produção & Obras</option>
                       <option>Recursos Humanos</option>
                       <option>TI & Dados</option>
                       <option>Marketing</option>
                    </select>
                  </div>
                  <div className="space-y-2">
