import React, { useState, useEffect } from 'react';
import { 
  Plus, Search, Edit3, Trash2, X, Check, Camera, 
  Loader2, AlertTriangle, Building2, MapPin, Ruler, BedDouble,
  CheckCircle2, AlertCircle, Bath, AlignLeft
} from 'lucide-react';
import { supabase } from '../supabaseClient';
import { Property, PropertyCategory } from '../types';

const CatalogView: React.FC = () => {
  const [properties, setProperties] = useState<Property[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editingItem, setEditingItem] = useState<Property | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

  const defaultPlaceholder = 'https://images.unsplash.com/photo-1564013799919-ab600027ffc6?auto=format&fit=crop&q=80&w=800';

  const [newProp, setNewProp] = useState<Partial<Property>>({
    title: '', 
    type: 'Casa', 
    dealType: 'Venda', 
    price: 0, 
    location: '', 
    beds: 1, 
    baths: 1, 
    area: 0, 
    description: '', 
    image: ''
  });

  useEffect(() => {
    fetchData();
  }, []);

  async function fetchData() {
    setLoading(true);
    try {
      const { data, error } = await supabase.from('properties').select('*').order('created_at', { ascending: false });
      if (error) throw error;
      setProperties(data || []);
    } catch (err: any) {
      console.error("Fetch error:", err);
      // Fail silently for the user or show a small hint, but keep the UI clean
    } finally {
      setLoading(false);
    }
  }

  const handleDeleteProp = async (id: string) => {
    if(confirm('Eliminar este imóvel permanentemente?')) {
      try {
        const { error } = await supabase.from('properties').delete().eq('id', id);
        if (error) throw error;
        setMessage({ type: 'success', text: 'Imóvel removido com sucesso.' });
        setTimeout(() => setMessage(null), 3000);
        fetchData();
      } catch (err: any) {
        setMessage({ type: 'error', text: 'Erro ao eliminar: ' + err.message });
      }
    }
  };

  const handleSaveProperty = async (e: React.FormEvent) => {
    e.preventDefault();
    setMessage(null);

    // Validações de Negócio
    if (Number(newProp.price) <= 0) {
      setMessage({ type: 'error', text: 'O preço deve ser um valor superior a zero.' });
      return;
    }

    if (Number(newProp.area) <= 0) {
      setMessage({ type: 'error', text: 'A área do imóvel deve ser um valor positivo.' });
      return;
    }

    setIsSubmitting(true);

    const payload = {
      ...newProp,
      price: Number(newProp.price),
      area: Number(newProp.area),
      beds: Number(newProp.beds),
      baths: Number(newProp.baths),
      image: newProp.image?.trim() || defaultPlaceholder
    };

    try {
      const { error } = editingItem 
        ? await supabase.from('properties').update(payload).eq('id', editingItem.id)
        : await supabase.from('properties').insert([payload]);

      if (error) throw error;

      setMessage({ 
        type: 'success', 
        text: editingItem ? 'Alterações guardadas com sucesso!' : 'Novo imóvel registado no catálogo Monte Hub.' 
      });

      setShowModal(false);
      setEditingItem(null);
      setNewProp({ title: '', type: 'Casa', dealType: 'Venda', price: 0, location: '', beds: 1, baths: 1, area: 0, description: '', image: '' });
      fetchData();

      // Limpar mensagem após 5 segundos
      setTimeout(() => setMessage(null), 5000);
    } catch (err: any) {
      setMessage({ type: 'error', text: 'Erro ao comunicar com a Cloud: ' + (err.message || 'Falha na rede') });
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-12">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-4">
           <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-blue-500/20">
             <Building2 size={24} />
           </div>
           <div>
             <h1 className="text-3xl font-black text-slate-900 tracking-tight">Gestão de Portfólio</h1>
             <p className="text-slate-500 font-medium">Controlo centralizado de ativos imobiliários.</p>
           </div>
        </div>
        <button 
          onClick={() => { 
            setMessage(null); 
            setEditingItem(null); 
            setNewProp({ title: '', type: 'Casa', dealType: 'Venda', price: 0, location: '', beds: 1, baths: 1, area: 0, description: '', image: '' }); 
            setShowModal(true); 
          }} 
          className="flex items-center gap-2 px-8 py-4 bg-blue-600 text-white rounded-[2rem] font-black text-sm shadow-xl hover:bg-blue-700 transition-all hover:scale-105 active:scale-95"
        >
          <Plus size={20} /> Registar Imóvel
        </button>
      </div>

      {/* Alertas de Feedback */}
      {message && (
        <div className={`p-5 rounded-[2rem] border-l-4 flex items-center justify-between gap-4 animate-in slide-in-from-top-4 shadow-lg ${
          message.type === 'success' 
            ? 'bg-emerald-50 border-emerald-500 text-emerald-800' 
            : 'bg-rose-50 border-rose-500 text-rose-800'
        }`}>
          <div className="flex items-center gap-4">
            {message.type === 'success' ? <CheckCircle2 size={24} className="text-emerald-500" /> : <AlertCircle size={24} className="text-rose-500" />}
            <p className="text-sm font-black uppercase tracking-tight">{message.text}</p>
          </div>
          <button onClick={() => setMessage(null)} className="p-2 hover:bg-black/5 rounded-full transition-colors">
            <X size={18} />
          </button>
        </div>
      )}

      {loading ? (
        <div className="flex flex-col items-center justify-center py-24 gap-4">
          <Loader2 className="animate-spin text-blue-600" size={40} />
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Sincronizando Catálogo...</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
          {properties.length === 0 ? (
            <div className="col-span-full py-24 text-center bg-white rounded-[3rem] border-2 border-dashed border-slate-100 flex flex-col items-center gap-4">
               <Building2 size={48} className="text-slate-200" />
               <p className="text-slate-400 font-bold uppercase tracking-widest text-xs">Nenhum imóvel registado no catálogo.</p>
            </div>
          ) : properties.map(prop => (
            <div key={prop.id} className="group bg-white rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden hover:shadow-2xl transition-all relative">
              <div className="h-56 relative overflow-hidden">
                <img src={prop.image || defaultPlaceholder} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" alt={prop.title} />
                <div className="absolute top-4 left-4 bg-white/90 backdrop-blur-md px-4 py-1.5 rounded-xl text-[10px] font-black uppercase text-blue-600 shadow-sm">
                  {prop.deal_type || prop.dealType}
                </div>
              </div>
              <div className="p-8">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{prop.type}</p>
                <h3 className="text-lg font-black text-slate-900 mb-4 truncate">{prop.title}</h3>

                <div className="flex items-center gap-2 text-[11px] text-slate-500 font-bold mb-6">
                  <MapPin size={14} className="text-blue-500" /> {prop.location || 'Sem localização'}
                </div>

                <div className="flex items-center justify-between pt-6 border-t border-slate-50">
                   <div>
                     <p className="text-[10px] font-black text-slate-400 uppercase tracking-tighter">Preço</p>
                     <p className="text-blue-600 font-black text-lg">{Number(prop.price).toLocaleString()} MT</p>
                   </div>
                   <div className="flex gap-2">
                     <button 
                       onClick={() => { 
                         setMessage(null); 
                         setEditingItem(prop); 
                         setNewProp(prop); 
                         setShowModal(true); 
                       }} 
                       className="p-3 bg-slate-50 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-xl transition-all"
                       title="Editar"
                     >
                       <Edit3 size={16} />
                     </button>
                     <button 
                       onClick={() => handleDeleteProp(prop.id)} 
                       className="p-3 bg-slate-50 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all"
                       title="Eliminar"
                     >
                       <Trash2 size={16} />
                     </button>
                   </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in">
          <div className="bg-white rounded-[4rem] p-10 md:p-14 max-w-3xl w-full shadow-2xl relative overflow-y-auto max-h-[90vh] custom-scrollbar">
            <button onClick={() => setShowModal(false)} className="absolute top-10 right-10 p-2 text-slate-400 hover:text-slate-900 bg-slate-50 rounded-xl transition-all">
              <X size={24} />
            </button>
            <h2 className="text-2xl font-black text-slate-900 mb-10 flex items-center gap-3 tracking-tight">
              <Camera className="text-blue-600" /> {editingItem ? 'Editar Registo' : 'Novo Imóvel no Catálogo'}
            </h2>
            <form onSubmit={handleSaveProperty} className="space-y-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="md:col-span-2 space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Título do Anúncio</label>
                  <input 
                    required 
                    value={newProp.title} 
                    onChange={e => setNewProp({...newProp, title: e.target.value})} 
                    className="w-full bg-slate-50 rounded-2xl p-5 border-none focus:ring-4 focus:ring-blue-100 font-bold outline-none transition-all" 
                    placeholder="Ex: Vivenda Moderna T4 no Alto da Manga" 
                  />
                </div>

                <div className="md:col-span-2 space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">URL da Imagem Principal</label>
                  <div className="relative">
                    <Camera className="absolute left-5 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                    <input 
                      value={newProp.image} 
                      onChange={e => setNewProp({...newProp, image: e.target.value})} 
                      className="w-full bg-slate-50 rounded-2xl p-5 pl-14 border-none focus:ring-4 focus:ring-blue-100 font-bold outline-none transition-all" 
                      placeholder="https://images.unsplash.com/..." 
                    />
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Preço (MT)</label>
                  <input 
                    type="number" 
                    required 
                    value={newProp.price} 
                    onChange={e => setNewProp({...newProp, price: Number(e.target.value)})} 
                    className="w-full bg-slate-50 rounded-2xl p-5 border-none focus:ring-4 focus:ring-blue-100 font-bold outline-none transition-all" 
