                   </div>
                </div>

                <div className="md:col-span-2 space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1 flex items-center gap-1"><AlignLeft size={12}/> Descrição Detalhada</label>
                  <textarea 
                    value={newProp.description} 
                    onChange={e => setNewProp({...newProp, description: e.target.value})} 
                    rows={4}
                    className="w-full bg-slate-50 rounded-[2rem] p-6 border-none focus:ring-4 focus:ring-blue-100 font-medium text-sm outline-none transition-all resize-none" 
                    placeholder="Descreva as características principais do imóvel..." 
                  />
                </div>
              </div>

              <div className="flex gap-4 pt-4">
                <button 
                  disabled={isSubmitting} 
                  type="submit" 
                  className="flex-1 py-6 bg-blue-600 text-white font-black rounded-[2.5rem] shadow-xl hover:bg-blue-700 transition-all flex items-center justify-center gap-3 active:scale-95 disabled:opacity-70"
                >
                  {isSubmitting ? <Loader2 size={24} className="animate-spin" /> : <><Check size={24} /> Sincronizar Portfólio Cloud</>}
                </button>
                <button 
                  type="button" 
                  onClick={() => setShowModal(false)} 
                  className="px-10 py-6 bg-slate-100 text-slate-500 font-black rounded-[2.5rem] hover:bg-slate-200 transition-all"
                >
                  Cancelar
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default CatalogView;
